def education_categories_rows():
    init_db()
    conn = db()
    conn.row_factory = sqlite3.Row
    cur = conn.cursor()
    cur.execute("SELECT * FROM education_categories WHERE active=1 ORDER BY sort_order ASC, title ASC")
