@webhook_app.route("/reset-pwa", methods=["GET"])
def reset_pwa_page():
    html = """
    <!doctype html>
    <html lang="en">
    <head>
      <meta charset="utf-8">
      <meta name="viewport" content="width=device-width, initial-scale=1">
      <title>Reset CoinPilotXAI App Cache</title>
      <style>
        body{margin:0;min-height:100vh;display:grid;place-items:center;padding:24px;background:#050b14;color:#f2fbff;font-family:Inter,system-ui,Arial,sans-serif}
        main{width:min(100%,560px);padding:28px;border:1px solid rgba(0,229,255,.22);border-radius:14px;background:#0d1627;text-align:center;box-shadow:0 24px 70px rgba(0,0,0,.35)}
        p{color:#9fb5c0;line-height:1.6}
      </style>
    </head>
    <body>
      <main>
        <h1>Resetting CoinPilotXAI app cache</h1>
        <p>Clearing old offline cache, service workers, and local app flags. You will be returned to the homepage automatically.</p>
      </main>
      <script>
        (async function () {
          try {
            console.log("[CoinPilotXAI PWA] reset started");
            if ("serviceWorker" in navigator) {
              var regs = await navigator.serviceWorker.getRegistrations();
              await Promise.all(regs.map(function (reg) { return reg.unregister(); }));
              console.log("[CoinPilotXAI PWA] service workers unregistered", regs.length);
            }
            if ("caches" in window) {
              var keys = await caches.keys();
              await Promise.all(keys.map(function (key) { return caches.delete(key); }));
              console.log("[CoinPilotXAI PWA] caches deleted", keys);
            }
            if ("indexedDB" in window && indexedDB.databases) {
              var databases = await indexedDB.databases();
              await Promise.all(databases.map(function (db) {
                return db && db.name ? new Promise(function (resolve) {
                  var req = indexedDB.deleteDatabase(db.name);
                  req.onsuccess = req.onerror = req.onblocked = function () { resolve(); };
                }) : Promise.resolve();
              }));
              console.log("[CoinPilotXAI PWA] indexedDB cleared");
            }
            try { localStorage.clear(); } catch (err) {}
            try { sessionStorage.clear(); } catch (err) {}
            try {
              localStorage.removeItem("coinpilotx_install_popup_dismissed_until");
              localStorage.removeItem("coinpilotx_offline");
              localStorage.removeItem("coinpilotx_offline_mode");
              localStorage.removeItem("offline");
            } catch (err) {}
          } finally {
            setTimeout(function () { location.href = "/?reset_pwa=1&ts=" + Date.now(); }, 1000);
          }
        })();
      </script>
    </body>
    </html>
    """
    response = Response(html, mimetype="text/html")
    response.headers["Cache-Control"] = "no-store, max-age=0"
    return response


@webhook_app.before_request
def start_performance_trace():
    g.performance_trace_id = request.headers.get("X-Trace-Id") or secrets.token_hex(6)
    g.performance_start = time.perf_counter()
    g.db_query_count = 0
    g.db_connection_count = 0
    g.db_query_signatures = {}
    return None


def record_performance_trace(path, method, status, duration_ms, db_queries, response_size, trace_id, level):
    try:
        if duration_ms < PERFORMANCE_SLOW_MS and level != "critical":
            return
        conn = db()
        cur = conn.cursor()
        duplicates = {
            key: count for key, count in (getattr(g, "db_query_signatures", {}) or {}).items()
            if int(count or 0) > 1
        }
        cur.execute(
            """
            INSERT INTO performance_traces
            (trace_id, path, method, status_code, duration_ms, db_query_count, db_connection_count, response_size, user_id, level, duplicate_queries_json, created_at)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                trace_id,
                str(path or "")[:500],
                str(method or "")[:12],
                int(status or 0),
                int(duration_ms or 0),
                int(db_queries or 0),
                int(getattr(g, "db_connection_count", 0) or 0),
                int(response_size or 0),
                int(account_user_id() or 0),
                level,
                json.dumps(duplicates)[:4000],
                datetime.utcnow().isoformat(timespec="seconds"),
            ),
        )
        conn.commit()
        conn.close()
    except Exception as exc:
        logging.debug("performance trace store skipped path=%s error=%s", path, exc)


@webhook_app.after_request
def add_pwa_headers(response):
    response.headers.setdefault("X-Content-Type-Options", "nosniff")
    response.headers.setdefault("Referrer-Policy", "strict-origin-when-cross-origin")
    if request.path.startswith(("/pulse/camera", "/pulse/live")):
        response.headers.setdefault("Permissions-Policy", "camera=(self), microphone=(self), geolocation=()")
    else:
        response.headers.setdefault("Permissions-Policy", "camera=(), microphone=(), geolocation=()")
    response.headers.setdefault("X-Frame-Options", "SAMEORIGIN")
    if request.headers.get("X-Forwarded-Proto", request.scheme) == "https":
        response.headers.setdefault("Strict-Transport-Security", "max-age=31536000; includeSubDomains")
    if not request.path.startswith(("/api/", "/static/")):
        response.headers.setdefault(
            "Content-Security-Policy",
            "default-src 'self'; object-src 'none'; img-src 'self' data: https:; style-src 'self' 'unsafe-inline'; script-src 'self' 'unsafe-inline'; connect-src 'self' https:; frame-ancestors 'self'; base-uri 'self'; form-action 'self' https://checkout.stripe.com; upgrade-insecure-requests;",
        )
    if request.path in ("/static/service-worker.js", "/sw.js"):
        response.headers["Service-Worker-Allowed"] = "/"
        response.headers["Cache-Control"] = "no-store, max-age=0"
    elif request.path.startswith(("/static/", "/icons/")):
        response.headers["Cache-Control"] = "public, max-age=31536000, immutable"
    elif request.path in ("/sitemap.xml", "/sitemap-pages.xml", "/sitemap-live.xml", "/sitemap-replays.xml", "/robots.txt", "/llms.txt", "/ai-index.json", "/manifest.json", "/site.webmanifest"):
        response.headers["Cache-Control"] = "public, max-age=300"
    if (
        response.status_code == 200
        and not response.direct_passthrough
        and "text/html" in (response.headers.get("Content-Type") or "")
    ):
        try:
            html = response.get_data(as_text=True)
            if "</head>" in html.lower() and "/static/img/favicon-32.png" not in html:
                favicon_tags = """
<link rel="icon" type="image/png" sizes="32x32" href="/static/img/favicon-32.png">
<link rel="icon" type="image/png" sizes="16x16" href="/static/img/favicon-16.png">
<link rel="shortcut icon" href="/favicon.ico">
<link rel="apple-touch-icon" sizes="180x180" href="/static/img/apple-touch-icon.png">
<link rel="manifest" href="/manifest.json">
<meta name="theme-color" content="#020817">
"""
                html = re.sub(r"</head>", favicon_tags + "</head>", html, count=1, flags=re.I)
                response.set_data(html)
                response.headers.pop("Content-Length", None)
        except Exception as exc:
            logging.info("GLOBAL_FAVICON_INJECT_SKIPPED path=%s error=%s", request.path, exc)
    try:
        duration_ms = int((time.perf_counter() - float(getattr(g, "performance_start", time.perf_counter()))) * 1000)
        response_size = response.calculate_content_length()
        if response_size is None:
            response_size = len(response.get_data()) if not response.direct_passthrough else 0
        db_queries = int(getattr(g, "db_query_count", 0) or 0)
        trace_id = getattr(g, "performance_trace_id", secrets.token_hex(6))
        level = "critical" if duration_ms >= PERFORMANCE_CRITICAL_MS else "warning" if duration_ms >= PERFORMANCE_SLOW_MS else "info"
        response.headers.setdefault("X-Trace-Id", trace_id)
        response.headers.setdefault("X-Response-Time-Ms", str(duration_ms))
        response.headers.setdefault("X-DB-Query-Count", str(db_queries))
        logging.log(
            logging.ERROR if level == "critical" else logging.WARNING if level == "warning" else logging.INFO,
            "PERF_REQUEST trace_id=%s method=%s path=%s status=%s duration_ms=%s db_queries=%s db_connections=%s user_id=%s response_size=%s level=%s",
            trace_id,
            request.method,
            request.path,
            response.status_code,
            duration_ms,
            db_queries,
            int(getattr(g, "db_connection_count", 0) or 0),
            account_user_id() or 0,
            response_size,
            level,
        )
        if level in {"warning", "critical"}:
            record_performance_trace(request.path, request.method, response.status_code, duration_ms, db_queries, response_size, trace_id, level)
    except Exception as exc:
        logging.debug("PERF_REQUEST_LOG_SKIPPED path=%s error=%s", request.path, exc)
    return response


@webhook_app.before_request
def enforce_https():
    host = request.host.split(":")[0]
    if host in {"localhost", "127.0.0.1", "0.0.0.0"}:
        return None
    forwarded_proto = request.headers.get("X-Forwarded-Proto", request.scheme)
    if forwarded_proto == "http":
        return redirect(request.url.replace("http://", "https://", 1), code=301)


@webhook_app.before_request
def enforce_arena_pro_access():
    path = request.path or ""
    public_arena_prefixes = (
        "/arena-preview",
        "/arena/player/",
        "/api/arena/share/",
    )
    if not (path == "/arena" or path.startswith("/arena/") or path.startswith("/api/arena/")):
        return None
    if path.startswith(public_arena_prefixes):
        return None
    user = load_account_by_id(account_user_id())
    if not user:
        if path.startswith("/api/arena/"):
            log_security_event("arena_api_auth_required", "blocked", 0, path)
            return jsonify({"ok": False, "message": "Please log in to use Arena.", "login_url": url_for("login_page", next=path)}), 401
        return redirect(url_for("login_page", next=path))
    if not platform_pro_access(user):
        return arena_access_preview_response(user)
    return None
    return None


