    status = (user.get("subscription_status") or "inactive").lower()
    access_type = pro_access_type(user)
    if access_type == "paid":
        return "Pulse Premium Active"
    if access_type == "trial":
        return "Legacy Trial"
    if has_pro_access(user):
        return "Premium Active"
    if status == "expired":
        return "Free Core"
    return "Free Core"


