def arena_challenge_key(value):
    raw = clean_html(str(value or "friend_battle")).strip().lower().replace(" ", "_").replace("-", "_")
    aliases = {
        "btc": "btc_duel",
        "eth": "eth_duel",
        "scam_duel": "scam_hunter_duel",
        "scam_hunter": "scam_hunter_duel",
        "portfolio_battle": "fake_portfolio_battle",
        "portfolio_survival": "fake_portfolio_battle",
        "quick": "quick_battle",
    }
    key = aliases.get(raw, raw)
    return key if key in ARENA_CHALLENGE_TYPES else "friend_battle"


def arena_challenge_details(challenge_type):
    key = arena_challenge_key(challenge_type)
    details = dict(ARENA_CHALLENGE_TYPES.get(key) or ARENA_CHALLENGE_TYPES["friend_battle"])
    details["key"] = key
    return details


def arena_match_label(match_type):
    return arena_challenge_details(match_type).get("label") or clean_html(str(match_type or "Arena Match")).replace("_", " ").title()


def arena_match_rules_for_type(match_type):
    details = arena_challenge_details(match_type)
    symbols = ["BTC", "ETH", "SOL"]
    if details["key"] == "eth_duel":
        symbols = ["ETH"]
    elif details["key"] == "btc_duel":
        symbols = ["BTC"]
    return {
        "fake_starting_balance": int(details.get("fake_balance") or 10000),
        "symbols": symbols,
        "max_trades": 8,
        "scoring": "risk_adjusted_discipline",
        "challenge_type": details["key"],
        "challenge_label": details["label"],
        "duration": details["duration"],
        "xp_reward": details["xp_reward"],
        "rules": details["rules"],
    }


def ensure_arena_participant(cur, match_id, user_id, fake_balance=10000):
    if not match_id or not user_id:
        return False
    now = datetime.now().isoformat()
    cur.execute(
        "INSERT OR IGNORE INTO arena_match_participants (match_id, user_id, fake_balance, score, result_json, joined_at) VALUES (?, ?, ?, 0, '{}', ?)",
        (int(match_id), int(user_id), float(fake_balance or 10000), now),
    )
    return cur.rowcount > 0


def arena_public_match_participants(cur, match_id):
    cur.execute(
        """
        SELECT p.*, ap.public_player_id, ap.display_name, ap.rank, ap.country, ap.avatar_url, ap.faction, ap.online_status
        FROM arena_match_participants p
        LEFT JOIN arena_profiles ap ON ap.user_id=p.user_id
        WHERE p.match_id=? ORDER BY p.score DESC, p.joined_at ASC
        """,
        (match_id,),
    )
    participants = []
    for row in cur.fetchall():
        item = dict(row)
        profile = public_arena_player({
            "user_id": item.get("user_id"),
            "public_player_id": item.get("public_player_id"),
            "display_name": item.get("display_name"),
            "rank": item.get("rank"),
            "country": item.get("country"),
            "avatar_url": item.get("avatar_url"),
            "faction": item.get("faction"),
            "online_status": item.get("online_status"),
        })
        item.update(profile)
        item.pop("email", None)
        item.pop("username", None)
        participants.append(item)
    return participants


def arena_match_can_join(match, user_id, participants=None):
    if not match:
        return False, "Match not found."
    status = (match.get("status") or "").lower()
    if status not in {"active", "open", "waiting", "accepted", "matchmaking"}:
        return False, "This match is not accepting new players."
    if participants and any(int(p.get("user_id") or 0) == int(user_id) for p in participants):
        return False, "Already joined."
    match_type = arena_challenge_key(match.get("match_type"))
    opponent_id = int(match.get("opponent_id") or 0)
    creator_id = int(match.get("creator_id") or 0)
    if match_type == "friend_battle" and opponent_id and int(user_id) not in {creator_id, opponent_id}:
        return False, "Private friend battles are limited to invited players."
    if opponent_id and int(user_id) not in {creator_id, opponent_id} and match_type not in {"btc_duel", "eth_duel", "scam_hunter_duel", "prediction_war"}:
        return False, "This battle is private."
    if participants and len(participants) >= 2 and match_type not in {"solo_market_survival", "survival_mode", "quick_battle"}:
        return False, "This battle is already full."
    return True, ""


def arena_user_display(user_id):
    user = load_account_by_id(user_id) or {}
    return account_display_name(user) if user else f"Pilot {user_id}"


def create_arena_match(creator_id, opponent_id=0, match_type="btc_duel", rules=None, status="active"):
    logging.info("ARENA_MATCH_CREATE_STARTED creator_id=%s opponent_id=%s match_type=%s status=%s", creator_id, opponent_id, match_type, status)
    now = datetime.now().isoformat()
    starts = now
    ends = (datetime.now() + timedelta(hours=1)).isoformat()
    match_key = arena_challenge_key(match_type)
    rules = rules or arena_match_rules_for_type(match_key)
    conn = db()
    cur = conn.cursor()
    cur.execute(
        """
        INSERT INTO arena_matches (match_type, creator_id, opponent_id, room_id, status, starts_at, ends_at, rules_json, created_at)
        VALUES (?, ?, ?, 0, ?, ?, ?, ?, ?)
        """,
        (match_key, creator_id, opponent_id or 0, status, starts, ends, json.dumps(rules), now),
    )
    match_id = cur.lastrowid
    if not match_id:
        conn.rollback()
        conn.close()
        logging.error("ARENA_MATCH_CREATE_FAILED creator_id=%s match_type=%s reason=no_match_id", creator_id, match_type)
        return 0
    for participant_id in [creator_id, opponent_id]:
        if participant_id:
            ensure_arena_participant(cur, match_id, participant_id, rules.get("fake_starting_balance") or rules.get("fake_balance") or 10000)
    cur.execute(
        "INSERT INTO arena_live_matches (match_id, status, phase, countdown_ends_at, live_payload_json, updated_at) VALUES (?, ?, 'live', ?, '{}', ?)",
        (match_id, status, (datetime.now() + timedelta(seconds=15)).isoformat(), now),
    )
    cur.execute(
        "INSERT INTO arena_match_events (match_id, user_id, event_type, title, body, payload_json, created_at) VALUES (?, ?, 'match_started', 'Arena battle started', 'Virtual-dollar battle created. No real trading occurs.', ?, ?)",
        (match_id, creator_id, json.dumps({"rules": rules}), now),
    )
    conn.commit()
    conn.close()
    logging.info("ARENA_MATCH_CREATE_SUCCESS match_id=%s creator_id=%s match_type=%s", match_id, creator_id, match_key)
    return match_id


def get_arena_match_payload(match_id, current_user_id=None):
    conn = db()
    conn.row_factory = sqlite3.Row
    cur = conn.cursor()
    cur.execute("SELECT * FROM arena_matches WHERE id=? LIMIT 1", (match_id,))
    match_row = cur.fetchone()
    if not match_row:
        conn.close()
        return None
    match = dict(match_row)
    match["rules"] = json.loads(match.get("rules_json") or "{}")
    match["display_name"] = arena_match_label(match.get("match_type"))
    participants = arena_public_match_participants(cur, match_id)
    cur.execute("SELECT * FROM arena_trade_positions WHERE match_id=? ORDER BY updated_at DESC", (match_id,))
    positions = [dict(row) for row in cur.fetchall()]
    cur.execute("SELECT * FROM arena_trades WHERE match_id=? ORDER BY created_at DESC LIMIT 20", (match_id,))
    trades = [dict(row) for row in cur.fetchall()]
    cur.execute("SELECT * FROM arena_match_events WHERE match_id=? ORDER BY created_at DESC LIMIT 30", (match_id,))
    events = [dict(row) for row in cur.fetchall()]
    cur.execute("SELECT COUNT(*) AS c FROM arena_spectators WHERE match_id=?", (match_id,))
    spectators_row = cur.fetchone()
    spectators = int(spectators_row["c"] if spectators_row else 0)
    cur.execute("SELECT COUNT(*) AS c FROM arena_emotes WHERE match_id=?", (match_id,))
    cheer_row = cur.fetchone()
    cheer_count = int(cheer_row["c"] if cheer_row else 0)
    conn.close()
    commentary = arena_commentator.match_recap(match, participants, events)
    payload = arena_realtime.live_match_payload(match, participants, positions, trades, events, spectators, commentary)
    current_id = int(current_user_id or 0)
    is_participant = any(int(p.get("user_id") or 0) == current_id for p in participants) if current_id else False
    can_join, join_reason = arena_match_can_join(match, current_id, participants) if current_id else (False, "Login required.")
    winner = participants[0] if (match.get("status") == "completed" and participants) else {}
    payload.update({
        "match_label": match.get("display_name"),
        "spectator_count": spectators,
        "cheer_count": cheer_count,
        "winner_public_player_id": winner.get("public_player_id") or "",
        "winner_display_name": winner.get("display_name") or "",
        "is_participant": is_participant,
        "is_spectator": bool(current_id and not is_participant),
        "can_join": bool(can_join),
        "can_trade": bool(is_participant and (match.get("status") or "").lower() in {"active", "open", "waiting", "accepted"}),
        "can_watch": bool(current_id),
        "can_cheer": bool(current_id),
        "can_challenge_winner": bool(match.get("status") == "completed" and winner),
        "join_required_reason": join_reason,
        "market_context": {
            "BTC": arena_live_price("BTC")[0],
            "ETH": arena_live_price("ETH")[0],
            "source": "live/cached market service",
            "updated_at": datetime.now().isoformat(),
        },
    })
    return payload


def arena_current_season():
    conn = db()
    conn.row_factory = sqlite3.Row
    cur = conn.cursor()
    cur.execute("SELECT * FROM arena_seasons WHERE status='active' ORDER BY starts_at DESC LIMIT 1")
    row = cur.fetchone()
    conn.close()
    return dict(row) if row else {"title": "Season 1: Market Survival", "narrative": "Survive markets with discipline.", "xp_multiplier": 1}


def arena_world_payload(user_id=None):
    world = arena_world_engine.current_world_state()
    conn = db()
    conn.row_factory = sqlite3.Row
    cur = conn.cursor()
    cur.execute("SELECT * FROM arena_factions WHERE status='active' ORDER BY influence DESC")
    factions = [dict(row) for row in cur.fetchall()]
    cur.execute("SELECT * FROM arena_world_events WHERE status='active' ORDER BY starts_at DESC LIMIT 12")
    world_events = [dict(row) for row in cur.fetchall()]
    cur.execute("SELECT * FROM arena_ai_governors WHERE status='active' ORDER BY id ASC")
    governors = [dict(row) for row in cur.fetchall()]
    conn.close()
    return {
        "ok": True,
        "world": world,
        "season": arena_current_season(),
        "factions": factions,
        "world_events": world_events,
        "governors": governors,
        "disclaimer": "Arena world systems are educational and simulated. No real-money trading occurs inside Arena matches.",
    }


def arena_player_story_payload(user_id):
    profile = get_or_create_arena_profile(user_id) or {}
    badges = arena_profile_payload(user_id).get("badges", [])
    story = arena_world_engine.player_story(profile, badges)
    conn = db()
    cur = conn.cursor()
    cur.execute(
        "INSERT INTO arena_player_stories (user_id, archetype, story, payload_json, created_at) VALUES (?, ?, ?, ?, ?)",
        (user_id, story["archetype"], story["story"], json.dumps(story), datetime.now().isoformat()),
    )
    conn.commit()
    conn.close()
    return {"ok": True, **story, "profile": profile}


def arena_live_feed(limit=30):
    conn = db()
    conn.row_factory = sqlite3.Row
    cur = conn.cursor()
    cur.execute(
        """
        SELECT 'match_event' AS feed_type, title, body, user_id, created_at FROM arena_match_events
        UNION ALL
        SELECT 'highlight' AS feed_type, title, summary AS body, user_id, created_at FROM arena_highlights
        UNION ALL
        SELECT 'story' AS feed_type, archetype AS title, story AS body, user_id, created_at FROM arena_player_stories
        ORDER BY created_at DESC LIMIT ?
        """,
        (int(limit or 30),),
    )
    feed = [dict(row) for row in cur.fetchall()]
    conn.close()
    if not feed:
        world = arena_world_engine.current_world_state()
        feed = [
            {"feed_type": "world", "title": world["title"], "body": world["narrative"], "user_id": 0, "created_at": world["updated_at"]},
            {"feed_type": "coach", "title": "AI Coach", "body": "Complete a mission or simulated battle to create your first Arena highlight.", "user_id": 0, "created_at": world["updated_at"]},
        ]
    return {"ok": True, "feed": feed, "updated_at": datetime.now().isoformat()}


def arena_coach_recommendations(user_id):
    profile = get_or_create_arena_profile(user_id) or {}
    discipline = int(profile.get("discipline_score") or 50)
    scam = int(profile.get("scam_defense_score") or 50)
    strategy = int(profile.get("strategy_score") or 50)
    recommendations = []
    if discipline < 70:
        recommendations.append({"title": "Train discipline", "path": "/arena/academy/risk-control-mastery", "reason": "You can improve by practicing smaller simulated position sizes."})
    if scam < 70:
        recommendations.append({"title": "Strengthen Scam Defense", "path": "/arena/academy/scam-defense-mastery", "reason": "Scam Hunter training protects your decision quality."})
    if strategy < 70:
        recommendations.append({"title": "Build strategy", "path": "/arena/academy/portfolio-strategy-mastery", "reason": "Portfolio training improves risk-adjusted scoring."})
    if not recommendations:
        recommendations.append({"title": "Enter an elite mission", "path": "/arena/quests", "reason": "Your profile is ready for harder seasonal quests."})
    return {"ok": True, "recommendations": recommendations, "archetype": arena_world_engine.player_archetype(profile)}


def arena_academy_payload(user_id):
    conn = db()
    conn.row_factory = sqlite3.Row
    cur = conn.cursor()
    cur.execute("SELECT * FROM arena_academy_paths WHERE active=1 ORDER BY id ASC")
    paths = [dict(row) for row in cur.fetchall()]
    cur.execute("SELECT * FROM arena_academy_progress WHERE user_id=?", (user_id,))
    progress = {row["path_key"]: dict(row) for row in cur.fetchall()}
    conn.close()
    for path in paths:
        path["progress"] = int((progress.get(path["path_key"]) or {}).get("progress") or 0)
    return {"ok": True, "paths": paths, "recommendations": arena_coach_recommendations(user_id).get("recommendations", [])}


def arena_quests_payload(user_id):
    conn = db()
    conn.row_factory = sqlite3.Row
    cur = conn.cursor()
    cur.execute("SELECT * FROM arena_quests WHERE active=1 ORDER BY quest_type ASC, reward_xp DESC")
    quests = [dict(row) for row in cur.fetchall()]
    cur.execute("SELECT * FROM arena_quest_progress WHERE user_id=?", (user_id,))
    progress = {int(row["quest_id"]): dict(row) for row in cur.fetchall()}
    conn.close()
    for quest in quests:
        item = progress.get(int(quest["id"])) or {}
        quest["progress"] = int(item.get("progress") or 0)
        quest["claimed"] = bool(item.get("claimed") or 0)
    return {"ok": True, "quests": quests}


