@webhook_app.route("/arena/chat/<int:thread_id>", methods=["GET"])
def arena_chat_page(thread_id):
    init_db()
    user = require_account()
    if not user:
        return redirect(url_for("signup_page", next=request.path))
    if chat_realtime_service.messages(user["user_id"], thread_id, limit=1):
        return redirect(f"/chat/thread/{int(thread_id)}?arena=1&focus=reply")
    conn = db()
    conn.row_factory = sqlite3.Row
    cur = conn.cursor()
    cur.execute("SELECT * FROM arena_chat_threads WHERE id=? AND (user_a_id=? OR user_b_id=?) LIMIT 1", (int(thread_id), user["user_id"], user["user_id"]))
    arena_thread = cur.fetchone()
    conn.close()
    if arena_thread:
        other_id = int(arena_thread["user_b_id"] if int(arena_thread["user_a_id"]) == int(user["user_id"]) else arena_thread["user_a_id"])
        private_thread_id = direct_conversation_between(user["user_id"], other_id)
        return redirect(f"/chat/thread/{int(private_thread_id)}?arena=1&focus=reply")
    payload = arena_chat_payload(thread_id, user["user_id"])
    if not payload:
        return arena_page_shell("Arena Chat", "<section class='card'><h1>Thread not found</h1><p>This Arena chat is unavailable or private.</p></section>", user=user), 404
    other = payload.get("other") or {}
    body = f"""
    <section class="hero">
      <article class="card wide"><div class="kicker">Arena Live Chat</div><h1>{clean_html(other.get('display_name') or 'Arena Pilot')}</h1><p><span class="rank">{clean_html(other.get('rank') or 'Rookie')}</span> <span class="muted">· live thread · public Arena identity only</span></p></article>
      <article class="card"><h2>Presence</h2><p><span class="online-dot">Online / recently active</span></p><p class="muted" data-typing>Ready.</p></article>
    </section>
    <section class="card" style="min-height:58vh;display:grid;grid-template-rows:auto 1fr auto;gap:12px">
      <div class="actions"><a class="button" href="/arena/inbox">Inbox</a><a class="button" href="/arena/player/{clean_html(other.get('public_player_id') or '')}">View Profile</a><button data-sound-toggle>Sound</button></div>
      <div class="chat-thread" data-arena-chat-thread></div>
      <form class="private-chat-form" data-arena-chat-form><input name="body" placeholder="Reply in Arena..." maxlength="1200" autocomplete="off"><button class="button primary">Send</button></form>
    </section>
    <script>
    const threadId={int(thread_id)};
    const esc=v=>String(v??'').replace(/[&<>"']/g,c=>({{'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}}[c]));
    let chatLoading=false, soundOn=false, lastMessageId=0;
    function messageHtml(m, optimistic=false){{return `<div class="chat-bubble ${{m.is_mine?'me':'them'}}" data-message-id="${{m.message_id||0}}"><span>${{esc(m.body)}}</span><small>${{esc(optimistic?'sending...':(m.delivery_status||'delivered'))}}</small></div>`;}}
    function appendMessages(items){{const box=document.querySelector('[data-arena-chat-thread]');const existing=new Set([...box.querySelectorAll('[data-message-id]')].map(n=>n.dataset.messageId));(items||[]).forEach(m=>{{if(existing.has(String(m.message_id)))return;box.insertAdjacentHTML('beforeend',messageHtml(m));lastMessageId=Math.max(lastMessageId,Number(m.message_id||0));}});box.scrollTop=box.scrollHeight;}}
    function renderMessages(items){{const box=document.querySelector('[data-arena-chat-thread]');box.innerHTML=(items||[]).map(m=>messageHtml(m)).join('')||'<div class="private-chat-empty">Send the first Arena reply.</div>';lastMessageId=Math.max(0,...(items||[]).map(m=>Number(m.message_id||0)));box.scrollTop=box.scrollHeight;}}
    async function loadChat(){{if(chatLoading||document.hidden)return;chatLoading=true;try{{const url=lastMessageId?`/api/arena/chat/${{threadId}}/new?after_id=${{lastMessageId}}`:`/api/arena/chat/${{threadId}}`;const d=await fetch(url,{{cache:'no-store'}}).then(r=>r.json());if(d.ok){{if(lastMessageId)appendMessages(d.messages);else renderMessages(d.messages);if(d.last_message_id)lastMessageId=Math.max(lastMessageId,Number(d.last_message_id));}}}}finally{{chatLoading=false;}}}}
    document.querySelector('[data-arena-chat-form]').addEventListener('submit',async e=>{{e.preventDefault();const input=e.target.elements.body;const button=e.target.querySelector('button');const body=input.value.trim();if(!body)return;input.value='';button.disabled=true;const tempId=`temp-${{Date.now()}}`;const box=document.querySelector('[data-arena-chat-thread]');box.insertAdjacentHTML('beforeend',`<div class="chat-bubble me" data-message-id="${{tempId}}"><span>${{esc(body)}}</span><small>sending...</small></div>`);box.scrollTop=box.scrollHeight;try{{const d=await fetch(`/api/arena/chat/${{threadId}}/send`,{{method:'POST',headers:{{'Content-Type':'application/json'}},body:JSON.stringify({{message:body,body}})}}).then(r=>r.json());const pending=box.querySelector(`[data-message-id="${{tempId}}"]`);if(d.ok&&d.message){{if(pending)pending.outerHTML=messageHtml(d.message);lastMessageId=Math.max(lastMessageId,Number(d.message.message_id||0));}}else if(pending){{pending.querySelector('small').textContent='failed - retry';input.value=body;}}}}catch(err){{input.value=body;}}finally{{button.disabled=false;if(navigator.vibrate)navigator.vibrate([30]);if(soundOn&&window.CoinPilotNotifications)window.CoinPilotNotifications.playSound();}}}});
    document.querySelector('[data-arena-chat-form] input').addEventListener('input',()=>fetch('/api/arena/chat/typing',{{method:'POST',headers:{{'Content-Type':'application/json'}},body:JSON.stringify({{thread_id:threadId}})}}).catch(()=>{{}}));
    document.addEventListener('click',e=>{{if(e.target.closest('[data-sound-toggle]')){{soundOn=!soundOn;e.target.textContent=soundOn?'Sound On':'Sound';}}}});
    loadChat(); setInterval(loadChat,2000); document.addEventListener('visibilitychange',()=>{{if(!document.hidden)loadChat();}});
    </script>
    """
    return arena_page_shell("Arena Chat", body, user=user)


@webhook_app.route("/arena/inbox", methods=["GET"])
def arena_inbox_page():
    init_db()
    user = require_account()
    if not user:
        return redirect(url_for("signup_page", next="/arena/inbox"))
    inbox = arena_inbox_payload(user["user_id"])
    def card(item):
        sender = item.get("sender") or {}
        public_id = clean_html(sender.get("public_player_id") or "")
        name = clean_html(sender.get("display_name") or "Arena Pilot")
        rank = clean_html(sender.get("rank") or "Rookie")
        faction = clean_html(sender.get("faction") or "Arena Faction")
        preview = clean_html(item.get("message_preview") or "Arena request")
        status = clean_html(item.get("status") or "pending")
        kind = item.get("type")
        details_html = ""
        if kind == "challenge":
            accept_url, reject_url, key, accept_text = "/api/arena/challenge/accept", "/api/arena/challenge/reject", "challenge_id", "Accept Challenge"
            details_html = f"""
            <div class="arena-request-details">
              <strong>{clean_html(item.get('challenge_label') or 'Arena Challenge')}</strong>
              <p>{clean_html(item.get('mode_description') or '')}</p>
              <p class="muted">Duration: {clean_html(item.get('duration') or 'Flexible')} · Reward: {clean_html(item.get('xp_reward') or 'XP only')} · Difficulty: {clean_html(item.get('difficulty') or 'Adaptive')}</p>
              <p class="muted">Virtual balance: ${int(item.get('fake_balance') or 0):,} · Expires in {int(item.get('expires_in_days') or 0)} days</p>
              <p class="muted">Rules: {clean_html(', '.join(item.get('rules') or ['XP only', 'No real money']))}</p>
            </div>
            """
        elif kind == "friend_request":
            accept_url, reject_url, key, accept_text = "/api/arena/friend-request/accept", "/api/arena/friend-request/reject", "request_id", "Accept Friend"
        else:
            accept_url, reject_url, key, accept_text = "/api/arena/message/accept", "/api/arena/message/reject", "request_id", "Accept Chat"
        stats = f"<p class='muted'>{rank} · {faction} · {clean_html(item.get('stakes') or 'XP only')}</p>" if kind == "challenge" else f"<p class='muted'>{rank} · {faction}</p>"
        reply_form = ""
        if kind == "message":
            thread_id = int(item.get("thread_id") or 0)
            reply_form = f"""
          <form data-inline-reply data-request-id="{int(item.get('id') or 0)}" data-public-player-id="{public_id}" data-thread-id="{thread_id}" hidden>
            <label class="muted">Reply to {name}</label>
            <textarea name="message" rows="3" placeholder="Type a fast Arena reply..."></textarea>
            <div class="actions"><button class="primary" type="submit">Send Reply</button><a class="button" href="{clean_html(item.get('chat_url') or item.get('next_url') or '#')}">Open Chat</a></div>
            <p class="muted" data-reply-status></p>
          </form>
            """
        if status == "pending":
            if kind == "message":
                primary_actions = f"""
            <button class="primary" data-arena-reply data-request-id="{int(item.get('id') or 0)}" data-public-player-id="{public_id}" data-thread-id="{int(item.get('thread_id') or 0)}" data-next-url="{clean_html(item.get('next_url') or '')}">Reply</button>
            <button data-arena-action="{accept_url}" data-key="{key}" data-id="{int(item.get('id') or 0)}">{accept_text}</button>
            <button data-arena-action="{reject_url}" data-key="{key}" data-id="{int(item.get('id') or 0)}">Decline</button>
                """
            else:
                primary_actions = f"""
            <button data-arena-action="{accept_url}" data-key="{key}" data-id="{int(item.get('id') or 0)}">{accept_text}</button>
            <button data-arena-action="{reject_url}" data-key="{key}" data-id="{int(item.get('id') or 0)}">Decline</button>
                """
        elif kind == "message" and status == "accepted" and item.get("chat_url"):
            primary_actions = f"""
            <button class="primary" data-arena-reply data-request-id="{int(item.get('id') or 0)}" data-public-player-id="{public_id}" data-thread-id="{int(item.get('thread_id') or 0)}" data-next-url="{clean_html(item.get('chat_url') or '')}">Reply</button>
            <button class='primary' data-arena-reply data-open-chat-direct="1" data-request-id="{int(item.get('id') or 0)}" data-public-player-id="{public_id}" data-thread-id="{int(item.get('thread_id') or 0)}">Open Chat</button>
            """
        elif kind == "challenge" and status == "accepted" and item.get("next_url"):
            primary_actions = f"<a class='button primary' href='{clean_html(item.get('next_url'))}'>Open Match</a>"
        else:
            primary_actions = f"<span class='rank'>{status.title()}</span>"
        return f"""
        <article class="player-card" data-request-card="{kind}:{int(item.get('id') or 0)}" data-sender-public-player-id="{public_id}">
          <strong>{name}</strong>{stats}
          <p>“{preview}”</p>
          {details_html}
          <small class="muted">{clean_html(item.get('created_at') or '')} · {status}</small>
          <div class="actions">
            {primary_actions}
            <a class="button" href="/arena/player/{public_id}">View Profile</a>
            <button data-arena-block="{public_id}">Block</button>
            <button data-arena-report="{public_id}">Report</button>
          </div>
          {reply_form}
        </article>
        """
    requests_html = "".join(card(item) for item in inbox.get("requests", [])) or "<article class='card'><h2>No pending Arena requests</h2><p class='muted'>When another player challenges or messages you, it appears here first.</p></article>"
    challenges_html = "".join(card(item) for item in inbox.get("challenges", [])[:20]) or "<p class='muted'>No challenges yet.</p>"
    messages_html = "".join(card(item) for item in inbox.get("messages", [])[:20]) or "<p class='muted'>No Arena message requests yet.</p>"
    friend_html = "".join(card(item) for item in inbox.get("friend_requests", [])[:20]) or "<p class='muted'>No friend requests yet.</p>"
    counts = inbox.get("counts") or {}
    body = f"""
    <section class="hero">
      <article class="card wide"><div class="kicker">Arena Inbox</div><h1>Actionable realtime requests</h1><p>Challenges, message requests, match invites, friend requests, and battle results live here instead of the generic notification center.</p></article>
      <article class="card"><h2>Live Count</h2><div class="metric">{int(counts.get('pending_requests') or 0)}</div><p>Pending Arena actions</p></article>
    </section>
    <section class="card"><h2>Requests</h2><div class="actions"><a class="button" href="#requests">Requests</a><a class="button" href="#challenges">Challenges</a><a class="button" href="#messages">Messages</a><a class="button" href="#friends">Friend Requests</a><a class="button" href="#results">Battle Results</a></div><div id="requests" class="grid">{requests_html}</div></section>
    <section class="grid"><article id="challenges" class="card wide"><h2>Challenges</h2>{challenges_html}</article><article id="messages" class="card"><h2>Messages</h2>{messages_html}</article><article class="card"><h2>Team Invites</h2><p class="muted">Team invites are ready for realtime routing.</p></article><article id="friends" class="card"><h2>Friend Requests</h2>{friend_html}</article><article id="results" class="card wide"><h2>Battle Results</h2><p class="muted">{len(inbox.get('battle_results') or [])} recent challenge results.</p></article></section>
    <script>
    function arenaToast(message){{
      let toast=document.querySelector('[data-arena-toast]');
      if(!toast){{toast=document.createElement('div');toast.dataset.arenaToast='1';toast.style.cssText='position:fixed;left:50%;bottom:18px;z-index:90;transform:translateX(-50%);max-width:min(92vw,420px);border:1px solid rgba(110,223,246,.35);border-radius:14px;background:rgba(8,19,35,.96);box-shadow:0 20px 70px rgba(0,0,0,.42),0 0 24px rgba(110,223,246,.18);padding:12px 14px;color:#f2fbff;font-weight:900';document.body.appendChild(toast);}}
      toast.textContent=message;
      clearTimeout(toast._timer);
      toast._timer=setTimeout(()=>toast.remove(),2600);
    }}
    document.addEventListener('click',async e=>{{
      const action=e.target.closest('[data-arena-action]');
      const reply=e.target.closest('[data-arena-reply]');
      const block=e.target.closest('[data-arena-block]');
      const report=e.target.closest('[data-arena-report]');
      if(reply){{
        reply.disabled=true;
        arenaToast('Opening chat...');
        const card=reply.closest('[data-request-card]');
        const form=card?.querySelector('[data-inline-reply]');
        let threadId=0;
        const public_player_id=reply.dataset.publicPlayerId||form?.dataset.publicPlayerId||card?.dataset.senderPublicPlayerId||'';
        const r=await fetch('/api/arena/message/accept',{{method:'POST',headers:{{'Content-Type':'application/json'}},body:JSON.stringify({{request_id:Number(reply.dataset.requestId||0),public_player_id}})}});
        const d=await r.json();
        if(!d.ok){{reply.disabled=false;arenaToast('Could not open this chat. Please refresh.');return;}}
        if(reply.dataset.openChatDirect&&d.next_url){{location.href=d.next_url;return;}}
        threadId=Number(d.thread_id||0);
        reply.dataset.threadId=threadId;
        reply.dataset.nextUrl=d.next_url||'';
        if(form){{form.dataset.threadId=threadId;const link=form.querySelector('a.button');if(link&&d.next_url)link.href=d.next_url;}}
        if(form){{form.hidden=false;form.querySelector('textarea')?.focus();}}
        reply.textContent='Reply open';
        reply.disabled=false;
      }}
      if(action){{action.disabled=true;action.textContent='Working...';const card=action.closest('[data-request-card]');const payload={{[action.dataset.key]:Number(action.dataset.id),public_player_id:card?.dataset.senderPublicPlayerId||''}};const r=await fetch(action.dataset.arenaAction,{{method:'POST',headers:{{'Content-Type':'application/json'}},body:JSON.stringify(payload)}});const d=await r.json();if(d.next_url)location.href=d.next_url;else if(d.match_id)location.href='/arena/match/'+d.match_id;else if(d.chat_url)location.href=d.chat_url;else if(d.ok===false){{arenaToast(d.message||'Could not complete action.');action.disabled=false;}}else action.closest('[data-request-card]')?.remove();}}
      if(block){{block.disabled=true;await fetch('/api/arena/block-player',{{method:'POST',headers:{{'Content-Type':'application/json'}},body:JSON.stringify({{public_player_id:block.dataset.arenaBlock,reason:'Blocked from Arena inbox'}})}});document.querySelectorAll(`[data-arena-block="${{block.dataset.arenaBlock}}"]`).forEach(n=>n.closest('[data-request-card]')?.remove());}}
      if(report){{await fetch('/api/arena/report-player',{{method:'POST',headers:{{'Content-Type':'application/json'}},body:JSON.stringify({{public_player_id:report.dataset.arenaReport,report_type:'inbox',details:'Reported from Arena inbox'}})}});arenaToast('Report sent.');}}
    }});
    document.addEventListener('submit',async e=>{{
      const form=e.target.closest('[data-inline-reply]');
      if(!form)return;
      e.preventDefault();
      const textarea=form.querySelector('textarea');
      const status=form.querySelector('[data-reply-status]');
      const button=form.querySelector('button[type="submit"]');
      const message=(textarea?.value||'').trim();
      if(!message)return;
      button.disabled=true;
      if(status)status.textContent='Sending...';
      const threadId=Number(form.dataset.threadId||0);
      const r=await fetch(`/api/chat/thread/${{threadId}}/send`,{{method:'POST',headers:{{'Content-Type':'application/json'}},body:JSON.stringify({{message}})}});
      const d=await r.json();
      if(d.ok){{textarea.value='';if(status)status.textContent='Message sent.';form.closest('[data-request-card]')?.querySelector('[data-arena-action]')?.remove();}}
      else if(status)status.textContent=d.message||'Could not send. Try again.';
      button.disabled=false;
    }});
    </script>
    """
    return arena_page_shell("Arena Inbox", body, user=user)


@webhook_app.route("/arena/play", methods=["GET"])
@webhook_app.route("/arena/quick-battle", methods=["GET"])
@webhook_app.route("/arena/survival", methods=["GET"])
@webhook_app.route("/arena/scam-rush", methods=["GET"])
@webhook_app.route("/arena/simulator", methods=["GET"])
@webhook_app.route("/arena/live", methods=["GET"])
def arena_continuous_play_page():
    init_db()
    user = require_account()
    if not user:
        return redirect(url_for("signup_page", next=request.path))
    log_product_event(user["user_id"], "arena_entered", {"path": request.path})
    if request.path == "/arena/live":
        live_cards = [
            {"title": "Global Arena Room", "body": "The main live room for challenges, chat, spectators, and realtime Arena activity.", "action": "<a class='button primary live-arena-cta' href='/arena/room/1'>Enter Global Room</a>"},
            {"title": "BTC War Room", "body": "Watch BTC Duels, rivalries, and market-storm training moments as they happen.", "action": "<a class='button' href='/arena/room/3'>Browse BTC Room</a>"},
            {"title": "Scam Hunter HQ", "body": "Follow scam-defense missions and challenge players protecting the Arena.", "action": "<a class='button' href='/arena/scam-rush'>Start Scam Rush</a>"},
        ]
        body = arena_simple_page(
            "Live Arena",
            "Live rooms are open",
            "Enter the social layer of Alpha Arena. Watch rivals, join public battles, send cheers, and jump into Global Arena whenever you are ready.",
            live_cards,
        )
        body += """
        <section class="card live-arena-card">
          <div class="kicker">Room Energy</div>
          <h2>ENTER LIVE ARENA</h2>
          <p>Global traders battling now. Watch live rivalries, join room chat, and jump into active challenges from the Arena floor.</p>
          <div class="crowd-meter"><span style="width:78%"></span></div>
          <div class="feed" style="margin-top:14px">
            <div>124 players online</div>
            <div>18 live battles active</div>
            <div>BTC Duel room heating up</div>
            <div>Titan player entered Global Arena</div>
          </div>
          <div class="actions" style="margin-top:14px">
            <a class="button primary live-arena-cta" href="/arena/room/1">Enter Global Room</a>
            <a class="button" href="/arena/play">Back to Play Hub</a>
          </div>
        </section>
        """
        return arena_page_shell("Live Arena", body, user=user)
    mode = request.path.rsplit("/", 1)[-1] if request.path != "/arena/play" else "play"
    cards = [
        {"title": "Live Rooms", "body": "Join global rooms, live chat, spectator cheers, and friendly challenges anytime.", "action": "<a class='button primary live-arena-cta' href='/arena/live' data-game-launch='live_rooms'>ENTER LIVE ARENA</a><p class='muted'>Global traders battling now</p><a class='button' href='/arena/room/1'>Enter Global Room</a>"},
        {"title": "Roast Battle", "body": "Step into the spotlight, throw clever lines, survive the crowd, and win the room. Live Multiplayer · Safe banter · Crowd vote.", "action": "<a class='button primary' href='/arena/roast-battle'>Enter Roast Battle</a><a class='button' href='/arena/roast-battle/room/1'>Watch Live</a>"},
        {"title": "Quick Battle", "body": "A 3-5 minute market, scam, and discipline challenge. Solo · Easy · 40 XP.", "action": "<a class='button primary' href='/arena/quick-battle' data-game-launch='quick_battle'>Play Now</a>"},
        {"title": "Alpha Arena Ranked", "body": "Enter ranked matchmaking and start climbing divisions. Multiplayer · Adaptive · 90 XP.", "action": "<a class='button primary' href='/arena/matchmaking' data-game-launch='ranked'>Enter Ranked</a>"},
        {"title": "BTC Duel", "body": "A focused virtual-dollar BTC decision battle. 1v1 · Medium · 70 XP.", "action": "<a class='button' href='/arena/matchmaking?mode=btc_duel' data-game-launch='btc_duel'>Join Battle</a>"},
        {"title": "ETH Duel", "body": "ETH strategy, discipline, and simulated trade timing. 1v1 · Medium · 70 XP.", "action": "<a class='button' href='/arena/matchmaking?mode=eth_duel' data-game-launch='eth_duel'>Join Battle</a>"},
        {"title": "Scam Hunter", "body": "Rapid scam detection with speed and accuracy scoring. Solo · Easy · 50 XP.", "action": "<a class='button' href='/arena/scam-rush' data-game-launch='scam_hunter'>Play Now</a>"},
        {"title": "Survival Mode", "body": "Market storm scenarios that test emotional control. Solo · Hard · 80 XP.", "action": "<a class='button' href='/arena/survival' data-game-launch='survival'>Enter Survival</a>"},
        {"title": "Market Storm", "body": "Volatility pressure, misleading signals, and tactical AI coaching. Solo · Hard · 85 XP.", "action": "<a class='button' href='/arena/survival' data-game-launch='market_storm'>Play Now</a>"},
        {"title": "AI Boss Fight", "body": "Train weaknesses against FOMO, scam, volatility, greed, and panic bosses. Solo · Boss · 100 XP.", "action": "<a class='button gold' href='/arena/bosses' data-game-launch='ai_boss'>Fight Boss</a>"},
        {"title": "Virtual Portfolio Battle", "body": "Virtual $10,000 portfolio duel. No real orders. Multiplayer · Hard · 120 XP.", "action": "<a class='button' href='/arena/matchmaking?mode=fake_portfolio' data-game-launch='fake_portfolio'>Join Battle</a>"},
        {"title": "Prediction War", "body": "Compete on reasoning quality and risk-aware predictions. Multiplayer · Medium · 90 XP.", "action": "<a class='button' href='/arena/matchmaking?mode=prediction_war' data-game-launch='prediction_war'>Join Battle</a>"},
        {"title": "Training Missions", "body": "Daily bonus missions, academy paths, and tactical skill drills. Solo · Training · 35 XP.", "action": "<a class='button' href='/arena/daily' data-game-launch='training'>Train Now</a>"},
    ]
    if request.path == "/arena/play":
        cards = [
            {"title": "Training Mission", "body": "Start here. One short mission explains the Arena loop and gives instant feedback. Solo · Training · 35 XP.", "action": "<a class='button primary' href='/arena/daily' data-game-launch='training'>Start Here</a>"},
            {"title": "Scam Hunter", "body": "Spot wallet traps, fake support, and phishing pressure before they catch you. Solo · Easy · 50 XP.", "action": "<a class='button' href='/arena/scam-rush' data-game-launch='scam_hunter'>Start Scam Hunt</a>"},
            {"title": "Quick Battle", "body": "A 3-5 minute market, scam, and discipline challenge with clear scoring. Solo · Easy · 40 XP.", "action": "<a class='button' href='/arena/quick-battle' data-game-launch='quick_battle'>Play Quick Battle</a>"},
            {"title": "Live Room", "body": "Watch, cheer, chat, and jump into live Arena energy when you are warm. Live · Social · 25 XP.", "action": "<a class='button primary live-arena-cta' href='/arena/live' data-game-launch='live_rooms'>Enter Live Arena</a>"},
            {"title": "Roast Battle", "body": "Step into the global stage for clever, moderated banter and crowd reactions. Live Multiplayer · 30 XP.", "action": "<a class='button' href='/arena/roast-battle'>Enter Roast Battle</a>"},
        ]
    script = """
    <script>
    const mode = location.pathname.includes('survival') ? 'survival' : location.pathname.includes('scam-rush') ? 'scam_rush' : 'quick_battle';
    function arenaModeToast(message){
      let toast=document.querySelector('[data-arena-mode-toast]');
      if(!toast){toast=document.createElement('div');toast.dataset.arenaModeToast='1';toast.style.cssText='position:fixed;left:50%;bottom:18px;z-index:90;transform:translateX(-50%);max-width:min(92vw,420px);border:1px solid rgba(110,223,246,.35);border-radius:14px;background:rgba(8,19,35,.96);box-shadow:0 20px 70px rgba(0,0,0,.42),0 0 24px rgba(110,223,246,.18);padding:12px 14px;color:#f2fbff;font-weight:900';document.body.appendChild(toast);}
      toast.textContent=message;
      clearTimeout(toast._timer);
      toast._timer=setTimeout(()=>toast.remove(),3200);
    }
    async function startRound(){
      const endpoint = mode === 'survival' ? '/api/arena/survival/start' : mode === 'scam_rush' ? '/api/arena/scam-rush/start' : '/api/arena/quick-battle/start';
      const d = await fetch(endpoint,{method:'POST',headers:{'Content-Type':'application/json'},body:'{}'}).then(r=>r.json());
      renderScenario(d);
    }
    function renderScenario(d){
      const s=d.scenario||{};
      const box=document.querySelector('[data-continuous-round]');
      if(!box)return;
      const options=(s.options||[]).map((o,i)=>typeof o==='string'?{id:String.fromCharCode(65+i),text:o}:o);
      box.innerHTML=`<h2>${s.title||'Arena Round'}</h2><p>${s.prompt||s.question||s.description||'Choose the most disciplined action.'}</p><div class='mission-options'>${options.map(o=>`<button data-round-id="${s.round_id||''}" data-option-id="${o.id||''}" data-answer="${String(o.text||'').replace(/"/g,'&quot;')}"><strong>${o.id||''}</strong> ${o.text||''}</button>`).join('')}</div><p class='muted'>Round ${s.round_id||''} · Session #${d.session_id||''}</p>`;
      box.dataset.sessionId=d.session_id||'';
      box.dataset.roundId=s.round_id||'';
    }
    document.addEventListener('click',async e=>{
      const launch=e.target.closest('[data-game-launch]');
      if(launch){
        e.preventDefault();
        const original=launch.textContent;
        launch.textContent='Opening...';
        launch.setAttribute('aria-busy','true');
        const controller=new AbortController();
        const timer=setTimeout(()=>controller.abort(),5000);
        const d=await fetch('/api/arena/game/launch',{method:'POST',headers:{'Content-Type':'application/json'},signal:controller.signal,body:JSON.stringify({game_type:launch.dataset.gameLaunch})}).then(r=>r.json()).catch(()=>({ok:false,message:'Could not open this Arena mode. Try again.'})).finally(()=>clearTimeout(timer));
        if(d.ok&&d.next_url){ location.href=d.next_url; return; }
        arenaModeToast(d.message||'Could not open this Arena mode. Try again.');
        launch.textContent=original;
        launch.removeAttribute('aria-busy');
      }
      if(e.target.closest('[data-start-continuous]')) startRound();
      const a=e.target.closest('[data-answer]');
      if(a){
        const box=document.querySelector('[data-continuous-round]');
        box.querySelectorAll('[data-answer]').forEach(btn=>btn.disabled=true);
        a.classList.add('selected-answer');
        a.textContent=a.textContent+' · locking';
        const endpoint = mode === 'survival' ? '/api/arena/survival/next' : mode === 'scam_rush' ? '/api/arena/scam-rush/submit' : '/api/arena/quick-battle/submit';
        const d=await fetch(endpoint,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({session_id:Number(box.dataset.sessionId||0),round_id:box.dataset.roundId||a.dataset.roundId,selected_option_id:a.dataset.optionId,answer:a.dataset.answer})}).then(r=>r.json());
        const correct=!!d.correct;
        const verdict=correct?'Correct ✅':'Incorrect ❌';
        const mark=(btn)=>btn.dataset.optionId===d.correct_option_id?' style="border-color:rgba(54,229,143,.65);box-shadow:0 0 20px rgba(54,229,143,.14)"':btn.dataset.optionId===d.selected_option_id?' style="border-color:rgba(255,107,122,.65);box-shadow:0 0 20px rgba(255,107,122,.14)"':'';
        const options=[...box.querySelectorAll('[data-answer]')].map(btn=>({id:btn.dataset.optionId,text:btn.dataset.answer,style:mark(btn)}));
        box.innerHTML=`<h2>${verdict}</h2><div class="mission-options">${options.map(o=>`<button disabled${o.style}><strong>${o.id}</strong> ${o.text}${o.id===d.correct_option_id?' · Correct answer':''}</button>`).join('')}</div><div class="notice"><strong>${verdict}</strong><p>${d.explanation||d.feedback||'AI coaching is ready for the next round.'}</p><p class="muted">Selected: ${d.selected_answer||d.selected||'No answer recorded'} · Correct answer: ${d.correct_answer||'Unavailable'}</p></div><span class='rank'>+${d.xp_awarded||d.xp_earned||0} XP</span><button data-start-continuous>Next Round</button>`;
        setTimeout(()=>{const next=box.querySelector('[data-start-continuous]'); if(next) next.focus();},250);
      }
    });
    if(!location.pathname.endsWith('/play')) startRound();
    </script>
    """
    body = arena_simple_page("Arena Play", "Play Arena anytime", "Daily missions are now bonus streaks. Quick battles, survival, scam rush, live rooms, bosses, and practice stay open all day.", cards, script)
    profile = get_or_create_arena_profile(user["user_id"]) or {}
    body += f"""
    <section class="card live-arena-card">
      <div class="kicker">Recommended Next Move</div>
      <h2>Continue your Arena climb</h2>
      <p>Rank: {clean_html(profile.get('rank') or 'Rookie')} · XP: {int(profile.get('xp') or 0)} · Streak: {int(profile.get('streak_count') or 0)} missions</p>
      <p class="muted">Best next step: start with Training Missions, sharpen Scam Hunter, then enter Quick Battle when you are warm.</p>
      <div class="actions"><a class="button primary" href="/arena/daily" data-game-launch="training">Start Here</a><a class="button" href="/arena/scam-rush" data-game-launch="scam_hunter">Start Scam Hunt</a><a class="button" href="/arena/live" data-game-launch="live_rooms">Join Live Room</a></div>
    </section>
    """
    body += arena_commentator_studio(active_battles=3, active_rooms=7, crowd_level=78)
    body += "<section class='card'><div class='kicker'>Continuous Round</div><div data-continuous-round><button class='primary' data-start-continuous>Start a training round</button></div></section>"
    return arena_page_shell("Arena Continuous Play", body, user=user)


@webhook_app.route("/arena/roast-battle", methods=["GET"])
@webhook_app.route("/arena/roast-battle/room/<int:room_id>", methods=["GET"])
@webhook_app.route("/arena/roast-battle/match/<int:match_id>", methods=["GET"])
def arena_roast_battle_page(room_id=None, match_id=None):
    init_db()
    user = require_account()
    if not user:
        return redirect(url_for("signup_page", next=request.path))
    body = f"""
    <style>
      .roast-world-stage{{position:relative;isolation:isolate;overflow:hidden;border-radius:20px}}
      .roast-world-stage:before,.roast-world-stage:after{{content:"";position:absolute;inset:-40%;pointer-events:none;background:conic-gradient(from 80deg,transparent,rgba(255,76,157,.16),transparent 28%,rgba(110,223,246,.18),transparent 58%,rgba(255,209,102,.14),transparent);animation:roastWorldSpin 12s linear infinite;opacity:.8}}
      .roast-world-stage:after{{animation-duration:18s;filter:blur(28px);opacity:.42}}
      .roast-world-stage>*{{position:relative;z-index:1}}
      .roast-ticker{{display:flex;gap:14px;overflow:hidden;white-space:nowrap;border:1px solid rgba(255,255,255,.08);border-radius:999px;padding:8px 12px;background:rgba(255,255,255,.045);color:#dff7ff}}
      .roast-ticker span{{animation:roastTicker 22s linear infinite}}
      .roast-live-grid{{display:grid;grid-template-columns:1.25fr .75fr;gap:16px;margin-top:16px}}
      .roast-avatar-duel{{display:grid;grid-template-columns:1fr auto 1fr;gap:12px;align-items:center}}
      .roast-player-grid{{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:12px;margin-top:12px}}
      .roast-avatar{{min-height:150px;border:1px solid rgba(110,223,246,.22);border-radius:18px;background:radial-gradient(circle at 50% 18%,rgba(110,223,246,.16),transparent 5rem),rgba(255,255,255,.04);display:grid;place-items:center;text-align:center;box-shadow:0 0 34px rgba(110,223,246,.10)}}
      .roast-avatar.balance-up{{animation:balanceUp .72s ease both}}
      .roast-avatar.balance-down{{animation:balanceDown .72s ease both}}
      .roast-balance{{font-size:1.25rem;font-weight:1000;color:#dff7ff}}
      .roast-delta{{display:inline-block;margin-top:4px;font-weight:1000}}
      .roast-delta.up{{color:#36e58f}}.roast-delta.down{{color:#ff6b7a}}
      .roast-face{{font-size:60px;animation:roastAvatarPulse 2.6s ease-in-out infinite}}
      .roast-feed-card{{max-height:360px;overflow:auto}}
      .roast-live-commentary div,.roast-crowd-chat div{{animation:arenaCardIn .22s ease both}}
      .roast-reaction-bar button{{width:auto;min-width:48px}}
      .roast-stage-fullscreen{{position:fixed!important;inset:0!important;z-index:100;background:#040812;overflow:auto;padding:18px}}
      @keyframes roastWorldSpin{{from{{transform:rotate(0deg)}}to{{transform:rotate(360deg)}}}}
      @keyframes roastTicker{{from{{transform:translateX(0)}}to{{transform:translateX(-55%)}}}}
      @keyframes roastAvatarPulse{{0%,100%{{transform:translateY(0) scale(1)}}50%{{transform:translateY(-4px) scale(1.04)}}}}
      @keyframes balanceUp{{0%{{box-shadow:0 0 0 rgba(54,229,143,0)}}45%{{box-shadow:0 0 34px rgba(54,229,143,.34);transform:translateY(-2px)}}100%{{box-shadow:0 0 34px rgba(110,223,246,.10);transform:none}}}}
      @keyframes balanceDown{{0%{{box-shadow:0 0 0 rgba(255,107,122,0)}}45%{{box-shadow:0 0 34px rgba(255,107,122,.30);transform:translateY(2px)}}100%{{box-shadow:0 0 34px rgba(110,223,246,.10);transform:none}}}}
      @media(max-width:768px){{.roast-live-grid,.roast-avatar-duel,.roast-player-grid{{grid-template-columns:1fr}}.roast-avatar{{min-height:104px}}.roast-face{{font-size:46px}}.roast-feed-card{{max-height:260px}}.roast-world-stage:before,.roast-world-stage:after{{animation:none;opacity:.25}}}}
      @media(prefers-reduced-motion:reduce){{.roast-world-stage:before,.roast-world-stage:after,.roast-ticker span,.roast-face,.roast-avatar.balance-up,.roast-avatar.balance-down{{animation:none!important}}}}
    </style>
    <section class="hero roast-world-stage" data-roast-stage>
      <article class="card wide live-arena-card">
        <div class="kicker">Global Live Event</div>
        <h1>Roast Battle</h1>
        <p>Step into the spotlight, throw clever lines, survive the crowd, and win the room. The energy is sharp, safe, and live across the Arena.</p>
        <div class="roast-ticker" aria-live="polite"><span data-roast-ticker>New challenger entered · Crowd surging · AI commentators online · Viral roast detected · Room heat rising · </span></div>
        <p class="muted">Roast Battle uses virtual dollars for entertainment scoring only. No real-money value.</p>
        <form data-roast-call-sign class="actions"><input name="call_sign" minlength="3" maxlength="24" placeholder="Choose call sign, e.g. Cyber Flame"><button type="submit">Save Call Sign</button></form>
        <div class="actions"><button class="primary" data-roast-enroll>Enter Roast Battle</button><a class="button" href="/arena/roast-battle/room/1">Watch Live</a><button type="button" data-roast-fullscreen>Theater Mode</button><a class="button" href="/arena/play">Back to Play Hub</a></div>
      </article>
      <article class="card"><h2>World Stage</h2><p><strong data-roast-world-count>Loading</strong> watching worldwide · <span data-roast-heat-label>Arena heating up</span></p><div class="crowd-meter"><span data-roast-crowd style="width:52%"></span></div><p class="muted">Playful roasts and rivalry energy are welcome. Personal attacks, threats, slurs, doxxing, and protected-class insults are blocked.</p></article>
    </section>
    <section class="roast-live-grid">
      <article class="card wide">
        <h2>Player Roast Feed</h2>
        <div class="roast-player-grid" data-roast-players>
          <div class="roast-avatar"><div><div class="roast-face" data-roast-avatar-a>😎</div><strong>Player A</strong><p class="roast-balance">Stage Balance: $1,000,000</p><p class="muted">Confidence rising</p></div></div>
          <div class="roast-avatar"><div><div class="roast-face" data-roast-avatar-b>😤</div><strong>Player B</strong><p class="roast-balance">Stage Balance: $1,000,000</p><p class="muted">Ready to answer</p></div></div>
        </div>
        <form data-roast-message class="actions" style="margin-top:12px">
          <select name="target_type"><option value="single">Target player</option><option value="leader">Current leader</option><option value="all">All opponents</option><option value="crowd">Crowd-facing line</option></select>
          <select name="target_user_id" data-roast-targets><option value="">Auto target</option></select>
          <input name="message" placeholder="Drop a clever, safe line" autocomplete="off">
          <button class="primary">Send Roast</button>
        </form>
        <p class="muted" data-roast-turn>Timed turns · 30 seconds per player · clean pressure scores highest.</p>
        <div class="feed roast-feed-card" data-roast-feed><div>The global stage is ready.</div></div>
      </article>
      <aside class="card">
        <h2>AI Commentators</h2>
        <div class="feed roast-live-commentary" data-roast-commentator-feed><div>AI commentator waiting for the first clean hit.</div></div>
        <h2 style="margin-top:14px">Quick Reactions</h2>
        <div class="actions roast-reaction-bar"><button data-roast-react>😂</button><button data-roast-react>🔥</button><button data-roast-react>👑</button><button data-roast-react>💀</button><button data-roast-react>🚀</button><button data-roast-react>🧠</button></div>
      </aside>
      <article class="card wide">
        <h2>Global Crowd Chat</h2>
        <div class="feed roast-crowd-chat roast-feed-card" data-roast-crowd-chat><div>Worldwide crowd feed online.</div></div>
      </article>
      <article class="card">
        <h2>Live Voting</h2>
        <p class="muted">Vote for the player controlling the room. Votes feed the crowd heat meter.</p>
        <div class="actions" data-roast-vote-buttons><p class="muted">Join or wait for active call signs.</p></div>
      </article>
    </section>
    <script>
    const roastMatchId={int(match_id or room_id or 1)};
    let roastLastEventId=0;
    const roastSeen=new Set();
    const esc=v=>String(v??'').replace(/[&<>"']/g,c=>({{'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}}[c]));
    function roastStorm(emoji){{const layer=document.createElement('div');layer.className='emoji-storm';for(let i=0;i<18;i++){{const s=document.createElement('span');s.textContent=emoji||['🔥','😂','👑','🚀','🧠'][i%5];s.style.left=Math.random()*100+'vw';s.style.animationDelay=(Math.random()*.35)+'s';s.style.setProperty('--drift',((Math.random()-.5)*120)+'px');layer.appendChild(s);}}document.body.appendChild(layer);setTimeout(()=>layer.remove(),3200);}}
    function addFeed(sel,html){{const el=document.querySelector(sel);if(!el)return;el.insertAdjacentHTML('afterbegin',html);while(el.children.length>24)el.lastElementChild.remove();}}
    function money(v){{return '$'+Number(v||0).toLocaleString(undefined,{{maximumFractionDigits:0}});}}
    function renderPlayers(players){{const grid=document.querySelector('[data-roast-players]');const targets=document.querySelector('[data-roast-targets]');const votes=document.querySelector('[data-roast-vote-buttons]');if(!grid)return;grid.innerHTML=(players||[]).map((p,i)=>`<div class="roast-avatar" data-roast-player="${{esc(p.public_player_id||p.player_id||'')}}"><div><div class="roast-face">${{['😎','😤','🧠','👑'][i%4]}}</div><strong>${{esc(p.call_sign||'Arena Pilot')}}</strong><p class="roast-balance">Stage Balance: ${{money(p.current_balance)}}</p><p class="muted">${{esc(p.status||'Ready')}} · Crowd ${{Math.round(Number(p.crowd_score||0))}}</p><div class="actions"><button data-message-player="${{esc(p.public_player_id||p.player_id||'')}}">Message</button></div></div></div>`).join('')||'<div class="roast-avatar"><div><strong>Waiting for players</strong><p class="roast-balance">Stage Balance: $1,000,000</p></div></div>';if(targets)targets.innerHTML='<option value="">Auto target</option>'+(players||[]).map(p=>`<option value="${{esc(p.public_player_id||p.player_id||'')}}">${{esc(p.call_sign||'Arena Pilot')}}</option>`).join('');if(votes)votes.innerHTML=(players||[]).map(p=>`<button data-roast-vote="${{esc(p.public_player_id||p.player_id||'')}}">${{esc('Vote '+(p.call_sign||'Arena Pilot'))}}</button>`).join('')||'<p class="muted">Waiting for active call signs.</p>';}}
    async function loadRoastState(){{try{{const d=await fetch(`/api/arena/roast/match/${{roastMatchId}}/state`,{{cache:'no-store'}}).then(r=>r.json());if(d.ok){{renderPlayers(d.participants||[]);const turn=document.querySelector('[data-roast-turn]');if(turn)turn.textContent=`${{d.match?.match_type==='four_player'?'Four-player chaos':'Two-player duel'}} · 30-second timed turns · virtual dollars decide the room`;}}}}catch(e){{}}}}
    function applySnapshot(snapshot){{if(!snapshot)return;const count=document.querySelector('[data-roast-world-count]');const heat=document.querySelector('[data-roast-crowd]');const label=document.querySelector('[data-roast-heat-label]');const ticker=document.querySelector('[data-roast-ticker]');if(count)count.textContent=Number(snapshot.watching_worldwide||0).toLocaleString()+' watching worldwide';if(heat)heat.style.width=Math.min(100,Number(snapshot.heat_meter||52))+'%';if(label)label.textContent=(snapshot.heat_meter||0)>82?'Arena exploding':'Arena heating up';if(ticker&&snapshot.ticker)ticker.textContent=snapshot.ticker.join(' · ')+' · ';}}
    function renderRoastEvent(ev){{if(!ev||roastSeen.has(String(ev.id)))return;roastSeen.add(String(ev.id));const p=ev.payload||{{}};if(ev.event_type==='roast_message'){{const m=p.message||{{}};const up=Number(p.balance_delta_sender||0)>=0;addFeed('[data-roast-feed]',`<div><strong>${{esc(m.call_sign||'Arena Pilot')}}:</strong> ${{esc(m.body)}}<br><small>${{esc(p.impact_label||'Clean Hit')}} · Weight ${{Number((p.line_weight||{{}}).weight||(p.score||{{}}).total||0)}} · <span class="roast-delta ${{up?'up':'down'}}">${{up?'+':''}}${{money(p.balance_delta_sender||0)}}</span></small></div>`);addFeed('[data-roast-commentator-feed]',`<div>${{esc(p.commentator_line||'The room felt that one.')}}</div>`);renderPlayers(p.participants||[]);const card=document.querySelector(`[data-roast-player="${{esc(m.public_player_id||m.player_id||'')}}"]`);if(card){{card.classList.add(up?'balance-up':'balance-down');setTimeout(()=>card.classList.remove('balance-up','balance-down'),760);}}const face=document.querySelector('[data-roast-avatar-a]');if(face)face.textContent=p.avatar_reaction==='laughing'?'😂':'😤';roastStorm(up?'🔥':'💀');}}if(ev.event_type==='crowd_reaction'){{const r=p.reaction||{{}};addFeed('[data-roast-crowd-chat]',`<div><strong>Crowd:</strong> ${{esc(r.emoji||'🔥')}} reaction landed.</div>`);addFeed('[data-roast-commentator-feed]',`<div>${{esc(p.commentator_line||'Chat is lighting up.')}}</div>`);roastStorm(r.emoji||'🔥');}}if(ev.event_type==='crowd_vote'){{const v=p.vote||{{}};addFeed('[data-roast-crowd-chat]',`<div><strong>Vote:</strong> Crowd backed ${{esc(v.call_sign||'Arena Pilot')}} · heat ${{Number(v.crowd_heat||0)}}</div>`);}}}}
    async function pollRoastLive(){{try{{const d=await fetch(`/api/arena/roast/match/${{roastMatchId}}/new?after_id=${{roastLastEventId}}`,{{cache:'no-store'}}).then(r=>r.json());if(d.ok){{(d.events||[]).forEach(ev=>{{roastLastEventId=Math.max(roastLastEventId,Number(ev.id||0));renderRoastEvent(ev);}});applySnapshot(d.snapshot);}}}}catch(e){{}}}}
    document.querySelector('[data-roast-call-sign]')?.addEventListener('submit',async e=>{{e.preventDefault();const call_sign=new FormData(e.target).get('call_sign');const d=await fetch('/api/arena/roast/call-sign',{{method:'POST',headers:{{'Content-Type':'application/json'}},body:JSON.stringify({{call_sign}})}}).then(r=>r.json()).catch(()=>({{ok:false,message:'Call sign could not be saved.'}}));addFeed('[data-roast-commentator-feed]',`<div>${{esc(d.ok?'Call sign locked: '+d.call_sign:(d.message||'Choose a different call sign.'))}}</div>`);if(d.ok)loadRoastState();}});
    document.querySelector('[data-roast-message]').addEventListener('submit',async e=>{{e.preventDefault();const fd=new FormData(e.target);const message=fd.get('message');if(!String(message||'').trim())return;const btn=e.target.querySelector('button');btn.disabled=true;addFeed('[data-roast-feed]',`<div><strong>You:</strong> ${{esc(message)}}<br><small>Sending live...</small></div>`);const d=await fetch(`/api/arena/roast/match/${{roastMatchId}}/say`,{{method:'POST',headers:{{'Content-Type':'application/json'}},body:JSON.stringify({{message,target_type:fd.get('target_type')||'single',target_public_player_id:fd.get('target_user_id')||''}})}}).then(r=>r.json()).catch(()=>({{ok:false,message:'Connection hiccup. Try again.'}}));btn.disabled=false;if(d.ok){{e.target.reset();pollRoastLive();loadRoastState();}}else{{addFeed('[data-roast-commentator-feed]',`<div>${{esc(d.message||'Too personal. Keep it clever, not harmful.')}}</div>`);loadRoastState();}}}});
    document.addEventListener('click',async e=>{{const react=e.target.closest('[data-roast-react]');if(react){{await fetch(`/api/arena/roast/match/${{roastMatchId}}/reaction`,{{method:'POST',headers:{{'Content-Type':'application/json'}},body:JSON.stringify({{emoji:react.textContent.trim()}})}}).catch(()=>null);pollRoastLive();}}const vote=e.target.closest('[data-roast-vote]');if(vote){{await fetch(`/api/arena/roast/match/${{roastMatchId}}/vote`,{{method:'POST',headers:{{'Content-Type':'application/json'}},body:JSON.stringify({{target_public_player_id:vote.dataset.roastVote}})}}).catch(()=>null);pollRoastLive();}}const msg=e.target.closest('[data-message-player]');if(msg){{const text=prompt('Message this Arena player');if(text){{const d=await fetch(`/api/players/${{encodeURIComponent(msg.dataset.messagePlayer)}}/message`,{{method:'POST',headers:{{'Content-Type':'application/json'}},body:JSON.stringify({{message:text,source_context:'roast_battle'}})}}).then(r=>r.json());if(d.next_url)location.href=d.next_url;else addFeed('[data-roast-commentator-feed]',`<div>${{esc(d.message||'Message could not be sent.')}}</div>`);}}}}if(e.target.closest('[data-roast-enroll]')){{const d=await fetch('/api/arena/roast/enroll',{{method:'POST',headers:{{'Content-Type':'application/json'}},body:JSON.stringify({{room_id:1}})}}).then(r=>r.json());if(d.next_url)location.href=d.next_url;}}if(e.target.closest('[data-roast-fullscreen]')){{document.querySelector('[data-roast-stage]').classList.toggle('roast-stage-fullscreen');}}}});
    pollRoastLive(); loadRoastState();
    setInterval(pollRoastLive,1400);
    setInterval(loadRoastState,5000);
    </script>
    """
    return arena_page_shell("Roast Battle", body, user=user)


@webhook_app.route("/arena/creator", methods=["GET"])
@webhook_app.route("/roast/creator", methods=["GET"])
def arena_creator_mode_page():
    init_db()
    user = require_account()
    if not user:
        return redirect(url_for("signup_page", next=request.path))
    is_roast = request.path.startswith("/roast")
    title = "Roast Creator Mode" if is_roast else "Arena Creator Mode"
    primary_url = "/arena/roast-battle/match/1" if is_roast else "/arena/live"
    body = f"""
    <style>
      .creator-stage{{min-height:78dvh;display:grid;grid-template-columns:1.35fr .65fr;gap:16px;align-items:stretch}}
      .creator-preview{{position:relative;overflow:hidden;border-radius:18px;background:radial-gradient(circle at 30% 20%,rgba(110,223,246,.22),transparent 20rem),linear-gradient(135deg,#060b16,#111a33);border:1px solid rgba(110,223,246,.22);padding:24px;display:grid;align-content:end}}
      .creator-preview:before{{content:"";position:absolute;inset:0;background:linear-gradient(120deg,transparent,rgba(255,255,255,.08),transparent);animation:creatorSweep 5s ease-in-out infinite;pointer-events:none}}
      .creator-preview>*{{position:relative;z-index:1}}.creator-big{{font-size:clamp(2.4rem,7vw,5.8rem);line-height:.95;margin:0}}.creator-card{{font-size:1.15rem}}
      @keyframes creatorSweep{{0%,100%{{transform:translateX(-60%)}}50%{{transform:translateX(60%)}}}}
      @media(max-width:768px){{.creator-stage{{grid-template-columns:1fr;min-height:auto}}.creator-preview{{min-height:56dvh;padding:16px}}}}
      @media(prefers-reduced-motion:reduce){{.creator-preview:before{{animation:none!important}}}}
    </style>
    <section class="creator-stage">
      <article class="creator-preview">
        <div class="kicker">Creator Mode</div>
        <h1 class="creator-big">{clean_html(title)}</h1>
        <p class="creator-card">Clean fullscreen stage, large commentator cards, audience reaction meter, spotlight mode, and reduced clutter for streaming or screen recording.</p>
        <div class="crowd-meter"><span style="width:76%"></span></div>
        <div class="actions"><a class="button primary" href="{primary_url}">Open Live Stage</a><button data-copy-overlay>Copy Overlay Link</button></div>
      </article>
      <aside class="card">
        <h2>Creator Controls</h2>
        <div class="actions"><button>Battle Spotlight</button><button>Audience Meter</button><button>Replay Marker</button><button>Commentator Cards</button></div>
        <p class="muted">Auto-posting is disabled. Creator Mode is for approved manual streaming, replays, and safe highlights.</p>
      </aside>
    </section>
    <script>document.addEventListener('click',async e=>{{if(e.target.closest('[data-copy-overlay]')){{await navigator.clipboard.writeText(location.origin+'{primary_url}?creator=1');e.target.textContent='Overlay Copied';}}}});</script>
    """
    return arena_page_shell(title, body, user=user)


@webhook_app.route("/arena/matchmaking", methods=["GET"])
def arena_matchmaking_page():
    init_db()
    user = require_account()
    if not user:
        return redirect(url_for("signup_page", next=request.full_path or "/arena/play"))
    game_type = request.args.get("mode") or "ranked"
    match_id = create_arena_match(user["user_id"], 0, game_type, status="matchmaking")
    if not match_id:
        logging.error("ARENA_MATCH_CREATE_FAILED route=arena_matchmaking_page user_id=%s mode=%s", user["user_id"], game_type)
        return redirect("/arena/play?launch_error=1")
    return redirect(f"/arena/match/{match_id}")


@webhook_app.route("/arena/solo", methods=["GET"])
@webhook_app.route("/arena/battle", methods=["GET"])
@webhook_app.route("/arena/league", methods=["GET"])
@webhook_app.route("/arena/room/<int:room_id>", methods=["GET"])
@webhook_app.route("/arena/match/<int:match_id>", methods=["GET"])
def arena_phase_two_page(room_id=None, match_id=None):
    init_db()
    user = require_account()
    if not user:
        return redirect(url_for("signup_page", next=request.path))
    if match_id:
        live = get_arena_match_payload(match_id, user["user_id"])
        if not live:
            logging.warning("ARENA_INVALID_MATCH_ROUTE_PREVENTED match_id=%s user_id=%s", match_id, user["user_id"])
            return arena_page_shell("Arena Match", "<section class='card'><h1>Unable to launch Arena match</h1><p>This battle is not available anymore. Head back to Arena and start a fresh match.</p><div class='actions'><a class='button primary' href='/arena/play'>Back to Play Arena</a><a class='button' href='/arena/live'>Open Live Rooms</a></div></section>", user=user), 200
        match_label = clean_html(live.get("match_label") or (live.get("match") or {}).get("display_name") or "Arena Match")
        body = f"""
        <div class="arena-intro"><div class="arena-intro-card"><div class="kicker">Match Opening</div><h2>{match_label}</h2><p>AI commentator online · market simulation pressure rising</p></div></div>
        <section class="hero">
          <article class="card wide"><div class="kicker">Live Battle Room</div><h1>{match_label}</h1><p>Simulation only. Virtual-dollar match. Live updates refresh every few seconds. No real orders or trading execution.</p><div class="actions"><button data-match-watch="{match_id}">Watch Live</button><button data-match-cheer="🔥">Cheer</button><button data-challenge-winner>Challenge Winner</button><button data-join-battle hidden>Join This Battle</button><a class="button" href="/arena/inbox">Back to Inbox</a></div><p class="muted">Room #{match_id} · <span data-match-state>{clean_html((live.get('match') or {}).get('status') or 'active')}</span></p></article>
          <article class="card"><h2>AI Commentator</h2><p data-match-commentary>{clean_html(live.get('ai_commentary'))}</p><p class="muted">Spectators: <span data-spectators>{int(live.get('spectator_count') or live.get('spectators') or 0)}</span> · Cheers: <span data-cheers>{int(live.get('cheer_count') or 0)}</span></p><div class="crowd-meter"><span data-crowd-meter style="width:24%"></span></div><p class="muted">Crowd pressure · live Arena energy</p></article>
        </section>
        {arena_commentator_studio(active_battles=1, active_rooms=1, crowd_level=52)}
        <section class="grid">
          <article class="card wide"><h2>Virtual Portfolio Battle</h2><div class="grid" data-participants></div></article>
          <article class="card"><h2>Simulated Trade Ticket</h2><div data-trade-gate></div><form data-arena-trade><input name="symbol" value="BTC" placeholder="BTC"><select name="side"><option value="buy">Buy</option><option value="sell">Sell</option><option value="stop_loss">Stop loss simulation</option><option value="take_profit">Take profit simulation</option></select><input name="quantity" type="number" step="any" min="0" placeholder="0.01"><button class="primary">Place Simulated Trade</button></form><p class="muted" data-trade-result></p></article>
          <article class="card"><h2>Market Context</h2><div data-market-context></div></article>
          <article class="card wide"><h2>Post-Match Recap</h2><div data-match-recap><p class="muted">Recap appears when the battle is completed.</p></div></article>
          <article class="card wide"><h2>Positions</h2><div data-positions></div></article>
          <article class="card"><h2>Battle Chat</h2><form data-match-chat><input name="message" placeholder="Keep it respectful"><button>Send</button></form><div class="feed" data-match-chat-feed></div></article>
          <article class="card wide"><h2>Live Commentary Stream</h2><div class="feed" data-match-events></div></article>
        </section>
        <script>
        const matchId = {match_id};
        const esc = v => String(v ?? '').replace(/[&<>"']/g, c => ({{'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}}[c]));
        let victoryShown=false;
        function emojiStorm(list) {{
          const storm=document.createElement('div');
          storm.className='emoji-storm';
          const emojis=list&&list.length?list:['📣','🔥','🚀','👑','💎','⚡','🌊','🎯','🧠','🏆'];
          for(let i=0;i<34;i++) {{
            const span=document.createElement('span');
            span.textContent=emojis[i%emojis.length];
            span.style.left=Math.random()*100+'vw';
            span.style.animationDelay=(Math.random()*.75)+'s';
            span.style.setProperty('--drift', ((Math.random()-.5)*160)+'px');
            storm.appendChild(span);
          }}
          document.body.appendChild(storm);
          setTimeout(()=>storm.remove(),3600);
        }}
        function showVictory(data) {{
          if(victoryShown||window.matchMedia('(prefers-reduced-motion: reduce)').matches) return;
          victoryShown=true;
          emojiStorm(data.effects?.emoji_storm);
          const overlay=document.createElement('div');
          overlay.className='victory-overlay';
          overlay.innerHTML=`<div class="victory-card"><div class="kicker">Victory Cinematic</div><h2 class="victory-title">VICTORY</h2><p><strong>${{esc(data.winner_display_name||'Arena Pilot')}}</strong></p><p>${{esc(data.commentator_line||'DISCIPLINE WINS AGAIN!')}}</p><div class="crowd-meter"><span style="width:${{Math.min(100,Number(data.crowd?.hype_meter||82))}}%"></span></div><p class="muted">${{esc(data.crowd?.state||'Arena exploding')}} · +${{Number(data.xp_awarded||0)}} XP</p><div class="actions"><a class="button primary" href="${{esc(data.replay?.replay_url||('/arena/replay/'+matchId))}}">Watch Replay</a><button type="button" data-close-victory>Queue Again</button></div></div>`;
          document.body.appendChild(overlay);
          overlay.addEventListener('click',e=>{{if(e.target.closest('[data-close-victory]'))overlay.remove();}});
          setTimeout(()=>overlay.remove(),8200);
        }}
        async function loadMatch() {{
          const r = await fetch(`/api/arena/match/${{matchId}}/live`, {{credentials:'same-origin', cache:'no-store'}});
          const d = await r.json();
          if (!d.ok) return;
          document.querySelector('[data-match-commentary]').textContent = d.ai_commentary || 'AI commentary is warming up.';
          document.querySelector('[data-spectators]').textContent = d.spectator_count || d.spectators || 0;
          document.querySelector('[data-cheers]').textContent = d.cheer_count || 0;
          document.querySelector('[data-crowd-meter]').style.width = Math.min(100, 18 + Number(d.spectator_count||d.spectators||0)*12 + Number(d.cheer_count||0)*4) + '%';
          document.querySelector('[data-match-state]').textContent = d.match?.status || 'active';
          const joinBtn=document.querySelector('[data-join-battle]');
          joinBtn.hidden=!d.can_join;
          document.querySelector('[data-arena-trade]').hidden=!d.can_trade;
          document.querySelector('[data-trade-gate]').innerHTML=d.can_trade?'':(d.can_join?'<p class="muted">Join this battle to enable the simulated trade ticket.</p>':'<p class="muted">Spectator mode. Simulated trading is only available to participants.</p>');
          document.querySelector('[data-participants]').innerHTML = (d.participants || []).map(p => `<div class="player-card"><strong>${{esc(p.display_name || 'Arena Pilot')}}</strong><span class="rank">${{p.score || 0}} pts</span><p>Virtual cash $${{Number(p.fake_balance || 0).toLocaleString()}}</p><p class="muted">${{esc(p.rank||'Rookie')}} · ${{esc(p.online_status||'training')}}</p></div>`).join('') || '<p class="muted">Waiting for pilots.</p>';
          document.querySelector('[data-positions]').innerHTML = (d.positions || []).map(p => `<div class="player-card"><strong>${{esc(p.symbol)}}</strong><p>Qty ${{Number(p.quantity || 0).toFixed(6)}} · Avg $${{Number(p.average_price || 0).toLocaleString()}} · Realized P/L $${{Number(p.realized_pnl || 0).toFixed(2)}}</p></div>`).join('') || '<p class="muted">No simulated positions yet.</p>';
          document.querySelector('[data-match-events]').innerHTML = (d.events || []).map(e => `<div><strong>${{esc(e.title || e.event_type)}}</strong><p>${{esc(e.body || '')}}</p><small>${{esc(e.created_at || '')}}</small></div>`).join('') || '<div>Waiting for the first Arena event.</div>';
          const m=d.market_context||{{}};
          document.querySelector('[data-market-context]').innerHTML=`<p><strong>BTC</strong> $${{Number(m.BTC||0).toLocaleString()}}</p><p><strong>ETH</strong> $${{Number(m.ETH||0).toLocaleString()}}</p><small class="muted">${{esc(m.source||'live/cached')}} · ${{esc(m.updated_at||'')}}</small>`;
          document.querySelector('[data-match-recap]').innerHTML=(d.match?.status==='completed')?`<div class="player-card elite"><strong>Winner: ${{esc(d.winner_display_name||'Arena Pilot')}}</strong><p>${{esc(d.ai_commentary||'AI recap ready.')}}</p><p class="muted">Smartest move, discipline score, XP movement, and shareable highlight are ready for this completed virtual-dollar battle.</p></div>`:'<p class="muted">Recap appears when the battle is completed.</p>';
          if(d.match?.status==='completed'&&!victoryShown) showVictory({{winner_display_name:d.winner_display_name,commentator_line:d.ai_commentary,xp_awarded:120,crowd:{{hype_meter:Math.min(100,28+Number(d.cheer_count||0)*8),state:'Arena exploding'}},effects:{{emoji_storm:['📣','🔥','🚀','👑','💎','⚡','🌊','🎯','🧠','🏆']}},replay:{{replay_url:'/arena/replay/'+matchId}}}});
        }}
        document.querySelector('[data-arena-trade]').addEventListener('submit', async e => {{
          e.preventDefault();
          const payload = Object.fromEntries(new FormData(e.target).entries());
          payload.match_id = matchId;
          const r = await fetch('/api/arena/trade', {{method:'POST',headers:{{'Content-Type':'application/json'}},credentials:'same-origin',body:JSON.stringify(payload)}});
          const d = await r.json();
          document.querySelector('[data-trade-result]').textContent = d.message || d.ai_commentary || 'Trade processed.';
          loadMatch();
        }});
        document.querySelector('[data-match-chat]').addEventListener('submit', async e => {{
          e.preventDefault();
          const message = new FormData(e.target).get('message');
          const r = await fetch(`/api/arena/match/${{matchId}}/chat`, {{method:'POST',headers:{{'Content-Type':'application/json'}},credentials:'same-origin',body:JSON.stringify({{message}})}});
          e.target.reset(); loadMatch();
        }});
        document.addEventListener('click', async e => {{
          const watch=e.target.closest('[data-match-watch]');
          if (watch) {{watch.disabled=true; const d=await fetch(`/api/arena/match/${{matchId}}/watch`, {{method:'POST',headers:{{'Content-Type':'application/json'}}}}).then(r=>r.json()); watch.textContent='Watching Live'; document.querySelector('[data-spectators]').textContent=d.spectators||0;}}
          const join=e.target.closest('[data-join-battle]');
          if (join) {{join.disabled=true; const d=await fetch(`/api/arena/match/${{matchId}}/join`, {{method:'POST',headers:{{'Content-Type':'application/json'}}}}).then(r=>r.json()); if(d.ok) loadMatch(); else alert(d.message||'Join unavailable.');}}
          const cheer = e.target.closest('[data-match-cheer]');
          if (cheer && !cheer.disabled) {{cheer.disabled=true; const d=await fetch(`/api/arena/match/${{matchId}}/cheer`, {{method:'POST',headers:{{'Content-Type':'application/json'}},body:JSON.stringify({{emote:cheer.dataset.matchCheer}})}}).then(r=>r.json()); document.querySelector('[data-cheers]').textContent=d.cheers||d.reaction_count||0; document.querySelector('[data-crowd-meter]').style.width=Math.min(100,Number(d.hype_meter||70))+'%'; emojiStorm([d.emoji||'🔥']); cheer.textContent='Cheered ✓'; setTimeout(()=>{{cheer.disabled=false;cheer.textContent='Cheer';}},1600);}}
          if(e.target.closest('[data-challenge-winner]')){{const d=await fetch(`/api/arena/match/${{matchId}}/winner`).then(r=>r.json());if(!d.ok){{alert(d.message||'Winner not decided yet.');return;}}const type=prompt(`Challenge ${{d.winner_display_name}} to which mode?`, 'btc_duel')||'btc_duel';const out=await fetch('/api/arena/challenge-winner',{{method:'POST',headers:{{'Content-Type':'application/json'}},body:JSON.stringify({{match_id:matchId,challenge_type:type,message:'Rematch?'}})}}).then(r=>r.json());alert(out.message||'Challenge sent.');}}
          loadMatch();
        }});
        loadMatch(); setInterval(loadMatch, 3500);
        </script>
        """
        return arena_page_shell("Arena Live Match", body, user=user)
    if room_id:
        body = f"""
        <section class="hero"><article class="card wide"><div class="kicker">Live Arena Room</div><h1>Room #{room_id}</h1><p>Live chat, AI insights, top players, and trending battles refresh without page reload.</p></article><article class="card"><h2>AI Room Pulse</h2><p data-room-commentary>Loading room intelligence...</p></article></section>
        <section class="grid"><article class="card wide"><h2>Room Chat</h2><form data-room-chat><input name="message" placeholder="Share a respectful training insight"><button class="primary">Send</button></form><div class="feed" data-room-messages></div></article><article class="card"><h2>Trending Battles</h2><div data-room-matches></div></article><article class="card wide"><h2>Top Players</h2><div class="grid" data-room-players></div></article></section>
        <script>
        const roomId={room_id}; const esc=v=>String(v??'').replace(/[&<>"']/g,c=>({{'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}}[c]));
        async function loadRoom(){{const r=await fetch(`/api/arena/rooms/${{roomId}}/live`,{{credentials:'same-origin',cache:'no-store'}});const d=await r.json();if(!d.ok)return;document.querySelector('[data-room-commentary]').textContent=d.ai_commentary||'Room active.';document.querySelector('[data-room-messages]').innerHTML=(d.messages||[]).map(m=>`<div><strong>${{esc(m.display_name||'Pilot')}}</strong><p>${{esc(m.message)}}</p></div>`).join('')||'<div>No room messages yet.</div>';document.querySelector('[data-room-matches]').innerHTML=(d.active_matches||[]).map(m=>`<div class="player-card" data-battle-card="${{m.id||0}}"><strong>${{esc(m.match_label||m.name||'Arena Battle')}}</strong><span class="rank">${{esc(m.status||'open')}}</span><p>${{esc(m.description||'Virtual-dollar training battle.')}}</p><p class="muted">${{esc(m.xp_reward||'XP')}} · ${{esc(m.difficulty||'Adaptive')}} · Players live now</p><div class="actions"><button data-join-battle-card data-match-id="${{m.id||0}}" data-battle-type="${{esc(m.match_type||'btc_duel')}}">Join</button>${{m.id?`<a class="button" href="/arena/match/${{m.id}}?spectate=1">Watch</a>`:''}}</div></div>`).join('')||'<p class="muted">No active battles yet.</p>';document.querySelector('[data-room-players]').innerHTML=(d.top_players||[]).map(p=>`<div class="player-card"><strong>${{esc(p.display_name||p.username)}}</strong><span class="rank">${{esc(p.rank)}}</span><p>Arena IQ ${{p.arena_iq||50}}</p></div>`).join('')||'<p class="muted">Complete missions to appear here.</p>'}}
        document.querySelector('[data-room-chat]').addEventListener('submit',async e=>{{e.preventDefault();const message=new FormData(e.target).get('message');await fetch(`/api/arena/rooms/${{roomId}}/message`,{{method:'POST',headers:{{'Content-Type':'application/json'}},body:JSON.stringify({{message}})}});e.target.reset();loadRoom();}});
        document.addEventListener('click',async e=>{{const btn=e.target.closest('[data-join-battle-card]');if(!btn)return;btn.disabled=true;btn.textContent='Joining...';const d=await fetch('/api/arena/battle/join',{{method:'POST',headers:{{'Content-Type':'application/json'}},body:JSON.stringify({{match_id:Number(btn.dataset.matchId||0),battle_type:btn.dataset.battleType}})}}).then(r=>r.json());if(d.next_url)location.href=d.next_url;else{{btn.disabled=false;btn.textContent=d.message||'Join';}}}});
        loadRoom(); setInterval(loadRoom,5000);
        </script>
        """
        return arena_page_shell("Arena Live Room", body, user=user)
    body = "<section class='hero'><article class='card wide'><div class='kicker'>Arena Phase 2</div><h1>Realtime battles are active.</h1><p>Create a virtual-dollar match, join live rooms, spectate battles, and practice risk-adjusted decisions. No real-money trading occurs inside Arena matches.</p><div class='actions'><button data-create-match>Start BTC Duel</button><a class='button' href='/arena/room/1'>Open Global Room</a><a class='button' href='/arena/leaderboard'>Leaderboard</a></div></article><article class='card'><h2>Battle Types</h2><p>BTC Duel · ETH Duel · Portfolio Survival · Prediction War · Scam Defense Battle · Volatility Survival · Speed Challenge</p></article></section><script>document.addEventListener('click',async e=>{if(e.target.closest('[data-create-match]')){const r=await fetch('/api/arena/matchmaking',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({match_type:'BTC Duel'})});const d=await r.json();if(d.match_id) location.href='/arena/match/'+d.match_id; else alert(d.message||'Match unavailable.')}})</script>"
    return arena_page_shell("Arena Mode", body, user=user)


@webhook_app.route("/admin/arena", methods=["GET"])
def admin_arena_page():
    init_db()
    admin = admin_login_required()
    if not admin:
        return redirect(url_for("admin_login_page"))
    leaderboard = arena_leaderboard_payload(limit=10).get("players", [])
    conn = db()
    cur = conn.cursor()
    cur.execute("SELECT COUNT(*) FROM arena_profiles")
    profiles = cur.fetchone()[0]
    cur.execute("SELECT COUNT(*) FROM arena_mission_attempts")
    attempts = cur.fetchone()[0]
    cur.execute("SELECT COUNT(*) FROM arena_friend_challenges WHERE status='pending'")
    pending = cur.fetchone()[0]
    cur.execute("SELECT COUNT(*) FROM arena_rooms WHERE status='active'")
    rooms = cur.fetchone()[0]
    cur.execute("SELECT COUNT(*) FROM arena_matches WHERE status='active'")
    active_matches = cur.fetchone()[0]
    cur.execute("SELECT COUNT(*) FROM arena_spectators")
    spectators = cur.fetchone()[0]
    cur.execute("SELECT COUNT(*) FROM arena_events WHERE status='active'")
    events = cur.fetchone()[0]
    conn.close()
    cards = f"<div class='grid'><div class='card'><div class='metric'>{profiles}</div><p>Profiles</p></div><div class='card'><div class='metric'>{attempts}</div><p>Mission attempts</p></div><div class='card'><div class='metric'>{pending}</div><p>Pending challenges</p></div><div class='card'><div class='metric'>{rooms}</div><p>Active rooms</p></div><div class='card'><div class='metric'>{active_matches}</div><p>Live battles</p></div><div class='card'><div class='metric'>{spectators}</div><p>Spectators</p></div><div class='card'><div class='metric'>{events}</div><p>Active events</p></div></div>"
    rows = "".join(f"<tr><td>{clean_html(p.get('display_name'))}</td><td>{clean_html(p.get('rank'))}</td><td>{int(p.get('arena_iq') or 0)}</td><td>{int(p.get('xp') or 0)}</td></tr>" for p in leaderboard)
    tools = """
    <div class='card'><h2>Create Seasonal Arena Event</h2>
      <form method='post' action='/admin/arena/events'>
        <input name='title' placeholder='Event title'>
        <input name='event_type' placeholder='event_type'>
        <input name='description' placeholder='Description'>
        <button>Create Event</button>
      </form>
      <p class='muted'>Events are educational XP multipliers only. No cash prizes or real-money trading.</p>
    </div>
    """
    return admin_page_html("Arena", cards + tools + f"<div class='card'><h2>Top Arena Players</h2><table><tr><th>Player</th><th>Rank</th><th>Arena IQ</th><th>XP</th></tr>{rows}</table></div>", admin=admin)


