@webhook_app.route("/admin/roast-battle", methods=["GET"])
def admin_roast_battle_page():
    init_db()
    admin = admin_login_required()
    if not admin:
        return redirect(url_for("admin_login_page"))
    conn = db()
    conn.row_factory = sqlite3.Row
    cur = conn.cursor()

    def scalar(query, params=()):
        try:
            cur.execute(query, params)
            row = cur.fetchone()
            return int((row[0] if row else 0) or 0)
        except Exception:
            return 0

    active_matches = scalar("SELECT COUNT(*) FROM roast_matches WHERE COALESCE(status,'active')='active'")
    four_player = scalar("SELECT COUNT(*) FROM roast_matches WHERE match_type='four_player'")
    unsafe_lines = scalar("SELECT COUNT(*) FROM arena_roast_lines WHERE safe=0")
    participants = scalar("SELECT COUNT(*) FROM arena_roast_participants")
    cur.execute(
        """
        SELECT call_sign, MAX(current_balance) AS balance, MAX(crowd_score) AS crowd
        FROM arena_roast_participants
        GROUP BY call_sign
        ORDER BY balance DESC
        LIMIT 10
        """
    )
    top_rows = cur.fetchall()
    cur.execute(
        """
        SELECT message, impact_label, moderation_reason, created_at
        FROM arena_roast_lines
        WHERE safe=0
        ORDER BY id DESC
        LIMIT 10
        """
    )
    unsafe_rows = cur.fetchall()
    conn.close()
    top = "".join(f"<tr><td>{clean_html(row['call_sign'] or 'Arena Pilot')}</td><td>${float(row['balance'] or 0):,.0f}</td><td>{float(row['crowd'] or 0):.0f}</td></tr>" for row in top_rows)
    unsafe = "".join(f"<tr><td>{clean_html(row['message'] or '')}</td><td>{clean_html(row['impact_label'] or '')}</td><td>{clean_html(row['moderation_reason'] or '')}</td><td>{clean_html(row['created_at'] or '')}</td></tr>" for row in unsafe_rows)
    body = f"""
    <div class='grid'>
      <div class='card'><div class='metric'>{active_matches}</div><p>Active roast matches</p></div>
      <div class='card'><div class='metric'>{four_player}</div><p>4-player floors</p></div>
      <div class='card'><div class='metric'>{participants}</div><p>Stage participants</p></div>
      <div class='card'><div class='metric'>{unsafe_lines}</div><p>Unsafe/penalized lines</p></div>
    </div>
    <div class='card'><h2>Top Call Signs</h2><table><tr><th>Call sign</th><th>Best stage balance</th><th>Crowd score</th></tr>{top or '<tr><td colspan="3">No players yet.</td></tr>'}</table></div>
    <div class='card'><h2>Moderation Events</h2><table><tr><th>Line</th><th>Impact</th><th>Reason</th><th>Time</th></tr>{unsafe or '<tr><td colspan="4">No unsafe lines logged.</td></tr>'}</table></div>
    """
    return admin_page_html("Roast Battle Health", body, admin=admin)


@webhook_app.route("/admin/chat-health", methods=["GET"])
def admin_chat_health_page():
    init_db()
    admin = admin_login_required()
    if not admin:
        return redirect(url_for("admin_login_page"))
    conn = db()
    conn.row_factory = sqlite3.Row
    cur = conn.cursor()

    def scalar(query, params=()):
        try:
            cur.execute(query, params)
            row = cur.fetchone()
            return int((row[0] if row else 0) or 0)
        except Exception:
            return 0

    today = datetime.now().date().isoformat()
    total_threads = scalar("SELECT COUNT(*) FROM conversations")
    messages_today = scalar("SELECT COUNT(*) FROM private_messages WHERE created_at>=?", (today,))
    fan_messages_today = scalar("SELECT COUNT(*) FROM private_messages WHERE created_at>=? AND source_context IN ('leaderboard','profile','players','roast_battle')", (today,))
    pending_requests = scalar("SELECT COUNT(*) FROM arena_message_requests WHERE status='pending'")
    reports_today = scalar("SELECT COUNT(*) FROM chat_reports WHERE created_at>=?", (today,))
    blocked_fan_messages = scalar("SELECT COUNT(*) FROM blocked_users")
    arena_threads = scalar("SELECT COUNT(*) FROM arena_chat_threads")
    failed_sends = 0
    duplicate_thread_count = 0
    try:
        cur.execute(
            """
            SELECT c.id, a.user_id AS user_a, b.user_id AS user_b
            FROM conversations c
            JOIN conversation_members a ON a.conversation_id=c.id
            JOIN conversation_members b ON b.conversation_id=c.id AND b.user_id>a.user_id
            WHERE c.conversation_type='direct'
            """
        )
        seen_pairs = {}
        for row in cur.fetchall():
            key = (int(row["user_a"] or 0), int(row["user_b"] or 0))
            seen_pairs[key] = seen_pairs.get(key, 0) + 1
        duplicate_thread_count = sum(1 for count in seen_pairs.values() if count > 1)
    except Exception:
        duplicate_thread_count = 0
    recent_error_rows = []
    try:
        cur.execute(
            """
            SELECT channel, status, COALESCE(error_message, provider_response, '') AS error_message, created_at
            FROM notification_delivery_logs
            WHERE status IN ('failed', 'error')
            ORDER BY id DESC
            LIMIT 8
            """
        )
        recent_error_rows = [dict(row) for row in cur.fetchall()]
    except Exception:
        recent_error_rows = []
    conn.close()
    errors = "".join(
        f"<tr><td>{clean_html(row.get('created_at') or '')}</td><td>{clean_html(row.get('channel') or '')}</td><td>{clean_html(row.get('status') or '')}</td><td>{clean_html(row.get('error_message') or '')}</td></tr>"
        for row in recent_error_rows
    ) or "<tr><td colspan='4' class='muted'>No recent delivery errors recorded.</td></tr>"
    body = f"""
    <div class='card'><h1>Chat Health</h1><p class='muted'>Private chat, Arena direct messages, message requests, and inbox replies now route into the same fast thread system.</p></div>
    <div class='grid'>
      <div class='card'><div class='metric'>{total_threads}</div><p>Total private threads</p></div>
      <div class='card'><div class='metric'>{messages_today}</div><p>Messages today</p></div>
      <div class='card'><div class='metric'>{fan_messages_today}</div><p>Fan messages today</p></div>
      <div class='card'><div class='metric'>{pending_requests}</div><p>Pending Arena requests</p></div>
      <div class='card'><div class='metric'>{reports_today}</div><p>Reports today</p></div>
      <div class='card'><div class='metric'>{blocked_fan_messages}</div><p>Blocked users</p></div>
      <div class='card'><div class='metric'>{arena_threads}</div><p>Legacy Arena threads bridged</p></div>
      <div class='card'><div class='metric'>{failed_sends}</div><p>Failed sends logged</p></div>
      <div class='card'><div class='metric'>{duplicate_thread_count}</div><p>Duplicate direct thread pairs</p></div>
    </div>
    <div class='card'><h2>Realtime Readiness</h2><table><tr><th>Capability</th><th>Status</th></tr><tr><td>Fast incremental polling</td><td><span class='rank'>Active</span></td></tr><tr><td>Latest 50 message load</td><td><span class='rank'>Active</span></td></tr><tr><td>Optimistic send</td><td><span class='rank'>Active</span></td></tr><tr><td>Arena inbox fallback</td><td><span class='rank'>Active</span></td></tr><tr><td>Browser alert removal</td><td><span class='rank'>Active</span></td></tr><tr><td>Average send latency</td><td class='muted'>Measured by request logs; target under 150ms.</td></tr></table></div>
    <div class='card'><h2>Recent Delivery Errors</h2><table><tr><th>Time</th><th>Channel</th><th>Status</th><th>Error</th></tr>{errors}</table></div>
    """
    return admin_page_html("Chat Health", body, admin=admin)


@webhook_app.route("/admin/arena/events", methods=["POST"])
def admin_arena_create_event():
    init_db()
    admin = admin_login_required()
    if not admin:
        return redirect(url_for("admin_login_page"))
    title = clean_html(request.form.get("title") or "")[:120]
    event_type = clean_html(request.form.get("event_type") or title.lower().replace(" ", "_"))[:80]
    description = clean_html(request.form.get("description") or "")[:500]
    if title:
        conn = db()
        cur = conn.cursor()
        cur.execute(
            "INSERT INTO arena_events (event_type, title, description, payload_json, starts_at, ends_at, status) VALUES (?, ?, ?, ?, ?, ?, 'active')",
            (event_type, title, description, json.dumps({"xp_multiplier": 1.1, "created_by_admin": admin.get("id")}), datetime.now().isoformat(), (datetime.now() + timedelta(days=14)).isoformat()),
        )
        conn.commit()
        conn.close()
