@webhook_app.route("/api/arena/challenge", methods=["POST"])
@webhook_app.route("/api/arena/battle/invite", methods=["POST"])
def api_arena_challenge():
    init_db()
    user = api_account_user()
    if not user:
        return jsonify({"ok": False, "message": "Login required."}), 401
    payload = request.get_json(silent=True) or {}
    opponent_id = int(payload.get("opponent_id") or payload.get("receiver_id") or 0)
    if not opponent_id and payload.get("public_player_id"):
        opponent_id = arena_internal_id_from_public(payload.get("public_player_id")) or 0
    if not opponent_id or opponent_id == int(user["user_id"]):
        return jsonify({"ok": False, "message": "Choose another Arena player to challenge."}), 400
    if not load_account_by_id(opponent_id):
        return jsonify({"ok": False, "message": "Opponent not found."}), 404
    conn = db()
    cur = conn.cursor()
    now = datetime.now().isoformat()
    challenge_type = arena_challenge_key(payload.get("challenge_type") or "friend_battle")
    details = arena_challenge_details(challenge_type)
    note = clean_html(payload.get("message") or payload.get("note") or "")[:500]
    expires_at = (datetime.now() + timedelta(days=ARENA_REQUEST_EXPIRATION_DAYS)).isoformat()
    challenge_payload = {
        "challenge_type": challenge_type,
        "label": details["label"],
        "duration": details["duration"],
        "xp_reward": details["xp_reward"],
        "fake_balance": details["fake_balance"],
        "rules": details["rules"],
        "description": details["description"],
        "message": note,
    }
    cur.execute(
        """
        INSERT INTO arena_friend_challenges (sender_id, receiver_id, challenge_type, status, created_at, expires_at, message_note, payload_json)
        VALUES (?, ?, ?, 'pending', ?, ?, ?, ?)
        """,
        (user["user_id"], opponent_id, challenge_type, now, expires_at, note, json.dumps(challenge_payload)),
    )
    challenge_id = cur.lastrowid
    conn.commit()
    conn.close()
    try:
        realtime_service.publish_arena_event("inbox", opponent_id, "arena_challenge", {"challenge_id": challenge_id, "challenge_type": challenge_type, "label": details["label"], "preview": note or f"{account_display_name(user)} challenged you to {details['label']}.", "next_url": "/arena/inbox"})
    except Exception:
        pass
    try:
        notification_service.send_push_alert(
            opponent_id,
            "Arena challenge received",
            f"{account_display_name(user)} challenged you to a {details['label']}.",
            {"challenge_id": challenge_id, "url": "/arena/inbox", "push_type": "arena_invite"},
        )
    except Exception as exc:
        logging.info("Arena challenge notification failed safely: %s", exc)
    log_product_event(user["user_id"], "arena_challenge_sent", {"opponent_id": opponent_id})
    return jsonify({"ok": True, "challenge_id": challenge_id, "challenge": challenge_payload, "message": f"{details['label']} challenge sent."})


@webhook_app.route("/api/arena/battle/accept", methods=["POST"])
@webhook_app.route("/api/arena/challenge/accept", methods=["POST"])
@webhook_app.route("/api/arena/request/accept", methods=["POST"])
def api_arena_battle_accept():
    init_db()
    user = api_account_user()
    if not user:
        return jsonify({"ok": False, "message": "Login required."}), 401
    payload = request.get_json(silent=True) or {}
    challenge_id = int(payload.get("challenge_id") or payload.get("request_id") or 0)
    conn = db()
    conn.row_factory = sqlite3.Row
    cur = conn.cursor()
    cur.execute("SELECT * FROM arena_friend_challenges WHERE id=? AND receiver_id=? AND status='pending' LIMIT 1", (challenge_id, user["user_id"]))
    challenge = cur.fetchone()
    if not challenge:
        thread_id, request_item = arena_thread_for_request(cur, challenge_id, user["user_id"])
        if thread_id and request_item and int(request_item.get("receiver_id") or 0) == int(user["user_id"]):
            private_thread_id = chat_realtime_service.direct_thread(cur, user["user_id"], int(request_item.get("sender_id") or 0))
            if request_item.get("first_message"):
                cur.execute("SELECT id FROM private_messages WHERE conversation_id=? LIMIT 1", (private_thread_id,))
                if not cur.fetchone():
                    cur.execute(
                        "INSERT INTO private_messages (conversation_id, sender_user_id, body, created_at) VALUES (?, ?, ?, ?)",
                        (private_thread_id, int(request_item.get("sender_id") or 0), clean_html(request_item.get("first_message") or "")[:2000], datetime.now().isoformat()),
                    )
            cur.execute("UPDATE arena_message_requests SET status='accepted', responded_at=?, thread_id=? WHERE id=? AND receiver_id=?", (datetime.now().isoformat(), thread_id, challenge_id, user["user_id"]))
            conn.commit()
            conn.close()
            return jsonify({"ok": True, "status": "accepted", "message": "Message request accepted.", "thread_id": private_thread_id, "arena_thread_id": thread_id, "chat_url": f"/chat/thread/{private_thread_id}", "next_url": f"/chat/thread/{private_thread_id}"})
        conn.close()
        return jsonify({"ok": False, "message": "Challenge not found."}), 404
    now = datetime.now().isoformat()
    cur.execute("UPDATE arena_friend_challenges SET status='accepted', responded_at=? WHERE id=? AND receiver_id=?", (now, challenge_id, user["user_id"]))
    changed = cur.rowcount
    conn.commit()
    conn.close()
    match_key = arena_challenge_key(challenge["challenge_type"] or "friend_battle")
    match_id = create_arena_match(int(challenge["sender_id"]), user["user_id"], match_key, arena_match_rules_for_type(match_key), status="active") if changed else 0
    if match_id:
        conn = db()
        cur = conn.cursor()
        cur.execute("UPDATE arena_friend_challenges SET match_id=? WHERE id=?", (match_id, challenge_id))
        conn.commit()
        conn.close()
    return jsonify({"ok": bool(changed), "status": "accepted" if changed else "not_found", "message": "Challenge accepted. Arena match created." if changed else "Challenge not found.", "match_id": match_id, "next_url": f"/arena/match/{match_id}" if match_id else ""})


