@webhook_app.route("/api/arena/message-player", methods=["POST"])
def api_arena_message_player():
    init_db()
    user = api_account_user()
    if not user:
        return jsonify({"ok": False, "message": "Login required."}), 401
    payload = request.get_json(silent=True) or {}
    receiver_id = arena_internal_id_from_public(payload.get("public_player_id") or "")
    message = clean_html(payload.get("message") or "")[:1000]
    source_context = clean_html(payload.get("source_context") or "arena")[:80]
    if not receiver_id:
        return jsonify({"ok": False, "message": "Arena player not found."}), 404
    if receiver_id == user["user_id"]:
        return jsonify({"ok": False, "message": "You cannot message yourself."}), 400
    if not message:
        return jsonify({"ok": False, "message": "Message cannot be empty."}), 400
    conn = db()
    conn.row_factory = sqlite3.Row
    cur = conn.cursor()
    cur.execute(
        """
        SELECT 1 FROM arena_blocks
        WHERE (blocker_id=? AND blocked_id=?) OR (blocker_id=? AND blocked_id=?)
        LIMIT 1
        """,
        (receiver_id, user["user_id"], user["user_id"], receiver_id),
    )
    if cur.fetchone():
        conn.close()
        return jsonify({"ok": False, "message": "You cannot message this player."}), 403
    now = datetime.now().isoformat()
    expires_at = (datetime.now() + timedelta(days=ARENA_REQUEST_EXPIRATION_DAYS)).isoformat()
    thread_id = arena_find_or_create_thread(cur, user["user_id"], receiver_id)
    private_thread_id = chat_realtime_service.direct_thread(cur, user["user_id"], receiver_id)
    sender_public = chat_realtime_service._public_profile(cur, user["user_id"])
    receiver_public = chat_realtime_service._public_profile(cur, receiver_id)
    cur.execute(
        "UPDATE conversations SET source_context=?, public_sender_display_name=?, public_receiver_display_name=?, public_player_id=? WHERE id=?",
        (source_context, sender_public.get("display_name"), receiver_public.get("display_name"), payload.get("public_player_id") or receiver_public.get("public_player_id"), private_thread_id),
    )
    cur.execute(
        """
        SELECT * FROM arena_message_requests
        WHERE sender_id=? AND receiver_id=? AND status IN ('pending','accepted')
        ORDER BY id DESC LIMIT 1
        """,
        (user["user_id"], receiver_id),
    )
    existing_request = cur.fetchone()
    if existing_request:
        request_id = int(existing_request["id"])
        cur.execute("UPDATE arena_message_requests SET thread_id=?, expires_at=COALESCE(expires_at, ?) WHERE id=?", (thread_id, expires_at, request_id))
    else:
        cur.execute(
            "INSERT INTO arena_message_requests (sender_id, receiver_id, status, first_message, created_at, expires_at, thread_id) VALUES (?, ?, 'pending', ?, ?, ?, ?)",
            (user["user_id"], receiver_id, message, now, expires_at, thread_id),
        )
        request_id = cur.lastrowid
    cur.execute(
        "INSERT INTO arena_chat_messages (thread_id, sender_id, body, status, source_request_id, created_at) VALUES (?, ?, ?, 'delivered', ?, ?)",
        (thread_id, user["user_id"], message, request_id, now),
    )
    message_id = cur.lastrowid
    cur.execute(
        "INSERT INTO private_messages (conversation_id, sender_user_id, body, created_at, public_sender_display_name, public_receiver_display_name, source_context, call_sign_snapshot) VALUES (?, ?, ?, ?, ?, ?, ?, ?)",
        (private_thread_id, user["user_id"], message, now, sender_public.get("display_name"), receiver_public.get("display_name"), source_context, sender_public.get("call_sign") or sender_public.get("display_name")),
    )
    private_message_id = cur.lastrowid
    cur.execute("UPDATE conversations SET updated_at=? WHERE id=?", (now, private_thread_id))
    cur.execute("UPDATE arena_chat_threads SET updated_at=?, last_message_at=? WHERE id=?", (now, now, thread_id))
    conn.commit()
    cur.execute("SELECT * FROM arena_chat_messages WHERE id=? LIMIT 1", (message_id,))
    message_payload = arena_public_message(cur, dict(cur.fetchone()), user["user_id"])
    conn.close()
    try:
        realtime_service.publish_arena_event("chat", thread_id, "message", message_payload)
        realtime_service.publish_arena_event("inbox", receiver_id, "arena_message", {"request_id": request_id, "thread_id": private_thread_id, "arena_thread_id": thread_id, "preview": message[:140], "next_url": f"/chat/thread/{private_thread_id}"})
    except Exception:
        pass
    try:
        notification_service.send_push_alert(
            receiver_id,
            "New Arena message",
            f"{sender_public.get('display_name') or 'Arena Pilot'}: {message[:120]}",
            {"request_id": request_id, "url": f"/chat/thread/{private_thread_id}", "push_type": "private_message"},
        )
    except Exception as exc:
        logging.info("Arena message request notification failed safely: %s", exc)
    return jsonify({
        "ok": True,
        "message": "Arena direct message opened.",
        "request_id": request_id,
        "thread_id": private_thread_id,
        "arena_thread_id": thread_id,
        "message_id": private_message_id,
        "next_url": f"/chat/thread/{private_thread_id}",
        "chat_url": f"/chat/thread/{private_thread_id}",
        "message_item": message_payload,
    })


