@webhook_app.route("/api/chat/start", methods=["POST"])
def api_chat_start():
    init_db()
    user = api_account_user()
    if not user:
        return jsonify({"ok": False, "message": "Login required."}), 401
    payload = request.get_json(silent=True) or {}
    query = clean_html(payload.get("query") or payload.get("public_pulse_id") or payload.get("public_player_id") or payload.get("username") or "").strip()
    target_user_id = safe_int(payload.get("target_user_id") or payload.get("user_id"), 0)
    if not query and not target_user_id:
        return jsonify({"ok": False, "message": "Search by name or public Pulse ID."}), 400
    conn = db(); conn.row_factory = sqlite3.Row; cur = conn.cursor()
    if not target_user_id:
        matches = pulse_search_users(cur, query, viewer_user_id=user["user_id"], limit=8, allow_email=bool(user.get("is_admin") or user.get("is_owner")))
        for match in matches:
            if not match.get("is_self"):
                target_user_id = int(match.get("user_id") or 0)
                break
    conn.close()
    if not target_user_id:
        return jsonify({"ok": False, "message": "Pulse user not found."}), 404
    if int(target_user_id) == int(user["user_id"]):
        return jsonify({"ok": False, "message": "You cannot message yourself."}), 400
    conversation_id = direct_conversation_between(user["user_id"], target_user_id)
    message = clean_html(payload.get("message") or payload.get("body") or "")[:2000]
    if message:
        conn = db()
        cur = conn.cursor()
        now = datetime.utcnow().isoformat(timespec="seconds")
        cur.execute(
            "INSERT INTO private_messages (conversation_id, sender_user_id, body, delivery_status, created_at) VALUES (?, ?, ?, 'sent', ?)",
            (conversation_id, user["user_id"], message, now),
        )
        cur.execute("UPDATE conversations SET last_message_at=?, updated_at=? WHERE id=?", (now, now, conversation_id))
        conn.commit(); conn.close()
    result = {"ok": True, "thread_id": conversation_id, "conversation_id": conversation_id, "next_url": f"/pulse/messages/{conversation_id}"}
    log_product_event(user["user_id"], "private_chat_started", {"thread_id": conversation_id, "source": "pulse_search"})
    return jsonify(result), 200


@webhook_app.route("/api/chat/thread/<int:thread_id>", methods=["GET"])
def api_chat_thread(thread_id):
    init_db()
    user = api_account_user()
    if not user:
        return jsonify({"ok": False, "message": "Login required."}), 401
    payload = chat_realtime_service.messages(user["user_id"], thread_id, limit=int(request.args.get("limit") or 50))
    if not payload:
        return jsonify({"ok": False, "message": "Conversation not found."}), 404
    return jsonify(payload)


@webhook_app.route("/api/chat/thread/<int:thread_id>/new", methods=["GET"])
def api_chat_thread_new(thread_id):
    init_db()
    user = api_account_user()
    if not user:
        return jsonify({"ok": False, "message": "Login required."}), 401
    after_id = int(request.args.get("after_id") or request.args.get("since_id") or 0)
    payload = chat_realtime_service.messages(user["user_id"], thread_id, after_id=after_id, limit=int(request.args.get("limit") or 50))
    if not payload:
        return jsonify({"ok": False, "message": "Conversation not found."}), 404
    return jsonify({"ok": True, "messages": payload.get("messages") or [], "last_message_id": payload.get("last_message_id") or after_id})


@webhook_app.route("/api/chat/thread/<int:thread_id>/send", methods=["POST"])
def api_chat_thread_send(thread_id):
    init_db()
    user = api_account_user()
    if not user:
        return jsonify({"ok": False, "message": "Login required."}), 401
    payload = request.get_json(silent=True) or {}
    result, status = chat_realtime_service.send_message(user["user_id"], thread_id, payload.get("message") or payload.get("body") or "", media_ids=payload.get("media_ids") or [])
    if result.get("ok"):
        log_product_event(user["user_id"], "private_message_sent", {"thread_id": thread_id, "source": "fast_chat"})
        try:
            conn = db()
            cur = conn.cursor()
            cur.execute("SELECT user_id FROM conversation_members WHERE conversation_id=? AND user_id != ?", (thread_id, user["user_id"]))
            recipients = [int(row["user_id"]) for row in cur.fetchall()]
            conn.close()
            for recipient_id in recipients:
                notification_service.send_user_alert(
                    recipient_id,
                    "private_message",
                    "New private message",
                    ("You received a photo, GIF, or short video." if (payload.get("media_ids") or []) and not (payload.get("message") or payload.get("body")) else "You received a private message in CoinPilotXAI."),
                    {"conversation_id": thread_id, "thread_id": thread_id, "message_id": result.get("message_id"), "next_url": f"/chat/thread/{thread_id}"},
                    channels=["in_app"],
                )
        except Exception as exc:
            logging.info("Fast chat notification failed safely: %s", exc)
    return jsonify(result), status


