def pulse_status_payload(row, viewer_user_id=0):
    item = dict(row or {})
    media_ids = []
    try:
        media_ids = json.loads(item.get("media_ids_json") or "[]")
    except Exception:
        media_ids = []
    media_items = []
    if media_ids:
        try:
            conn = db()
            conn.row_factory = sqlite3.Row
            cur = conn.cursor()
            placeholders = ",".join(["?"] * len(media_ids[:8]))
            cur.execute(f"SELECT * FROM chat_media_uploads WHERE id IN ({placeholders}) AND moderation_status!='blocked'", media_ids[:8])
            media_items = [media_service.resolve_media(dict(media_row)) for media_row in cur.fetchall()]
            conn.close()
        except Exception:
            media_items = []
    return {
        "id": int(item.get("id") or 0),
        "user_id": int(item.get("user_id") or 0),
        "author_name": item.get("author_name") or item.get("display_name") or "Pulse member",
        "status_type": item.get("status_type") or "image",
        "body": item.get("body") or "",
        "visibility": item.get("visibility") or "public",
        "media_ids": media_ids,
        "created_at": item.get("created_at") or "",
        "expires_at": item.get("expires_at") or "",
        "viewed": bool(item.get("viewer_viewed")),
        "media": media_items,
        "adaptive": {"fit_mode": "smart", "preload": "nearby", "weak_network": "poster_first"},
    }


