def ensure_pulse_messenger_schema(cur, conn=None):
    """Keep Messenger reads survivable when a production DB is one migration behind."""
    cur.execute("""
    CREATE TABLE IF NOT EXISTS pulse_message_threads (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        user_one_id INTEGER,
        user_two_id INTEGER,
        source_context TEXT DEFAULT 'pulse',
        status TEXT DEFAULT 'active',
        created_at TEXT,
        updated_at TEXT
    )
    """)
    add_columns_if_missing(cur, "pulse_message_threads", [
        ("user_one_id", "INTEGER"),
        ("user_two_id", "INTEGER"),
        ("conversation_id", "INTEGER"),
        ("source_context", "TEXT DEFAULT 'pulse'"),
        ("status", "TEXT DEFAULT 'active'"),
        ("created_at", "TEXT"),
        ("updated_at", "TEXT"),
    ], conn=conn)
    cur.execute("""
    CREATE TABLE IF NOT EXISTS pulse_conversations (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        conversation_type TEXT DEFAULT 'direct',
        created_by_user_id INTEGER,
        created_at TEXT,
        updated_at TEXT,
        last_message_at TEXT
    )
    """)
    add_columns_if_missing(cur, "pulse_conversations", [
        ("conversation_type", "TEXT DEFAULT 'direct'"),
        ("created_by_user_id", "INTEGER"),
        ("group_id", "INTEGER"),
        ("linked_group_id", "INTEGER"),
        ("linked_space_id", "TEXT"),
        ("linked_live_id", "INTEGER"),
        ("title", "TEXT"),
        ("description", "TEXT"),
        ("avatar_url", "TEXT"),
        ("owner_user_id", "INTEGER"),
        ("privacy", "TEXT DEFAULT 'private'"),
        ("member_count", "INTEGER DEFAULT 0"),
        ("is_public", "INTEGER DEFAULT 0"),
        ("participant_limit", "INTEGER DEFAULT 250"),
        ("last_activity_at", "TEXT"),
        ("last_message_at", "TEXT"),
        ("status", "TEXT DEFAULT 'active'"),
        ("deleted_at", "TEXT"),
        ("updated_at", "TEXT"),
        ("created_at", "TEXT"),
    ], conn=conn)
    cur.execute("""
    CREATE TABLE IF NOT EXISTS pulse_conversation_participants (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        conversation_id INTEGER,
        user_id INTEGER,
        role TEXT DEFAULT 'member',
        muted INTEGER DEFAULT 0,
        archived INTEGER DEFAULT 0,
        last_read_at TEXT,
        created_at TEXT
    )
    """)
    add_columns_if_missing(cur, "pulse_conversation_participants", [
        ("conversation_id", "INTEGER"),
        ("user_id", "INTEGER"),
        ("role", "TEXT DEFAULT 'member'"),
        ("muted", "INTEGER DEFAULT 0"),
        ("archived", "INTEGER DEFAULT 0"),
        ("muted_until", "TEXT"),
        ("joined_at", "TEXT"),
        ("left_at", "TEXT"),
        ("last_read_at", "TEXT"),
        ("last_seen_at", "TEXT"),
        ("last_read_message_id", "INTEGER DEFAULT 0"),
        ("unread_count", "INTEGER DEFAULT 0"),
        ("pinned_at", "TEXT"),
        ("pinned_rank", "INTEGER DEFAULT 0"),
        ("created_at", "TEXT"),
    ], conn=conn)
    cur.execute("""
    CREATE TABLE IF NOT EXISTS pulse_messages (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        thread_id INTEGER,
        conversation_id INTEGER,
        sender_user_id INTEGER,
        receiver_user_id INTEGER,
        body TEXT,
        read_at TEXT,
        created_at TEXT
    )
    """)
    add_columns_if_missing(cur, "pulse_messages", [
        ("thread_id", "INTEGER"),
        ("conversation_id", "INTEGER"),
        ("sender_user_id", "INTEGER"),
        ("receiver_user_id", "INTEGER"),
        ("body", "TEXT"),
        ("read_at", "TEXT"),
        ("reply_to_id", "INTEGER"),
        ("media_url", "TEXT"),
        ("thumbnail_url", "TEXT"),
        ("message_type", "TEXT DEFAULT 'text'"),
        ("media_metadata", "TEXT"),
        ("file_size", "INTEGER DEFAULT 0"),
        ("duration_seconds", "REAL DEFAULT 0"),
        ("client_message_id", "TEXT"),
        ("local_created_at", "TEXT"),
        ("delivered_at", "TEXT"),
        ("seen_at", "TEXT"),
        ("delivery_status", "TEXT DEFAULT 'sent'"),
        ("status", "TEXT DEFAULT 'sent'"),
        ("edited_at", "TEXT"),
        ("deleted_at", "TEXT"),
        ("updated_at", "TEXT"),
    ], conn=conn)
    cur.execute("""
    CREATE TABLE IF NOT EXISTS pulse_message_reactions (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        message_id INTEGER,
        conversation_id INTEGER,
        user_id INTEGER,
        reaction_type TEXT,
        created_at TEXT,
        updated_at TEXT,
        UNIQUE(message_id, user_id)
    )
    """)
    cur.execute("""
    CREATE TABLE IF NOT EXISTS pulse_message_reports (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        message_id INTEGER,
        conversation_id INTEGER,
        reporter_user_id INTEGER,
        reason TEXT,
        status TEXT DEFAULT 'open',
        created_at TEXT,
        updated_at TEXT
    )
    """)
    cur.execute("""
    CREATE TABLE IF NOT EXISTS pulse_message_receipts (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        message_id INTEGER,
        conversation_id INTEGER,
        user_id INTEGER,
        status TEXT DEFAULT 'seen',
        created_at TEXT,
        updated_at TEXT,
        UNIQUE(message_id, user_id, status)
    )
    """)
    cur.execute("""
    CREATE TABLE IF NOT EXISTS pulse_conversation_typing (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        conversation_id INTEGER,
        user_id INTEGER,
        typing_until TEXT,
        updated_at TEXT,
        UNIQUE(conversation_id, user_id)
    )
    """)
    cur.execute("""
    CREATE TABLE IF NOT EXISTS pulse_chat_rooms (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        room_key TEXT UNIQUE,
        name TEXT,
        description TEXT,
        notice TEXT,
        conversation_id INTEGER,
        status TEXT DEFAULT 'active',
        created_at TEXT,
        updated_at TEXT
    )
    """)
    add_columns_if_missing(cur, "pulse_chat_rooms", [
        ("room_key", "TEXT"),
        ("name", "TEXT"),
        ("description", "TEXT"),
        ("notice", "TEXT"),
        ("conversation_id", "INTEGER"),
        ("status", "TEXT DEFAULT 'active'"),
        ("created_at", "TEXT"),
        ("updated_at", "TEXT"),
    ], conn=conn)
    cur.execute("""
    CREATE TABLE IF NOT EXISTS pulse_chat_room_members (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        room_key TEXT,
        conversation_id INTEGER,
        user_id INTEGER,
        role TEXT DEFAULT 'member',
        joined_at TEXT,
        last_seen_at TEXT,
        UNIQUE(room_key, user_id)
    )
    """)
    cur.execute("""
    CREATE TABLE IF NOT EXISTS pulse_chat_room_messages (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        room_key TEXT,
        conversation_id INTEGER,
        message_id INTEGER,
        created_at TEXT
    )
    """)
    cur.execute("""
    CREATE TABLE IF NOT EXISTS pulse_room_members (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        room_id TEXT,
        conversation_id INTEGER,
        user_id INTEGER,
        role TEXT DEFAULT 'member',
        joined_at TEXT,
        last_seen_at TEXT,
        status TEXT DEFAULT 'active'
    )
    """)
    cur.execute("""
    CREATE TABLE IF NOT EXISTS pulse_room_messages (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        room_id TEXT,
        conversation_id INTEGER,
        message_id INTEGER,
        user_id INTEGER,
        body TEXT,
        message_type TEXT DEFAULT 'text',
        created_at TEXT
    )
    """)
    cur.execute("""
    CREATE TABLE IF NOT EXISTS pulse_chat_health_traces (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        trace_id TEXT,
        user_id INTEGER,
        endpoint TEXT,
        status TEXT,
        details_json TEXT,
        created_at TEXT
    )
    """)
    cur.execute("""
    CREATE TABLE IF NOT EXISTS pulse_chat_recovery_events (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        trace_id TEXT,
        user_id INTEGER,
        conversation_id INTEGER,
        event_type TEXT,
        details_json TEXT,
        created_at TEXT
    )
    """)
    for statement in [
        "CREATE INDEX IF NOT EXISTS idx_pulse_conversation_participants_user ON pulse_conversation_participants(user_id, conversation_id)",
        "CREATE INDEX IF NOT EXISTS idx_pulse_conversation_participants_conversation ON pulse_conversation_participants(conversation_id, user_id)",
        "CREATE INDEX IF NOT EXISTS idx_pulse_conversation_participants_user_only ON pulse_conversation_participants(user_id)",
        "CREATE INDEX IF NOT EXISTS idx_pulse_conversation_participants_conversation_only ON pulse_conversation_participants(conversation_id)",
        "CREATE INDEX IF NOT EXISTS idx_pulse_conversations_type_activity ON pulse_conversations(conversation_type, last_activity_at)",
        "CREATE INDEX IF NOT EXISTS idx_pulse_conversations_type_updated ON pulse_conversations(conversation_type, updated_at)",
        "CREATE INDEX IF NOT EXISTS idx_pulse_conversations_updated ON pulse_conversations(updated_at)",
        "CREATE INDEX IF NOT EXISTS idx_pulse_messages_conversation ON pulse_messages(conversation_id, created_at)",
        "CREATE INDEX IF NOT EXISTS idx_pulse_messages_conversation_created ON pulse_messages(conversation_id, created_at)",
        "CREATE INDEX IF NOT EXISTS idx_pulse_messages_conversation_id ON pulse_messages(conversation_id, id)",
        "CREATE INDEX IF NOT EXISTS idx_pulse_messages_sender ON pulse_messages(sender_user_id, created_at)",
        "CREATE INDEX IF NOT EXISTS idx_pulse_messages_client_id ON pulse_messages(conversation_id, sender_user_id, client_message_id)",
        "CREATE INDEX IF NOT EXISTS idx_pulse_chat_rooms_key ON pulse_chat_rooms(room_key)",
        "CREATE INDEX IF NOT EXISTS idx_pulse_chat_room_members_room ON pulse_chat_room_members(room_key, user_id)",
        "CREATE INDEX IF NOT EXISTS idx_pulse_chat_room_messages_room ON pulse_chat_room_messages(room_key, message_id)",
        "CREATE INDEX IF NOT EXISTS idx_pulse_room_members_room ON pulse_room_members(room_id, user_id)",
        "CREATE INDEX IF NOT EXISTS idx_pulse_room_messages_room ON pulse_room_messages(room_id, message_id)",
        "CREATE INDEX IF NOT EXISTS idx_pulse_message_threads_users ON pulse_message_threads(user_one_id, user_two_id)",
        "CREATE INDEX IF NOT EXISTS idx_pulse_message_threads_conversation ON pulse_message_threads(conversation_id)",
        "CREATE INDEX IF NOT EXISTS idx_pulse_chat_health_traces_trace ON pulse_chat_health_traces(trace_id)",
        "CREATE INDEX IF NOT EXISTS idx_pulse_chat_recovery_user ON pulse_chat_recovery_events(user_id, conversation_id, created_at)",
    ]:
        try:
            cur.execute(statement)
        except Exception as exc:
            logging.warning("Messenger schema index skipped safely: %s", exc)


