def pulse_conversation_summaries(cur, user_id, include_types=None, limit=80, trace_id=""):
    user_id = int(user_id or 0)
    include_types = set(include_types or [])
    limit = max(1, min(int(limit or 80), 120))
    params = [user_id, user_id]
    type_filter = ""
    if include_types:
        placeholders = ",".join(["?"] * len(include_types))
        type_filter = f"AND COALESCE(c.conversation_type,'direct') IN ({placeholders})"
        params.extend(sorted(include_types))
    params.append(limit)
    cur.execute(
        f"""
        SELECT c.*,
               mine.unread_count AS my_unread_count,
               mine.last_read_at AS my_last_read_at,
               mine.last_read_message_id AS my_last_read_message_id,
               mine.pinned_at AS my_pinned_at,
               mine.muted_until AS my_muted_until,
               (
                 SELECT p.user_id
                 FROM pulse_conversation_participants p
                 WHERE p.conversation_id=c.id
                   AND p.user_id!=?
                   AND COALESCE(p.left_at,'')=''
                 ORDER BY p.id ASC
                 LIMIT 1
               ) AS participant_user_id,
               (
                 SELECT COUNT(*)
                 FROM pulse_conversation_participants p
                 WHERE p.conversation_id=c.id
                   AND COALESCE(p.left_at,'')=''
               ) AS live_member_count,
               (
                 SELECT pm.body
                 FROM pulse_messages pm
                 WHERE pm.conversation_id=c.id
                   AND COALESCE(pm.deleted_at,'')=''
                 ORDER BY pm.id DESC
                 LIMIT 1
               ) AS latest_message,
               (
                 SELECT pm.message_type
                 FROM pulse_messages pm
                 WHERE pm.conversation_id=c.id
                   AND COALESCE(pm.deleted_at,'')=''
                 ORDER BY pm.id DESC
                 LIMIT 1
               ) AS latest_message_type,
               (
                 SELECT pm.created_at
                 FROM pulse_messages pm
                 WHERE pm.conversation_id=c.id
                   AND COALESCE(pm.deleted_at,'')=''
                 ORDER BY pm.id DESC
                 LIMIT 1
               ) AS latest_message_created_at
        FROM pulse_conversations c
        JOIN pulse_conversation_participants mine
          ON mine.conversation_id=c.id
         AND mine.user_id=?
         AND COALESCE(mine.left_at,'')=''
        WHERE COALESCE(c.status,'active')='active'
          AND COALESCE(c.deleted_at,'')=''
          {type_filter}
        ORDER BY CASE WHEN COALESCE(mine.pinned_at,'')!='' THEN 0 ELSE 1 END,
                 COALESCE(mine.pinned_at,c.last_message_at,c.last_activity_at,c.updated_at,c.created_at) DESC
        LIMIT ?
        """,
        params,
    )
    conversations = []
    skipped = []
    typing_cutoff = (datetime.utcnow() - timedelta(seconds=8)).isoformat(timespec="seconds")
    now = datetime.utcnow().isoformat(timespec="seconds")
    for row in cur.fetchall():
        try:
            item = dict(row)
            conversation_id = int(item.get("id") or 0)
            if not conversation_id:
                skipped.append({"id": 0, "reason": "missing_conversation_id"})
                continue
            convo_type = item.get("conversation_type") or "direct"
            if convo_type == "direct":
                try:
                    other = pulse_identity_for_user(cur, item.get("participant_user_id") or 0)
                except Exception:
                    logging.exception("PULSE_CONVERSATION_IDENTITY_FAILED trace_id=%s conversation_id=%s", trace_id, conversation_id)
                    other = {"name": "Pulse user", "avatar_url": "", "premium_mark": None}
            else:
                other = {"name": item.get("title") or ("Pulse Room" if convo_type == "room" else "Group Chat"), "avatar_url": item.get("avatar_url") or "", "premium_mark": None}
            latest = item.get("latest_message") or ("Media message" if item.get("latest_message_type") not in {"", "text", None} else "")
            unread_count = int(item.get("my_unread_count") or 0)
            if not unread_count:
                try:
                    cur.execute(
                        """
                        SELECT COUNT(*) AS total
                        FROM pulse_messages
                        WHERE conversation_id=?
                          AND sender_user_id!=?
                          AND COALESCE(deleted_at,'')=''
                          AND id>COALESCE(?,0)
                        """,
                        (conversation_id, user_id, int(item.get("my_last_read_message_id") or 0)),
                    )
                    unread_count = int(dict(cur.fetchone() or {}).get("total") or 0)
                except Exception:
                    logging.exception("PULSE_CONVERSATION_UNREAD_FAILED trace_id=%s conversation_id=%s", trace_id, conversation_id)
            typing_names = []
            try:
                cur.execute(
                    """
                    SELECT COALESCE(u.display_name,u.username,'Pulse member') AS display_name
                    FROM pulse_conversation_typing t
                    JOIN users u ON u.user_id=t.user_id
                    WHERE t.conversation_id=? AND t.user_id!=? AND t.typing_until>=?
                    ORDER BY t.updated_at DESC LIMIT 3
                    """,
                    (conversation_id, user_id, typing_cutoff),
                )
                typing_names = [dict(row).get("display_name") or "Pulse member" for row in cur.fetchall()]
            except Exception:
                logging.exception("PULSE_CONVERSATION_TYPING_FAILED trace_id=%s conversation_id=%s", trace_id, conversation_id)
            preview_users = []
            try:
                cur.execute(
                    """
                    SELECT user_id
                    FROM pulse_conversation_participants
                    WHERE conversation_id=? AND COALESCE(left_at,'')=''
                    ORDER BY CASE role WHEN 'owner' THEN 0 WHEN 'admin' THEN 1 ELSE 2 END, joined_at ASC, created_at ASC
                    LIMIT 6
                    """,
                    (conversation_id,),
                )
                for preview_row in cur.fetchall():
                    preview_id = int(dict(preview_row).get("user_id") or 0)
                    try:
                        preview_ident = pulse_identity_for_user(cur, preview_id)
                    except Exception:
                        preview_ident = {"name": "Pulse user", "avatar_url": "", "public_player_id": pulse_public_id_for_user(preview_id)}
                    preview_users.append({
                        "id": preview_id,
                        "display_name": preview_ident.get("name") or "Pulse user",
                        "avatar_url": preview_ident.get("avatar_url") or "",
                        "public_pulse_id": f"@{preview_ident.get('public_player_id') or pulse_public_id_for_user(preview_id)}",
                        "is_self": preview_id == user_id,
                    })
            except Exception:
                logging.exception("PULSE_CONVERSATION_PREVIEW_FAILED trace_id=%s conversation_id=%s", trace_id, conversation_id)
            conversations.append({
                "id": conversation_id,
                "conversation_id": conversation_id,
                "conversation_type": convo_type,
                "other_user_id": int(item.get("participant_user_id") or 0),
                "title": other.get("name") or "Pulse user",
                "avatar_url": other.get("avatar_url") or "",
                "premium_mark": other.get("premium_mark"),
                "member_count": int(item.get("live_member_count") or item.get("member_count") or (2 if convo_type == "direct" else 1)),
                "last_message": latest,
                "latest_message": latest,
                "updated_at": item.get("updated_at") or item.get("created_at") or "",
                "last_message_at": item.get("latest_message_created_at") or item.get("last_message_at") or item.get("last_activity_at") or item.get("updated_at") or item.get("created_at") or "",
                "unread_count": unread_count,
                "last_read_message_id": int(item.get("my_last_read_message_id") or 0),
                "pinned": bool(item.get("my_pinned_at")),
                "muted": bool(item.get("my_muted_until") and str(item.get("my_muted_until")) > now),
                "typing_users": typing_names,
                "participants_preview": preview_users,
            })
        except Exception as exc:
            skipped.append({"id": safe_int(dict(row).get("id") if row else 0, 0), "reason": exc.__class__.__name__})
            logging.exception("PULSE_CONVERSATION_ROW_SKIPPED trace_id=%s row=%s", trace_id, dict(row) if row else {})
    return conversations, skipped


def pulse_room_definition(room_id):
    key = clean_html(str(room_id or "general-pulse")).strip().lower().replace("_", "-")
    aliases = {"pulse-general": "general-pulse", "general": "general-pulse"}
    key = aliases.get(key, key)
    for room in PULSE_CHAT_ROOMS:
        if room["key"] == key:
            return room
    return None


def pulse_ensure_default_rooms(cur, current_user_id):
    rooms = []
    for room in PULSE_CHAT_ROOMS:
        try:
            result, _ = pulse_get_or_create_room_conversation(cur, current_user_id, room_key=room["key"])
            conversation = result.get("conversation") or {}
            conversation_id = int(result.get("conversation_id") or conversation.get("id") or 0)
            now = datetime.utcnow().isoformat(timespec="seconds")
            cur.execute("SELECT id FROM pulse_chat_rooms WHERE room_key=? LIMIT 1", (room["key"],))
            room_row = dict(cur.fetchone() or {})
            if room_row:
                cur.execute(
                    """
                    UPDATE pulse_chat_rooms
                    SET name=?, description=?, notice=?, conversation_id=?, status='active', updated_at=?
                    WHERE id=?
                    """,
                    (room["name"], room["description"], room["notice"], conversation_id, now, int(room_row.get("id") or 0)),
                )
            else:
                cur.execute(
                    """
                    INSERT INTO pulse_chat_rooms (room_key, name, description, notice, conversation_id, status, created_at, updated_at)
                    VALUES (?, ?, ?, ?, ?, 'active', ?, ?)
                    """,
                    (room["key"], room["name"], room["description"], room["notice"], conversation_id, now, now),
                )
            cur.execute(
                """
                SELECT m.body, m.created_at
                FROM pulse_messages m
                WHERE m.conversation_id=? AND COALESCE(m.deleted_at,'')=''
                ORDER BY m.id DESC LIMIT 1
                """,
                (conversation_id,),
            )
            last = dict(cur.fetchone() or {})
            cur.execute("SELECT COUNT(*) AS total FROM pulse_conversation_participants WHERE conversation_id=? AND COALESCE(left_at,'')=''", (conversation_id,))
            online_count = int(dict(cur.fetchone() or {}).get("total") or 0)
            cur.execute("SELECT COALESCE(unread_count,0) AS unread_count, COALESCE(last_read_message_id,0) AS last_read_message_id FROM pulse_conversation_participants WHERE conversation_id=? AND user_id=? LIMIT 1", (conversation_id, current_user_id))
            mine = dict(cur.fetchone() or {})
            unread_count = int(mine.get("unread_count") or 0)
            if not unread_count:
                cur.execute(
                    """
                    SELECT COUNT(*) AS total FROM pulse_messages
                    WHERE conversation_id=? AND sender_user_id!=? AND COALESCE(deleted_at,'')='' AND id>COALESCE(?,0)
                    """,
                    (conversation_id, current_user_id, int(mine.get("last_read_message_id") or 0)),
                )
                unread_count = int(dict(cur.fetchone() or {}).get("total") or 0)
            rooms.append({
                "id": room["key"],
                "room_id": room["key"],
                "energy": min(99, 42 + online_count * 3),
                "conversation_id": conversation_id,
                "name": room["name"],
                "title": room["name"],
                "description": room["description"],
                "pinned_notice": room["notice"],
                "online_count": online_count,
                "unread_count": unread_count,
                "last_message": last.get("body") or "",
                "last_message_at": last.get("created_at") or conversation.get("last_activity_at") or "",
            })
        except Exception:
            logging.exception("PULSE_DEFAULT_ROOM_SKIPPED room_key=%s user_id=%s", room.get("key"), current_user_id)
            rooms.append({
                "id": room["key"],
                "room_id": room["key"],
                "energy": 42,
                "conversation_id": 0,
                "name": room["name"],
                "title": room["name"],
                "description": room["description"],
                "pinned_notice": room["notice"],
                "online_count": 0,
                "unread_count": 0,
                "last_message": "",
                "last_message_at": "",
                "partial": True,
            })
            continue
    return rooms


def pulse_send_conversation_message(cur, user, conversation_id, body, message_type="text", media_url="", thumbnail_url="", metadata=None, reply_to_id=0, file_size=0, duration_seconds=0, client_message_id="", local_created_at=""):
    conversation_id = int(conversation_id or 0)
    body = clean_html(body or "")[:2000].strip()
    message_type = clean_html(message_type or "text")[:40]
    media_url = clean_html(media_url or "")[:1000]
    thumbnail_url = clean_html(thumbnail_url or media_url)[:1000]
    metadata = metadata if isinstance(metadata, dict) else {}
    reply_to_id = safe_int(reply_to_id, 0)
    client_message_id = clean_html(client_message_id or metadata.get("client_message_id") or "")[:120]
    local_created_at = clean_html(local_created_at or metadata.get("local_created_at") or "")[:80]
    allowed_types = {"text", "image", "gif", "video", "voice", "audio", "file", "system", "reaction", "call_event", "link", "post_share", "reel_share", "group_share", "marketplace_share", "live_share"}
    if message_type not in allowed_types:
        message_type = "text"
    if not body and not media_url:
        return {"ok": False, "message": "Write a message before sending.", "trace_id": secrets.token_hex(6)}, 400
    cur.execute("SELECT * FROM pulse_conversations WHERE id=? AND COALESCE(status,'active')='active' LIMIT 1", (conversation_id,))
    conversation = dict(cur.fetchone() or {})
    if not conversation:
        return {"ok": False, "message": "Conversation not found.", "trace_id": secrets.token_hex(6)}, 404
    cur.execute(
        "SELECT role FROM pulse_conversation_participants WHERE conversation_id=? AND user_id=? AND COALESCE(left_at,'')='' LIMIT 1",
        (conversation_id, user["user_id"]),
    )
    participant = dict(cur.fetchone() or {})
    if not participant and not bool(conversation.get("is_public")):
        return {"ok": False, "message": "Join this chat before sending.", "trace_id": secrets.token_hex(6)}, 403
    if not participant and bool(conversation.get("is_public")):
        now_join = datetime.utcnow().isoformat(timespec="seconds")
        cur.execute(
            "INSERT INTO pulse_conversation_participants (conversation_id, user_id, role, muted, archived, joined_at, created_at) VALUES (?, ?, 'member', 0, 0, ?, ?)",
            (conversation_id, user["user_id"], now_join, now_join),
        )
    if client_message_id:
        cur.execute(
            """
            SELECT * FROM pulse_messages
            WHERE conversation_id=? AND sender_user_id=? AND client_message_id=? AND COALESCE(deleted_at,'')=''
            ORDER BY id DESC LIMIT 1
            """,
            (conversation_id, user["user_id"], client_message_id),
        )
        existing = cur.fetchone()
        if existing:
            message_payload = _pulse_message_payload(existing, user["user_id"])
            return {
                "ok": True,
                "message": "Message already sent.",
                "conversation_id": conversation_id,
                "message_id": int(message_payload.get("id") or 0),
                "data": message_payload,
                "delivery_status": message_payload.get("status") or "sent",
                "idempotent": True,
                "event_name": "message_sync",
            }, 200
    now = datetime.utcnow().isoformat(timespec="seconds")
    cur.execute(
        """
        INSERT INTO pulse_messages
        (thread_id, conversation_id, sender_user_id, receiver_user_id, body, message_type, media_url, thumbnail_url, media_metadata, file_size, duration_seconds, reply_to_id, client_message_id, local_created_at, delivered_at, delivery_status, status, created_at)
        VALUES (0, ?, ?, 0, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'sent', 'sent', ?)
        """,
        (conversation_id, user["user_id"], body, message_type, media_url, thumbnail_url, json.dumps(metadata, default=str)[:4000], int(file_size or 0), float(duration_seconds or 0), reply_to_id or None, client_message_id, local_created_at, now, now),
    )
    message_id = int(cur.lastrowid)
    cur.execute("UPDATE pulse_conversations SET updated_at=?, last_message_at=?, last_activity_at=? WHERE id=?", (now, now, now, conversation_id))
    cur.execute(
        """
        UPDATE pulse_conversation_participants
        SET unread_count=COALESCE(unread_count,0)+1
        WHERE conversation_id=? AND user_id!=? AND COALESCE(left_at,'')=''
        """,
        (conversation_id, user["user_id"]),
    )
    cur.execute(
        """
        UPDATE pulse_conversation_participants
        SET last_read_at=?, last_seen_at=?, last_read_message_id=?, unread_count=0
        WHERE conversation_id=? AND user_id=?
        """,
        (now, now, message_id, conversation_id, user["user_id"]),
    )
    if (conversation.get("conversation_type") or "") in {"room", "chat_room"}:
        cur.execute("INSERT INTO pulse_chat_room_messages (room_key, conversation_id, message_id, created_at) VALUES (?, ?, ?, ?)", (conversation.get("linked_space_id") or "", conversation_id, message_id, now))
    cur.execute("SELECT COUNT(*) AS total FROM pulse_conversation_participants WHERE conversation_id=? AND COALESCE(left_at,'')=''", (conversation_id,))
    member_count = int(dict(cur.fetchone() or {}).get("total") or 0)
    cur.execute("UPDATE pulse_conversations SET member_count=? WHERE id=?", (member_count, conversation_id))
    cur.execute("SELECT * FROM pulse_messages WHERE id=? LIMIT 1", (message_id,))
    message_payload = _pulse_message_payload(cur.fetchone(), user["user_id"])
    conversation_type = conversation.get("conversation_type") or "direct"
    if conversation_type in {"room", "chat_room"}:
        event_name = "room_message_created"
    elif conversation_type in {"group", "community", "community_group", "creator", "live"}:
        event_name = "group_message_created"
    else:
        event_name = "pulse_message_sent"
    return {
        "ok": True,
        "message": "Message sent.",
        "conversation_id": conversation_id,
        "message_id": message_id,
        "data": message_payload,
        "event_name": event_name,
        "delivery_status": "sent",
    }, 200


PULSE_VISIBLE_MESSAGE_FILTER = "AND NOT (COALESCE(message_type,'') IN ('system','system_join','chat_event') AND lower(COALESCE(body,'')) LIKE '% joined')"


def pulse_mark_conversation_read(cur, conversation_id, user_id):
    conversation_id = int(conversation_id or 0)
    user_id = int(user_id or 0)
    if not conversation_id or not user_id:
        return 0
    now = datetime.utcnow().isoformat(timespec="seconds")
    cur.execute(
        """
        SELECT COALESCE(MAX(id),0) AS last_id
        FROM pulse_messages
        WHERE conversation_id=? AND COALESCE(deleted_at,'')=''
        """,
        (conversation_id,),
    )
    last_message_id = int(dict(cur.fetchone() or {}).get("last_id") or 0)
    cur.execute(
        """
        UPDATE pulse_conversation_participants
        SET last_read_at=?, last_seen_at=?, last_read_message_id=?, unread_count=0
        WHERE conversation_id=? AND user_id=?
        """,
        (now, now, last_message_id, conversation_id, user_id),
    )
    return last_message_id


def pulse_attach_reply_previews(cur, messages):
    reply_ids = sorted({int((message or {}).get("reply_to_id") or 0) for message in (messages or []) if int((message or {}).get("reply_to_id") or 0)})
    if not reply_ids:
        return messages
    placeholders = ",".join(["?"] * len(reply_ids))
    cur.execute(
        f"""
        SELECT m.id, m.body, m.message_type, m.media_url, m.sender_user_id,
               COALESCE(u.display_name,u.username,'Pulse user') AS sender_name
        FROM pulse_messages m
        LEFT JOIN users u ON u.user_id=m.sender_user_id
        WHERE m.id IN ({placeholders})
        """,
        reply_ids,
    )
    previews = {
        int(dict(row).get("id") or 0): dict(row)
        for row in cur.fetchall()
    }
    for message in messages or []:
        preview = previews.get(int(message.get("reply_to_id") or 0))
        if preview:
            message["reply_to"] = {
                "id": int(preview.get("id") or 0),
                "sender_name": preview.get("sender_name") or "Pulse user",
                "body": (preview.get("body") or ("Media message" if preview.get("media_url") else ""))[:180],
                "message_type": preview.get("message_type") or "text",
            }
    return messages


def pulse_conversation_presence_payload(cur, conversation_id, current_user_id=0):
    conversation_id = int(conversation_id or 0)
    cur.execute("SELECT * FROM pulse_conversations WHERE id=? LIMIT 1", (conversation_id,))
    conversation = dict(cur.fetchone() or {})
    if not conversation:
        return {}
    cutoff = (datetime.utcnow() - timedelta(minutes=6)).isoformat(timespec="seconds")
    cur.execute(
        """
        SELECT DISTINCT u.user_id, COALESCE(u.display_name,u.username,'Pulse user') AS display_name,
               COALESCE(u.avatar_url,'') AS avatar_url,
               COALESCE(p.role,'member') AS role,
               MAX(COALESCE(os.last_seen_at,u.last_seen_at,'')) AS seen_at
        FROM pulse_conversation_participants p
        JOIN users u ON u.user_id=p.user_id
        LEFT JOIN pulse_online_sessions os ON os.user_id=p.user_id AND COALESCE(os.last_seen_at,'')>=?
        WHERE p.conversation_id=? AND COALESCE(p.left_at,'')=''
        GROUP BY u.user_id
        ORDER BY COALESCE(os.last_seen_at,u.last_seen_at,p.joined_at,p.created_at,'') DESC
        LIMIT 12
        """,
        (cutoff, conversation_id),
    )
    members = [dict(row) for row in cur.fetchall()]
    active_members = []
    online_count = 0
    for member in members:
        is_online = bool(member.get("seen_at") and str(member.get("seen_at")) >= cutoff)
        if is_online:
            online_count += 1
        active_members.append({
            "id": int(member.get("user_id") or 0),
            "display_name": member.get("display_name") or "Pulse user",
            "avatar_url": member.get("avatar_url") or "",
            "role": member.get("role") or "member",
            "online": is_online,
            "is_self": int(member.get("user_id") or 0) == int(current_user_id or 0),
        })
    cur.execute(
        """
        SELECT body, message_type, created_at
        FROM pulse_messages
        WHERE conversation_id=? AND COALESCE(deleted_at,'')=''
        ORDER BY id DESC LIMIT 30
        """,
        (conversation_id,),
    )
    recent_messages = [dict(row) for row in cur.fetchall()]
    recent_count = len([m for m in recent_messages if m.get("created_at") and str(m.get("created_at")) >= (datetime.utcnow() - timedelta(hours=1)).isoformat(timespec="seconds")])
    stop = {"the", "and", "for", "you", "that", "this", "with", "from", "have", "are", "what", "your", "about", "into", "just", "pulse"}
    words = {}
    for message in recent_messages:
        for word in re.findall(r"[A-Za-z][A-Za-z0-9]{3,}", (message.get("body") or "").lower()):
            if word not in stop:
                words[word] = words.get(word, 0) + 1
    keywords = [word for word, _ in sorted(words.items(), key=lambda item: (-item[1], item[0]))[:5]]
    cur.execute(
        """
        SELECT COALESCE(u.display_name,u.username,'Pulse member') AS display_name, COUNT(*) AS total
        FROM pulse_messages m
        JOIN users u ON u.user_id=m.sender_user_id
        WHERE m.conversation_id=? AND COALESCE(m.deleted_at,'')='' AND m.sender_user_id!=?
        GROUP BY m.sender_user_id
        ORDER BY total DESC, MAX(m.created_at) DESC
        LIMIT 1
        """,
        (conversation_id, int(current_user_id or 0)),
    )
    helpful = dict(cur.fetchone() or {})
    pulse_energy = min(99, 42 + online_count * 7 + recent_count * 5)
    title = conversation.get("title") or ("Pulse Room" if (conversation.get("conversation_type") or "") in {"room", "chat_room"} else "Group Chat")
    summary = "The room is warming up. Start with a useful question or a quick update."
    if recent_messages:
        latest = next((m for m in recent_messages if m.get("body")), {})
        if latest:
            summary = f"Latest energy: {str(latest.get('body') or '')[:140]}"
    moderators = [m for m in active_members if str(m.get("role") or "").lower() in {"owner", "admin", "moderator"}][:4]
    typing_cutoff = (datetime.utcnow() - timedelta(seconds=8)).isoformat(timespec="seconds")
    cur.execute(
        """
        SELECT t.user_id, COALESCE(u.display_name,u.username,'Pulse member') AS display_name
        FROM pulse_conversation_typing t
        JOIN users u ON u.user_id=t.user_id
        WHERE t.conversation_id=? AND t.user_id!=? AND t.typing_until>=?
        ORDER BY t.updated_at DESC
        LIMIT 5
        """,
        (conversation_id, int(current_user_id or 0), typing_cutoff),
    )
    typing_users = [{"id": int(row["user_id"]), "display_name": row["display_name"] or "Pulse member"} for row in cur.fetchall()]
    return {
        "conversation_id": conversation_id,
        "title": title,
        "conversation_type": conversation.get("conversation_type") or "group",
        "online_count": max(online_count, 1 if active_members else 0),
        "active_members": active_members[:8],
        "moderators": moderators,
        "pulse_energy": pulse_energy,
        "hot_discussion": recent_count >= 5,
        "trending_keywords": keywords,
        "ai_summary": summary,
        "helpful_member": helpful.get("display_name") or "",
        "typing_users": typing_users,
        "typing_count": len(typing_users),
        "topic": conversation.get("description") or "",
        "pinned_notice": conversation.get("description") or "",
    }


GROUP_REACTION_TYPES = {"fire", "smart", "scam_alert", "whale", "bullish", "bearish"}


def pulse_group_post_context(cur, post_id, user_id=0):
    cur.execute(
        """
        SELECT p.*, g.slug AS group_slug, g.name AS group_name, g.group_type, g.status AS group_status,
               g.owner_user_id, gm.role AS member_role
        FROM pulse_group_posts p
        JOIN pulse_groups g ON g.id=p.group_id
        LEFT JOIN pulse_group_members gm ON gm.group_id=p.group_id AND gm.user_id=?
        WHERE p.id=? AND COALESCE(g.status,'active') NOT IN ('deleted','removed') LIMIT 1
        """,
        (int(user_id or 0), int(post_id or 0)),
    )
    return dict(cur.fetchone() or {})


def pulse_group_role_allows_moderation(role):
    return str(role or "").lower() in {"owner", "admin", "moderator"}


def pulse_group_user_is_admin(user):
    try:
        return bool(user and admin_current_user())
    except Exception:
        return False


def pulse_group_can_interact(post_ctx, user):
    if not user:
        return False, "Login required."
    if not post_ctx:
        return False, "Group post not found."
    if post_ctx.get("deleted_at") or str(post_ctx.get("status") or "published").lower() in {"deleted", "removed"}:
        return False, "This group post is no longer available."
    if str(post_ctx.get("group_status") or "active").lower() in {"frozen", "suspended"}:
        return False, "This group is paused for review."
    if str(post_ctx.get("group_status") or "active").lower() in {"deleted", "removed"}:
        return False, "This group is no longer available."
    group_type = str(post_ctx.get("group_type") or "public").lower()
    if group_type in {"private", "invite-only"} and not post_ctx.get("member_role") and int(post_ctx.get("owner_user_id") or 0) != int(user.get("user_id") or 0):
        return False, "Join this group before interacting."
    return True, ""


def pulse_group_reaction_counts(cur, post_id):
    counts = {key: 0 for key in GROUP_REACTION_TYPES}
    cur.execute(
        "SELECT reaction_type, COUNT(*) AS total FROM pulse_group_post_reactions WHERE group_post_id=? GROUP BY reaction_type",
        (int(post_id or 0),),
    )
    for row in cur.fetchall():
        item = dict(row)
        reaction_type = item.get("reaction_type") or ""
        if reaction_type in counts:
            counts[reaction_type] = int(item.get("total") or 0)
    return counts


def pulse_group_post_stats(cur, post_id, user_id=0):
    cur.execute("SELECT reaction_type FROM pulse_group_post_reactions WHERE group_post_id=? AND user_id=? LIMIT 1", (int(post_id or 0), int(user_id or 0)))
    my_reaction = dict(cur.fetchone() or {}).get("reaction_type") or ""
    cur.execute("SELECT COUNT(*) AS total FROM pulse_group_post_comments WHERE group_post_id=? AND deleted_at IS NULL AND COALESCE(status,'visible')='visible'", (int(post_id or 0),))
    comment_count = int(dict(cur.fetchone() or {}).get("total") or 0)
    return {"reactions": pulse_group_reaction_counts(cur, post_id), "my_reaction": my_reaction, "comment_count": comment_count}


def pulse_group_can_delete_post(post_ctx, user):
    if not user or not post_ctx:
        return False
    user_id = int(user.get("user_id") or 0)
    if int(post_ctx.get("user_id") or 0) == user_id:
        return True
    if int(post_ctx.get("owner_user_id") or 0) == user_id:
        return True
    if pulse_group_role_allows_moderation(post_ctx.get("member_role")):
        return True
    return pulse_group_user_is_admin(user)


def pulse_group_can_moderate_post(post_ctx, user):
    if not user or not post_ctx:
        return False
    user_id = int(user.get("user_id") or 0)
    if int(post_ctx.get("owner_user_id") or 0) == user_id:
        return True
    if pulse_group_role_allows_moderation(post_ctx.get("member_role")):
        return True
    return pulse_group_user_is_admin(user)


def pulse_group_can_delete_group(group, user, role=""):
    if not user or not group:
        return False
    user_id = int(user.get("user_id") or 0)
    if int(group.get("owner_user_id") or 0) == user_id:
        return True
    return pulse_group_user_is_admin(user)


def pulse_group_can_manage_group(group, user, role=""):
    if not user or not group:
        return False
    user_id = int(user.get("user_id") or 0)
    if int(group.get("owner_user_id") or 0) == user_id:
        return True
    if pulse_group_role_allows_moderation(role):
        return True
    return pulse_group_user_is_admin(user)


def pulse_group_local_media_path(media_url):
    url = str(media_url or "").strip()
    if not url.startswith("/static/uploads/"):
        return None
    path = os.path.abspath(os.path.join(webhook_app.root_path, url.lstrip("/")))
    uploads_root = os.path.abspath(os.path.join(webhook_app.root_path, "static", "uploads"))
    try:
        common = os.path.commonpath([path, uploads_root])
    except ValueError:
        return None
    if common != uploads_root:
        return None
    return path


def pulse_group_cleanup_media_files(media_urls):
    removed = 0
    for media_url in set(media_urls or []):
        path = pulse_group_local_media_path(media_url)
        if path and os.path.isfile(path):
            try:
                os.remove(path)
                removed += 1
            except OSError:
                logging.warning("PULSE_GROUP_MEDIA_FILE_DELETE_FAILED media_url=%s", media_url)
    return removed


def pulse_group_collect_post_media_urls(cur, post_ids):
    ids = [int(pid) for pid in (post_ids or []) if int(pid or 0)]
    if not ids:
        return []
    placeholders = ",".join(["?"] * len(ids))
    urls = []
    try:
        cur.execute(f"SELECT media_url, thumbnail_url FROM pulse_group_posts WHERE id IN ({placeholders})", ids)
        for row in cur.fetchall():
            item = dict(row)
            urls.extend([item.get("media_url") or "", item.get("thumbnail_url") or ""])
    except Exception:
        pass
    try:
        cur.execute(f"SELECT media_url, thumbnail_url FROM pulse_group_post_media WHERE group_post_id IN ({placeholders})", ids)
        for row in cur.fetchall():
            item = dict(row)
            urls.extend([item.get("media_url") or "", item.get("thumbnail_url") or ""])
    except Exception:
        pass
    return [url for url in urls if url]


def pulse_group_hard_delete_posts(cur, post_ids):
    ids = [int(pid) for pid in (post_ids or []) if int(pid or 0)]
    if not ids:
        return {}
    placeholders = ",".join(["?"] * len(ids))
    deleted = {}
    media_urls = pulse_group_collect_post_media_urls(cur, ids)
    if media_urls:
        media_placeholders = ",".join(["?"] * len(media_urls))
        cur.execute(
            f"UPDATE chat_media_uploads SET deleted_at=COALESCE(deleted_at, ?) WHERE media_url IN ({media_placeholders}) OR thumbnail_url IN ({media_placeholders})",
            [datetime.utcnow().isoformat(timespec="seconds")] + media_urls + media_urls,
        )
        deleted["upload_refs"] = int(cur.rowcount or 0)
    cur.execute(f"SELECT id FROM pulse_group_post_comments WHERE group_post_id IN ({placeholders})", ids)
    comment_ids = [int(dict(row).get("id") or 0) for row in cur.fetchall()]
    if comment_ids:
        comment_placeholders = ",".join(["?"] * len(comment_ids))
        cur.execute(f"DELETE FROM pulse_group_comment_reports WHERE comment_id IN ({comment_placeholders})", comment_ids)
        deleted["comment_reports_by_comment"] = int(cur.rowcount or 0)
    cur.execute(f"DELETE FROM pulse_group_comment_reports WHERE group_post_id IN ({placeholders})", ids)
    deleted["comment_reports"] = int(cur.rowcount or 0)
    cur.execute(f"DELETE FROM pulse_group_post_reports WHERE group_post_id IN ({placeholders})", ids)
    deleted["post_reports"] = int(cur.rowcount or 0)
    cur.execute(f"DELETE FROM pulse_group_post_reactions WHERE group_post_id IN ({placeholders})", ids)
    deleted["reactions"] = int(cur.rowcount or 0)
    cur.execute(f"DELETE FROM pulse_group_post_comments WHERE group_post_id IN ({placeholders})", ids)
    deleted["comments"] = int(cur.rowcount or 0)
    cur.execute(f"DELETE FROM pulse_group_post_media WHERE group_post_id IN ({placeholders})", ids)
    deleted["media"] = int(cur.rowcount or 0)
    cur.execute(f"DELETE FROM pulse_group_posts WHERE id IN ({placeholders})", ids)
    deleted["posts"] = int(cur.rowcount or 0)
    return deleted


def pulse_group_hard_delete_group(cur, group_id):
    group_id = int(group_id or 0)
    cur.execute("SELECT id FROM pulse_group_posts WHERE group_id=?", (group_id,))
    post_ids = [int(dict(row).get("id") or 0) for row in cur.fetchall()]
    media_urls = pulse_group_collect_post_media_urls(cur, post_ids)
    deleted = pulse_group_hard_delete_posts(cur, post_ids)
    cur.execute("SELECT id FROM pulse_conversations WHERE group_id=? OR linked_group_id=?", (group_id, group_id))
    conversation_ids = [int(dict(row).get("id") or 0) for row in cur.fetchall()]
    if conversation_ids:
        placeholders = ",".join(["?"] * len(conversation_ids))
        cur.execute(f"DELETE FROM pulse_message_reactions WHERE conversation_id IN ({placeholders})", conversation_ids)
        deleted["message_reactions"] = int(cur.rowcount or 0)
        cur.execute(f"SELECT id, media_url, thumbnail_url FROM pulse_messages WHERE conversation_id IN ({placeholders})", conversation_ids)
        message_ids = []
        for row in cur.fetchall():
            item = dict(row)
            message_ids.append(int(item.get("id") or 0))
            media_urls.extend([item.get("media_url") or "", item.get("thumbnail_url") or ""])
        if message_ids:
            message_placeholders = ",".join(["?"] * len(message_ids))
            cur.execute(f"UPDATE chat_media_uploads SET deleted_at=COALESCE(deleted_at, ?) WHERE message_id IN ({message_placeholders})", [datetime.utcnow().isoformat(timespec="seconds")] + message_ids)
            deleted["message_upload_refs"] = int(cur.rowcount or 0)
        cur.execute(f"DELETE FROM pulse_message_receipts WHERE conversation_id IN ({placeholders})", conversation_ids)
        deleted["message_receipts"] = int(cur.rowcount or 0)
        cur.execute(f"DELETE FROM pulse_messages WHERE conversation_id IN ({placeholders})", conversation_ids)
        deleted["messages"] = int(cur.rowcount or 0)
        cur.execute(f"DELETE FROM pulse_conversation_participants WHERE conversation_id IN ({placeholders})", conversation_ids)
        deleted["conversation_participants"] = int(cur.rowcount or 0)
        cur.execute(f"DELETE FROM pulse_conversations WHERE id IN ({placeholders})", conversation_ids)
        deleted["conversations"] = int(cur.rowcount or 0)
    cur.execute("DELETE FROM pulse_group_reports WHERE group_id=?", (group_id,))
    deleted["group_reports"] = int(cur.rowcount or 0)
    cur.execute("DELETE FROM pulse_group_invites WHERE group_id=?", (group_id,))
    deleted["invites"] = int(cur.rowcount or 0)
    cur.execute("DELETE FROM pulse_group_roles WHERE group_id=?", (group_id,))
    deleted["roles"] = int(cur.rowcount or 0)
    cur.execute("DELETE FROM pulse_group_bans WHERE group_id=?", (group_id,))
    deleted["bans"] = int(cur.rowcount or 0)
    cur.execute("DELETE FROM pulse_group_members WHERE group_id=?", (group_id,))
    deleted["members"] = int(cur.rowcount or 0)
    cur.execute("DELETE FROM pulse_groups WHERE id=?", (group_id,))
    deleted["groups"] = int(cur.rowcount or 0)
    return deleted, media_urls


