def pulse_emit_event(event_type, payload=None, actor_user_id=0, post_id=0):
    try:
        init_db()
        raw_type = str(event_type or "")
        payload = payload or {}
        # Room joins/leaves are presence signals, not durable content.
        # They should move UI state quietly without replaying as "someone joined"
        # spam after reconnect.
        silent_presence_events = {"chat_room_joined", "participant_joined", "participant_removed"}
        persist_event = raw_type not in silent_presence_events
        canonical_type = {
            "new_comment": "pulse_comment_created",
            "reaction_added": "pulse_reaction_updated",
            "reaction_removed": "pulse_reaction_updated",
            "typing_start": "pulse_typing_started",
            "typing_stop": "pulse_typing_stopped",
            "message_received": "pulse_message_created",
            "friend_request": "pulse_friend_request_created",
            "notification_created": "pulse_notification_created",
            "livestream_started": "pulse_live_started",
            "pulse_reel_created": "pulse_reel_created",
            "pulse_reel_reaction_updated": "pulse_reel_reaction_updated",
            "pulse_reel_comment_created": "pulse_reel_comment_created",
        }.get(raw_type, raw_type or "event")
        realtime_engine.publish_event("pulse:global", canonical_type, payload)
        conversation_channel_id = safe_int((payload or {}).get("conversation_id"), 0)
        if conversation_channel_id:
            realtime_engine.publish_event(f"pulse:conversation:{conversation_channel_id}", canonical_type, payload)
        event_bus_engine.publish("pulse:global", canonical_type, payload, priority="live")
        distributed_realtime_engine.publish("pulse:global", canonical_type, payload)
        if raw_type in {"typing_start", "typing_stop", "pulse_typing"}:
            scope_id = safe_int((payload or {}).get("conversation_id") or (payload or {}).get("post_id"), 0)
            coalesce_key = f"pulse:typing:{raw_type}:{scope_id}:{safe_int((payload or {}).get('user_id') or actor_user_id, 0)}"
            if cache_engine.cache_get(coalesce_key):
                return 0
            cache_engine.cache_set(coalesce_key, True, ttl_seconds=2)
        if not persist_event:
            return 0
        conn = db()
        cur = conn.cursor()
        cur.execute(
            "INSERT INTO pulse_live_events (event_type, actor_user_id, post_id, payload_json, created_at) VALUES (?, ?, ?, ?, ?)",
            (
                str(event_type or "")[:80],
                int(actor_user_id or 0),
                int(post_id or 0),
                json.dumps(payload or {}, default=str)[:12000],
                datetime.utcnow().isoformat(timespec="seconds"),
            ),
        )
        conn.commit()
        event_id = int(cur.lastrowid)
        conn.close()
        return event_id
    except Exception as exc:
        logging.warning("Pulse live event write failed type=%s error=%s", event_type, exc)
        return 0


def pulse_mark_online(user_id, connection_type="http", current_path=""):
    try:
        user_id = int(user_id or 0)
        if not user_id:
            return
        sid = session.get("visitor_session_id") or session.get("csrf_token") or request.cookies.get("session") or "pulse"
        realtime_engine.heartbeat(user_id, str(sid)[:160], "pulse:global", {"path": str(current_path or request.path)[:260], "connection_type": str(connection_type)[:40]})
        websocket_orchestrator.heartbeat(str(sid)[:160], user_id=user_id, channel="pulse:global", transport=str(connection_type or "http")[:40], metadata={"path": str(current_path or request.path)[:260]})
        now = datetime.utcnow().isoformat(timespec="seconds")
        conn = db()
        cur = conn.cursor()
        session_id = str(sid)[:160]
        cur.execute(
            """
            UPDATE pulse_online_sessions
            SET connection_type=?, current_path=?, last_seen_at=?, online_status='online'
            WHERE user_id=? AND session_id=?
            """,
            (str(connection_type)[:40], str(current_path or request.path)[:260], now, user_id, session_id),
        )
        if cur.rowcount == 0:
            cur.execute(
                """
                INSERT INTO pulse_online_sessions (user_id, session_id, connection_type, current_path, last_seen_at, online_status, created_at)
                VALUES (?, ?, ?, ?, ?, 'online', ?)
                """,
                (user_id, session_id, str(connection_type)[:40], str(current_path or request.path)[:260], now, now),
            )
        cur.execute("UPDATE users SET last_seen_at=? WHERE user_id=?", (now, user_id))
        conn.commit()
        conn.close()
    except Exception as exc:
        logging.debug("PULSE_ONLINE_MARK_SKIPPED user_id=%s error=%s", user_id, exc)


def pulse_live_snapshot(cur, since_id=0, limit=80):
    cur.execute(
        "SELECT * FROM pulse_live_events WHERE id>? ORDER BY id ASC LIMIT ?",
        (int(since_id or 0), max(1, min(int(limit or 80), 200))),
    )
    events = []
    for row in cur.fetchall():
        item = dict(row)
        try:
            payload = json.loads(item.get("payload_json") or "{}")
        except Exception:
            payload = {}
        events.append({
            "id": item.get("id"),
            "event_type": item.get("event_type"),
            "actor_user_id": item.get("actor_user_id"),
            "post_id": item.get("post_id"),
            "payload": payload,
            "created_at": item.get("created_at"),
        })
    return events


def pulse_live_metrics():
    conn = db()
    conn.row_factory = sqlite3.Row
    cur = conn.cursor()
    since = (datetime.utcnow() - timedelta(minutes=1)).isoformat(timespec="seconds")
    metrics = {}
    for name, query in {
        "events_last_minute": "SELECT COUNT(*) AS total FROM pulse_live_events WHERE created_at>=?",
        "comments_last_minute": "SELECT COUNT(*) AS total FROM pulse_live_events WHERE created_at>=? AND event_type='new_comment'",
        "reactions_last_minute": "SELECT COUNT(*) AS total FROM pulse_live_events WHERE created_at>=? AND event_type='reaction_added'",
        "typing_last_minute": "SELECT COUNT(*) AS total FROM pulse_live_events WHERE created_at>=? AND event_type IN ('typing_start','typing_stop')",
        "new_posts_last_minute": "SELECT COUNT(*) AS total FROM pulse_live_events WHERE created_at>=? AND event_type='new_post'",
        "active_users": "SELECT COUNT(DISTINCT actor_user_id) AS total FROM pulse_live_events WHERE created_at>=? AND actor_user_id>0",
    }.items():
        try:
            cur.execute(query, (since,))
            metrics[name] = int(dict(cur.fetchone() or {}).get("total") or 0)
        except Exception:
            metrics[name] = 0
    try:
        cur.execute("SELECT MAX(id) AS total FROM pulse_live_events")
        metrics["latest_event_id"] = int(dict(cur.fetchone() or {}).get("total") or 0)
    except Exception:
        metrics["latest_event_id"] = 0
    conn.close()
    realtime_health = realtime_engine.health_snapshot()
    metrics["transport"] = "sse_with_polling_fallback"
    metrics["comments_per_sec"] = round(metrics.get("comments_last_minute", 0) / 60, 3)
    metrics["reactions_per_sec"] = round(metrics.get("reactions_last_minute", 0) / 60, 3)
    metrics["online_users"] = max(metrics.get("active_users", 0), realtime_health.get("online_users", 0))
    metrics["active_realtime_clients"] = realtime_health.get("active_realtime_clients", 0)
    metrics["websocket_clients"] = 0
    metrics["failed_socket_events"] = realtime_health.get("failed_broadcasts", 0)
    metrics["reconnect_count"] = realtime_health.get("reconnect_count", 0)
    metrics["queue_latency_ms"] = 0
    return metrics


