@webhook_app.route("/pulse/reels/<int:reel_id>", methods=["GET"])
def pulse_reel_detail_page(reel_id):
    init_db()
    user = require_account()
    if not user:
        return redirect(url_for("login_page", next=request.path))
    reel = pulse_reel_payload(reel_id, viewer_user_id=user["user_id"])
    if not reel:
        return pulse_social_shell("Pulse Reel", "Reel not found.", "<section class='card'><a class='button primary' href='/pulse/reels'>Back to Reels</a></section>")
    media = (reel.get("media") or [{}])[0] or {}
    video = clean_html(media.get("media_url") or reel.get("video_url") or "")
    video_html = f"<video src='{video}' autoplay muted playsinline loop controls style='width:100%;max-height:72dvh;border-radius:18px;background:#020712'></video>" if video else "<div class='card'><p class='muted'>This Reel is waiting for media processing.</p></div>"
    main = f"<section class='card'>{video_html}<h1>{clean_html(reel.get('title') or 'Pulse Reel')}</h1><p>{clean_html(reel.get('body') or reel.get('caption') or '')}</p><p><span class='pill'>{clean_html((reel.get('author') or {}).get('primary_label') or 'Member')}</span> <span class='pill'>Score {safe_int(reel.get('reel_score'), 0)}</span></p><div class='actions'><button class='button' id='reelReact'>🔥 React</button><a class='button primary' href='/pulse/reels'>More Reels</a></div></section>"
    script = f"document.getElementById('reelReact')?.addEventListener('click',()=>pulseApi('/api/pulse/reels/react',{{method:'POST',body:JSON.stringify({{reel_id:{int(reel_id)},reaction_type:'fire'}})}}).then(()=>toast('Reaction added.')).catch(e=>toast(e.message)));"
    return pulse_social_shell("Pulse Reel", "Vertical Pulse clip with live social actions.", main, "", script)


def pulse_reel_payload(reel_id=0, post_id=0, viewer_user_id=0):
    conn = db()
    conn.row_factory = sqlite3.Row
    cur = conn.cursor()
    try:
        if reel_id:
            cur.execute("SELECT * FROM pulse_reels WHERE id=? AND COALESCE(status,'active')!='deleted' LIMIT 1", (int(reel_id),))
        else:
            cur.execute("SELECT * FROM pulse_reels WHERE post_id=? AND COALESCE(status,'active')!='deleted' LIMIT 1", (int(post_id),))
        reel_row = dict(cur.fetchone() or {})
    except Exception:
        reel_row = {}
    conn.close()
    if not reel_row and post_id:
        reel_row = {"id": int(post_id), "post_id": int(post_id), "category": "Community"}
    if not reel_row:
        return None
    post = pulse_feed_engine.get_post(int(reel_row.get("post_id") or 0), viewer_user_id=viewer_user_id, include_private=False)
    if not post:
        return None
    merged = {**post, **{k: v for k, v in reel_row.items() if v not in (None, "")}}
    merged["reel_id"] = int(reel_row.get("id") or post.get("id") or 0)
    merged["post_id"] = int(post.get("id") or reel_row.get("post_id") or 0)
    merged["caption"] = reel_row.get("caption") or post.get("body") or ""
    tags = post.get("ai_tags") or post.get("tags") or []
    try:
        extra_tags = json.loads(reel_row.get("ai_tags_json") or "[]")
    except Exception:
        extra_tags = []
    merged["ai_tags"] = list(dict.fromkeys([*(tags or []), *(extra_tags or [])]))[:10]
    merged["human_time"] = smart_time_text(merged.get("created_at") or reel_row.get("created_at") or "")
    audio = {}
    try:
        conn = db()
        conn.row_factory = sqlite3.Row
        cur = conn.cursor()
        cur.execute(
            """
            SELECT at.*, ra.start_seconds, ra.end_seconds, ra.volume
            FROM pulse_reel_audio ra
            JOIN pulse_audio_tracks at ON at.id=ra.audio_track_id
            WHERE ra.reel_id=?
            ORDER BY ra.id DESC LIMIT 1
            """,
            (int(merged.get("reel_id") or 0),),
        )
        audio = dict(cur.fetchone() or {})
        conn.close()
    except Exception:
        audio = {}
    merged["audio"] = {
        "id": int(audio.get("id") or 0),
        "track_id": int(audio.get("id") or 0),
        "title": audio.get("title") or reel_row.get("sound_title") or "",
        "artist": audio.get("artist") or "",
        "duration": float(audio.get("duration_seconds") or 0),
        "waveform": audio.get("waveform_json") or "",
        "bpm": int(audio.get("bpm") or 0),
        "usage_count": int(audio.get("usage_count") or 0),
        "trend_score": int(audio.get("trend_score") or 0),
    }
    merged.update(reel_ranking_engine.score_reel({
        **merged,
        "premium_mark": bool((post.get("author") or {}).get("premium_mark")),
        "engagement_score": post.get("engagement_score") or post.get("reactions_count") or 0,
    }))
    return merged


PULSE_REEL_LANES = {
    "for_you": "For You",
    "following": "Following",
    "trending": "Trending",
    "new_creators": "New Creators",
    "ai_picks": "AI Picks",
    "local": "Local",
    "global": "Global",
    "educational": "Educational",
    "music": "Music",
    "live": "Live",
    "category": "Category",
}


def normalize_reel_lane(lane):
    lane = str(lane or "for_you").strip().lower().replace("-", "_").replace(" ", "_")
    return lane if lane in PULSE_REEL_LANES else "for_you"


def reel_text_blob(reel):
    bits = [
        reel.get("category") or "",
        reel.get("title") or "",
        reel.get("caption") or "",
        reel.get("body") or "",
        reel.get("sound_title") or "",
        " ".join(str(t) for t in (reel.get("ai_tags") or reel.get("tags") or [])),
    ]
    return " ".join(bits).lower()


def pulse_reel_matches_lane(reel, lane, viewer_user_id=0, category=""):
    lane = normalize_reel_lane(lane)
    if lane in {"for_you", "global"}:
        return True
    if lane == "category":
        return not category or str(reel.get("category") or "").lower() == str(category).lower()
    if lane == "following":
        return bool(reel.get("viewer_follows_author"))
    if lane == "new_creators":
        return int(reel.get("author_post_count") or 0) <= 5 or int(reel.get("author_follower_count") or 0) <= 25
    if lane == "ai_picks":
        return int(reel.get("reel_score") or 0) >= 55 or bool(reel.get("ai_tags"))
    if lane == "local":
        return bool(str(reel.get("author_country") or reel.get("author_region") or "").strip())
    blob = reel_text_blob(reel)
    if lane == "educational":
        return any(token in blob for token in ["learn", "lesson", "teacher", "education", "tutorial", "safety", "scam", "course", "wallet", "cyber"])
    if lane == "music":
        audio = reel.get("audio") or {}
        return bool(audio.get("track_id") or audio.get("title") or reel.get("sound_title"))
    if lane == "live":
        return any(token in blob for token in ["live", "livestream", "stream", "event", "highlight"])
    if lane == "trending":
        return True
    return True


def pulse_reel_feed_payload(viewer_user_id=0, category="", limit=12, offset=0, lane="for_you"):
    lane = normalize_reel_lane(lane)
    base = pulse_feed_engine.list_feed(viewer_user_id=viewer_user_id, feed="reels", limit=max(int(limit or 12), 40), offset=offset)
    posts = base.get("posts") or []
    conn = db()
    conn.row_factory = sqlite3.Row
    cur = conn.cursor()
    reel_rows = {}
    if posts:
        placeholders = ",".join(["?"] * len(posts))
        try:
            cur.execute(f"SELECT * FROM pulse_reels WHERE post_id IN ({placeholders}) AND COALESCE(status,'active')!='deleted'", tuple(int(p.get("id") or 0) for p in posts))
            reel_rows = {int(row["post_id"]): dict(row) for row in cur.fetchall()}
        except Exception:
            reel_rows = {}
    reels = []
    author_ids = [int(p.get("user_id") or 0) for p in posts if int(p.get("user_id") or 0)]
    following_ids = set()
    author_counts = {}
    author_followers = {}
    author_geo = {}
    if viewer_user_id and author_ids:
        placeholders = ",".join(["?"] * len(set(author_ids)))
        ids = tuple(sorted(set(author_ids)))
        try:
            cur.execute(f"SELECT followed_user_id FROM pulse_follows WHERE follower_user_id=? AND followed_user_id IN ({placeholders})", (int(viewer_user_id), *ids))
            following_ids = {int(dict(row).get("followed_user_id") or 0) for row in cur.fetchall()}
        except Exception:
            following_ids = set()
        try:
            cur.execute(f"SELECT user_id, COUNT(*) AS total FROM pulse_posts WHERE user_id IN ({placeholders}) AND deleted_at IS NULL GROUP BY user_id", ids)
            author_counts = {int(dict(row).get("user_id") or 0): int(dict(row).get("total") or 0) for row in cur.fetchall()}
        except Exception:
            author_counts = {}
        try:
            cur.execute(f"SELECT followed_user_id, COUNT(*) AS total FROM pulse_follows WHERE followed_user_id IN ({placeholders}) GROUP BY followed_user_id", ids)
            author_followers = {int(dict(row).get("followed_user_id") or 0): int(dict(row).get("total") or 0) for row in cur.fetchall()}
        except Exception:
            author_followers = {}
        try:
            cur.execute(f"SELECT user_id, country, state_region FROM users WHERE user_id IN ({placeholders})", ids)
            author_geo = {int(dict(row).get("user_id") or 0): dict(row) for row in cur.fetchall()}
        except Exception:
            author_geo = {}
    conn.close()
    for post in posts:
        row = reel_rows.get(int(post.get("id") or 0), {})
        reel = {**post, **{k: v for k, v in row.items() if v not in (None, "")}}
        reel["reel_id"] = int(row.get("id") or post.get("id") or 0)
        reel["post_id"] = int(post.get("id") or 0)
        reel["caption"] = row.get("caption") or post.get("body") or ""
        author_id = int(reel.get("user_id") or 0)
        reel["viewer_follows_author"] = author_id in following_ids
        reel["author_post_count"] = author_counts.get(author_id, 0)
        reel["author_follower_count"] = author_followers.get(author_id, 0)
        geo = author_geo.get(author_id, {})
        reel["author_country"] = geo.get("country") or ""
        reel["author_region"] = geo.get("state_region") or ""
        reel["premium_mark"] = bool((post.get("author") or {}).get("premium_mark"))
        reel["human_time"] = smart_time_text(reel.get("created_at") or row.get("created_at") or "")
        audio = {}
        track_id = safe_int(row.get("audio_track_id"), 0)
        if track_id:
            try:
                cur.execute("SELECT * FROM pulse_audio_tracks WHERE id=? LIMIT 1", (track_id,))
                audio = dict(cur.fetchone() or {})
            except Exception:
                audio = {}
        reel["audio"] = {
            "id": int(audio.get("id") or 0),
            "track_id": int(audio.get("id") or 0),
            "title": audio.get("title") or row.get("sound_title") or "",
            "artist": audio.get("artist") or "",
            "duration": float(audio.get("duration_seconds") or 0),
            "waveform": audio.get("waveform_json") or "",
            "bpm": int(audio.get("bpm") or 0),
            "usage_count": int(audio.get("usage_count") or 0),
            "trend_score": int(audio.get("trend_score") or 0),
        }
        reel.update(reel_ranking_engine.score_reel(reel))
        if not pulse_reel_matches_lane(reel, lane, viewer_user_id, category):
            continue
        reels.append(reel)
    ranked = reel_ranking_engine.rank_reels(reels)
    if lane == "trending":
        ranked = sorted(ranked, key=lambda r: (int(r.get("engagement_score") or 0) + int(r.get("reactions_count") or 0) + int(r.get("comments_count") or 0) + int(r.get("reel_score") or 0)), reverse=True)
    elif lane == "new_creators":
        ranked = sorted(ranked, key=lambda r: (int(r.get("author_post_count") or 0), -int(r.get("reel_score") or 0)))
    elif lane == "music":
        ranked = sorted(ranked, key=lambda r: int(((r.get("audio") or {}).get("trend_score") or 0)) + int(((r.get("audio") or {}).get("usage_count") or 0)), reverse=True)
    return {**base, "feed": "reels", "lane": lane, "lane_label": PULSE_REEL_LANES.get(lane, "For You"), "reels": ranked[: int(limit or 12)], "categories": ["Crypto Education", "Scam Alerts", "Market Pulse", "Teachers", "Livestream Highlights", "Founder Picks", "Community", "Arena"]}


@webhook_app.route("/pulse/friends", methods=["GET"])
def pulse_friends_page():
    init_db()
    user = require_account()
    if not user:
        return redirect(url_for("login_page", next=request.path))
    conn = db()
    conn.row_factory = sqlite3.Row
    cur = conn.cursor()
    graph = pulse_friend_graph(cur, user["user_id"])

    def person_card(person_id, mode="suggested", request_id=""):
        ident = pulse_person_public_payload(cur, person_id)
        avatar = f"<img src='{clean_html(ident['avatar_url'])}' alt=''>" if ident.get("avatar_url") else clean_html((ident.get("display_name") or "P")[:1])
        username = f"<span class='pill'>@{clean_html(ident['username'])}</span>" if ident.get("username") else ""
        mutual = "Mutual spaces: Scam Watch, Alpha Arena"
        actions = ""
        if mode == "incoming":
            actions = f"<button class='primary' data-accept='{clean_html(request_id)}'>Accept</button><button data-decline='{clean_html(request_id)}'>Decline</button>"
        elif mode == "friend":
            actions = f"<a class='button primary' href='/pulse/profile/{clean_html(ident['public_player_id'])}'>View Profile</a>"
        else:
            actions = f"<button class='primary' data-friend-public='{clean_html(ident['public_player_id'])}'>Add Friend</button><button data-follow-public='{clean_html(ident['public_player_id'])}'>Follow</button>"
        actions += f"<button data-message-public='{clean_html(ident['public_player_id'])}'>Message</button>"
        return f"<article class='card friend-card'><div class='person'><span class='avatar'>{avatar}</span><div><h3>{clean_html(ident['display_name'])}{pulse_premium_mark_html(ident.get('premium_mark'))}</h3><div class='actions'>{username}<span class='pill'>{clean_html(ident['rank'])}</span></div><p>{mutual}</p></div></div><div class='actions friend-actions'>{actions}</div></article>"

    incoming_html = "".join(person_card(int(row.get("requester_user_id") or 0), "incoming", row.get("id")) for row in graph["incoming"])
    friends_html = "".join(person_card(fid, "friend") for fid in graph["friends"])
    following_html = "".join(person_card(fid, "friend") for fid in graph["following"])
    followers_html = "".join(person_card(fid, "friend") for fid in graph["followers"])
    suggested_html = "".join(person_card(sid, "suggested") for sid in graph["suggested"])
    conn.close()
    main = f"""
    <section class='card'><h2>Friend Requests</h2>{incoming_html or '<p>No pending friend requests. Suggested people are below.</p>'}</section>
    <section class='card'><h2>Search People</h2><input id='peopleSearch' placeholder='Search by display name or username'><p class='muted'>Search is privacy-safe and never exposes emails, phone numbers, or internal IDs.</p></section>
    <section class='card'><h2>Suggested People</h2><div class='grid' id='suggestedPeople'>{suggested_html or '<article class="card"><p>Publish or follow Pulse posts to unlock smarter suggestions.</p></article>'}</div></section>
    <section class='card'><h2>Following</h2><div class='grid'>{following_html or '<article class="card"><p>Creators and friends you follow will appear here.</p></article>'}</div></section>
    <section class='card'><h2>Followers</h2><div class='grid'>{followers_html or '<article class="card"><p>People who follow you will appear here.</p></article>'}</div></section>
    <section class='card'><h2>Your Friends</h2><div class='grid'>{friends_html or '<article class="card"><p>Friends you accept will appear here with quick messaging.</p></article>'}</div></section>
    <section class='card'><h2>Invite Friends</h2><p>Bring trusted learners, creators, and crypto safety-minded people into Pulse.</p><div class='actions'><button class='primary' id='copyInvite'>Copy Invite Link</button><a class='button' href='/pulse/messages'>Open Messenger</a></div></section>
    """
    script = """
    document.addEventListener('click', async e => {
      const accept=e.target.closest('[data-accept]');
      const decline=e.target.closest('[data-decline]');
      const friend=e.target.closest('[data-friend-public]');
      const follow=e.target.closest('[data-follow-public]');
      const msg=e.target.closest('[data-message-public]');
      try {
        if (accept) { await pulseApi('/api/pulse/friends/accept',{method:'POST',body:JSON.stringify({request_id:accept.dataset.accept})}); accept.closest('.card').innerHTML='<h3>Friend request accepted.</h3><p class="muted">You can message this friend from Pulse Messenger.</p><a class="button primary" href="/pulse/messages">Open Messenger</a>'; toast('Friend request accepted.'); }
        if (decline) { await pulseApi('/api/pulse/friends/decline',{method:'POST',body:JSON.stringify({request_id:decline.dataset.decline})}); decline.closest('.card').innerHTML='<h3>Request declined.</h3><p class="muted">No notification includes private details.</p>'; toast('Friend request declined.'); }
        if (friend) { await pulseApi('/api/pulse/friends/request',{method:'POST',body:JSON.stringify({public_player_id:friend.dataset.friendPublic})}); toast('Friend request sent.'); }
        if (follow) { const d=await pulseApi('/api/pulse/follows/toggle',{method:'POST',body:JSON.stringify({public_player_id:follow.dataset.followPublic})}); follow.textContent=d.following?'Following':'Follow'; toast(d.following?'Followed.':'Unfollowed.'); }
        if (msg) { const d=await pulseApi('/api/pulse/messages/start',{method:'POST',body:JSON.stringify({public_player_id:msg.dataset.messagePublic})}); location.href=d.next_url; }
        if (e.target.closest('#copyInvite')) { await navigator.clipboard.writeText(location.origin + '/pulse'); toast('Invite link copied.'); }
      } catch(err) { toast(err.message); }
    });
    """
    return pulse_social_shell("Friends and Following", "Build your trusted CoinPilotXAI circle, follow creators, accept requests, and message without exposing private identity data.", main, "", script)


