@webhook_app.route("/pulse/profile/edit", methods=["GET"])
def pulse_profile_edit_page():
    init_db()
    user = require_account()
    if not user:
        return redirect(url_for("login_page", next=request.path))
    conn = db()
    conn.row_factory = sqlite3.Row
    cur = conn.cursor()
    cur.execute("SELECT display_name, username, avatar_url, avatar_filter, COALESCE(cover_url,banner_url,'') AS cover_url, cover_position, cover_filter, bio, social_links_json, expertise_tags_json, profile_visibility FROM users WHERE user_id=? LIMIT 1", (user["user_id"],))
    row = dict(cur.fetchone() or {})
    conn.close()
    avatar = row.get("avatar_url") or ""
    cover = row.get("cover_url") or ""
    avatar_html = f"<img id='avatarPreview' src='{clean_html(avatar)}' alt='Profile picture'>" if avatar else "<span id='avatarPreview'>P</span>"
    cover_style = f" style=\"background-image:linear-gradient(135deg,rgba(5,11,20,.22),rgba(5,11,20,.14)),url('{clean_html(cover)}');background-size:cover;background-position:{clean_html(row.get('cover_position') or 'center')}\"" if cover else ""
    main = f"""
    <style>.profile-edit-preview{{padding:0;overflow:hidden}}.cover-edit-preview{{height:220px;border-radius:16px 16px 0 0;background:radial-gradient(circle at 20% 20%,rgba(255,209,102,.34),transparent 28%),radial-gradient(circle at 82% 10%,rgba(110,223,246,.32),transparent 34%),linear-gradient(135deg,#071321,#12213b)}}.profile-edit-avatar{{width:112px;height:112px;border-radius:28px;border:3px solid #050b14;margin:-54px 0 0 18px;box-shadow:0 18px 55px rgba(0,0,0,.38),0 0 28px rgba(110,223,246,.18)}}.media-actions{{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:10px}}@media(max-width:620px){{.media-actions{{grid-template-columns:1fr}}.cover-edit-preview{{height:170px}}}}</style>
    <section class='card'>
      <h2>Social Profile</h2>
      <p class='muted'>This is your normal Pulse identity. Roast Battle call signs stay inside competitive battle modes.</p>
      <article class='profile-edit-preview'><div class='cover-edit-preview' id='coverPreview'{cover_style}></div><span class='avatar profile-edit-avatar'>{avatar_html}</span></article>
      <p class='muted'>Recommended cover size: 1600 x 600. JPG, PNG, and WebP are supported.</p>
      <div class='media-actions'><label>Upload Profile Picture<input id='avatarFile' type='file' accept='image/png,image/jpeg,image/webp'></label><label>Upload Cover Picture<input id='coverFile' type='file' accept='image/png,image/jpeg,image/webp'></label><a class='button' href='/pulse/camera?target=avatar'>Take Profile Picture</a><a class='button' href='/pulse/camera?target=cover'>Take Cover Picture</a><button class='primary' id='avatarSave'>Save Profile Picture</button><button class='primary' id='coverSave'>Save Cover Picture</button><button id='avatarRemove'>Remove Profile Picture</button><button id='coverRemove'>Remove Cover Picture</button></div>
    </section>
    <section class='card'>
      <h2>Edit Details</h2>
      <input id='displayName' value='{clean_html(row.get('display_name') or '')}' placeholder='Display name'>
      <textarea id='bio' placeholder='Bio'>{clean_html(row.get('bio') or '')}</textarea>
      <input id='socialLinks' value='{clean_html(row.get('social_links_json') or '')}' placeholder='Social links or website'>
      <input id='expertiseTags' value='{clean_html(row.get('expertise_tags_json') or '')}' placeholder='Expertise tags, comma separated'>
      <select id='profileVisibility'><option value='public'>Public profile</option><option value='private'>Private profile</option></select>
      <button class='primary' id='profileSave'>Save Profile</button>
      <a class='button' href='/pulse/profile'>Preview Profile</a>
    </section>
    """
    script = f"""
    document.getElementById('profileVisibility').value={json.dumps(row.get('profile_visibility') or 'public')};
    document.getElementById('avatarFile').addEventListener('change',e=>{{const file=e.target.files[0];if(!file)return;const reader=new FileReader();reader.onload=()=>{{document.querySelector('.profile-edit-avatar').innerHTML=`<img id="avatarPreview" src="${{reader.result}}" alt="Profile picture preview">`;}};reader.readAsDataURL(file);}});
    document.getElementById('coverFile').addEventListener('change',e=>{{const file=e.target.files[0];if(!file)return;const reader=new FileReader();reader.onload=()=>{{document.getElementById('coverPreview').style.backgroundImage=`linear-gradient(135deg,rgba(5,11,20,.22),rgba(5,11,20,.14)),url('${{reader.result}}')`;}};reader.readAsDataURL(file);}});
    document.getElementById('avatarSave').addEventListener('click',async()=>{{const file=document.getElementById('avatarFile').files[0];if(!file){{toast('Choose a jpg, png, or webp profile picture.');return}}const fd=new FormData();fd.append('avatar',file);try{{const r=await fetch('/api/pulse/profile/avatar',{{method:'POST',credentials:'same-origin',body:fd}});const d=await r.json();if(!r.ok||!d.ok)throw new Error(d.message||'Upload failed.');toast('Profile picture updated.');document.querySelectorAll('.avatar img').forEach(img=>img.src=d.avatar_url);}}catch(err){{toast(err.message)}}}});
    document.getElementById('coverSave').addEventListener('click',async()=>{{const file=document.getElementById('coverFile').files[0];if(!file){{toast('Choose a jpg, png, or webp cover picture.');return}}const fd=new FormData();fd.append('cover',file);try{{const r=await fetch('/api/pulse/profile/cover',{{method:'POST',credentials:'same-origin',body:fd}});const d=await r.json();if(!r.ok||!d.ok)throw new Error(d.message||'Upload failed.');toast('Cover photo updated.');document.getElementById('coverPreview').style.backgroundImage=`linear-gradient(135deg,rgba(5,11,20,.22),rgba(5,11,20,.14)),url('${{d.cover_url}}')`;}}catch(err){{toast(err.message)}}}});
    document.getElementById('avatarRemove').addEventListener('click',async()=>{{try{{await pulseApi('/api/pulse/profile/avatar/remove',{{method:'POST',body:JSON.stringify({{}})}});document.querySelector('.profile-edit-avatar').innerHTML='P';toast('Profile picture removed.');}}catch(err){{toast(err.message)}}}});
    document.getElementById('coverRemove').addEventListener('click',async()=>{{try{{await pulseApi('/api/pulse/profile/cover/remove',{{method:'POST',body:JSON.stringify({{}})}});document.getElementById('coverPreview').style.backgroundImage='';toast('Cover photo removed.');}}catch(err){{toast(err.message)}}}});
    document.getElementById('profileSave').addEventListener('click',async()=>{{try{{await pulseApi('/api/pulse/profile/update',{{method:'POST',body:JSON.stringify({{display_name:document.getElementById('displayName').value,bio:document.getElementById('bio').value,social_links:document.getElementById('socialLinks').value,expertise_tags:document.getElementById('expertiseTags').value,profile_visibility:document.getElementById('profileVisibility').value}})}});toast('Profile updated.');}}catch(err){{toast(err.message)}}}});
    """
    return pulse_social_shell("Edit Pulse Profile", "Manage your profile picture, display name, bio, public links, expertise tags, and privacy.", main, "", script)


@webhook_app.route("/pulse/groups", methods=["GET"])
def pulse_groups_page():
    init_db()
    user = require_account()
    if not user:
        return redirect(url_for("login_page", next=request.path))
    conn = db(); conn.row_factory = sqlite3.Row; cur = conn.cursor()
    cur.execute("SELECT g.*, COUNT(m.user_id) AS members FROM pulse_groups g LEFT JOIN pulse_group_members m ON m.group_id=g.id WHERE COALESCE(g.status,'active') NOT IN ('suspended','deleted','removed') GROUP BY g.id ORDER BY COALESCE(g.featured,0) DESC, g.id DESC LIMIT 80")
    groups = [dict(row) for row in cur.fetchall()]
    conn.close()
    group_html = "".join(f"<article class='card group-list-card'><span class='pill'>{clean_html(g.get('category') or 'Community')}</span><h2>{clean_html(g.get('name'))}</h2><p>{clean_html(g.get('description') or '')}</p><p class='group-pill-row'><span class='pill'>{clean_html(g.get('group_type') or 'public')}</span> <span class='pill'>{int(g.get('members') or g.get('member_count') or 0)} members</span> <span class='pill'>{clean_html(g.get('trust_level') or 'standard')}</span></p><div class='group-card-actions'><button class='primary' data-join-group='{clean_html(g.get('slug') or str(g.get('id') or 0))}'>Join</button><a class='button' href='/pulse/groups/{clean_html(g.get('slug') or str(g.get('id') or 0))}'>Open</a></div></article>" for g in groups)
    main = f"""<style>.group-list-card{{width:100%;overflow:hidden}}.group-pill-row{{display:flex;gap:6px;flex-wrap:wrap}}.group-card-actions{{display:grid;grid-template-columns:1fr;gap:10px;margin-top:12px}}@media(min-width:768px){{.group-card-actions{{grid-template-columns:repeat(2,1fr)}}}}</style><section class='card'><h2>Create Group</h2><p class='muted'>Groups support public, private, and invite-only communities with rules, owners, members, and safe posting.</p><div class='group-card-actions'><a class='button primary' href='/pulse/groups/create'>Create Group</a></div></section><section class='grid'>{group_html or '<article class="card"><h2>No groups yet.</h2><p>Create the first Pulse group for your community.</p></article>'}</section>"""
    script = "document.addEventListener('click',async e=>{const b=e.target.closest('[data-join-group]');if(!b)return;try{await pulseApi(`/api/pulse/groups/${encodeURIComponent(b.dataset.joinGroup)}/join`,{method:'POST',body:JSON.stringify({})});toast('Joined group.')}catch(err){toast(err.message)}});"
    return pulse_social_shell("Pulse Groups", "Create focused communities, invite friends, post updates, and grow safe discussion spaces.", main, "", script)


