@webhook_app.route("/api/pulse/posts", methods=["POST"])
def api_pulse_posts():
    init_db()
    user = api_account_user()
    if not user:
        return jsonify({"ok": False, "message": "Login required."}), 401
    post_type = "text"
    content_length = int(request.content_length or 0)
    has_file = False

    def exception_hint(exc_text):
        text = str(exc_text or "")
        lower = text.lower()
        table = ""
        field = ""
        for candidate in ["pulse_posts", "pulse_jobs", "pulse_post_attempts", "chat_media_uploads", "arena_profiles", "users"]:
            if candidate in lower:
                table = candidate
                break
        match = re.search(r"(?:column|field) ['\"]?([a-zA-Z_][a-zA-Z0-9_]*)", text, re.I) or re.search(r"no such column: ([a-zA-Z_][a-zA-Z0-9_\\.]*)(?:\\b|$)", text, re.I)
        if match:
            field = match.group(1).split(".")[-1]
        return table, field

    def record_attempt(status_label, status_code, error_reason="", exception_message=""):
        try:
            failing_table, failing_field = exception_hint(exception_message or error_reason)
            conn = db()
            cur = conn.cursor()
            cur.execute(
                """
                INSERT INTO pulse_post_attempts
                (user_id, post_type, status, error_reason, content_length, has_file, status_code, exception_message, failing_table, failing_field, created_at)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                (
                    user["user_id"],
                    post_type,
                    status_label,
                    str(error_reason or "")[:500],
                    content_length,
                    1 if has_file else 0,
                    int(status_code or 0),
                    str(exception_message or "")[:1000],
                    failing_table[:120],
                    failing_field[:120],
                    datetime.utcnow().isoformat(timespec="seconds"),
                ),
            )
            conn.commit()
            conn.close()
        except Exception:
            logging.debug("Pulse post attempt logging failed", exc_info=True)

    try:
        if request.content_type and ("multipart/form-data" in request.content_type or "application/x-www-form-urlencoded" in request.content_type):
            form = request.form
            post_type = form.get("post_type") or "text"
            uploads = request.files.getlist("file") + request.files.getlist("files")
            has_file = any(bool(getattr(upload, "filename", "")) for upload in uploads)
            tags_raw = form.get("tags") or ""
            try:
                tags = json.loads(tags_raw) if tags_raw.strip().startswith("[") else [x.strip() for x in tags_raw.split(",") if x.strip()]
            except Exception:
                tags = []
            media_ids = []
            media_ids_raw = form.get("media_ids") or ""
            if media_ids_raw:
                try:
                    parsed = json.loads(media_ids_raw)
                    media_ids = parsed if isinstance(parsed, list) else []
                except Exception:
                    media_ids = [x.strip() for x in media_ids_raw.split(",") if x.strip()]
            for upload in uploads:
                if not upload or not getattr(upload, "filename", ""):
                    continue
                result, status = media_service.save_upload(user["user_id"], upload, context_type="pulse", context_id="draft")
                if not result.get("ok"):
                    raise ValueError(result.get("message") or "File upload failed.")
                media_ids.append(result.get("media", {}).get("id"))
            payload = {
                "body": form.get("body") or form.get("message") or "",
                "title": form.get("title") or "",
                "post_type": post_type,
                "tags": tags,
                "visibility": form.get("visibility") or "public",
                "media_ids": media_ids,
            }
        else:
            payload = request.get_json(silent=True)
            if payload is None:
                record_attempt("failed", 400, "Could not read the post request. Please refresh and try again.")
                logging.warning("PULSE_POST_FAILED user_id=%s post_type=%s content_length=%s has_file=%s status_code=400 error=%s", user["user_id"], post_type, content_length, has_file, "unreadable request")
                return jsonify({"ok": False, "message": "Could not read the post request. Please refresh and try again."}), 400
            post_type = payload.get("post_type") or "text"
        result = pulse_feed_engine.create_post(
            user["user_id"],
            payload.get("body") or "",
            payload.get("post_type") or "text",
            payload.get("title") or "",
            payload.get("tags") or [],
            payload.get("visibility") or "public",
            payload.get("media_ids") or [],
        )
        status = 200 if result.get("ok") else 400
        record_attempt("success" if result.get("ok") else "failed", status, "" if result.get("ok") else result.get("message", ""))
        logging.info(
            "PULSE_POST_ATTEMPT user_id=%s post_type=%s content_length=%s has_file=%s status_code=%s ok=%s",
            user["user_id"], post_type, content_length, has_file, status, result.get("ok"),
        )
        log_product_event(user["user_id"], "pulse_post_created", {"post_id": result.get("post_id"), "status": result.get("status"), "ok": result.get("ok")})
        if result.get("ok") and (result.get("post") or {}).get("moderation_status") == "approved":
            post_payload = result.get("post") or {}
            author = post_payload.get("author") or {}
            event_payload = {
                "event": "pulse_post_created",
                "post_id": result.get("post_id"),
                "user_id": user["user_id"],
                "username": author.get("display_name") or user.get("display_name") or user.get("username") or "",
                "display_role": author.get("primary_label") or author.get("rank") or "Member",
                "premium_mark": bool(author.get("premium_mark")),
                "post_type": post_payload.get("post_type"),
                "body": post_payload.get("body"),
                "media_url": ((post_payload.get("media") or [{}])[0] or {}).get("media_url") or "",
                "created_at": post_payload.get("created_at"),
                "post": post_payload,
                "next_url": result.get("next_url"),
            }
            pulse_emit_event("pulse_post_created", event_payload, user["user_id"], result.get("post_id") or 0)
            pulse_emit_event("new_post", {"post": post_payload, "next_url": result.get("next_url")}, user["user_id"], result.get("post_id") or 0)
        return jsonify(result), status
    except ValueError as exc:
        message = str(exc) or "Server error while publishing."
        record_attempt("failed", 400, message, str(exc))
        logging.warning("PULSE_POST_FAILED user_id=%s post_type=%s content_length=%s has_file=%s status_code=400 error=%s", user["user_id"], post_type, content_length, has_file, message)
        return jsonify({"ok": False, "message": message}), 400
    except Exception as exc:
        logging.exception("Pulse post publish failed user_id=%s post_type=%s error=%s", user["user_id"], post_type, exc)
        exc_text = str(exc)
        message = "Server error while publishing. Please try again."
        failing_table, failing_field = exception_hint(exc_text)
        if any(token in exc_text.lower() for token in ["pulse_posts", "pulse_jobs", "chat_media_uploads", "pulse_post", "no such table", "undefined table", "undefined column", "no such column", "does not exist"]):
            detail = f" ({failing_table}{'.' + failing_field if failing_field else ''})" if failing_table or failing_field else ""
            message = f"Database migration missing{detail}. Please run the latest migration and try again."
        record_attempt("failed", 500, message, exc_text)
        return jsonify({"ok": False, "message": message}), 500


