@webhook_app.route("/api/pulse/reels/sounds", methods=["GET"])
def api_pulse_reels_sounds():
    init_db()
    user = api_account_user()
    if not user:
        return api_error("Login required.", 401)
    query = clean_html(request.args.get("q") or "")[:120].strip()
    category = clean_html(request.args.get("category") or "")[:80].strip()
    conn = db(); conn.row_factory = sqlite3.Row; cur = conn.cursor()
    params = []
    where = "WHERE COALESCE(at.safety_status,'approved')!='blocked'"
    if query:
        where += " AND (lower(COALESCE(at.title,'')) LIKE ? OR lower(COALESCE(at.artist,'')) LIKE ?)"
        like = f"%{query.lower()}%"
        params.extend([like, like])
    if category and category.lower() == "saved":
        where += " AND (ss.id IS NOT NULL OR pss.id IS NOT NULL)"
    elif category:
        where += " AND lower(COALESCE(ts.category,at.source_type,''))=lower(?)"
        params.append(category)
    cur.execute(
        f"""
        SELECT at.*, COALESCE(ts.trend_score, at.trend_score, 0) AS live_trend_score,
               COALESCE(ts.usage_count, at.usage_count, 0) AS live_usage_count,
               COALESCE(ts.category, at.source_type, 'Trending') AS live_category,
               CASE WHEN ss.id IS NULL AND pss.id IS NULL THEN 0 ELSE 1 END AS saved
        FROM pulse_audio_tracks at
        LEFT JOIN pulse_trending_sounds ts ON ts.audio_track_id=at.id
        LEFT JOIN pulse_reel_sound_saves ss ON ss.audio_track_id=at.id AND ss.user_id=?
        LEFT JOIN pulse_saved_sounds pss ON pss.audio_track_id=at.id AND pss.user_id=?
        {where}
        ORDER BY live_trend_score DESC, live_usage_count DESC, at.created_at DESC
        LIMIT 40
        """,
        [user["user_id"], user["user_id"], *params],
    )
    sounds = []
    for row in cur.fetchall():
        item = dict(row)
        sounds.append({
            "id": int(item.get("id") or 0),
            "track_id": int(item.get("id") or 0),
            "title": item.get("title") or "Pulse sound",
            "artist": item.get("artist") or "CoinPilotXAI",
            "audio_url": item.get("audio_url") or "",
            "duration": float(item.get("duration_seconds") or 0),
            "waveform": item.get("waveform_json") or "",
            "bpm": int(item.get("bpm") or 0),
            "usage_count": int(item.get("live_usage_count") or 0),
            "trend_score": int(item.get("live_trend_score") or 0),
            "category": item.get("live_category") or "Trending",
            "saved": bool(item.get("saved")),
        })
    conn.close()
    return jsonify({"ok": True, "sounds": sounds})


@webhook_app.route("/api/pulse/reels/sounds/save", methods=["POST"])
def api_pulse_reels_sound_save():
    init_db()
    user = api_account_user()
    if not user:
        return api_error("Login required.", 401)
    payload = request.get_json(silent=True) or {}
    track_id = safe_int(payload.get("track_id") or payload.get("audio_track_id") or payload.get("sound_id"), 0)
    if not track_id:
        return api_error("Choose a sound to save.", 400)
    conn = db(); conn.row_factory = sqlite3.Row; cur = conn.cursor()
    cur.execute("SELECT id FROM pulse_audio_tracks WHERE id=? AND COALESCE(safety_status,'approved')!='blocked' LIMIT 1", (track_id,))
    if not cur.fetchone():
        conn.close()
        return api_error("Sound not found.", 404)
    now = datetime.utcnow().isoformat(timespec="seconds")
    cur.execute("INSERT OR IGNORE INTO pulse_reel_sound_saves (user_id, audio_track_id, created_at) VALUES (?, ?, ?)", (user["user_id"], track_id, now))
    cur.execute("INSERT OR IGNORE INTO pulse_saved_sounds (user_id, audio_track_id, created_at) VALUES (?, ?, ?)", (user["user_id"], track_id, now))
    conn.commit(); conn.close()
    return jsonify({"ok": True, "message": "Sound saved.", "track_id": track_id})


@webhook_app.route("/api/pulse/reels/sounds/upload", methods=["POST"])
def api_pulse_reels_sound_upload():
    init_db()
    user = api_account_user()
    if not user:
        return api_error("Login required.", 401)
    upload = request.files.get("file")
    if not upload or not upload.filename:
        return api_error("Choose an audio file.", 400)
    filename = secure_filename(upload.filename or "")
    ext = filename.rsplit(".", 1)[-1].lower() if "." in filename else ""
    if ext not in {"mp3", "m4a", "wav", "ogg", "webm"}:
        return api_error("Upload MP3, M4A, WAV, OGG, or WebM audio.", 400)
    if upload.mimetype and not (upload.mimetype.startswith("audio/") or upload.mimetype in {"video/webm", "application/ogg"}):
        return api_error("That file does not look like an audio track.", 400)
    result, status = media_service.save_upload(user["user_id"], upload, context_type="pulse_sound", context_id="reels")
    if not result.get("ok"):
        return jsonify(result), status
    media = result.get("media") or {}
    title = clean_html(request.form.get("title") or filename.rsplit(".", 1)[0] or "Original Pulse Sound")[:120]
    artist = clean_html(request.form.get("artist") or user.get("display_name") or user.get("username") or "Pulse Creator")[:120]
    now = datetime.utcnow().isoformat(timespec="seconds")
    conn = db(); cur = conn.cursor()
    cur.execute(
        """
        INSERT INTO pulse_audio_tracks
        (title, artist, uploader_user_id, audio_url, duration_seconds, waveform_json, bpm, usage_count, trend_score, source_type, safety_status, created_at, updated_at)
        VALUES (?, ?, ?, ?, 0, ?, 0, 0, 0, 'uploaded', 'approved', ?, ?)
        """,
        (title, artist, user["user_id"], media.get("media_url") or "", json.dumps([0.22, 0.48, 0.35, 0.68, 0.44, 0.58, 0.26, 0.52]), now, now),
    )
    track_id = int(cur.lastrowid)
    cur.execute("INSERT OR IGNORE INTO pulse_saved_sounds (user_id, audio_track_id, created_at) VALUES (?, ?, ?)", (user["user_id"], track_id, now))
    cur.execute("INSERT OR IGNORE INTO pulse_reel_sound_saves (user_id, audio_track_id, created_at) VALUES (?, ?, ?)", (user["user_id"], track_id, now))
    conn.commit(); conn.close()
    sound = {"id": track_id, "track_id": track_id, "title": title, "artist": artist, "audio_url": media.get("media_url") or "", "duration": 0, "category": "Uploaded", "saved": True}
    return jsonify({"ok": True, "message": "Original sound uploaded.", "track_id": track_id, "sound": sound})


@webhook_app.route("/api/pulse/reels/create", methods=["POST"])
def api_pulse_reels_create():
    init_db()
    user = api_account_user()
    if not user:
        return jsonify({"ok": False, "message": "Login required."}), 401
    payload = request.get_json(silent=True) or {}
    trace_id = secrets.token_hex(6)
    try:
        caption = clean_html(payload.get("caption") or payload.get("body") or "")[:2200]
        title = clean_html(payload.get("title") or "Pulse Reel")[:140]
        category = clean_html(payload.get("category") or "Community")[:80]
        media_ids = payload.get("media_ids") or []
        audio_track_id = safe_int(payload.get("audio_track_id") or payload.get("sound_id"), 0)
        sound_start = float(payload.get("sound_start_seconds") or payload.get("audio_start_seconds") or 0)
        sound_end = float(payload.get("sound_end_seconds") or payload.get("audio_end_seconds") or 0)
        tags = payload.get("tags") or ai_social_engine.suggest_hashtags(caption, category)
        safety = ai_moderation_core.moderate_text(caption or title, "reel")
        if safety.get("status") == "blocked":
            return jsonify({"ok": False, "message": "This Reel needs changes before publishing.", "trace_id": trace_id}), 400
        result = pulse_feed_engine.create_post(user["user_id"], caption, payload.get("post_type") or "video", title, tags=tags, visibility=payload.get("visibility") or "public", media_ids=media_ids)
        if not result.get("ok"):
            return jsonify({**result, "trace_id": trace_id}), 400
        post_id = int(result.get("post_id") or 0)
        score = reel_ranking_engine.score_reel({"risk_score": safety.get("risk_score"), "educational_value": 65, "created_at": datetime.utcnow().isoformat(timespec="seconds")})
        now = datetime.utcnow().isoformat(timespec="seconds")
        conn = db()
        cur = conn.cursor()
        cur.execute(
            """
            INSERT INTO pulse_reels
            (post_id, user_id, category, caption, ai_tags_json, safety_score, educational_value, reel_score, status, created_at, updated_at)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, 'active', ?, ?)
            ON CONFLICT(post_id) DO UPDATE SET category=excluded.category, caption=excluded.caption, ai_tags_json=excluded.ai_tags_json, safety_score=excluded.safety_score, educational_value=excluded.educational_value, reel_score=excluded.reel_score, updated_at=excluded.updated_at
            """,
            (post_id, user["user_id"], category, caption, json.dumps(tags[:10]), score["safety_score"], score["educational_score"], score["reel_score"], now, now),
        )
        reel_id = int(cur.lastrowid or 0)
        if not reel_id:
            cur.execute("SELECT id FROM pulse_reels WHERE post_id=? LIMIT 1", (post_id,))
            reel_id = safe_int((cur.fetchone() or [0])[0], post_id)
        if audio_track_id:
            cur.execute("SELECT title FROM pulse_audio_tracks WHERE id=? AND COALESCE(safety_status,'approved')!='blocked' LIMIT 1", (audio_track_id,))
            track = dict(cur.fetchone() or {})
            if track:
                cur.execute("UPDATE pulse_reels SET audio_track_id=?, sound_title=?, sound_start_seconds=?, sound_end_seconds=? WHERE id=?", (audio_track_id, track.get("title") or "", sound_start, sound_end, reel_id))
                cur.execute(
                    "INSERT OR REPLACE INTO pulse_reel_audio (reel_id, audio_track_id, start_seconds, end_seconds, volume, created_at) VALUES (?, ?, ?, ?, 1, ?)",
                    (reel_id, audio_track_id, sound_start, sound_end, now),
                )
                cur.execute("UPDATE pulse_audio_tracks SET usage_count=COALESCE(usage_count,0)+1, updated_at=? WHERE id=?", (now, audio_track_id))
                cur.execute("UPDATE pulse_trending_sounds SET usage_count=COALESCE(usage_count,0)+1, trend_score=COALESCE(trend_score,0)+1, updated_at=? WHERE audio_track_id=?", (now, audio_track_id))
        conn.commit()
        conn.close()
        reel = pulse_reel_payload(reel_id=reel_id, viewer_user_id=user["user_id"])
        pulse_emit_event("pulse_reel_created", {"reel_id": reel_id, "post_id": post_id, "reel": reel}, user["user_id"], post_id)
        return jsonify({"ok": True, "data": {"reel": reel}, "reel": reel, "reel_id": reel_id, "post_id": post_id, "next_url": f"/pulse/reels/{reel_id}"})
    except Exception as exc:
        logging.exception("PULSE_REELS_CREATE_FAILED trace_id=%s user_id=%s error=%s", trace_id, user.get("user_id"), exc)
        return jsonify({"ok": False, "message": "Reel could not be created.", "trace_id": trace_id}), 500


