@webhook_app.route("/api/pulse/follows/toggle", methods=["POST"])
def api_pulse_follows_toggle():
    init_db()
    user = api_account_user()
    if not user:
        return jsonify({"ok": False, "message": "Login required."}), 401
    payload = request.get_json(silent=True) or {}
    conn = db(); conn.row_factory = sqlite3.Row; cur = conn.cursor()
    target_id = payload.get("followed_user_id") or pulse_user_id_from_public(cur, payload.get("public_player_id") or payload.get("followed_public_player_id") or "")
    if not target_id:
        conn.close()
        return jsonify({"ok": False, "message": "Choose a valid Pulse member."}), 400
    target_id = int(target_id)
    if target_id == int(user["user_id"]):
        conn.close()
        return jsonify({"ok": False, "message": "You cannot follow yourself."}), 400
    cur.execute("SELECT 1 FROM pulse_follows WHERE follower_user_id=? AND followed_user_id=? LIMIT 1", (user["user_id"], target_id))
    existing = bool(cur.fetchone())
    if existing:
        cur.execute("DELETE FROM pulse_follows WHERE follower_user_id=? AND followed_user_id=?", (user["user_id"], target_id))
        following = False
    else:
        public_id = pulse_identity_for_user(cur, target_id).get("public_player_id") or ""
        cur.execute("INSERT INTO pulse_follows (follower_user_id, followed_user_id, followed_public_player_id, created_at) VALUES (?, ?, ?, ?)", (user["user_id"], target_id, public_id, datetime.utcnow().isoformat(timespec="seconds")))
        following = True
    conn.commit(); conn.close()
    return jsonify({"ok": True, "following": following, "message": "Followed." if following else "Unfollowed."})


@webhook_app.route("/api/pulse/messages/send", methods=["POST"])
def api_pulse_message_send():
    init_db()
    user = api_account_user()
    if not user:
        return jsonify({"ok": False, "message": "Login required."}), 401
    payload = request.get_json(silent=True) or {}
    message = clean_html(payload.get("message") or payload.get("body") or payload.get("content") or "")[:2000].strip()
    message_type = clean_html(payload.get("type") or payload.get("message_type") or "text")[:40]
    allowed_types = {"text", "image", "gif", "video", "voice", "audio", "file", "system", "reaction", "call_event", "link", "post_share", "reel_share", "group_share", "marketplace_share", "live_share"}
    if message_type not in allowed_types:
        message_type = "text"
    media_url = clean_html(payload.get("media_url") or "")[:1000]
    thumbnail_url = clean_html(payload.get("thumbnail_url") or media_url)[:1000]
    metadata = payload.get("media_metadata") if isinstance(payload.get("media_metadata"), dict) else {}
    reply_to_id = safe_int(payload.get("reply_to_id"), 0)
    if not message and not media_url:
        return jsonify({"ok": False, "message": "Write a message or attach media before sending."}), 400
    if media_url and message_type == "text":
        message_type = "link" if media_url.startswith(("http://", "https://", "/pulse/")) and not media_url.startswith("/static/") else "image"
    trace_id = secrets.token_hex(6)
    conn = db(); conn.row_factory = sqlite3.Row; cur = conn.cursor()
    ensure_pulse_messenger_schema(cur, conn)
    conversation_id = int(payload.get("conversation_id") or 0)
    thread_id = int(payload.get("thread_id") or 0)
    logging.info(
        "PULSE_MESSAGE_SEND_START trace_id=%s user_id=%s conversation_id=%s thread_id=%s type=%s",
        trace_id,
        user.get("user_id"),
        conversation_id,
        thread_id,
        message_type,
    )
    if conversation_id:
        try:
            result, status = pulse_send_conversation_message(
                cur,
                user,
                conversation_id,
                message,
                message_type,
                media_url,
                thumbnail_url,
                metadata,
                reply_to_id,
                safe_int(payload.get("file_size"), 0),
                float(payload.get("duration") or payload.get("duration_seconds") or 0),
                payload.get("client_message_id") or payload.get("local_id") or "",
                payload.get("local_created_at") or "",
            )
            result["trace_id"] = trace_id
            if result.get("ok"):
                if media_url:
                    cur.execute(
                        "UPDATE chat_media_uploads SET message_id=?, context_type='pulse_message', context_id=? WHERE uploader_user_id=? AND media_url=? AND message_id IS NULL",
                        (int(result.get("message_id") or 0), str(conversation_id), user["user_id"], media_url),
                    )
                conn.commit(); conn.close()
                event = {
                    "message": result.get("data"),
                    "thread_id": 0,
                    "conversation_id": conversation_id,
                    "message_id": result.get("message_id"),
                    "message_type": message_type,
                    "media_url": media_url,
                }
                pulse_emit_event(result.get("event_name") or "pulse_message_sent", event, user["user_id"], conversation_id)
                pulse_emit_event("conversation_updated", event, user["user_id"], conversation_id)
                logging.info("PULSE_MESSAGE_SEND_OK trace_id=%s user_id=%s conversation_id=%s canonical=1 message_id=%s", trace_id, user.get("user_id"), conversation_id, result.get("message_id"))
            else:
                conn.rollback(); conn.close()
                logging.warning("PULSE_MESSAGE_SEND_REJECTED trace_id=%s user_id=%s conversation_id=%s status=%s result=%s", trace_id, user.get("user_id"), conversation_id, status, result)
            return jsonify(result), status
        except Exception as exc:
            try:
                conn.rollback(); conn.close()
            except Exception:
                pass
            logging.exception("PULSE_MESSAGE_SEND_CANONICAL_FAILED trace_id=%s user_id=%s conversation_id=%s", trace_id, user.get("user_id"), conversation_id)
            return jsonify({"ok": False, "message": "Message could not be sent.", "trace_id": trace_id, "error": str(exc), "error_type": exc.__class__.__name__}), 500
    if thread_id:
        cur.execute("SELECT * FROM pulse_message_threads WHERE id=? AND (user_one_id=? OR user_two_id=?) LIMIT 1", (thread_id, user["user_id"], user["user_id"]))
        thread = dict(cur.fetchone() or {})
        if not thread:
            cur.execute(
                """
                SELECT cm.user_id
                FROM conversation_members cm
                WHERE cm.conversation_id=? AND cm.user_id!=?
                LIMIT 1
                """,
                (thread_id, user["user_id"]),
            )
            old_peer_id = int(dict(cur.fetchone() or {}).get("user_id") or 0)
            if old_peer_id:
                bridge_result, bridge_status = pulse_start_conversation(cur, user["user_id"], target_user_id=old_peer_id)
                if bridge_result.get("ok"):
                    conversation_id = int(bridge_result.get("conversation_id") or 0)
                    thread_id = int(bridge_result.get("thread_id") or 0)
                    cur.execute("SELECT * FROM pulse_message_threads WHERE id=? AND (user_one_id=? OR user_two_id=?) LIMIT 1", (thread_id, user["user_id"], user["user_id"]))
                    thread = dict(cur.fetchone() or {})
                    logging.info("PULSE_MESSAGE_SEND_BRIDGED_OLD_THREAD trace_id=%s user_id=%s old_thread_id=%s pulse_conversation_id=%s pulse_thread_id=%s", trace_id, user.get("user_id"), payload.get("thread_id"), conversation_id, thread_id)
                else:
                    logging.warning("PULSE_MESSAGE_SEND_BRIDGE_FAILED trace_id=%s user_id=%s submitted_thread_id=%s status=%s result=%s", trace_id, user.get("user_id"), thread_id, bridge_status, bridge_result)
            if not thread:
                logging.warning("PULSE_MESSAGE_SEND_NOT_FOUND trace_id=%s user_id=%s submitted_conversation_id=%s submitted_thread_id=%s reason=pulse_thread_missing", trace_id, user.get("user_id"), payload.get("conversation_id"), payload.get("thread_id"))
                conn.close()
                return jsonify({"ok": False, "message": "This conversation is no longer available.", "trace_id": trace_id}), 404
        receiver_id = int(thread.get("user_two_id") if int(thread.get("user_one_id") or 0) == int(user["user_id"]) else thread.get("user_one_id"))
        conversation_id = conversation_id or int(thread.get("conversation_id") or 0)
    else:
        receiver_id = payload.get("receiver_user_id") or pulse_user_id_from_public(cur, payload.get("receiver_public_player_id") or "")
        result, status = pulse_start_conversation(cur, user["user_id"], target_user_id=receiver_id)
        if not result.get("ok"):
            conn.close()
            logging.warning("PULSE_MESSAGE_SEND_START_CONVERSATION_FAILED trace_id=%s user_id=%s result=%s", trace_id, user.get("user_id"), result)
            return jsonify({**result, "trace_id": result.get("trace_id") or trace_id}), status
        receiver_id = int(result["target_user_id"])
        thread_id = int(result["thread_id"])
        conversation_id = int(result["conversation_id"])
    now = datetime.utcnow().isoformat(timespec="seconds")
    cur.execute(
        """
        INSERT INTO pulse_messages
        (thread_id, conversation_id, sender_user_id, receiver_user_id, body, message_type, media_url, thumbnail_url, media_metadata, file_size, duration_seconds, reply_to_id, delivery_status, status, created_at)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'sent', 'sent', ?)
        """,
        (
            thread_id,
            conversation_id,
            user["user_id"],
            receiver_id,
            message,
            message_type,
            media_url,
            thumbnail_url,
            json.dumps(metadata, default=str)[:4000],
            int(payload.get("file_size") or 0),
            float(payload.get("duration") or payload.get("duration_seconds") or 0),
            reply_to_id or None,
            now,
        ),
    )
    message_id = int(cur.lastrowid)
    if media_url:
        cur.execute("UPDATE chat_media_uploads SET message_id=?, context_type='pulse_message', context_id=? WHERE uploader_user_id=? AND media_url=? AND message_id IS NULL", (message_id, str(conversation_id), user["user_id"], media_url))
    cur.execute("UPDATE pulse_message_threads SET updated_at=? WHERE id=?", (now, thread_id))
    cur.execute("UPDATE pulse_conversations SET updated_at=?, last_message_at=? WHERE id=?", (now, now, conversation_id))
    cur.execute("UPDATE pulse_conversation_participants SET unread_count=COALESCE(unread_count,0)+1 WHERE conversation_id=? AND user_id!=? AND COALESCE(left_at,'')=''", (conversation_id, user["user_id"]))
    cur.execute("UPDATE pulse_conversation_participants SET last_read_at=?, last_seen_at=?, last_read_message_id=?, unread_count=0 WHERE conversation_id=? AND user_id=?", (now, now, message_id, conversation_id, user["user_id"]))
    cur.execute("INSERT INTO pulse_notifications (user_id, type, title, body, target_url, created_at) VALUES (?, 'message', 'New Pulse message', 'You received a Pulse message.', ?, ?)", (receiver_id, f"/pulse/messages/{conversation_id}", now))
    cur.execute("SELECT * FROM pulse_messages WHERE id=? LIMIT 1", (message_id,))
    message_payload = _pulse_message_payload(cur.fetchone(), user["user_id"])
    conn.commit(); conn.close()
    logging.info("PULSE_MESSAGE_SEND_OK trace_id=%s user_id=%s conversation_id=%s thread_id=%s conversation_type=direct message_id=%s", trace_id, user.get("user_id"), conversation_id, thread_id, message_id)
    event = {"message": message_payload, "thread_id": thread_id, "conversation_id": conversation_id, "target_user_id": receiver_id, "message_id": message_id, "message_type": message_type, "media_url": media_url}
    pulse_emit_event("pulse_message_sent", event, user["user_id"], 0)
    pulse_emit_event("message_created", event, user["user_id"], 0)
    pulse_emit_event("conversation_updated", event, user["user_id"], 0)
    return jsonify({"ok": True, "thread_id": thread_id, "conversation_id": conversation_id, "redirect_url": f"/pulse/messages/{conversation_id}", "next_url": f"/pulse/messages/{conversation_id}", "message": "Message sent.", "message_id": message_id, "message_type": message_type, "data": message_payload})


def _pulse_message_payload(row, current_user_id=0):
    item = dict(row or {})
    message_type = item.get("message_type") or "text"
    body = item.get("body") or ""
    return {
        "id": int(item.get("id") or 0),
        "message_id": int(item.get("id") or 0),
        "conversation_id": int(item.get("conversation_id") or item.get("thread_id") or 0),
        "thread_id": int(item.get("thread_id") or 0),
        "sender_id": int(item.get("sender_user_id") or 0),
        "sender_user_id": int(item.get("sender_user_id") or 0),
        "type": message_type,
        "content": body,
        "body": body,
        "media_url": item.get("media_url") or "",
        "thumbnail_url": item.get("thumbnail_url") or item.get("media_url") or "",
        "media_metadata": item.get("media_metadata") or "",
        "message_type": message_type,
        "duration": float(item.get("duration_seconds") or 0),
        "duration_seconds": float(item.get("duration_seconds") or 0),
        "file_size": int(item.get("file_size") or 0),
        "reply_to_id": int(item.get("reply_to_id") or 0),
        "client_message_id": item.get("client_message_id") or "",
        "local_created_at": item.get("local_created_at") or "",
        "reactions": {},
        "status": item.get("delivery_status") or item.get("status") or "sent",
        "delivery_status": item.get("delivery_status") or item.get("status") or "sent",
        "created_at": item.get("created_at") or "",
        "delivered_at": item.get("delivered_at") or "",
        "seen_at": item.get("seen_at") or "",
        "edited_at": item.get("edited_at") or "",
        "deleted_at": item.get("deleted_at") or "",
        "is_mine": int(item.get("sender_user_id") or 0) == int(current_user_id or 0),
    }


def pulse_normalize_emoji_reaction(value):
    aliases = {
        "heart": "❤️",
        "like": "👍",
        "thumbs_up": "👍",
        "fire": "🔥",
        "laugh": "😂",
        "wow": "😮",
        "sad": "😢",
        "angry": "😡",
        "pray": "🙏",
        "rocket": "🚀",
    }
    raw = str(value or "").strip()
    raw = aliases.get(raw.lower(), raw)
    # Keep one Unicode emoji cluster, including common variation selectors,
    # zero-width joiners, and skin tone modifiers. This lets the platform
    # support the standard emoji keyboard without licensing a proprietary set.
    cleaned = "".join(ch for ch in raw[:16] if unicodedata.category(ch)[0] != "C" or ch == "\u200d")
    if not cleaned:
        return ""
    has_emoji_codepoint = any(
        0x1F000 <= ord(ch) <= 0x1FAFF
        or 0x2600 <= ord(ch) <= 0x27BF
        or ord(ch) in {0x2764, 0xFE0F, 0x200D}
        for ch in cleaned
    )
    return cleaned[:16] if has_emoji_codepoint else ""


@webhook_app.route("/api/pulse/messages/direct/open", methods=["POST"])
@webhook_app.route("/api/pulse/messages/start", methods=["POST"])
def api_pulse_message_start():
    init_db()
    user = api_account_user()
    if not user:
        return jsonify({"ok": False, "message": "Login required."}), 401
    trace_id = secrets.token_hex(6)
    started = time.perf_counter()
    payload = request.get_json(silent=True) or {}
    query = clean_html(
        payload.get("query")
        or payload.get("public_pulse_id")
        or payload.get("public_player_id")
        or payload.get("receiver_public_player_id")
        or payload.get("username")
        or ""
    ).strip()
    target_user_id = safe_int(payload.get("target_user_id") or payload.get("receiver_user_id") or payload.get("user_id"), 0)
    if not query and not target_user_id:
        return jsonify({"ok": False, "message": "Search by name or public Pulse ID."}), 400
    conn = None
    try:
        conn = db(); conn.row_factory = sqlite3.Row; cur = conn.cursor()
        ensure_pulse_messenger_schema(cur, conn)
        if not target_user_id:
            matches = pulse_search_users(cur, query, viewer_user_id=user["user_id"], limit=8, allow_email=bool(user.get("is_admin") or user.get("is_owner")))
            for match in matches:
                if not match.get("is_self"):
                    target_user_id = int(match.get("user_id") or 0)
                    break
        if not target_user_id:
            conn.close()
            logging.warning("PULSE_MESSAGE_START_NO_TARGET trace_id=%s user_id=%s payload=%s query=%s", trace_id, user.get("user_id"), payload, query)
            return jsonify({"ok": False, "message": "Pulse user not found.", "trace_id": trace_id}), 404
        if int(target_user_id) == int(user["user_id"]):
            conn.close()
            return jsonify({"ok": False, "message": "You cannot message yourself.", "trace_id": trace_id}), 400
        result, status = pulse_start_conversation(cur, user["user_id"], target_user_id=target_user_id)
        result["trace_id"] = trace_id
        if result.get("ok"):
            chat_health_service.record_trace(cur, user["user_id"], "/api/pulse/messages/direct/open", "ok", trace_id, {"target_user_id": target_user_id, "conversation_id": result.get("conversation_id"), "latency_ms": int((time.perf_counter() - started) * 1000)})
            conn.commit()
            logging.info("PULSE_MESSAGE_START_OK trace_id=%s user_id=%s target_user_id=%s conversation_id=%s thread_id=%s", trace_id, user.get("user_id"), target_user_id, result.get("conversation_id"), result.get("thread_id"))
        else:
            chat_health_service.record_trace(cur, user["user_id"], "/api/pulse/messages/direct/open", "rejected", trace_id, {"target_user_id": target_user_id, "status": status, "latency_ms": int((time.perf_counter() - started) * 1000)})
            conn.rollback()
            logging.warning("PULSE_MESSAGE_START_REJECTED trace_id=%s user_id=%s target_user_id=%s status=%s result=%s", trace_id, user.get("user_id"), target_user_id, status, result)
        conn.close()
        log_product_event(user["user_id"], "pulse_message_thread_started", {"conversation_id": result.get("conversation_id"), "thread_id": result.get("thread_id"), "target_user_id": target_user_id, "source": "pulse_messenger", "trace_id": trace_id})
        return jsonify(result), status
    except Exception as exc:
        try:
            if conn:
                conn.rollback(); conn.close()
        except Exception:
            pass
        logging.exception("PULSE_MESSAGE_START_FAILED trace_id=%s user_id=%s payload=%s target_user_id=%s", trace_id, user.get("user_id"), payload, target_user_id)
        return jsonify({"ok": False, "message": "Direct chat could not be opened.", "error": str(exc), "trace_id": trace_id, "error_type": exc.__class__.__name__}), 500


