@webhook_app.route("/api/pulse/messages/upload", methods=["POST"])
@webhook_app.route("/api/pulse/messages/media/upload", methods=["POST"])
def api_pulse_messages_upload():
    init_db()
    user = api_account_user()
    if not user:
        return api_error("Login required.", 401)
    conversation_id = safe_int(request.form.get("conversation_id") or request.args.get("conversation_id") or 0, 0)
    if conversation_id:
        conn = db(); conn.row_factory = sqlite3.Row; cur = conn.cursor()
        cur.execute("SELECT 1 FROM pulse_conversation_participants WHERE conversation_id=? AND user_id=? LIMIT 1", (conversation_id, user["user_id"]))
        allowed = bool(cur.fetchone())
        conn.close()
        if not allowed:
            return api_error("Conversation not found.", 404)
    file_storage = request.files.get("file") or request.files.get("media") or request.files.get("upload")
    result, status = media_service.save_upload(user["user_id"], file_storage, context_type="pulse_message", context_id=str(conversation_id or "draft"))
    if not result.get("ok"):
        return jsonify(result), status
    media = result.get("media") or {}
    media_type = media.get("media_type") or "image"
    mime_type = media.get("mime_type") or ""
    message_type = "gif" if media_type == "gif" else "video" if media_type == "video" else "voice" if mime_type.startswith("audio/") and str(request.form.get("voice") or "").lower() in {"1", "true", "yes"} else "audio" if media_type == "audio" else "file" if media_type == "file" else "image"
    pulse_emit_event("pulse_upload_progress", {"conversation_id": conversation_id, "media_type": message_type, "status": "complete", "progress": 100}, user["user_id"], 0)
    pulse_emit_event("message_media_uploaded", {"conversation_id": conversation_id, "media_type": message_type}, user["user_id"], 0)
    return jsonify({
        "ok": True,
        "message": "Media uploaded.",
        "media_url": media.get("media_url") or "",
        "thumbnail_url": media.get("thumbnail_url") or media.get("media_url") or "",
        "message_type": message_type,
        "type": message_type,
        "file_size": int(media.get("file_size_bytes") or 0),
        "media": media,
    }), 200


@webhook_app.route("/api/pulse/messages/<int:conversation_id>/messages", methods=["GET"])
def api_pulse_conversation_messages(conversation_id):
    init_db()
    user = api_account_user()
    if not user:
        return jsonify({"ok": False, "message": "Login required."}), 401
    conn = db(); conn.row_factory = sqlite3.Row; cur = conn.cursor()
    ensure_pulse_messenger_schema(cur, conn)
    cur.execute(
        """
        SELECT c.*
        FROM pulse_conversations c
        JOIN pulse_conversation_participants p ON p.conversation_id=c.id AND p.user_id=? AND COALESCE(p.left_at,'')=''
        WHERE c.id=? AND COALESCE(c.status,'active')='active'
        LIMIT 1
        """,
        (user["user_id"], conversation_id),
    )
    conversation = dict(cur.fetchone() or {})
    if not conversation:
        conn.close()
        return jsonify({"ok": False, "message": "This conversation is no longer available."}), 404
    limit = max(1, min(safe_int(request.args.get("limit"), 30), 80))
    before_id = safe_int(request.args.get("before_id"), 0)
    if before_id:
        cur.execute("SELECT * FROM pulse_messages WHERE conversation_id=? AND deleted_at IS NULL " + PULSE_VISIBLE_MESSAGE_FILTER + " AND id<? ORDER BY id DESC LIMIT ?", (conversation_id, before_id, limit))
    else:
        cur.execute("SELECT * FROM pulse_messages WHERE conversation_id=? AND deleted_at IS NULL " + PULSE_VISIBLE_MESSAGE_FILTER + " ORDER BY id DESC LIMIT ?", (conversation_id, limit))
    messages = [_pulse_message_payload(row, user["user_id"]) for row in reversed(cur.fetchall())]
    messages = pulse_attach_reply_previews(cur, messages)
    message_ids = [m["id"] for m in messages]
    if message_ids:
        placeholders = ",".join(["?"] * len(message_ids))
        cur.execute(f"SELECT message_id, reaction_type, COUNT(*) AS total FROM pulse_message_reactions WHERE message_id IN ({placeholders}) GROUP BY message_id, reaction_type", message_ids)
        by_message = {}
        for row in cur.fetchall():
            r = dict(row)
            by_message.setdefault(int(r.get("message_id") or 0), {})[r.get("reaction_type") or ""] = int(r.get("total") or 0)
        for m in messages:
            m["reactions"] = by_message.get(m["id"], {})
    now = datetime.utcnow().isoformat(timespec="seconds")
    for m in messages[-100:]:
        if not m.get("is_mine"):
            cur.execute(
                "INSERT OR IGNORE INTO pulse_message_receipts (message_id, conversation_id, user_id, status, created_at, updated_at) VALUES (?, ?, ?, 'seen', ?, ?)",
                (m["id"], conversation_id, user["user_id"], now, now),
            )
    pulse_mark_conversation_read(cur, conversation_id, user["user_id"])
    convo_type = conversation.get("conversation_type") or "direct"
    title = conversation.get("title") or ""
    avatar_url = conversation.get("avatar_url") or ""
    if convo_type == "direct":
        cur.execute("SELECT user_id FROM pulse_conversation_participants WHERE conversation_id=? AND user_id!=? AND COALESCE(left_at,'')='' LIMIT 1", (conversation_id, user["user_id"]))
        other_id = int(dict(cur.fetchone() or {}).get("user_id") or 0)
        other = pulse_identity_for_user(cur, other_id) if other_id else {}
        title = other.get("name") or "Private conversation"
        avatar_url = other.get("avatar_url") or ""
    conn.commit()
    conn.close()
    return jsonify({"ok": True, "conversation_id": conversation_id, "conversation": {"id": conversation_id, "conversation_id": conversation_id, "conversation_type": convo_type, "title": title or "Pulse chat", "avatar_url": avatar_url, "member_count": int(conversation.get("member_count") or (2 if convo_type == "direct" else 1))}, "messages": messages})


@webhook_app.route("/api/pulse/messages/<int:message_id>/react", methods=["POST"])
def api_pulse_message_react(message_id):
    init_db()
    user = api_account_user()
    if not user:
        return api_error("Login required.", 401)
    trace_id = secrets.token_hex(6)
    payload = request.get_json(silent=True) or {}
    reaction = pulse_normalize_emoji_reaction(payload.get("reaction_type") or payload.get("reaction") or "heart")
    if not reaction:
        return api_error("Choose a supported emoji reaction.", 400, trace_id)
    conn = db(); conn.row_factory = sqlite3.Row; cur = conn.cursor()
    cur.execute("SELECT * FROM pulse_messages WHERE id=? AND deleted_at IS NULL LIMIT 1", (message_id,))
    message = dict(cur.fetchone() or {})
    if not message:
        conn.close()
        return api_error("Message not found.", 404, trace_id)
    conversation_id = int(message.get("conversation_id") or 0)
    cur.execute("SELECT 1 FROM pulse_conversation_participants WHERE conversation_id=? AND user_id=? AND COALESCE(left_at,'')='' LIMIT 1", (conversation_id, user["user_id"]))
    if not cur.fetchone():
        conn.close()
        return api_error("Conversation not found.", 404, trace_id)
    now = datetime.utcnow().isoformat(timespec="seconds")
    cur.execute("SELECT reaction_type FROM pulse_message_reactions WHERE message_id=? AND user_id=? LIMIT 1", (message_id, user["user_id"]))
    existing = dict(cur.fetchone() or {}).get("reaction_type") or ""
    cur.execute("DELETE FROM pulse_message_reactions WHERE message_id=? AND user_id=?", (message_id, user["user_id"]))
    active = ""
    if existing != reaction:
        cur.execute(
            "INSERT INTO pulse_message_reactions (message_id, conversation_id, user_id, reaction_type, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?)",
            (message_id, conversation_id, user["user_id"], reaction, now, now),
        )
        active = reaction
    cur.execute("SELECT reaction_type, COUNT(*) AS total FROM pulse_message_reactions WHERE message_id=? GROUP BY reaction_type", (message_id,))
    reactions = {dict(row).get("reaction_type") or "": int(dict(row).get("total") or 0) for row in cur.fetchall()}
    conn.commit(); conn.close()
    event = {"message_id": message_id, "conversation_id": conversation_id, "reactions": reactions, "my_reaction": active}
    pulse_emit_event("pulse_message_reacted", event, user["user_id"], conversation_id)
    return jsonify({"ok": True, "message": "Reaction updated.", "reactions": reactions, "my_reaction": active})


@webhook_app.route("/api/pulse/messages/<int:message_id>/delete", methods=["POST", "DELETE"])
def api_pulse_message_delete(message_id):
    init_db()
    user = api_account_user()
    if not user:
        return api_error("Login required.", 401)
    trace_id = secrets.token_hex(6)
    conn = db(); conn.row_factory = sqlite3.Row; cur = conn.cursor()
    cur.execute("SELECT * FROM pulse_messages WHERE id=? AND deleted_at IS NULL LIMIT 1", (message_id,))
    message = dict(cur.fetchone() or {})
    if not message:
        conn.close()
        return api_error("Message not found.", 404, trace_id)
    conversation_id = int(message.get("conversation_id") or 0)
    cur.execute("SELECT role FROM pulse_conversation_participants WHERE conversation_id=? AND user_id=? AND COALESCE(left_at,'')='' LIMIT 1", (conversation_id, user["user_id"]))
    role = (dict(cur.fetchone() or {}).get("role") or "").lower()
    can_delete = int(message.get("sender_user_id") or 0) == int(user["user_id"]) or role in {"owner", "admin", "moderator"} or pulse_group_user_is_admin(user)
    if not can_delete:
        conn.close()
        return api_error("You cannot delete this message.", 403, trace_id)
    now = datetime.utcnow().isoformat(timespec="seconds")
    cur.execute("UPDATE pulse_messages SET deleted_at=?, status='deleted', delivery_status='deleted' WHERE id=?", (now, message_id))
    conn.commit(); conn.close()
    pulse_emit_event("pulse_message_deleted", {"message_id": message_id, "conversation_id": conversation_id}, user["user_id"], conversation_id)
    return jsonify({"ok": True, "message": "Message deleted.", "message_id": message_id})


@webhook_app.route("/api/pulse/messages/<int:message_id>/report", methods=["POST"])
def api_pulse_message_report(message_id):
    init_db()
    user = api_account_user()
    if not user:
        return api_error("Login required.", 401)
    trace_id = secrets.token_hex(6)
    payload = request.get_json(silent=True) or {}
    reason = clean_html(payload.get("reason") or "safety")[:80]
    notes = clean_html(payload.get("notes") or "")[:500]
    conn = db(); conn.row_factory = sqlite3.Row; cur = conn.cursor()
    try:
        cur.execute("SELECT * FROM pulse_messages WHERE id=? AND COALESCE(deleted_at,'')='' LIMIT 1", (message_id,))
        message = dict(cur.fetchone() or {})
        if not message:
            conn.close()
            return api_error("Message not found.", 404, trace_id)
        conversation_id = int(message.get("conversation_id") or 0)
        cur.execute("SELECT 1 FROM pulse_conversation_participants WHERE conversation_id=? AND user_id=? AND COALESCE(left_at,'')='' LIMIT 1", (conversation_id, user["user_id"]))
        if not cur.fetchone():
            conn.close()
            return api_error("Conversation not found.", 404, trace_id)
        now = datetime.utcnow().isoformat(timespec="seconds")
        cur.execute(
            """
            INSERT INTO pulse_reports (reporter_user_id, target_type, target_id, reason, details, status, created_at)
            VALUES (?, 'message', ?, ?, ?, 'open', ?)
            """,
            (user["user_id"], message_id, reason, json.dumps({"notes": notes, "conversation_id": conversation_id, "trace_id": trace_id})[:2000], now),
        )
        conn.commit(); conn.close()
        log_product_event(user["user_id"], "pulse_message_reported", {"message_id": message_id, "conversation_id": conversation_id, "reason": reason, "trace_id": trace_id})
        return jsonify({"ok": True, "message": "Report submitted.", "trace_id": trace_id})
    except Exception as exc:
        conn.rollback(); conn.close()
        logging.exception("PULSE_MESSAGE_REPORT_FAILED trace_id=%s user_id=%s message_id=%s", trace_id, user.get("user_id"), message_id)
        return api_error("Report could not be submitted. The team can trace this safely.", 500, trace_id, error_type=exc.__class__.__name__)


@webhook_app.route("/api/pulse/messages/<int:conversation_id>/seen", methods=["POST"])
def api_pulse_messages_seen(conversation_id):
    init_db()
    user = api_account_user()
    if not user:
        return api_error("Login required.", 401)
    conn = db(); conn.row_factory = sqlite3.Row; cur = conn.cursor()
    cur.execute("SELECT 1 FROM pulse_conversation_participants WHERE conversation_id=? AND user_id=? LIMIT 1", (conversation_id, user["user_id"]))
    if not cur.fetchone():
        conn.close()
        return api_error("Conversation not found.", 404)
    now = datetime.utcnow().isoformat(timespec="seconds")
    last_message_id = pulse_mark_conversation_read(cur, conversation_id, user["user_id"])
    cur.execute("SELECT id FROM pulse_messages WHERE conversation_id=? AND sender_user_id!=? AND deleted_at IS NULL ORDER BY id DESC LIMIT 100", (conversation_id, user["user_id"]))
    ids = [int(dict(row).get("id") or 0) for row in cur.fetchall()]
    for message_id in ids:
        cur.execute("INSERT OR IGNORE INTO pulse_message_receipts (message_id, conversation_id, user_id, status, created_at, updated_at) VALUES (?, ?, ?, 'seen', ?, ?)", (message_id, conversation_id, user["user_id"], now, now))
    if ids:
        placeholders = ",".join(["?"] * len(ids))
        cur.execute(f"UPDATE pulse_messages SET seen_at=?, delivery_status='seen' WHERE id IN ({placeholders}) AND sender_user_id!=?", [now, *ids, user["user_id"]])
    conn.commit(); conn.close()
    pulse_emit_event("pulse_message_seen", {"conversation_id": conversation_id, "user_id": user["user_id"]}, user["user_id"], conversation_id)
    return jsonify({"ok": True, "message": "Seen.", "seen_count": len(ids), "last_read_message_id": last_message_id, "unread_count": 0})


@webhook_app.route("/api/pulse/messages/<int:conversation_id>/sync", methods=["GET", "POST"])
def api_pulse_messages_sync(conversation_id):
    init_db()
    user = api_account_user()
    if not user:
        return api_error("Login required.", 401)
    trace_id = secrets.token_hex(6)
    payload = request.get_json(silent=True) or {}
    after_id = safe_int(request.args.get("after_id") or payload.get("after_id"), 0)
    limit = max(1, min(safe_int(request.args.get("limit") or payload.get("limit"), 50), 100))
    conn = db(); conn.row_factory = sqlite3.Row; cur = conn.cursor()
    try:
        ensure_pulse_messenger_schema(cur, conn)
        cur.execute(
            """
            SELECT c.*
            FROM pulse_conversations c
            JOIN pulse_conversation_participants p ON p.conversation_id=c.id AND p.user_id=? AND COALESCE(p.left_at,'')=''
            WHERE c.id=? AND COALESCE(c.status,'active')='active'
            LIMIT 1
            """,
            (user["user_id"], conversation_id),
        )
        conversation = dict(cur.fetchone() or {})
        if not conversation:
            conn.close()
            return api_error("This conversation is no longer available.", 404, trace_id)
        cur.execute(
            """
            SELECT * FROM pulse_messages
            WHERE conversation_id=? AND id>? AND COALESCE(deleted_at,'')=''
            ORDER BY id ASC LIMIT ?
            """,
            (conversation_id, after_id, limit),
        )
        messages = [_pulse_message_payload(row, user["user_id"]) for row in cur.fetchall()]
        messages = pulse_attach_reply_previews(cur, messages)
        message_ids = [m["id"] for m in messages]
        if message_ids:
            placeholders = ",".join(["?"] * len(message_ids))
            cur.execute(f"SELECT message_id, reaction_type, COUNT(*) AS total FROM pulse_message_reactions WHERE message_id IN ({placeholders}) GROUP BY message_id, reaction_type", message_ids)
            reaction_map = {}
            for row in cur.fetchall():
                item = dict(row)
                reaction_map.setdefault(int(item.get("message_id") or 0), {})[item.get("reaction_type") or ""] = int(item.get("total") or 0)
            for message in messages:
                message["reactions"] = reaction_map.get(message["id"], {})
        presence = pulse_conversation_presence_payload(cur, conversation_id, user["user_id"])
        last_message_id = max([after_id] + [int(m.get("id") or 0) for m in messages])
        conn.close()
        events = realtime_engine.poll_events(f"pulse:conversation:{conversation_id}", after_id=0, limit=40)
        return jsonify({
            "ok": True,
            "trace_id": trace_id,
            "conversation_id": conversation_id,
            "messages": messages,
            "last_message_id": last_message_id,
            "presence": presence,
            "events": events,
            "sync_interval_ms": 2500,
        })
    except Exception as exc:
        conn.close()
        logging.exception("PULSE_MESSAGES_SYNC_FAILED trace_id=%s user_id=%s conversation_id=%s", trace_id, user.get("user_id"), conversation_id)
        return api_error("Messages could not sync. Tap to retry.", 500, trace_id, error_type=exc.__class__.__name__)


@webhook_app.route("/api/pulse/messages/<int:conversation_id>/typing", methods=["POST"])
def api_pulse_messages_typing(conversation_id):
    init_db()
    user = api_account_user()
    if not user:
        return api_error("Login required.", 401)
    typing = bool((request.get_json(silent=True) or {}).get("typing", True))
    conn = db(); conn.row_factory = sqlite3.Row; cur = conn.cursor()
    cur.execute("SELECT 1 FROM pulse_conversation_participants WHERE conversation_id=? AND user_id=? AND COALESCE(left_at,'')='' LIMIT 1", (conversation_id, user["user_id"]))
    allowed = bool(cur.fetchone())
    if allowed:
        now = datetime.utcnow().isoformat(timespec="seconds")
        typing_until = (datetime.utcnow() + timedelta(seconds=8)).isoformat(timespec="seconds") if typing else ""
        cur.execute(
            """
            INSERT INTO pulse_conversation_typing (conversation_id, user_id, typing_until, updated_at)
            VALUES (?, ?, ?, ?)
            ON CONFLICT(conversation_id, user_id) DO UPDATE SET typing_until=excluded.typing_until, updated_at=excluded.updated_at
            """,
            (conversation_id, user["user_id"], typing_until, now),
        )
        cur.execute("UPDATE pulse_conversation_participants SET last_seen_at=? WHERE conversation_id=? AND user_id=?", (now, conversation_id, user["user_id"]))
        conn.commit()
    conn.close()
    if not allowed:
        return api_error("Conversation not found.", 404)
    ident = pulse_identity_for_user(db().cursor(), user["user_id"]) if False else {"name": user.get("display_name") or user.get("username") or "Pulse user"}
    pulse_emit_event("typing_start" if typing else "typing_stop", {"conversation_id": conversation_id, "typing": typing, "user_id": user["user_id"], "display_name": ident.get("name")}, user["user_id"], conversation_id)
    pulse_emit_event("pulse_typing", {"conversation_id": conversation_id, "typing": typing, "user_id": user["user_id"], "display_name": ident.get("name")}, user["user_id"], conversation_id)
    return jsonify({"ok": True, "typing": typing})


