    reason = clean_html(str(reason or "other").strip().lower())[:80] or "other"
    if reason not in allowed_reasons:
        reason = "other"
    notes = clean_html(notes or "")[:1000]
    conn = db(); conn.row_factory = sqlite3.Row; cur = conn.cursor()
