@webhook_app.route("/admin/pulse-moderation", methods=["GET", "POST"])
def admin_pulse_moderation_page():
    admin, denied = require_admin_page("system.view")
    if denied:
        return denied
    init_db()
    message = ""
    if request.method == "POST":
        post_id = int(request.form.get("post_id") or 0)
        action = request.form.get("action") or ""
        if post_id and action in {"approve", "block", "delete"}:
            conn = db()
            cur = conn.cursor()
            if action == "approve":
                cur.execute("UPDATE pulse_posts SET moderation_status='approved', updated_at=? WHERE id=?", (datetime.utcnow().isoformat(timespec="seconds"), post_id))
                message = "Post approved."
            elif action == "block":
                cur.execute("UPDATE pulse_posts SET moderation_status='blocked', updated_at=? WHERE id=?", (datetime.utcnow().isoformat(timespec="seconds"), post_id))
                message = "Post blocked."
            else:
                cur.execute("UPDATE pulse_posts SET deleted_at=?, updated_at=? WHERE id=?", (datetime.utcnow().isoformat(timespec="seconds"), datetime.utcnow().isoformat(timespec="seconds"), post_id))
                message = "Post deleted."
            conn.commit()
            conn.close()
            if action == "delete":
                pulse_emit_event("pulse_post_deleted", {"post_id": post_id, "deleted": True, "source": "admin_moderation"}, admin.get("id") or 0, post_id)
                pulse_emit_event("post_deleted", {"post_id": post_id, "deleted": True, "source": "admin_moderation"}, admin.get("id") or 0, post_id)
    conn = db()
    conn.row_factory = sqlite3.Row
    cur = conn.cursor()
    cur.execute("SELECT * FROM pulse_posts WHERE deleted_at IS NULL AND moderation_status IN ('pending','needs_review','blocked') ORDER BY created_at DESC LIMIT 100")
    posts = [dict(row) for row in cur.fetchall()]
    cur.execute("SELECT * FROM pulse_reports WHERE status='open' ORDER BY created_at DESC LIMIT 100")
    reports = [dict(row) for row in cur.fetchall()]
    conn.close()
    rows = "".join(f"<tr><td>{p.get('id')}</td><td>{clean_html(p.get('post_type') or '')}</td><td>{clean_html(p.get('moderation_status') or '')}</td><td>{int(p.get('risk_score') or 0)}</td><td>{clean_html((p.get('body') or '')[:180])}</td><td><form method='post'><input type='hidden' name='post_id' value='{p.get('id')}'><button name='action' value='approve'>Approve</button><button name='action' value='block'>Block</button><button name='action' value='delete'>Delete</button></form></td></tr>" for p in posts)
    report_rows = "".join(f"<tr><td>{r.get('id')}</td><td>{clean_html(r.get('target_type') or '')}</td><td>{r.get('target_id')}</td><td>{clean_html(r.get('reason') or '')}</td><td>{clean_html(r.get('created_at') or '')}</td></tr>" for r in reports)
    body = f"<h1>Pulse Moderation</h1><p>{clean_html(message)}</p><div class='card'><h2>Posts Needing Review</h2><table><tr><th>ID</th><th>Type</th><th>Status</th><th>Risk</th><th>Body</th><th>Action</th></tr>{rows or '<tr><td colspan=6>No pending posts.</td></tr>'}</table></div><div class='card'><h2>Open Reports</h2><table><tr><th>ID</th><th>Target</th><th>Target ID</th><th>Reason</th><th>Created</th></tr>{report_rows or '<tr><td colspan=5>No open reports.</td></tr>'}</table></div>"
    return admin_page_html("Pulse Moderation", body, admin)


@webhook_app.route("/admin/pulse-feed-health", methods=["GET", "POST"])
def admin_pulse_feed_health_page():
    admin, denied = require_admin_page("system.view")
    if denied:
        return denied
    init_db()
    message = ""
    conn = db()
    conn.row_factory = sqlite3.Row
    cur = conn.cursor()
    now = datetime.utcnow().isoformat(timespec="seconds")
    if request.method == "POST":
        action = request.form.get("action") or ""
        if action == "flush_deleted_cache":
            cur.execute(
                """
                SELECT id FROM pulse_posts
                WHERE deleted_at IS NOT NULL
                ORDER BY deleted_at DESC
                LIMIT 250
                """
            )
            deleted_ids = [int(dict(row).get("id") or 0) for row in cur.fetchall()]
            for post_id in deleted_ids:
                pulse_emit_event("pulse_post_deleted", {"post_id": post_id, "deleted": True, "source": "feed_health_flush"}, admin.get("id") or 0, post_id)
                pulse_emit_event("post_deleted", {"post_id": post_id, "deleted": True, "source": "feed_health_flush"}, admin.get("id") or 0, post_id)
            message = f"Rebroadcast deletion purge for {len(deleted_ids)} recent deleted posts."
        elif action in {"rebuild_feed_cache", "rebuild_trending", "regenerate_media_thumbnails"}:
            message = f"{action.replace('_', ' ').title()} queued safely. Current local cache is read-through, so public feed queries already use canonical visibility."
    checks = []
    queries = [
        ("Visible approved posts", "SELECT COUNT(*) AS total FROM pulse_posts WHERE deleted_at IS NULL AND COALESCE(visibility,'public')='public' AND COALESCE(moderation_status,'approved')='approved'"),
        ("Deleted posts", "SELECT COUNT(*) AS total FROM pulse_posts WHERE deleted_at IS NOT NULL"),
        ("Blocked visible rows", "SELECT COUNT(*) AS total FROM pulse_posts WHERE deleted_at IS NULL AND COALESCE(moderation_status,'approved')='blocked'"),
        ("Recent deletion events", "SELECT COUNT(*) AS total FROM pulse_live_events WHERE event_type IN ('post_deleted','pulse_post_deleted') AND created_at>=?"),
        ("Recent new-post events", "SELECT COUNT(*) AS total FROM pulse_live_events WHERE event_type IN ('new_post','pulse_post_created') AND created_at>=?"),
    ]
    since = (datetime.utcnow() - timedelta(hours=24)).isoformat(timespec="seconds")
    for label, query in queries:
        try:
            params = (since,) if "created_at>=?" in query else ()
            cur.execute(query, params)
            checks.append({"check": label, "value": int(dict(cur.fetchone() or {}).get("total") or 0), "detail": "24h window" if params else "current"})
        except Exception as exc:
            checks.append({"check": label, "value": "error", "detail": exc.__class__.__name__})
    hidden_rows = []
    for label, query in [
        ("Deleted", "SELECT COUNT(*) AS total FROM pulse_posts WHERE deleted_at IS NOT NULL"),
        ("Rejected/blocked", "SELECT COUNT(*) AS total FROM pulse_posts WHERE deleted_at IS NULL AND COALESCE(moderation_status,'approved') IN ('rejected','blocked','removed','deleted')"),
        ("Pending review", "SELECT COUNT(*) AS total FROM pulse_posts WHERE deleted_at IS NULL AND COALESCE(moderation_status,'approved') NOT IN ('approved','rejected','blocked','removed','deleted')"),
        ("Private/followers", "SELECT COUNT(*) AS total FROM pulse_posts WHERE deleted_at IS NULL AND COALESCE(visibility,'public')!='public'"),
    ]:
        try:
            cur.execute(query)
            hidden_rows.append({"reason": label, "count": int(dict(cur.fetchone() or {}).get("total") or 0)})
        except Exception as exc:
            hidden_rows.append({"reason": label, "count": exc.__class__.__name__})
    media_rows = []
    broken_media = 0
    try:
        cur.execute(
            """
            SELECT id, media_url, thumbnail_url, context_type, context_id, media_type, mime_type, width, height, created_at
            FROM chat_media_uploads
            WHERE COALESCE(moderation_status,'approved')!='blocked'
              AND context_type IN ('pulse','pulse_post','pulse_reel')
            ORDER BY id DESC
            LIMIT 120
            """
        )
        for row in cur.fetchall():
            item = dict(row)
            test_url = item.get("thumbnail_url") or item.get("media_url") or ""
            item["public_url"] = pulse_media_url(test_url)
            item["exists"] = pulse_media_exists(test_url)
            if not item["exists"]:
                broken_media += 1
            media_rows.append(item)
    except Exception as exc:
        media_rows.append({"id": "error", "media_type": exc.__class__.__name__, "public_url": "", "exists": False})
    cur.execute(
        """
        SELECT id, title, moderation_status, visibility, deleted_at, updated_at
        FROM pulse_posts
        WHERE deleted_at IS NOT NULL
        ORDER BY deleted_at DESC
        LIMIT 20
        """
    )
    recent_deleted = [dict(row) for row in cur.fetchall()]
    conn.close()
    body = (
        f"<h1>Pulse Feed Health</h1><p class='muted'>{clean_html(message or 'Deleted posts are purged from public feed queries, live queues, and client pending-post buffers.')}</p>"
        f"<div class='card'><h2>Cache + Feed Checks</h2>{admin_rows_table(checks, [('check','Check'),('value','Value'),('detail','Detail')])}</div>"
        f"<div class='card'><h2>Visibility Hidden Reasons</h2>{admin_rows_table(hidden_rows, [('reason','Reason'),('count','Count')])}</div>"
        f"<div class='card'><h2>Media Delivery</h2><p class='metric'>{broken_media}</p><p class='muted'>Recent Pulse media with missing local files or unreachable local URLs.</p>{admin_rows_table(media_rows[:30], [('id','ID'),('context_type','Context'),('context_id','Post/Context'),('media_type','Type'),('mime_type','MIME'),('width','W'),('height','H'),('public_url','Public URL'),('exists','Exists')])}</div>"
        f"<div class='card'><h2>Repair Actions</h2><form method='post' class='actions'><button class='primary' name='action' value='flush_deleted_cache'>Flush Deleted IDs From Live Feed Clients</button><button name='action' value='rebuild_feed_cache'>Rebuild Feed Cache</button><button name='action' value='rebuild_trending'>Rebuild Trending</button><button name='action' value='regenerate_media_thumbnails'>Regenerate Media Thumbnails</button></form></div>"
        f"<div class='card'><h2>Recent Deleted Posts</h2>{admin_rows_table(recent_deleted, [('id','ID'),('title','Title'),('moderation_status','Moderation'),('visibility','Visibility'),('deleted_at','Deleted'),('updated_at','Updated')])}</div>"
        f"<p class='muted'>Last checked {clean_html(now)}.</p>"
    )
    return admin_page_html("Pulse Feed Health", body, admin)


@webhook_app.route("/admin/pulse-visibility-health", methods=["GET", "POST"])
def admin_pulse_visibility_health_page():
    admin, denied = require_admin_page("system.view")
    if denied:
        return denied
    init_db()
    post_id = safe_int(request.values.get("post_id"), 0)
    viewer_user_id = safe_int(request.values.get("viewer_user_id"), 0)
    explanation = {}
    if post_id:
        try:
            explanation = pulse_feed_engine.explain_visibility(post_id, viewer_user_id=viewer_user_id)
            for media in explanation.get("media") or []:
                media["exists"] = pulse_media_exists(media.get("media_url") or media.get("thumbnail_url") or "")
        except Exception as exc:
            logging.exception("PULSE_VISIBILITY_HEALTH_EXPLAIN_FAILED post_id=%s viewer_user_id=%s", post_id, viewer_user_id)
            explanation = {"ok": False, "post_id": post_id, "viewer_user_id": viewer_user_id, "visible": False, "reason": exc.__class__.__name__}
    conn = db(); conn.row_factory = sqlite3.Row; cur = conn.cursor()
    public_approved = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_posts WHERE deleted_at IS NULL AND COALESCE(visibility,'public')='public' AND COALESCE(moderation_status,'approved')='approved'")
    author_only = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_posts WHERE deleted_at IS NULL AND COALESCE(visibility,'public')='public' AND COALESCE(moderation_status,'approved')!='approved'")
    broken_media = 0
    media_rows = []
    try:
        cur.execute(
            """
            SELECT id, media_url, thumbnail_url, context_type, context_id, media_type, moderation_status, created_at
            FROM chat_media_uploads
            WHERE COALESCE(moderation_status,'approved')!='blocked'
              AND context_type IN ('pulse','pulse_post')
            ORDER BY id DESC
            LIMIT 80
            """
        )
        for row in cur.fetchall():
            item = dict(row)
            url = item.get("thumbnail_url") or item.get("media_url") or ""
            item["public_url"] = pulse_media_url(url)
            item["exists"] = pulse_media_exists(url)
            if not item["exists"]:
                broken_media += 1
            media_rows.append(item)
    except Exception:
        logging.exception("PULSE_VISIBILITY_HEALTH_MEDIA_SCAN_FAILED")
    conn.close()
    decision_rows = []
    if explanation:
        fields = explanation.get("fields") or {}
        decision_rows = [
            {"field": "visible", "value": str(explanation.get("visible"))},
            {"field": "reason", "value": explanation.get("reason") or ""},
            {"field": "post_user_id", "value": fields.get("user_id")},
            {"field": "visibility", "value": fields.get("visibility")},
            {"field": "moderation_status", "value": fields.get("moderation_status")},
            {"field": "status", "value": fields.get("status")},
            {"field": "deleted_at", "value": fields.get("deleted_at")},
            {"field": "media_ids_json", "value": fields.get("media_ids_json")},
        ]
    body = f"""
    <h1>Pulse Visibility Health</h1>
    <p class='muted'>Explain exactly why a Pulse post is or is not visible to a viewer, and verify public media access.</p>
    <section class='grid'><div class='card'><h2>Public Approved Posts</h2><p class='metric'>{public_approved}</p></div><div class='card'><h2>Public Not Approved</h2><p class='metric'>{author_only}</p><p class='muted'>These no longer appear in global feeds for only the author.</p></div><div class='card'><h2>Recent Broken Media</h2><p class='metric'>{broken_media}</p></div></section>
    <section class='card'><h2>Explain Visibility</h2><form method='get' class='admin-inline-form'><input name='post_id' placeholder='Pulse ID' value='{post_id or ""}'><input name='viewer_user_id' placeholder='Viewer user ID' value='{viewer_user_id or ""}'><button class='primary'>Explain</button></form>{admin_rows_table(decision_rows, [('field','Field'),('value','Value')]) if decision_rows else '<p class="muted">Enter a Pulse ID and optional viewer user ID.</p>'}</section>
    <section class='card'><h2>Post Media Decision</h2>{admin_rows_table(explanation.get('media') or [], [('id','ID'),('media_type','Type'),('media_url','Media URL'),('thumbnail_url','Thumbnail'),('exists','Exists')]) if explanation else '<p class="muted">Run a visibility check to inspect this post media.</p>'}</section>
    <section class='card'><h2>Recent Pulse Media</h2>{admin_rows_table(media_rows, [('id','ID'),('context_type','Context'),('context_id','Context ID'),('media_type','Type'),('public_url','Public URL'),('exists','Exists'),('created_at','Created')])}</section>
    <p><a class='button' href='/admin/pulse-feed-health'>Feed Health</a> <a class='button' href='/admin/media'>Media Diagnostics</a></p>
    """
    return admin_page_html("Pulse Visibility Health", body, admin)


