@webhook_app.route("/admin/pulse-post-debug", methods=["GET"])
def admin_pulse_post_debug_page():
    admin, denied = require_admin_page("system.view")
    if denied:
        return denied
    init_db()
    route_registered = any(str(rule.rule) == "/api/pulse/posts" and "POST" in rule.methods for rule in webhook_app.url_map.iter_rules())
    page_registered = any(str(rule.rule) == "/pulse/questions" for rule in webhook_app.url_map.iter_rules())
    account_user = api_account_user()
    conn = db()
    conn.row_factory = sqlite3.Row
    cur = conn.cursor()
    tables = {}
    for table in ["pulse_posts", "pulse_comments", "pulse_reactions", "pulse_reports", "pulse_jobs", "pulse_post_attempts", "pulse_friend_requests", "pulse_message_threads", "marketplace_listings", "teacher_profiles", "pulse_groups", "pulse_space_members", "chat_media_uploads"]:
        tables[table] = {"exists": migration_table_exists(cur, table), "columns": sorted(migration_table_columns(cur, table))}
    try:
        cur.execute("SELECT * FROM pulse_post_attempts ORDER BY id DESC LIMIT 20")
        attempts = [dict(row) for row in cur.fetchall()]
    except Exception as exc:
        attempts = [{"status": "debug_error", "error_reason": str(exc), "created_at": datetime.utcnow().isoformat(timespec="seconds")}]
    try:
        cur.execute("SELECT COUNT(*) AS total FROM pulse_jobs WHERE status='pending'")
        pending_jobs = int(dict(cur.fetchone() or {}).get("total") or 0)
    except Exception:
        pending_jobs = 0
    social_counts = {}
    for key, query in {
        "spaces_joined": "SELECT COUNT(*) AS total FROM pulse_space_members",
        "groups": "SELECT COUNT(*) AS total FROM pulse_groups",
        "teachers": "SELECT COUNT(*) AS total FROM teacher_profiles",
        "marketplace_listings": "SELECT COUNT(*) AS total FROM marketplace_listings",
        "message_threads": "SELECT COUNT(*) AS total FROM pulse_message_threads",
    }.items():
        try:
            cur.execute(query)
            social_counts[key] = int(dict(cur.fetchone() or {}).get("total") or 0)
        except Exception:
            social_counts[key] = 0
    try:
        cur.execute("SELECT * FROM worker_heartbeats WHERE worker_name='pulse_worker' LIMIT 1")
        heartbeat = dict(cur.fetchone() or {})
    except Exception:
        heartbeat = {}
    try:
        cur.execute(
            """
            SELECT p.id, p.user_id, p.post_type, p.moderation_status, p.visibility, p.title, p.body, p.created_at,
                   COALESCE(u.display_name, u.username, '') AS author_name
            FROM pulse_posts p
            LEFT JOIN users u ON u.user_id=p.user_id
            WHERE p.deleted_at IS NULL
            ORDER BY p.id DESC
            LIMIT 20
            """
        )
        latest_posts = [dict(row) for row in cur.fetchall()]
    except Exception as exc:
        latest_posts = [{"id": "", "post_type": "debug_error", "moderation_status": "", "visibility": "", "title": "", "body": str(exc), "created_at": "", "author_name": ""}]
    jobs_by_post = {}
    try:
        post_ids = [int(row.get("id") or 0) for row in latest_posts if int(row.get("id") or 0)]
        if post_ids:
            placeholders = ",".join(["?"] * len(post_ids))
            cur.execute(
                f"SELECT target_id, job_type, status FROM pulse_jobs WHERE target_type='post' AND target_id IN ({placeholders}) ORDER BY id DESC",
                post_ids,
            )
            for job in cur.fetchall():
                item = dict(job)
                jobs_by_post.setdefault(int(item.get("target_id") or 0), []).append(f"{item.get('job_type')}:{item.get('status')}")
    except Exception:
        jobs_by_post = {}
    conn.close()
    last_error = next((row for row in attempts if row.get("status") != "success"), {})
    attempt_rows = "".join(
        f"<tr><td>{clean_html(row.get('created_at') or '')}</td><td>{clean_html(row.get('status') or '')}</td><td>{clean_html(row.get('post_type') or '')}</td><td>{int(row.get('content_length') or 0)}</td><td>{'yes' if int(row.get('has_file') or 0) else 'no'}</td><td>{int(row.get('status_code') or 0)}</td><td>{clean_html(row.get('failing_table') or '')}</td><td>{clean_html(row.get('failing_field') or '')}</td><td>{clean_html(row.get('error_reason') or '')}</td><td>{clean_html((row.get('exception_message') or '')[:240])}</td></tr>"
        for row in attempts
    )
    table_rows = "".join(
        f"<tr><td>{clean_html(name)}</td><td>{'yes' if info['exists'] else 'no'}</td><td>{clean_html(', '.join(info['columns'])[:500])}</td></tr>"
        for name, info in tables.items()
    )
    status_rows = [
        {"name": "POST /api/pulse/posts registered", "value": route_registered, "detail": "Main publish API"},
        {"name": "/pulse/questions page registered", "value": page_registered, "detail": "Questions feed route"},
        {"name": "Current account can post", "value": bool(account_user), "detail": f"user_id={(account_user or {}).get('user_id') or ''}"},
        {"name": "Current request user agent", "value": clean_html(request.user_agent.string or ""), "detail": "Mobile debugging context"},
        {"name": "Pending Pulse jobs", "value": pending_jobs, "detail": "Background queue"},
        {"name": "Pulse social route health", "value": ", ".join(f"{k}={v}" for k, v in social_counts.items()), "detail": "Spaces, groups, teachers, marketplace, messenger"},
        {"name": "Last request error", "value": last_error.get("error_reason") or "none", "detail": last_error.get("created_at") or ""},
    ]
    latest_row_parts = []
    for row in latest_posts:
        moderation_status = row.get("moderation_status") or ""
        visibility = row.get("visibility") or ""
        appears = moderation_status == "approved" and visibility == "public"
        if appears:
            reason = "Eligible for /pulse and matching tabs."
        elif moderation_status != "approved":
            reason = f"Hidden from public feed: moderation_status={moderation_status}"
        elif visibility != "public":
            reason = f"Hidden from public feed: visibility={visibility}"
        else:
            reason = "Check post filters."
        post_id = int(row.get("id") or 0)
        jobs = ", ".join(jobs_by_post.get(post_id, [])[:6])
        latest_row_parts.append(
            f"<tr><td><a href='/pulse/post/{post_id}'>{post_id}</a></td><td>{clean_html(row.get('author_name') or ('User #' + str(row.get('user_id') or '')))}</td><td>{clean_html(row.get('post_type') or '')}</td><td>{clean_html(moderation_status)}</td><td>{clean_html(visibility)}</td><td>{'yes' if appears else 'no'}</td><td>{clean_html(reason)}</td><td>{clean_html(jobs or 'none')}</td><td>{clean_html(row.get('title') or '')}</td><td>{clean_html((row.get('body') or '')[:120])}</td><td>{clean_html(row.get('created_at') or '')}</td></tr>"
        )
    latest_rows = "".join(latest_row_parts)
    body = f"<h1>Pulse Post Debug</h1><p class='muted'>Production publishing diagnostics for /pulse/questions and /api/pulse/posts.</p><form method='get' class='card'><button>Check Feed Eligibility</button></form><div class='card'>{admin_rows_table(status_rows, [('name','Check'),('value','Value'),('detail','Detail')])}</div><div class='card'><h2>Latest Created Posts</h2><table><tr><th>ID</th><th>Author</th><th>Type</th><th>Status</th><th>Visibility</th><th>Feed</th><th>Eligibility Reason</th><th>Jobs</th><th>Title</th><th>Body</th><th>Created</th></tr>{latest_rows or '<tr><td colspan=11>No posts created yet.</td></tr>'}</table></div><div class='card'><h2>Pulse Tables</h2><table><tr><th>Table</th><th>Exists</th><th>Columns</th></tr>{table_rows}</table></div><div class='card'><h2>Worker Heartbeat</h2><pre>{clean_html(json.dumps(heartbeat, indent=2))}</pre></div><div class='card'><h2>Last 20 Publish Attempts</h2><table><tr><th>Time</th><th>Status</th><th>Type</th><th>Length</th><th>File</th><th>HTTP</th><th>Table</th><th>Field</th><th>Error</th><th>Exception</th></tr>{attempt_rows or '<tr><td colspan=10>No publish attempts logged yet.</td></tr>'}</table></div>"
    return admin_page_html("Pulse Post Debug", body, admin)


def trust_public_page(title, headline, body_html, cta="/signup"):
    return Response(f"""<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>{clean_html(title)} | CoinPilotXAI</title><meta name="description" content="{clean_html(headline)}"><meta name="robots" content="index,follow"><link rel="canonical" href="https://coinpilotx.app{clean_html(request.path)}"><link rel="manifest" href="/manifest.json"><link rel="icon" href="/static/Coinpilot%20Logo/NewLogo.png"><style>:root{{color-scheme:dark;--bg:#050b14;--panel:#0d1627;--line:rgba(110,223,246,.22);--text:#f2fbff;--muted:#9fb5c0;--cyan:#6edff6;--green:#36e58f;--gold:#ffd166}}*{{box-sizing:border-box}}body{{margin:0;background:radial-gradient(circle at 15% 0,rgba(110,223,246,.18),transparent 26rem),linear-gradient(145deg,#050b14,#081421);color:var(--text);font-family:Inter,system-ui,sans-serif}}.wrap{{width:min(100% - 28px,1080px);margin:auto;padding:22px 0 80px}}nav{{display:flex;align-items:center;justify-content:space-between;gap:12px}}a{{color:inherit}}.brand{{display:flex;align-items:center;gap:10px;text-decoration:none;font-weight:950}}.brand img{{width:38px;height:38px;border-radius:10px}}.hero{{padding:42px 0 18px}}h1{{font-size:clamp(38px,7vw,74px);line-height:.95;margin:8px 0}}p{{color:var(--muted);line-height:1.6}}.grid{{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:14px}}.card{{border:1px solid var(--line);border-radius:16px;background:linear-gradient(180deg,rgba(17,29,50,.9),rgba(13,22,39,.84));padding:16px}}.button{{min-height:46px;border-radius:10px;background:linear-gradient(135deg,var(--green),var(--cyan));color:#06101b;text-decoration:none;font-weight:950;padding:12px 15px;display:inline-flex;align-items:center;justify-content:center}}.badge{{display:inline-flex;border:1px solid rgba(255,255,255,.12);border-radius:999px;padding:5px 9px;color:#dffcff;background:rgba(110,223,246,.08)}}li{{margin:8px 0;color:var(--muted)}}@media(max-width:850px){{.grid{{grid-template-columns:1fr}}.button{{width:100%}}}}</style></head><body><main class="wrap"><nav><a class="brand" href="/"><img src="/static/Coinpilot%20Logo/NewLogo.png" alt="">CoinPilotXAI</a><a class="button" href="{clean_html(cta)}">Get Started</a></nav><section class="hero"><span class="badge">Trust-first platform</span><h1>{clean_html(headline)}</h1></section>{body_html}</main></body></html>""")


@webhook_app.route("/privacy-center", methods=["GET", "POST"])
def privacy_center_page():
    init_db()
    user = require_account()
    message = ""
    if request.method == "POST" and user:
        prefs = {
            "analytics_opt_out": 1 if request.form.get("analytics_opt_out") else 0,
            "personalized_ads_opt_out": 1 if request.form.get("personalized_ads_opt_out") else 0,
            "public_profile": 1 if request.form.get("public_profile") else 0,
            "creator_visibility": 1 if request.form.get("creator_visibility") else 0,
        }
        conn = db()
        cur = conn.cursor()
        cur.execute(
            """
            INSERT INTO privacy_preferences (user_id, analytics_opt_out, personalized_ads_opt_out, public_profile, creator_visibility, updated_at)
            VALUES (?, ?, ?, ?, ?, ?)
            ON CONFLICT(user_id) DO UPDATE SET
                analytics_opt_out=excluded.analytics_opt_out,
                personalized_ads_opt_out=excluded.personalized_ads_opt_out,
                public_profile=excluded.public_profile,
                creator_visibility=excluded.creator_visibility,
                updated_at=excluded.updated_at
            """,
            (user["user_id"], prefs["analytics_opt_out"], prefs["personalized_ads_opt_out"], prefs["public_profile"], prefs["creator_visibility"], datetime.utcnow().isoformat(timespec="seconds")),
        )
        conn.commit()
        conn.close()
        message = "Privacy preferences saved."
    policy = privacy_intelligence_engine.data_policy_summary()
    card_parts = []
    for name, values in [("Private / Never Sell", policy["private_never_sell"]), ("Product Improvement", policy["product_improvement"]), ("Aggregate Only", policy["monetizable_only_in_aggregate"])]:
        items = "".join("<li>{}</li>".format(clean_html(str(x).replace("_", " "))) for x in values)
        card_parts.append(f"<article class='card'><h2>{clean_html(name.replace('_',' ').title())}</h2><ul>{items}</ul></article>")
    cards = "".join(card_parts)
    controls = ""
    if user:
        retention = f"Raw analytics: {int(os.getenv('RAW_ANALYTICS_RETENTION_DAYS', '90') or 90)} days · Security logs: {int(os.getenv('SECURITY_LOG_RETENTION_DAYS', '180') or 180)} days · Aggregate analytics: {int(os.getenv('AGGREGATE_ANALYTICS_RETENTION_DAYS', '730') or 730)} days"
        controls = f"<section class='card'><h2>Your Controls</h2><p>{clean_html(message)}</p><form method='post'><label><input type='checkbox' name='analytics_opt_out'> Opt out of optional analytics where legally required</label><br><label><input type='checkbox' name='personalized_ads_opt_out' checked> Opt out of personalized ads</label><br><label><input type='checkbox' name='public_profile' checked> Public profile visible</label><br><label><input type='checkbox' name='creator_visibility' checked> Creator visibility enabled</label><br><button class='button'>Save Privacy Controls</button></form><p><strong>Account data controls:</strong> Download account data and delete account workflows are visible here for staged rollout and support-assisted processing.</p><p><strong>Retention:</strong> {clean_html(retention)}</p><p><a href='/terms'>Terms</a> · <a href='/community-rules'>Community Rules</a> · <a href='/advertising-policy'>Advertising Policy</a> · <a href='/creator-monetization-policy'>Creator Monetization Policy</a></p></section>"
    return trust_public_page("Privacy Center", "Your data is not the product.", f"<p>{clean_html(policy['principle'])}</p><section class='grid'>{cards}</section>{controls}", "/dashboard" if user else "/signup")


