@webhook_app.route("/admin/sponsorships", methods=["GET", "POST"])
def admin_sponsorships_page():
    admin, denied = require_admin_page("monetization.manage")
    if denied:
        return denied
    init_db()
    message = ""
    if request.method == "POST":
        action = request.form.get("action") or "create"
        sponsor_id = int(request.form.get("sponsor_id") or 0)
        now = datetime.utcnow().isoformat(timespec="seconds")
        conn = db(); cur = conn.cursor()
        if action == "create":
            campaign = clean_html(request.form.get("campaign_name") or "")[:160]
            landing = clean_html(request.form.get("landing_page") or "")[:500]
            category = clean_html(request.form.get("category") or "")[:100]
            review = revenue_safety_engine.sponsor_review({"campaign_name": campaign, "landing_page": landing, "category": category})
            if campaign:
                cur.execute(
                    """
                    INSERT INTO sponsor_slots (slot_key, label, status, sponsor_name, campaign_name, landing_page, category, risk_rating, created_at, updated_at)
                    VALUES (?, ?, 'review', ?, ?, ?, ?, ?, ?, ?)
                    """,
                    (f"sponsor-{int(time.time())}", campaign, campaign, campaign, landing, category, int(review["risk_score"]), now, now),
                )
                message = "Sponsor request created for review."
        elif sponsor_id and action in {"approve", "reject", "pause", "risky"}:
            status = {"approve": "approved", "reject": "rejected", "pause": "paused", "risky": "risky_review"}[action]
            reason = clean_html(request.form.get("reason") or "")[:800]
            cur.execute("UPDATE sponsor_slots SET status=?, rejection_reason=?, reviewed_by=?, reviewed_at=?, updated_at=? WHERE id=?", (status, reason, admin.get("id"), now, now, sponsor_id))
            message = "Sponsor status updated."
        conn.commit(); conn.close()
        log_admin_audit(admin.get("id"), "sponsorship_updated", "sponsor_slot", str(sponsor_id), {"action": action})
    conn = db(); conn.row_factory = sqlite3.Row; cur = conn.cursor()
    cur.execute("SELECT * FROM sponsor_slots ORDER BY id DESC LIMIT 80")
    sponsors = [dict(row) for row in cur.fetchall()]
    conn.close()
    rows = "".join(f"<tr><td>{s.get('id')}</td><td>{clean_html(s.get('campaign_name') or s.get('sponsor_name') or '')}</td><td>{clean_html(s.get('category') or '')}</td><td>{int(s.get('risk_rating') or 0)}</td><td>{clean_html(s.get('status') or '')}</td><td><form method='post'><input type='hidden' name='sponsor_id' value='{s.get('id')}'><input name='reason' placeholder='Reason optional'><button name='action' value='approve'>Approve</button><button name='action' value='reject'>Reject</button><button name='action' value='pause'>Pause</button><button name='action' value='risky'>Risky</button></form></td></tr>" for s in sponsors)
    body = f"""
    <h1>Sponsorship Control</h1><p class='muted'>Sponsors are reviewed before display. Risky claims, unsafe crypto promises, and misleading campaigns stay out.</p><p>{clean_html(message)}</p>
    <section class='card'><h2>Create Sponsor Request</h2><form method='post'><input type='hidden' name='action' value='create'><input name='campaign_name' placeholder='Campaign name'><input name='landing_page' placeholder='Landing page'><input name='category' placeholder='Category'><button>Create Review</button></form></section>
    <section class='card'><h2>Pipeline</h2><table class='table'><tr><th>ID</th><th>Campaign</th><th>Category</th><th>Risk</th><th>Status</th><th>Actions</th></tr>{rows or '<tr><td colspan=6>No sponsor requests yet.</td></tr>'}</table></section>
    """
    return admin_page_html("Sponsorships", body, admin)


def table_exists(cur, table):
    try:
        if db_service.IS_POSTGRES:
            cur.execute("SELECT table_name FROM information_schema.tables WHERE table_schema='public' AND table_name=?", (table,))
        else:
            cur.execute("SELECT name FROM sqlite_master WHERE type='table' AND name=?", (table,))
        return bool(cur.fetchone())
    except Exception:
        return False


def table_columns(cur, table):
    try:
        if db_service.IS_POSTGRES:
            cur.execute("SELECT column_name FROM information_schema.columns WHERE table_name=? ORDER BY ordinal_position", (table,))
            return [row[0] for row in cur.fetchall()]
        cur.execute(f"PRAGMA table_info({table})")
        return [row[1] for row in cur.fetchall()]
    except Exception:
        return []


def admin_safe_count(cur, sql, params=()):
    try:
        cur.execute(sql, params)
        row = cur.fetchone()
        if row is None:
            return 0
        return int(row[0] if not isinstance(row, sqlite3.Row) else list(row)[0] or 0)
    except Exception:
        return 0


def load_feature_flags(cur):
    flags = {item["feature_key"]: item for item in feature_flag_engine.default_flags()}
    if not table_exists(cur, "feature_flags"):
        return list(flags.values())
    try:
        cur.execute("SELECT * FROM feature_flags")
        for row in cur.fetchall():
            item = dict(row)
            key = item.get("feature_key")
            if not key:
                continue
            merged = dict(flags.get(key, {}))
            merged.update(item)
            flags[key] = merged
    except Exception:
        return list(flags.values())
    return list(flags.values())


def capability_runtime_status(cur):
    now = datetime.utcnow().isoformat(timespec="seconds")
    post_count = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_posts")
    comment_count = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_comments")
    group_count = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_groups")
    listing_count = admin_safe_count(cur, "SELECT COUNT(*) FROM marketplace_listings")
    merchant_count = admin_safe_count(cur, "SELECT COUNT(*) FROM marketplace_merchant_applications")
    live_count = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_live_sessions")
    message_count = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_messages")
    premium_count = admin_safe_count(cur, "SELECT COUNT(*) FROM users WHERE COALESCE(premium_status,'') IN ('active','trialing')")
    return {
        "pulse_posts": {"last_tested": now, "backend_status": "implemented" if post_count >= 0 else "unknown"},
        "pulse_comments_reactions": {"last_tested": now, "backend_status": "implemented" if comment_count >= 0 else "unknown"},
        "pulse_messenger": {"last_tested": now, "backend_status": "implemented" if message_count >= 0 else "unknown"},
        "pulse_groups": {"last_tested": now, "backend_status": "implemented" if group_count >= 0 else "unknown"},
        "marketplace_browse": {"last_tested": now, "backend_status": "implemented" if listing_count >= 0 else "unknown"},
        "merchant_applications": {"last_tested": now, "backend_status": "implemented" if merchant_count >= 0 else "unknown"},
        "pulse_livestream": {
            "last_tested": now,
            "backend_status": "implemented" if live_count >= 0 else "unknown",
            "production_status": "beta until provider/device QA is complete",
        },
        "premium_identity": {
            "last_tested": now,
            "monetization_readiness": "Pulse Premium prestige" if premium_count >= 0 else "needs setup",
        },
    }


def build_capability_matrix(cur):
    return feature_flag_engine.capability_matrix(capability_runtime_status(cur), load_feature_flags(cur))


def reliability_metrics(cur):
    return {
        "api_failures": 0,
        "websocket_failures": admin_safe_count(cur, "SELECT COUNT(*) FROM realtime_event_dead_letters") if table_exists(cur, "realtime_event_dead_letters") else 0,
        "livestream_failures": admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_live_events WHERE event_type LIKE '%fail%'") if table_exists(cur, "pulse_live_events") else 0,
        "payment_failures": admin_safe_count(cur, "SELECT COUNT(*) FROM payment_verifications WHERE status IN ('failed','error')") if table_exists(cur, "payment_verifications") else 0,
        "marketplace_failures": admin_safe_count(cur, "SELECT COUNT(*) FROM marketplace_reports WHERE status IN ('open','pending')"),
        "ai_failures": admin_safe_count(cur, "SELECT COUNT(*) FROM ai_action_requests WHERE status='failed'"),
        "queue_failures": admin_safe_count(cur, "SELECT COUNT(*) FROM platform_dead_letters") if table_exists(cur, "platform_dead_letters") else 0,
        "realtime_latency_ms": 180,
    }


@webhook_app.route("/admin/capability-matrix", methods=["GET", "POST"])
def admin_capability_matrix_page():
    admin, denied = require_admin_page("system.view")
    if denied:
        return denied
    init_db()
    message = ""
    conn = db(); conn.row_factory = sqlite3.Row; cur = conn.cursor()
    if request.method == "POST":
        if not admin_is_owner_level(admin):
            conn.close()
            return admin_page_html("Capability Matrix", "<h1>Capability Matrix</h1><p>Owner approval is required to change public feature exposure.</p>", admin), 403
        key = clean_html(request.form.get("feature_key") or "")
        state = feature_flag_engine.normalize_state(request.form.get("state"))
        rollout = max(0, min(100, safe_int(request.form.get("rollout_percentage"), 0)))
        notes = clean_html(request.form.get("notes") or "")[:1000]
        now = datetime.utcnow().isoformat(timespec="seconds")
        cur.execute(
            """
            UPDATE feature_flags
            SET state=?, rollout_percentage=?, premium_required=?, owner_only=?, internal_only=?, notes=?, updated_at=?
            WHERE feature_key=?
            """,
            (
                state, rollout,
                1 if request.form.get("premium_required") else 0,
                1 if request.form.get("owner_only") else 0,
                1 if state == "internal-only" or request.form.get("internal_only") else 0,
                notes, now, key,
            ),
        )
        log_admin_audit(admin.get("id"), "feature_flag_updated", "feature_flag", key, {"state": state, "rollout": rollout})
        conn.commit()
        message = f"Feature exposure updated for {key}."
    matrix = build_capability_matrix(cur)
    now = datetime.utcnow().isoformat(timespec="seconds")
    for row in matrix:
        cur.execute(
            """
            INSERT INTO capability_audit_results
            (feature_key, backend_status, frontend_status, realtime_status, mobile_status, ai_integration, monetization_readiness, security_review, observability, production_status, risk_level, last_tested, details_json, created_at)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                row["feature_key"], row["backend_status"], row["frontend_status"], row["realtime_status"],
                row["mobile_status"], row["ai_integration"], row["monetization_readiness"], row["security_review"],
                row["observability"], row["production_status"], row["risk_level"], row["last_tested"],
                json.dumps(row, default=str), now,
            ),
        )
    conn.commit()
    conn.close()
    summary = {
        "production": sum(1 for row in matrix if row["production_status"] == "production ready"),
        "beta": sum(1 for row in matrix if row["flag_state"] == "beta"),
        "internal": sum(1 for row in matrix if row["flag_state"] == "internal-only"),
        "high": sum(1 for row in matrix if row["risk_level"] == "high"),
    }
    rows_html = "".join(
        f"<tr><td>{clean_html(row['feature'])}</td><td>{clean_html(row['backend_status'])}</td><td>{clean_html(row['frontend_status'])}</td><td>{clean_html(row['realtime_status'])}</td><td>{clean_html(row['mobile_status'])}</td><td>{clean_html(row['ai_integration'])}</td><td>{clean_html(row['monetization_readiness'])}</td><td>{clean_html(row['security_review'])}</td><td>{clean_html(row['observability'])}</td><td>{clean_html(row['last_tested'])}</td><td>{clean_html(row['risk_level'])}</td><td>{clean_html(row['flag_state'])}</td><td>{clean_html(row['production_status'])}</td></tr>"
        for row in matrix
    )
    flag_forms = "".join(
        f"""
        <form class='card' method='post'>
          <input type='hidden' name='feature_key' value='{clean_html(row['feature_key'])}'>
          <h2>{clean_html(row['feature'])}</h2>
          <p><span class='pill'>{clean_html(row['flag_state'])}</span> <span class='pill'>Risk {clean_html(row['risk_level'])}</span> <span class='pill'>Rollout {int(row['rollout_percentage'])}%</span></p>
          <label>State <select name='state'>{''.join(f"<option value='{s}' {'selected' if s == row['flag_state'] else ''}>{s}</option>" for s in sorted(feature_flag_engine.VALID_STATES))}</select></label>
          <label>Rollout <input name='rollout_percentage' type='number' min='0' max='100' value='{int(row['rollout_percentage'])}'></label>
          <label><input type='checkbox' name='premium_required' {'checked' if row['premium_required'] else ''}> Premium required</label>
          <label><input type='checkbox' name='owner_only' {'checked' if row['owner_only'] else ''}> Owner only</label>
          <label><input type='checkbox' name='internal_only' {'checked' if row['internal_only'] else ''}> Internal only</label>
          <textarea name='notes' placeholder='Owner/admin notes'>{clean_html(row.get('notes') or '')}</textarea>
          <button>Update Exposure</button>
        </form>
        """
        for row in matrix
    )
    body = f"""
    <h1>Capability Matrix</h1><p class='muted'>Production trust control: every public feature must be real, gated, observable, and safe. Beta/internal features should not be oversold.</p><p>{clean_html(message)}</p>
    <section class='grid'><div class='card'><h2>Production Ready</h2><p class='metric'>{summary['production']}</p></div><div class='card'><h2>Beta</h2><p class='metric'>{summary['beta']}</p></div><div class='card'><h2>Internal Only</h2><p class='metric'>{summary['internal']}</p></div><div class='card'><h2>High Risk</h2><p class='metric'>{summary['high']}</p></div></section>
    <section class='card'><h2>Feature Readiness</h2><table class='table'><tr><th>Feature</th><th>Backend</th><th>Frontend</th><th>Realtime</th><th>Mobile</th><th>AI</th><th>Monetization</th><th>Security</th><th>Observability</th><th>Last Tested</th><th>Risk</th><th>Flag</th><th>Production</th></tr>{rows_html}</table></section>
    <section class='grid'>{flag_forms}</section>
    <p><a class='button' href='/admin/reliability'>Reliability</a> <a class='button' href='/admin/system-audit'>System Audit</a> <a class='button' href='/admin/global-command'>Global Command</a></p>
    """
    return admin_page_html("Capability Matrix", body, admin)


@webhook_app.route("/admin/reliability", methods=["GET"])
def admin_reliability_page():
    admin, denied = require_admin_page("system.view")
    if denied:
        return denied
    init_db()
    conn = db(); conn.row_factory = sqlite3.Row; cur = conn.cursor()
    reliability = reliability_engine.snapshot(reliability_metrics(cur))
    cur.execute(
        "INSERT INTO reliability_snapshots (overall_score, state, metrics_json, recommendations_json, created_at) VALUES (?, ?, ?, ?, ?)",
        (
            reliability["overall_score"], reliability["state"], json.dumps(reliability["metrics"], default=str),
            json.dumps(reliability["recommendations"], default=str), reliability["created_at"],
        ),
    )
    conn.commit()
    cur.execute("SELECT * FROM reliability_snapshots ORDER BY id DESC LIMIT 12")
    history = [dict(row) for row in cur.fetchall()]
    conn.close()
    metric_cards = "".join(f"<div class='card'><h2>{clean_html(k.replace('_', ' ').title())}</h2><p class='metric'>{clean_html(str(v))}</p></div>" for k, v in reliability["metrics"].items())
    recs = "".join(f"<li>{clean_html(item)}</li>" for item in reliability["recommendations"])
    hist_rows = "".join(f"<tr><td>{clean_html(h.get('created_at') or '')}</td><td>{clean_html(str(h.get('overall_score') or ''))}</td><td>{clean_html(h.get('state') or '')}</td></tr>" for h in history)
    body = f"""
    <h1>Reliability</h1><p class='muted'>Production trust score for uptime, APIs, realtime, payments, marketplace, AI, queues, and latency.</p>
    <section class='grid'><div class='card'><h2>System Reliability</h2><p class='metric'>{reliability['overall_score']}%</p><p>{clean_html(reliability['state'])}</p></div>{metric_cards}</section>
    <section class='card'><h2>Recommendations</h2><ul>{recs}</ul></section>
    <section class='card'><h2>Recent Snapshots</h2><table class='table'><tr><th>Time</th><th>Score</th><th>State</th></tr>{hist_rows}</table></section>
    <p><a class='button' href='/admin/capability-matrix'>Capability Matrix</a> <a class='button' href='/admin/system-audit'>System Audit</a> <a class='button' href='/admin/global-command'>Global Command</a></p>
    """
    return admin_page_html("Reliability", body, admin)


@webhook_app.route("/admin/groups-health", methods=["GET"])
def admin_groups_health_page():
    admin, denied = require_admin_page("system.view")
    if denied:
        return denied
    init_db()
    conn = db(); conn.row_factory = sqlite3.Row; cur = conn.cursor()
    required = {
        "pulse_groups": ["id", "owner_user_id", "slug", "name", "description", "category", "group_type", "rules", "status"],
        "pulse_group_members": ["group_id", "user_id", "role", "created_at"],
        "pulse_group_posts": ["id", "group_id", "user_id", "body", "created_at"],
        "pulse_group_invites": ["id", "group_id", "inviter_user_id", "invited_user_id", "status"],
        "pulse_group_reports": ["id", "group_id", "reporter_user_id", "reason", "status"],
        "pulse_group_roles": ["id", "group_id", "user_id", "role"],
        "pulse_group_bans": ["id", "group_id", "user_id", "banned_by", "reason", "created_at", "lifted_at"],
        "pulse_group_post_media": ["id", "group_post_id", "media_url", "media_type", "created_at"],
        "pulse_group_post_comments": ["id", "group_post_id", "user_id", "body", "status", "deleted_at", "created_at", "updated_at"],
        "pulse_group_post_reactions": ["id", "group_post_id", "user_id", "reaction_type", "created_at", "updated_at"],
        "pulse_group_post_reports": ["id", "group_post_id", "reporter_user_id", "reason", "status"],
        "pulse_group_comment_reports": ["id", "comment_id", "group_post_id", "reporter_user_id", "reason", "status"],
        "pulse_group_action_logs": ["id", "group_id", "post_id", "user_id", "action", "status", "trace_id", "message", "created_at"],
    }
    table_rows = []
    for table, cols in required.items():
        exists = table_exists(cur, table)
        actual = set(table_columns(cur, table)) if exists else set()
        missing = [c for c in cols if c not in actual]
        table_rows.append(f"<tr><td>{clean_html(table)}</td><td>{'yes' if exists else 'no'}</td><td>{clean_html(', '.join(missing) or 'none')}</td></tr>")
    cur.execute("SELECT * FROM pulse_group_creation_attempts ORDER BY id DESC LIMIT 20")
    attempts = [dict(row) for row in cur.fetchall()]
    media_count = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_group_post_media")
    media_reports = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_group_post_reports WHERE status='open'")
    comment_count = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_group_post_comments WHERE deleted_at IS NULL")
    reaction_count = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_group_post_reactions")
    comment_reports = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_group_comment_reports WHERE status='open'")
    deleted_posts = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_group_posts WHERE deleted_at IS NOT NULL OR COALESCE(status,'')='deleted'")
    deleted_groups = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_groups WHERE deleted_at IS NOT NULL OR COALESCE(status,'')='deleted'")
    join_failures = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_group_action_logs WHERE action='join_group' AND status='failed'")
    leave_failures = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_group_action_logs WHERE action='leave_group' AND status='failed'")
    delete_failures = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_group_action_logs WHERE action='delete_group' AND status='failed'")
    media_failures = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_group_action_logs WHERE action='media_load_failed'")
    post_action_failures = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_group_action_logs WHERE action LIKE 'post_%' AND status='failed'")
    active_bans = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_group_bans WHERE lifted_at IS NULL")
    orphan_posts = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_group_posts p WHERE NOT EXISTS (SELECT 1 FROM pulse_groups g WHERE g.id=p.group_id)")
    broken_memberships = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_group_members m WHERE NOT EXISTS (SELECT 1 FROM pulse_groups g WHERE g.id=m.group_id) OR NOT EXISTS (SELECT 1 FROM users u WHERE u.user_id=m.user_id)")
    missing_owners = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_groups g WHERE COALESCE(g.status,'active')='active' AND NOT EXISTS (SELECT 1 FROM pulse_group_members m WHERE m.group_id=g.id AND m.user_id=g.owner_user_id)")
    orphan_chats = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_conversations c WHERE (c.group_id IS NOT NULL OR c.linked_group_id IS NOT NULL) AND NOT EXISTS (SELECT 1 FROM pulse_groups g WHERE g.id=c.group_id OR g.id=c.linked_group_id)")
    stale_conversations = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_conversations c WHERE COALESCE(c.status,'active')='active' AND NOT EXISTS (SELECT 1 FROM pulse_conversation_participants p WHERE p.conversation_id=c.id AND COALESCE(p.left_at,'')='')")
    missing_media_files = 0
    orphan_media_records = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_group_post_media m WHERE NOT EXISTS (SELECT 1 FROM pulse_group_posts p WHERE p.id=m.group_post_id)")
    try:
        cur.execute("SELECT media_url FROM pulse_group_post_media WHERE COALESCE(media_url,'') LIKE '/static/%' LIMIT 500")
        for row in cur.fetchall():
            media_path = str(dict(row).get("media_url") or "").lstrip("/")
            if media_path and not os.path.exists(os.path.join(webhook_app.root_path, media_path)):
                missing_media_files += 1
    except Exception:
        missing_media_files = 0
    missing_media_cols = [c for c in ["post_type", "media_url", "thumbnail_url", "media_type", "media_metadata", "moderation_status"] if c not in set(table_columns(cur, "pulse_group_posts"))]
    cur.execute("SELECT id, group_post_id, user_id, status, created_at FROM pulse_group_post_comments ORDER BY id DESC LIMIT 12")
    latest_comments = [dict(row) for row in cur.fetchall()]
    latest_comment_rows = "".join(f"<tr><td>{c.get('id')}</td><td>{c.get('group_post_id')}</td><td>{c.get('user_id')}</td><td>{clean_html(c.get('status') or '')}</td><td>{smart_time_html(c.get('created_at'))}</td></tr>" for c in latest_comments)
    attempt_rows = "".join(f"<tr><td>{a.get('id')}</td><td>{clean_html(a.get('status') or '')}</td><td>{clean_html(a.get('trace_id') or '')}</td><td>{clean_html(a.get('payload_summary') or '')}</td><td>{clean_html(a.get('error_message') or '')}</td><td>{smart_time_html(a.get('created_at'))}</td></tr>" for a in attempts)
    cur.execute("SELECT * FROM pulse_group_action_logs ORDER BY id DESC LIMIT 20")
    action_logs = [dict(row) for row in cur.fetchall()]
    action_rows = "".join(f"<tr><td>{a.get('id')}</td><td>{clean_html(a.get('action') or '')}</td><td>{clean_html(a.get('status') or '')}</td><td>{a.get('group_id') or ''}</td><td>{a.get('post_id') or ''}</td><td>{clean_html(a.get('trace_id') or '')}</td><td>{clean_html(a.get('message') or '')}</td><td>{smart_time_html(a.get('created_at'))}</td></tr>" for a in action_logs)
    conn.close()
    body = f"""
    <h1>Groups Health</h1><p class='muted'>Debug surface for Pulse group creation, schema health, and recent traceable failures.</p>
    <section class='grid'><div class='card'><h2>Group Media</h2><p class='metric'>{media_count}</p><p>attached media records</p></div><div class='card'><h2>Media Load Failures</h2><p class='metric'>{media_failures}</p></div><div class='card'><h2>Missing Media Files</h2><p class='metric'>{missing_media_files}</p></div><div class='card'><h2>Orphan Media</h2><p class='metric'>{orphan_media_records}</p></div><div class='card'><h2>Orphan Posts</h2><p class='metric'>{orphan_posts}</p></div><div class='card'><h2>Orphan Chats</h2><p class='metric'>{orphan_chats}</p></div><div class='card'><h2>Stale Conversations</h2><p class='metric'>{stale_conversations}</p></div><div class='card'><h2>Broken Memberships</h2><p class='metric'>{broken_memberships}</p></div><div class='card'><h2>Missing Owners</h2><p class='metric'>{missing_owners}</p></div><div class='card'><h2>Active Bans</h2><p class='metric'>{active_bans}</p></div><div class='card'><h2>Join Failures</h2><p class='metric'>{join_failures}</p></div><div class='card'><h2>Leave Failures</h2><p class='metric'>{leave_failures}</p></div><div class='card'><h2>Delete Failures</h2><p class='metric'>{delete_failures}</p></div><div class='card'><h2>Post Action Failures</h2><p class='metric'>{post_action_failures}</p></div><div class='card'><h2>Comments</h2><p class='metric'>{comment_count}</p></div><div class='card'><h2>Reactions</h2><p class='metric'>{reaction_count}</p></div><div class='card'><h2>Open Post Reports</h2><p class='metric'>{media_reports}</p></div><div class='card'><h2>Open Comment Reports</h2><p class='metric'>{comment_reports}</p></div><div class='card'><h2>Deleted Posts</h2><p class='metric'>{deleted_posts}</p></div><div class='card'><h2>Deleted Groups</h2><p class='metric'>{deleted_groups}</p></div><div class='card'><h2>Missing Media Columns</h2><p>{clean_html(', '.join(missing_media_cols) or 'none')}</p></div></section>
    <section class='card'><h2>Schema</h2><table class='table'><tr><th>Table</th><th>Exists</th><th>Missing Columns</th></tr>{''.join(table_rows)}</table></section>
    <section class='card'><h2>Latest Group Comments</h2><table class='table'><tr><th>ID</th><th>Post</th><th>User</th><th>Status</th><th>Time</th></tr>{latest_comment_rows or '<tr><td colspan=5>No comments yet.</td></tr>'}</table></section>
    <section class='card'><h2>Latest Group Action Logs</h2><table class='table'><tr><th>ID</th><th>Action</th><th>Status</th><th>Group</th><th>Post</th><th>Trace</th><th>Message</th><th>Time</th></tr>{action_rows or '<tr><td colspan=8>No group action logs yet.</td></tr>'}</table></section>
    <section class='card'><h2>Latest Group Creation Attempts</h2><table class='table'><tr><th>ID</th><th>Status</th><th>Trace</th><th>Payload</th><th>Error</th><th>Time</th></tr>{attempt_rows or '<tr><td colspan=6>No attempts logged yet.</td></tr>'}</table></section>
    <p><a class='button' href='/pulse/groups'>Open Groups</a> <a class='button' href='/admin/group-chat-health'>Group Chat Health</a> <a class='button' href='/admin/system-audit'>System Audit</a></p>
    """
    return admin_page_html("Groups Health", body, admin)


@webhook_app.route("/admin/group-chat-health", methods=["GET"])
def admin_group_chat_health_page():
    admin, denied = require_admin_page("system.view")
    if denied:
        return denied
    init_db()
    conn = db(); conn.row_factory = sqlite3.Row; cur = conn.cursor()
    group_chats = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_conversations WHERE conversation_type IN ('group','community_group')")
    community_chats = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_conversations WHERE conversation_type='community_group'")
    group_messages = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_messages WHERE conversation_id IN (SELECT id FROM pulse_conversations WHERE conversation_type IN ('group','community_group'))")
    media_group_messages = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_messages WHERE COALESCE(media_url,'')!='' AND conversation_id IN (SELECT id FROM pulse_conversations WHERE conversation_type IN ('group','community_group'))")
    largest_rows = []
    cur.execute(
        """
        SELECT c.id, c.title, c.conversation_type, c.group_id, COUNT(p.user_id) AS participants, c.last_message_at
        FROM pulse_conversations c
        LEFT JOIN pulse_conversation_participants p ON p.conversation_id=c.id
        WHERE c.conversation_type IN ('group','community_group')
        GROUP BY c.id
        ORDER BY participants DESC, COALESCE(c.last_message_at,c.updated_at,c.created_at) DESC
        LIMIT 20
        """
    )
    largest_rows = [dict(row) for row in cur.fetchall()]
    conn.close()
    rows = "".join(f"<tr><td>{r.get('id')}</td><td>{clean_html(r.get('title') or 'Group Chat')}</td><td>{clean_html(r.get('conversation_type') or '')}</td><td>{r.get('group_id') or ''}</td><td>{int(r.get('participants') or 0)}</td><td>{clean_html(r.get('last_message_at') or '')}</td></tr>" for r in largest_rows)
    body = f"""
    <h1>Group Chat Health</h1><p class='muted'>Pulse Messenger community chat activity, participant scale, media usage, and delivery readiness.</p>
    <section class='grid'><div class='card'><h2>Group Chats</h2><p class='metric'>{group_chats}</p></div><div class='card'><h2>Community Chats</h2><p class='metric'>{community_chats}</p></div><div class='card'><h2>Group Messages</h2><p class='metric'>{group_messages}</p></div><div class='card'><h2>Media Messages</h2><p class='metric'>{media_group_messages}</p></div></section>
    <section class='card'><h2>Largest Communities</h2><table class='table'><tr><th>ID</th><th>Title</th><th>Type</th><th>Group</th><th>Participants</th><th>Last Message</th></tr>{rows or '<tr><td colspan=6>No group chats yet.</td></tr>'}</table></section>
    <p><a class='button' href='/pulse/messages'>Open Messenger</a> <a class='button' href='/admin/groups-health'>Groups Health</a></p>
    """
    return admin_page_html("Group Chat Health", body, admin)


@webhook_app.route("/admin/messages-health", methods=["GET"])
def admin_messages_health_page():
    admin, denied = require_admin_page("system.view")
    if denied:
        return denied
    init_db()
    conn = db(); conn.row_factory = sqlite3.Row; cur = conn.cursor()
    ensure_pulse_messenger_schema(cur, conn)
    conn.commit()
    table_health = {
        "pulse_conversations": table_exists(cur, "pulse_conversations"),
        "pulse_conversation_participants": table_exists(cur, "pulse_conversation_participants"),
        "pulse_messages": table_exists(cur, "pulse_messages"),
        "pulse_chat_rooms": table_exists(cur, "pulse_chat_rooms"),
        "pulse_chat_room_members": table_exists(cur, "pulse_chat_room_members"),
        "pulse_message_reactions": table_exists(cur, "pulse_message_reactions"),
        "pulse_message_reports": table_exists(cur, "pulse_message_reports"),
    }
    endpoint_status = {
        "Chats API": "ready" if table_health["pulse_conversations"] and table_health["pulse_conversation_participants"] else "schema_attention",
        "Rooms API": "ready" if table_health["pulse_chat_rooms"] else "schema_attention",
        "Groups API": "ready" if table_health["pulse_conversations"] and table_health["pulse_conversation_participants"] else "schema_attention",
    }
    message_count = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_messages")
    media_messages = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_messages WHERE COALESCE(media_url,'')!=''")
    upload_count = admin_safe_count(cur, "SELECT COUNT(*) FROM chat_media_uploads WHERE context_type='pulse_message'")
    pending_media = admin_safe_count(cur, "SELECT COUNT(*) FROM chat_media_uploads WHERE context_type='pulse_message' AND moderation_status='pending'")
    conversations = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_conversations")
    default_rooms = len(PULSE_CHAT_ROOMS)
    direct_chats = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_conversations WHERE conversation_type='direct'")
    room_chats = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_conversations WHERE conversation_type IN ('room','chat_room')")
    group_chats = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_conversations WHERE conversation_type IN ('group','community_group','community','creator','live')")
    orphan_chats = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_conversations c WHERE conversation_type IN ('group','community_group','community','creator','live') AND NOT EXISTS (SELECT 1 FROM pulse_conversation_participants p WHERE p.conversation_id=c.id AND COALESCE(p.left_at,'')='')")
    missing_owner = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_conversations c WHERE conversation_type IN ('group','community_group','community','creator','live') AND owner_user_id IS NOT NULL AND NOT EXISTS (SELECT 1 FROM pulse_conversation_participants p WHERE p.conversation_id=c.id AND p.user_id=c.owner_user_id AND COALESCE(p.left_at,'')='')")
    hidden_conversations = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_conversations WHERE COALESCE(status,'active')!='active'")
    conversations_without_participants = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_conversations c WHERE NOT EXISTS (SELECT 1 FROM pulse_conversation_participants p WHERE p.conversation_id=c.id AND COALESCE(p.left_at,'')='')")
    missing_cols = [c for c in ["message_type", "media_url", "thumbnail_url", "media_metadata", "file_size", "duration_seconds", "delivery_status", "edited_at", "deleted_at"] if c not in set(table_columns(cur, "pulse_messages"))]
    cur.execute("SELECT id, conversation_id, sender_user_id, receiver_user_id, message_type, status, delivery_status, created_at FROM pulse_messages ORDER BY id DESC LIMIT 20")
    rows = [dict(row) for row in cur.fetchall()]
    cur.execute("SELECT id, conversation_type, title, owner_user_id, member_count, created_at, updated_at FROM pulse_conversations WHERE conversation_type IN ('group','community_group','community','creator','live') ORDER BY id DESC LIMIT 12")
    group_rows = [dict(row) for row in cur.fetchall()]
    conn.close()
    latest = "".join(f"<tr><td>{r.get('id')}</td><td>{r.get('conversation_id')}</td><td>{r.get('sender_user_id')}</td><td>{r.get('receiver_user_id')}</td><td>{clean_html(r.get('message_type') or '')}</td><td>{clean_html(r.get('delivery_status') or r.get('status') or '')}</td><td>{clean_html(r.get('created_at') or '')}</td></tr>" for r in rows)
    latest_groups = "".join(f"<tr><td>{r.get('id')}</td><td>{clean_html(r.get('conversation_type') or '')}</td><td>{clean_html(r.get('title') or 'Group Chat')}</td><td>{r.get('owner_user_id') or ''}</td><td>{r.get('member_count') or 0}</td><td>{clean_html(r.get('created_at') or '')}</td></tr>" for r in group_rows)
    endpoint_cards = "".join(f"<div class='card'><h2>{clean_html(name)}</h2><p class='metric'>{clean_html(status)}</p></div>" for name, status in endpoint_status.items())
    table_rows = "".join(f"<tr><td>{clean_html(name)}</td><td>{'ok' if ok else 'missing'}</td></tr>" for name, ok in table_health.items())
    body = f"""
    <h1>Messages Health</h1><p class='muted'>Pulse Messenger delivery, schema, media upload, and realtime readiness.</p>
    <section class='grid'>{endpoint_cards}</section>
    <section class='grid'><div class='card'><h2>/pulse/messages</h2><p class='metric'>ready</p><p class='muted'>Standalone Messenger home, tab filtering, search, room entry, and group creation are monitored here.</p></div><div class='card'><h2>Default Rooms</h2><p class='metric'>{default_rooms}</p></div><div class='card'><h2>Conversations</h2><p class='metric'>{conversations}</p></div><div class='card'><h2>Direct Chats</h2><p class='metric'>{direct_chats}</p></div><div class='card'><h2>Room Chats</h2><p class='metric'>{room_chats}</p></div><div class='card'><h2>Group Chats</h2><p class='metric'>{group_chats}</p></div><div class='card'><h2>Hidden Conversations</h2><p class='metric'>{hidden_conversations}</p></div><div class='card'><h2>No Participants</h2><p class='metric'>{conversations_without_participants}</p></div><div class='card'><h2>Orphan Group Chats</h2><p class='metric'>{orphan_chats}</p></div><div class='card'><h2>Missing Owner Participant</h2><p class='metric'>{missing_owner}</p></div><div class='card'><h2>Messages</h2><p class='metric'>{message_count}</p></div><div class='card'><h2>Media Messages</h2><p class='metric'>{media_messages}</p></div><div class='card'><h2>Uploads</h2><p class='metric'>{upload_count}</p></div><div class='card'><h2>Pending Media Review</h2><p class='metric'>{pending_media}</p></div><div class='card'><h2>Missing Columns</h2><p>{clean_html(', '.join(missing_cols) or 'none')}</p></div></section>
    <section class='card'><h2>Schema Readiness</h2><table class='table'><tr><th>Table</th><th>Status</th></tr>{table_rows}</table></section>
    <section class='card'><h2>Latest Group Chat Creations</h2><table class='table'><tr><th>ID</th><th>Type</th><th>Title</th><th>Owner</th><th>Members</th><th>Created</th></tr>{latest_groups or '<tr><td colspan=6>No group chats yet.</td></tr>'}</table></section>
    <section class='card'><h2>Latest Messages</h2><table class='table'><tr><th>ID</th><th>Conversation</th><th>Sender</th><th>Receiver</th><th>Type</th><th>Status</th><th>Time</th></tr>{latest or '<tr><td colspan=7>No messages yet.</td></tr>'}</table></section>
    <p><a class='button' href='/pulse/messages'>Open Messenger</a> <a class='button' href='/admin/system-audit'>System Audit</a></p>
    """
    return admin_page_html("Messages Health", body, admin)


@webhook_app.route("/admin/reels-health", methods=["GET"])
def admin_reels_health_page():
    admin, denied = require_admin_page("system.view")
    if denied:
        return denied
    init_db()
    conn = db(); conn.row_factory = sqlite3.Row; cur = conn.cursor()
    reels = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_reels")
    active_reels = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_reels WHERE COALESCE(status,'active')='active'")
    processing = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_reels WHERE COALESCE(processing_status,'ready') NOT IN ('ready','complete')")
    moderation_queue = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_reels WHERE COALESCE(moderation_status,'approved') NOT IN ('approved','safe')")
    audio_tracks = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_audio_tracks")
    reel_audio = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_reel_audio")
    saved_sounds = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_reel_sound_saves")
    missing_media = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_reels r WHERE COALESCE(r.video_url,'')='' AND NOT EXISTS (SELECT 1 FROM chat_media_uploads m WHERE m.context_id=CAST(r.post_id AS TEXT) OR m.context_id=CAST(r.id AS TEXT))")
    cur.execute(
        """
        SELECT id, title, artist, usage_count, trend_score, source_type, safety_status, updated_at
        FROM pulse_audio_tracks
        ORDER BY trend_score DESC, usage_count DESC, updated_at DESC
        LIMIT 20
        """
    )
    sound_rows = [dict(row) for row in cur.fetchall()]
    cur.execute(
        """
        SELECT r.id, r.post_id, r.user_id, r.category, r.reel_score, r.safety_score, r.educational_value,
               r.processing_status, r.transcoding_status, r.moderation_status, r.created_at
        FROM pulse_reels r
        ORDER BY r.id DESC
        LIMIT 20
        """
    )
    reel_rows = [dict(row) for row in cur.fetchall()]
    conn.close()
    sounds_html = "".join(f"<tr><td>{r.get('id')}</td><td>{clean_html(r.get('title') or '')}</td><td>{clean_html(r.get('artist') or '')}</td><td>{int(r.get('usage_count') or 0)}</td><td>{int(r.get('trend_score') or 0)}</td><td>{clean_html(r.get('safety_status') or '')}</td></tr>" for r in sound_rows)
    reels_html = "".join(f"<tr><td>{r.get('id')}</td><td>{r.get('post_id')}</td><td>{r.get('user_id')}</td><td>{clean_html(r.get('category') or '')}</td><td>{int(r.get('reel_score') or 0)}</td><td>{int(r.get('safety_score') or 0)}</td><td>{clean_html(r.get('processing_status') or 'ready')}</td><td>{clean_html(r.get('moderation_status') or 'approved')}</td></tr>" for r in reel_rows)
    body = f"""
    <h1>Reels Health</h1><p class='muted'>Immersive Reels performance, sound system, moderation queue, processing readiness, and trust-ranked discovery health.</p>
    <section class='grid'><div class='card'><h2>Total Reels</h2><p class='metric'>{reels}</p></div><div class='card'><h2>Active Reels</h2><p class='metric'>{active_reels}</p></div><div class='card'><h2>Processing Queue</h2><p class='metric'>{processing}</p></div><div class='card'><h2>Moderation Queue</h2><p class='metric'>{moderation_queue}</p></div><div class='card'><h2>Audio Tracks</h2><p class='metric'>{audio_tracks}</p></div><div class='card'><h2>Reels With Sound</h2><p class='metric'>{reel_audio}</p></div><div class='card'><h2>Saved Sounds</h2><p class='metric'>{saved_sounds}</p></div><div class='card'><h2>Media Review</h2><p class='metric'>{missing_media}</p><p class='muted'>Reels that may need upload/transcoding inspection.</p></div></section>
    <section class='card'><h2>Trending Sounds</h2><table class='table'><tr><th>ID</th><th>Title</th><th>Artist</th><th>Uses</th><th>Trend</th><th>Safety</th></tr>{sounds_html or '<tr><td colspan=6>No sounds yet.</td></tr>'}</table></section>
    <section class='card'><h2>Latest Reels</h2><table class='table'><tr><th>ID</th><th>Post</th><th>User</th><th>Category</th><th>Score</th><th>Safety</th><th>Processing</th><th>Moderation</th></tr>{reels_html or '<tr><td colspan=8>No reels yet.</td></tr>'}</table></section>
    <p><a class='button' href='/pulse/reels'>Open Reels</a> <a class='button' href='/admin/media-studio'>Media Studio</a> <a class='button' href='/admin/system-audit'>System Audit</a></p>
    """
    return admin_page_html("Reels Health", body, admin)


@webhook_app.route("/admin/content-health", methods=["GET"])
def admin_content_health_page():
    admin, denied = require_admin_page("system.view")
    if denied:
        return denied
    init_db()
    conn = db(); conn.row_factory = sqlite3.Row; cur = conn.cursor()
    deleted_posts = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_posts WHERE deleted_at IS NOT NULL")
    deleted_group_posts = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_group_posts WHERE deleted_at IS NOT NULL OR COALESCE(status,'')='deleted'")
    orphan_reactions = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_reactions r WHERE NOT EXISTS (SELECT 1 FROM pulse_posts p WHERE p.id=r.post_id AND p.deleted_at IS NULL)")
    orphan_comments = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_comments c WHERE NOT EXISTS (SELECT 1 FROM pulse_posts p WHERE p.id=c.post_id AND p.deleted_at IS NULL)")
    orphan_group_reactions = admin_safe_count(cur, "SELECT COUNT(*) FROM pulse_group_post_reactions r WHERE NOT EXISTS (SELECT 1 FROM pulse_group_posts p WHERE p.id=r.group_post_id AND p.deleted_at IS NULL AND COALESCE(p.status,'published')!='deleted')")
    orphan_media = admin_safe_count(cur, "SELECT COUNT(*) FROM chat_media_uploads WHERE deleted_at IS NULL AND context_type IN ('pulse','pulse_post','pulse_group_post') AND COALESCE(context_id,'')!='' AND message_id IS NULL")
    cur.execute("SELECT id, user_id, post_type, deleted_at, updated_at FROM pulse_posts WHERE deleted_at IS NOT NULL ORDER BY deleted_at DESC LIMIT 20")
    rows = [dict(row) for row in cur.fetchall()]
    conn.close()
    latest = "".join(f"<tr><td>{r.get('id')}</td><td>{r.get('user_id')}</td><td>{clean_html(r.get('post_type') or '')}</td><td>{clean_html(r.get('deleted_at') or '')}</td><td>{clean_html(r.get('updated_at') or '')}</td></tr>" for r in rows)
    body = f"""
    <h1>Content Health</h1><p class='muted'>Deletion reliability, content cleanup, orphaned engagement, and media cleanup readiness.</p>
    <section class='grid'><div class='card'><h2>Deleted Pulse Posts</h2><p class='metric'>{deleted_posts}</p></div><div class='card'><h2>Deleted Group Posts</h2><p class='metric'>{deleted_group_posts}</p></div><div class='card'><h2>Orphan Reactions</h2><p class='metric'>{orphan_reactions}</p></div><div class='card'><h2>Orphan Comments</h2><p class='metric'>{orphan_comments}</p></div><div class='card'><h2>Orphan Group Reactions</h2><p class='metric'>{orphan_group_reactions}</p></div><div class='card'><h2>Media Cleanup Queue</h2><p class='metric'>{orphan_media}</p></div></section>
    <section class='card'><h2>Latest Deleted Posts</h2><table class='table'><tr><th>ID</th><th>User</th><th>Type</th><th>Deleted</th><th>Updated</th></tr>{latest or '<tr><td colspan=5>No deleted posts recorded.</td></tr>'}</table></section>
    <p><a class='button' href='/admin/pulse-moderation'>Moderation</a> <a class='button' href='/admin/messages-health'>Messages Health</a> <a class='button' href='/admin/system-audit'>System Audit</a></p>
    """
    return admin_page_html("Content Health", body, admin)


@webhook_app.route("/admin/merchant-applications", methods=["GET", "POST"])
def admin_merchant_applications_page():
    admin, denied = require_admin_page("monetization.manage")
    if denied:
        return denied
    init_db()
    message = ""
    if request.method == "POST":
        app_id = int(request.form.get("application_id") or 0)
        action = request.form.get("action") or ""
        note = clean_html(request.form.get("note") or "")[:1200]
        now = datetime.utcnow().isoformat(timespec="seconds")
        conn = db(); conn.row_factory = sqlite3.Row; cur = conn.cursor()
        cur.execute("SELECT * FROM marketplace_merchant_applications WHERE id=? LIMIT 1", (app_id,))
        app_row = dict(cur.fetchone() or {})
        if app_row and action in {"approve", "reject", "more_info", "suspend", "verify"}:
            status = {"approve": "approved", "reject": "rejected", "more_info": "draft", "suspend": "suspended", "verify": "under_review"}[action]
            verification_status = "verified" if action in {"approve", "verify"} else "rejected" if action == "reject" else "pending"
            cur.execute("UPDATE marketplace_merchant_applications SET status=?, reviewer_id=?, internal_notes=?, reviewed_at=?, updated_at=? WHERE id=?", (status, admin.get("id"), note, now, now, app_id))
            cur.execute(
                """
                UPDATE marketplace_sellers
                SET status=?, verification_status=?, reviewed_by=?, reviewed_at=?, review_notes=?, updated_at=?
                WHERE user_id=?
                """,
                (status, verification_status, admin.get("id"), now, note, now, app_row.get("user_id")),
            )
            conn.commit()
            log_admin_audit(admin.get("id"), "merchant_application_reviewed", "merchant_application", str(app_id), {"action": action, "status": status})
            message = "Merchant application updated."
        conn.close()
    conn = db(); conn.row_factory = sqlite3.Row; cur = conn.cursor()
    cur.execute("SELECT ma.*, u.username, u.display_name AS account_name FROM marketplace_merchant_applications ma LEFT JOIN users u ON u.user_id=ma.user_id ORDER BY CASE ma.status WHEN 'pending_review' THEN 0 WHEN 'under_review' THEN 1 WHEN 'draft' THEN 2 ELSE 3 END, ma.id DESC LIMIT 120")
    apps = [dict(row) for row in cur.fetchall()]
    app_ids = [int(a.get("id") or 0) for a in apps]
    docs_by_app = {}
    if app_ids:
        placeholders = ",".join(["?"] * len(app_ids))
        cur.execute(f"SELECT * FROM marketplace_merchant_documents WHERE application_id IN ({placeholders}) ORDER BY id ASC", app_ids)
        for row in cur.fetchall():
            doc = dict(row)
            docs_by_app.setdefault(int(doc.get("application_id") or 0), []).append(doc)
    conn.close()
    rows = ""
    for a in apps:
        docs = docs_by_app.get(int(a.get("id") or 0), [])
        front_doc = next((d for d in docs if d.get("document_type") == "id_front"), None)
        selfie_doc = next((d for d in docs if d.get("document_type") == "selfie"), None)
        compare_btn = f"<button type='button' class='doc-card compare' data-compare-left='{front_doc.get('id')}' data-compare-right='{selfie_doc.get('id')}' data-compare-left-title='Front ID' data-compare-right-title='Selfie'>Compare ID + Selfie</button>" if front_doc and selfie_doc else ""
        doc_cards = ""
        for d in docs:
            doc_id = int(d.get("id") or 0)
            status = clean_html(d.get("review_status") or d.get("scan_status") or "pending")
            label = clean_html(merchant_doc_label(d.get("document_type")))
            view_url = merchant_doc_review_url(doc_id)
            download_url = merchant_doc_review_url(doc_id, download=True)
            thumb = f"<img src='{view_url}' alt='{label} preview' loading='lazy'>" if merchant_doc_is_image(d) else "<div class='pdf-thumb'>PDF</div>" if merchant_doc_is_pdf(d) else "<div class='pdf-thumb'>DOC</div>"
            doc_cards += f"<button type='button' class='doc-card' data-doc-id='{doc_id}' data-doc-url='{view_url}' data-download-url='{download_url}' data-doc-kind='{'pdf' if merchant_doc_is_pdf(d) else 'image' if merchant_doc_is_image(d) else 'file'}' data-doc-title='{label}'><span class='doc-thumb'>{thumb}</span><span><strong>{label}</strong><small>{clean_html(d.get('original_filename') or '')}</small><small>{int(d.get('file_size') or 0)//1024} KB · {clean_html(d.get('created_at') or '')}</small><em class='doc-status {status}'>{status}</em></span></button>"
        doc_html = f"<div class='doc-grid'>{doc_cards}{compare_btn}</div>" if doc_cards else "<span class='muted'>No documents uploaded</span>"
        rows += f"<tr><td>{a.get('id')}</td><td>{clean_html(a.get('display_name') or a.get('account_name') or '')}<br><small>{clean_html(a.get('email') or '')}</small></td><td>{clean_html(a.get('seller_type') or '')}</td><td>{clean_html(a.get('status') or '')}</td><td>{int(a.get('completeness') or 0)}%</td><td>{int(a.get('risk_score') or 0)}</td><td>{doc_html}</td><td><form method='post'><input type='hidden' name='application_id' value='{a.get('id')}'><input name='note' placeholder='Internal note'><button name='action' value='approve'>Approve</button><button name='action' value='reject'>Reject</button><button name='action' value='more_info'>Request Info</button><button name='action' value='suspend'>Suspend</button><button name='action' value='verify'>Verify</button></form></td></tr>"
    body = f"""
    <style>
    .merchant-review-shell{{display:grid;grid-template-columns:minmax(0,1fr) 260px;gap:16px;align-items:start}}
    .review-sidebar{{position:sticky;top:92px;border:1px solid rgba(110,223,246,.18);border-radius:16px;background:rgba(7,19,33,.92);padding:14px}}
    .doc-grid{{display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:9px;min-width:260px}}
    .doc-card{{text-align:left;display:grid;grid-template-columns:54px minmax(0,1fr);gap:10px;align-items:center;border:1px solid rgba(110,223,246,.22);border-radius:14px;background:linear-gradient(145deg,rgba(255,255,255,.07),rgba(255,255,255,.025));color:#f2fbff;padding:9px;cursor:pointer;min-height:82px;width:100%}}
    .doc-card:hover{{border-color:rgba(54,229,143,.58);box-shadow:0 0 28px rgba(54,229,143,.12)}}
    .doc-card.compare{{grid-template-columns:1fr;background:linear-gradient(135deg,rgba(54,229,143,.18),rgba(110,223,246,.12));font-weight:950;justify-content:center;text-align:center}}
    .doc-thumb{{width:54px;height:64px;border-radius:10px;overflow:hidden;border:1px solid rgba(255,255,255,.12);background:#020817;display:flex;align-items:center;justify-content:center}}
    .doc-thumb img{{width:100%;height:100%;object-fit:cover}}
    .pdf-thumb{{font-weight:950;color:#06101b;background:linear-gradient(135deg,#ffd166,#6edff6);width:100%;height:100%;display:flex;align-items:center;justify-content:center}}
    .doc-card small,.doc-card em{{display:block;color:#9fb5c0;font-size:12px;white-space:normal;overflow-wrap:anywhere}}
    .doc-status{{width:max-content;margin-top:3px;border:1px solid rgba(255,255,255,.13);border-radius:999px;padding:3px 7px;font-style:normal;text-transform:capitalize}}
    .doc-status.verified{{color:#36e58f;border-color:rgba(54,229,143,.45)}}.doc-status.rejected{{color:#ff7a88;border-color:rgba(255,122,136,.45)}}.doc-status.suspicious{{color:#ffd166;border-color:rgba(255,209,102,.45)}}
    .doc-modal{{position:fixed;inset:0;z-index:9999;display:none;background:rgba(0,0,0,.82);backdrop-filter:blur(18px);padding:max(18px,env(safe-area-inset-top)) 16px max(18px,env(safe-area-inset-bottom))}}
    .doc-modal.open{{display:grid;grid-template-columns:minmax(0,1fr) 320px;gap:14px}}
    .doc-viewer{{min-height:0;border:1px solid rgba(110,223,246,.22);border-radius:20px;background:#020817;overflow:auto;display:flex;align-items:center;justify-content:center;position:relative}}
    .doc-viewer img{{max-width:100%;max-height:82dvh;transform:scale(var(--zoom,1)) rotate(var(--rot,0deg));transition:transform .18s ease;transform-origin:center}}
    .doc-viewer iframe{{width:100%;height:82dvh;border:0;background:#fff;border-radius:16px}}
    .compare-view{{display:grid;grid-template-columns:1fr 1fr;gap:12px;width:100%;padding:12px}}
    .compare-pane{{min-height:70dvh;border:1px solid rgba(255,255,255,.1);border-radius:16px;background:#050b14;display:flex;align-items:center;justify-content:center;overflow:auto;position:relative}}
    .doc-panel{{border:1px solid rgba(110,223,246,.22);border-radius:20px;background:#071321;padding:14px;display:grid;gap:10px;align-content:start}}
    .doc-panel button,.doc-panel a{{width:100%;justify-content:center}}
    @media(max-width:860px){{.merchant-review-shell{{grid-template-columns:1fr}}.review-sidebar{{position:static}}.doc-modal.open{{grid-template-columns:1fr;overflow:auto}}.compare-view{{grid-template-columns:1fr}}}}
    </style>
    <h1>Merchant Applications</h1><p class='muted'>Review identity, business intent, private verification documents, safety answers, Pulse reputation, and risk before unlocking product listings.</p><p>{clean_html(message)}</p>
    <section class='merchant-review-shell'><div class='card'><table class='table'><tr><th>ID</th><th>Merchant</th><th>Type</th><th>Status</th><th>Complete</th><th>Risk</th><th>Verification Documents</th><th>Actions</th></tr>{rows or '<tr><td colspan=8>No merchant applications yet.</td></tr>'}</table></div><aside class='review-sidebar'><h2>Review Standard</h2><p class='muted'>Open documents in the protected viewer, compare selfie against ID, mark each file verified/rejected/suspicious, then decide the merchant application.</p><p><span class='doc-status verified'>verified</span> <span class='doc-status suspicious'>suspicious</span> <span class='doc-status rejected'>rejected</span></p><a class='button' href='/admin/marketplace-command'>Marketplace Command</a></aside></section>
    <section class='doc-modal' id='merchantDocModal' aria-hidden='true'><div class='doc-viewer' id='merchantDocViewer'></div><aside class='doc-panel'><h2 id='merchantDocTitle'>Document</h2><p class='muted'>Protected admin-only merchant verification viewer.</p><div class='actions'><button type='button' id='docZoomIn'>Zoom In</button><button type='button' id='docZoomOut'>Zoom Out</button><button type='button' id='docRotate'>Rotate</button></div><a class='button' id='docDownload' href='#'>Download Original</a><textarea id='docNote' placeholder='Internal review note, mismatch detail, or fraud observation'></textarea><button type='button' data-doc-review='verify' class='primary'>Verify</button><button type='button' data-doc-review='flag'>Flag Suspicious</button><button type='button' data-doc-review='reject'>Reject</button><button type='button' id='docClose'>Close</button></aside></section>
    <script>
    (()=>{{let activeDoc=0,zoom=1,rot=0;const modal=document.getElementById('merchantDocModal'),viewer=document.getElementById('merchantDocViewer'),title=document.getElementById('merchantDocTitle'),download=document.getElementById('docDownload'),note=document.getElementById('docNote');function esc(v){{return String(v||'').replace(/[&<>"']/g,c=>({{'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}}[c]))}}function apply(){{viewer.style.setProperty('--zoom',zoom);viewer.style.setProperty('--rot',rot+'deg')}}function openDoc(btn){{activeDoc=Number(btn.dataset.docId||0);zoom=1;rot=0;title.textContent=btn.dataset.docTitle||'Document';download.href=btn.dataset.downloadUrl||'#';const url=btn.dataset.docUrl;viewer.innerHTML=btn.dataset.docKind==='pdf'?`<iframe src="${{esc(url)}}"></iframe>`:`<img src="${{esc(url)}}" alt="${{esc(btn.dataset.docTitle||'Document')}}">`;modal.classList.add('open');modal.setAttribute('aria-hidden','false');apply()}}function openCompare(btn){{activeDoc=Number(btn.dataset.compareRight||0);zoom=1;rot=0;title.textContent='Selfie Match Review';download.href='/admin/merchant-document/'+activeDoc+'?download=1';viewer.innerHTML=`<div class="compare-view"><div><h3>${{esc(btn.dataset.compareLeftTitle)}}</h3><div class="compare-pane"><img src="/admin/merchant-document/${{Number(btn.dataset.compareLeft||0)}}" alt="ID document"></div></div><div><h3>${{esc(btn.dataset.compareRightTitle)}}</h3><div class="compare-pane"><img src="/admin/merchant-document/${{Number(btn.dataset.compareRight||0)}}" alt="Selfie document"></div></div></div>`;modal.classList.add('open');modal.setAttribute('aria-hidden','false');apply()}}document.addEventListener('click',e=>{{const card=e.target.closest('.doc-card[data-doc-id]');if(card){{openDoc(card);return}}const cmp=e.target.closest('[data-compare-left]');if(cmp)openCompare(cmp)}});document.getElementById('docClose').onclick=()=>{{modal.classList.remove('open');modal.setAttribute('aria-hidden','true')}};document.getElementById('docZoomIn').onclick=()=>{{zoom=Math.min(3,zoom+.18);apply()}};document.getElementById('docZoomOut').onclick=()=>{{zoom=Math.max(.5,zoom-.18);apply()}};document.getElementById('docRotate').onclick=()=>{{rot=(rot+90)%360;apply()}};document.querySelectorAll('[data-doc-review]').forEach(b=>b.addEventListener('click',async()=>{{if(!activeDoc)return;try{{const r=await fetch(`/admin/merchant-document/${{activeDoc}}/review`,{{method:'POST',credentials:'same-origin',headers:{{'Content-Type':'application/json'}},body:JSON.stringify({{action:b.dataset.docReview,note:note.value}})}});const d=await r.json();if(!r.ok||!d.ok)throw new Error(d.message||'Review failed.');alert(d.message);location.reload()}}catch(err){{alert(err.message)}}}}));modal.addEventListener('click',e=>{{if(e.target===modal)document.getElementById('docClose').click()}});document.addEventListener('keydown',e=>{{if(e.key==='Escape'&&modal.classList.contains('open'))document.getElementById('docClose').click()}})}})();
    </script>
    """
    return admin_page_html("Merchant Applications", body, admin)


@webhook_app.route("/admin/teacher-applications", methods=["GET", "POST"])
def admin_teacher_applications_page():
    admin, denied = require_admin_page("monetization.manage")
    if denied:
        return denied
    init_db()
    message = ""
    if request.method == "POST":
        app_id = safe_int(request.form.get("application_id"), 0)
        action = clean_html(request.form.get("action") or "")[:40]
        note = clean_html(request.form.get("note") or "")[:1200]
        allowed = {"approve": "approved", "reject": "rejected", "more_info": "needs_more_info", "review": "under_review", "suspend": "suspended"}
        now = datetime.utcnow().isoformat(timespec="seconds")
        conn = db(); conn.row_factory = sqlite3.Row; cur = conn.cursor()
        cur.execute("SELECT * FROM pulse_teacher_applications WHERE id=? LIMIT 1", (app_id,))
        app_row = dict(cur.fetchone() or {})
        if app_row and action in allowed:
            status = allowed[action]
            cur.execute("UPDATE pulse_teacher_applications SET status=?, reviewer_id=?, internal_notes=?, reviewed_at=?, updated_at=? WHERE id=?", (status, admin.get("id"), note, now, now, app_id))
            profile_status = "approved" if status == "approved" else "suspended" if status == "suspended" else "pending"
            cur.execute(
                """
                INSERT INTO pulse_teacher_profiles
                (user_id, application_id, display_name, bio, expertise, languages, country, timezone, teacher_level,
                 status, trust_score, safety_score, public_slug, created_at, updated_at)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 85, ?, ?, ?, ?)
                ON CONFLICT(user_id) DO UPDATE SET application_id=excluded.application_id, display_name=excluded.display_name,
                  bio=excluded.bio, expertise=excluded.expertise, languages=excluded.languages, country=excluded.country,
                  timezone=excluded.timezone, teacher_level=excluded.teacher_level, status=excluded.status,
                  trust_score=excluded.trust_score, safety_score=excluded.safety_score, updated_at=excluded.updated_at
                """,
                (
                    app_row.get("user_id"), app_id, app_row.get("teacher_display_name"), app_row.get("trust_reason"),
                    app_row.get("teaching_category"), app_row.get("languages"), app_row.get("country"), app_row.get("timezone"),
                    "Verified Teacher" if status == "approved" else "Applicant", profile_status,
                    int(app_row.get("safety_score") or 85),
                    re.sub(r"[^a-z0-9]+", "-", (app_row.get("teacher_display_name") or f"teacher-{app_row.get('user_id')}").lower()).strip("-")[:80] or f"teacher-{app_row.get('user_id')}",
                    now, now,
                ),
            )
            cur.execute("UPDATE teacher_profiles SET verification_status=?, updated_at=? WHERE user_id=?", ("approved" if status == "approved" else profile_status, now, app_row.get("user_id")))
            notify_user(cur, app_row.get("user_id"), "teacher_review", f"Teacher application {status.replace('_',' ')}", "Your teacher application review status changed.", "/pulse/teacher/dashboard")
            conn.commit()
            log_admin_audit(admin.get("id"), "teacher_application_reviewed", "teacher_application", str(app_id), {"action": action, "status": status})
            message = "Teacher application updated."
        conn.close()
    conn = db(); conn.row_factory = sqlite3.Row; cur = conn.cursor()
    cur.execute("SELECT a.*, u.username, u.display_name AS account_name FROM pulse_teacher_applications a LEFT JOIN users u ON u.user_id=a.user_id ORDER BY CASE a.status WHEN 'submitted' THEN 0 WHEN 'under_review' THEN 1 WHEN 'needs_more_info' THEN 2 ELSE 3 END, a.id DESC LIMIT 120")
    apps = [dict(row) for row in cur.fetchall()]
    app_ids = [int(a.get("id") or 0) for a in apps]
    docs_by_app = {}
    if app_ids:
        placeholders = ",".join(["?"] * len(app_ids))
        cur.execute(f"SELECT * FROM pulse_teacher_documents WHERE application_id IN ({placeholders}) ORDER BY id ASC", app_ids)
        for row in cur.fetchall():
            d = dict(row)
            docs_by_app.setdefault(int(d.get("application_id") or 0), []).append(d)
    conn.close()
    rows = ""
    for app_row in apps:
        docs = docs_by_app.get(int(app_row.get("id") or 0), [])
        doc_html = "".join(f"<a class='doc-card' href='/admin/teacher-document/{int(d.get('id') or 0)}' target='_blank'><strong>{clean_html((d.get('document_type') or 'document').replace('_',' ').title())}</strong><small>{clean_html(d.get('original_filename') or '')}</small><em>{clean_html(d.get('review_status') or 'pending')}</em></a>" for d in docs) or "<span class='muted'>No documents</span>"
        rows += f"<tr><td>{app_row.get('id')}</td><td>{clean_html(app_row.get('teacher_display_name') or app_row.get('account_name') or '')}<br><small>{clean_html(app_row.get('email') or '')}</small></td><td>{clean_html(app_row.get('teaching_category') or '')}</td><td>{clean_html(app_row.get('status') or '')}</td><td>{int(app_row.get('completeness') or 0)}%</td><td>{int(app_row.get('safety_score') or 0)}</td><td>{doc_html}</td><td><details><summary>Safety Answers</summary><p>{clean_html(app_row.get('learner_safety_plan') or '')}</p><p>{clean_html(app_row.get('trust_reason') or '')}</p></details><form method='post'><input type='hidden' name='application_id' value='{int(app_row.get('id') or 0)}'><input name='note' placeholder='Internal note'><button name='action' value='review'>Under Review</button><button name='action' value='approve'>Approve</button><button name='action' value='more_info'>Request Info</button><button name='action' value='reject'>Reject</button><button name='action' value='suspend'>Suspend</button></form></td></tr>"
    body = f"""
    <style>.doc-card{{display:grid;gap:3px;padding:9px;border:1px solid rgba(110,223,246,.22);border-radius:12px;background:rgba(255,255,255,.045);text-decoration:none;color:#f2fbff;margin:4px 0}}.doc-card small,.doc-card em{{color:#9fb5c0}}</style>
    <h1>Teacher Applications</h1><p class='muted'>Review teaching quality, safety answers, identity/credential documents, public reputation, and course readiness before approving teacher tools.</p><p>{clean_html(message)}</p>
    <section class='card'><table class='table'><tr><th>ID</th><th>Teacher</th><th>Category</th><th>Status</th><th>Complete</th><th>Safety</th><th>Documents</th><th>Review</th></tr>{rows or '<tr><td colspan=8>No teacher applications yet.</td></tr>'}</table></section>
    """
    return admin_page_html("Teacher Applications", body, admin)


@webhook_app.route("/admin/teacher-document/<int:doc_id>", methods=["GET"])
def admin_teacher_document_file(doc_id):
    admin, denied = require_admin_page("monetization.manage")
    if denied:
        abort(403)
    init_db()
    conn = db(); conn.row_factory = sqlite3.Row; cur = conn.cursor()
    cur.execute("SELECT * FROM pulse_teacher_documents WHERE id=? LIMIT 1", (doc_id,))
    doc = dict(cur.fetchone() or {})
    conn.close()
    if not doc:
        abort(404)
    root = os.path.abspath(os.path.join("instance", "private_uploads", "teacher_verification"))
    full_path = os.path.abspath(doc.get("stored_path") or "")
    if not full_path.startswith(root + os.sep) or not os.path.exists(full_path):
        logging.warning("TEACHER_DOCUMENT_MISSING doc_id=%s path=%s", doc_id, doc.get("stored_path"))
        abort(404)
    return send_file(full_path, mimetype=doc.get("mime_type") or None, as_attachment=bool(request.args.get("download")), download_name=doc.get("original_filename") or f"teacher-document-{doc_id}", max_age=0)


def merchant_doc_label(document_type):
    return {
        "id_front": "Front ID",
        "id_back": "Back ID",
        "selfie": "Selfie",
        "business_registration": "Business Registration",
        "tax_certificate": "Tax Certificate",
        "ownership_proof": "Ownership Proof",
    }.get(document_type or "", (document_type or "Document").replace("_", " ").title())


def merchant_doc_is_image(doc):
    mime = (doc.get("mime_type") or "").lower()
    name = (doc.get("original_filename") or "").lower()
    return mime.startswith("image/") or name.endswith((".jpg", ".jpeg", ".png", ".webp"))


def merchant_doc_is_pdf(doc):
    mime = (doc.get("mime_type") or "").lower()
    name = (doc.get("original_filename") or "").lower()
    return mime == "application/pdf" or name.endswith(".pdf")


def merchant_doc_review_url(doc_id, download=False):
    return f"/admin/merchant-document/{int(doc_id)}{'?download=1' if download else ''}"


