@webhook_app.route("/admin/merchant-document/<int:doc_id>/review", methods=["POST"])
def admin_merchant_document_review(doc_id):
    admin, denied = require_admin_page("monetization.manage")
    if denied:
        return api_error("Admin access required.", 403)
    init_db()
    payload = request.get_json(silent=True) or request.form
    action = clean_html(payload.get("action") or "")[:40]
    note = clean_html(payload.get("note") or "")[:1200]
    allowed = {"verify": "verified", "reject": "rejected", "flag": "suspicious", "pending": "pending"}
    if action not in allowed:
        return api_error("Choose a valid document action.", 400)
    now = datetime.utcnow().isoformat(timespec="seconds")
    conn = db(); conn.row_factory = sqlite3.Row; cur = conn.cursor()
    cur.execute("SELECT * FROM marketplace_merchant_documents WHERE id=? LIMIT 1", (doc_id,))
    doc = dict(cur.fetchone() or {})
    if not doc:
        conn.close()
        return api_error("Document not found.", 404)
    cur.execute(
        "UPDATE marketplace_merchant_documents SET review_status=?, review_notes=?, reviewed_by=?, reviewed_at=?, updated_at=? WHERE id=?",
        (allowed[action], note, admin.get("id"), now, now, doc_id),
    )
    conn.commit(); conn.close()
    log_admin_audit(admin.get("id"), "merchant_document_reviewed", "merchant_document", str(doc_id), {"action": action, "status": allowed[action]})
    return jsonify({"ok": True, "message": f"Document marked {allowed[action]}.", "document_id": doc_id, "status": allowed[action]})


@webhook_app.route("/admin/marketplace-command", methods=["GET", "POST"])
def admin_marketplace_command_page():
    admin, denied = require_admin_page("monetization.manage")
    if denied:
        return denied
    init_db()
    message = ""
    if request.method == "POST":
        listing_id = int(request.form.get("listing_id") or 0)
        action = request.form.get("action") or ""
        now = datetime.utcnow().isoformat(timespec="seconds")
        conn = db(); cur = conn.cursor()
        if listing_id and action in {"approve", "reject", "hide", "suspend", "feature"}:
            status = {"approve": "approved", "reject": "rejected", "hide": "hidden", "suspend": "suspended", "feature": "approved"}[action]
            cur.execute("UPDATE marketplace_listings SET status=?, approval_status=?, featured=CASE WHEN ?='feature' THEN 1 ELSE COALESCE(featured,0) END, reviewed_by=?, reviewed_at=?, updated_at=? WHERE id=?", (status, status, action, admin.get("id"), now, now, listing_id))
            conn.commit()
            log_admin_audit(admin.get("id"), "marketplace_listing_reviewed", "marketplace_listing", str(listing_id), {"action": action})
            message = "Listing updated."
        conn.close()
    conn = db(); conn.row_factory = sqlite3.Row; cur = conn.cursor()
    counts = {}
    for key, sql in {
        "pending_merchants": "SELECT COUNT(*) AS total FROM marketplace_merchant_applications WHERE status IN ('pending_review','under_review')",
        "pending_products": "SELECT COUNT(*) AS total FROM marketplace_listings WHERE status IN ('pending_review','review_ready') OR approval_status IN ('needs_review','blocked_review','review_ready')",
        "approved_merchants": "SELECT COUNT(*) AS total FROM marketplace_sellers WHERE status='approved'",
        "risky_products": "SELECT COUNT(*) AS total FROM marketplace_listings WHERE COALESCE(safety_score,0)>=30",
        "saved_products": "SELECT COUNT(*) AS total FROM marketplace_saved_products",
    }.items():
        try:
            cur.execute(sql)
            counts[key] = int(dict(cur.fetchone() or {}).get("total") or 0)
        except Exception:
            counts[key] = 0
    cur.execute("SELECT l.*, COALESCE(u.display_name,u.username,'Seller') AS seller_name FROM marketplace_listings l LEFT JOIN users u ON u.user_id=l.seller_user_id ORDER BY CASE l.status WHEN 'pending_review' THEN 0 WHEN 'review_ready' THEN 1 ELSE 2 END, l.id DESC LIMIT 100")
    listings = [dict(row) for row in cur.fetchall()]
    listing_ids = [int(l.get("id") or 0) for l in listings]
    media_by_listing = {}
    if listing_ids:
        placeholders = ",".join(["?"] * len(listing_ids))
        cur.execute(f"SELECT * FROM marketplace_product_media WHERE product_id IN ({placeholders}) ORDER BY is_cover DESC, position ASC, id ASC", listing_ids)
        for row in cur.fetchall():
            item = dict(row)
            media_by_listing.setdefault(int(item.get("product_id") or 0), []).append(item)
    conn.close()
    cards = "".join(f"<div class='card'><h2>{clean_html(k.replace('_',' ').title())}</h2><p class='metric'>{v}</p></div>" for k, v in counts.items())
    rows = ""
    for l in listings:
        media_items = media_by_listing.get(int(l.get("id") or 0), [])
        media_html = "".join((f"<video src='{clean_html(m.get('media_url') or '')}' muted playsinline preload='metadata'></video>" if (m.get("media_type") or "") == "video" else f"<img src='{clean_html(m.get('thumbnail_url') or m.get('media_url') or '')}' alt='Product media' loading='lazy'>") for m in media_items[:4]) or "<span class='muted'>No media</span>"
        rows += f"<tr><td>{l.get('id')}</td><td>{clean_html(l.get('title') or '')}<div class='market-media-strip'>{media_html}</div></td><td>{clean_html(l.get('seller_name') or '')}</td><td>{clean_html(l.get('category') or '')}</td><td>{clean_html(l.get('status') or '')}</td><td>{int(l.get('safety_score') or 0)}</td><td><form method='post'><input type='hidden' name='listing_id' value='{l.get('id')}'><button name='action' value='approve'>Approve</button><button name='action' value='reject'>Reject</button><button name='action' value='hide'>Hide</button><button name='action' value='suspend'>Suspend</button><button name='action' value='feature'>Feature</button></form></td></tr>"
    body = f"<style>.market-media-strip{{display:flex;gap:7px;flex-wrap:wrap;margin-top:8px}}.market-media-strip img,.market-media-strip video{{width:72px;height:72px;object-fit:cover;border-radius:10px;border:1px solid rgba(255,255,255,.12);background:#020817}}</style><h1>Marketplace Command</h1><p class='muted'>Merchant approvals, product moderation, scam-risk alerts, seller trust, and listing trends.</p><p>{clean_html(message)}</p><section class='grid'>{cards}</section><section class='card'><h2>Product Review Queue</h2><table class='table'><tr><th>ID</th><th>Product + Media</th><th>Seller</th><th>Category</th><th>Status</th><th>Safety</th><th>Actions</th></tr>{rows or '<tr><td colspan=7>No listings yet.</td></tr>'}</table></section><p><a class='button' href='/admin/merchant-applications'>Merchant Applications</a></p>"
    return admin_page_html("Marketplace Command", body, admin)


@webhook_app.route("/admin/spaces-command", methods=["GET", "POST"])
def admin_spaces_command_page():
    admin, denied = require_admin_page("command_center.view")
    if denied:
        return denied
    init_db()
    message = ""
    if request.method == "POST":
        action = request.form.get("action") or ""
        slug = clean_html(request.form.get("slug") or "")[:120]
        conn = db(); conn.row_factory = sqlite3.Row; cur = conn.cursor()
        if action in {"feature", "freeze"} and slug:
            # Default static spaces are virtual. Persist a matching Pulse group shell
            # so admins can start moderating/freeze/feature without duplicate spaces.
            space = next((item for item in PULSE_SPACES if item["slug"] == slug), None)
            if space:
                now = datetime.utcnow().isoformat(timespec="seconds")
                cur.execute(
                    """
                    INSERT INTO pulse_groups (owner_user_id, slug, name, description, category, group_type, rules, status, featured, trust_level, created_at, updated_at)
                    VALUES (?, ?, ?, ?, ?, 'public', 'Keep it safe, educational, and scam-free.', ?, ?, 'trusted', ?, ?)
                    ON CONFLICT(slug) DO UPDATE SET status=excluded.status, featured=excluded.featured, updated_at=excluded.updated_at
                    """,
                    (admin.get("id") or 0, slug, space["name"], space["description"], space.get("category") or "Community", "frozen" if action == "freeze" else "active", 1 if action == "feature" else 0, now, now),
                )
                conn.commit()
                message = "Space command updated."
        elif action in {"pause_ai", "resume_ai"} and slug:
            cur.execute("UPDATE pulse_ai_schedules SET enabled=?, updated_at=? WHERE space_slug=?", (0 if action == "pause_ai" else 1, datetime.utcnow().isoformat(timespec="seconds"), slug))
            conn.commit()
            message = "Space AI schedule updated."
        elif action == "run_ai":
            result = pulse_ai.run_due_space_ai_posts(cur, PULSE_SPACES, pulse_create_post=pulse_feed_engine.create_post, force=True, limit=16)
            conn.commit()
            message = f"Space AI generated {int(result.get('ran') or 0)} posts."
        elif action in {"unpublish_ai", "approve_ai"}:
            ai_post_id = safe_int(request.form.get("ai_post_id"), 0)
            cur.execute("UPDATE pulse_ai_posts SET status=?, updated_at=? WHERE id=?", ("published" if action == "approve_ai" else "unpublished", datetime.utcnow().isoformat(timespec="seconds"), ai_post_id))
            conn.commit()
            message = "AI post status updated."
        elif action == "regenerate_ai":
            ai_post_id = safe_int(request.form.get("ai_post_id"), 0)
            cur.execute("SELECT space_slug, schedule_slot FROM pulse_ai_posts WHERE id=? LIMIT 1", (ai_post_id,))
            old = dict(cur.fetchone() or {})
            space = next((item for item in PULSE_SPACES if item["slug"] == old.get("space_slug")), None)
            if space:
                cur.execute("UPDATE pulse_ai_posts SET status='regenerated', updated_at=? WHERE id=?", (datetime.utcnow().isoformat(timespec="seconds"), ai_post_id))
                from services.pulse_ai.space_post_scheduler import publish_space_ai_post
                publish_space_ai_post(cur, space, old.get("schedule_slot") or "morning", pulse_create_post=pulse_feed_engine.create_post, approve_only=False)
                conn.commit()
                message = "AI post regenerated."
        conn.close()
    conn = db(); conn.row_factory = sqlite3.Row; cur = conn.cursor()
    cur.execute("SELECT space_slug, COUNT(*) AS total FROM pulse_space_members GROUP BY space_slug")
    counts = {dict(row).get("space_slug"): int(dict(row).get("total") or 0) for row in cur.fetchall()}
    cur.execute("SELECT space_slug, COUNT(*) AS total FROM pulse_ai_posts WHERE status IN ('published','queued','pending_approval') GROUP BY space_slug")
    ai_counts = {dict(row).get("space_slug"): int(dict(row).get("total") or 0) for row in cur.fetchall()}
    cur.execute("SELECT space_slug, SUM(CASE WHEN enabled=1 THEN 1 ELSE 0 END) AS enabled, MIN(next_run_at) AS next_run FROM pulse_ai_schedules GROUP BY space_slug")
    ai_schedules = {dict(row).get("space_slug"): dict(row) for row in cur.fetchall()}
    cur.execute("SELECT id, title, space_slug, post_type, topic, quality_score, topic_score, trust_score, energy_score, sentiment_score, status, metadata_json, schedule_slot, created_at FROM pulse_ai_posts ORDER BY id DESC LIMIT 18")
    latest_ai_rows = [dict(row) for row in cur.fetchall()]
    conn.close()
    rows = ""
    for space in PULSE_SPACES:
        metrics = space_discovery_engine.score_space(space, counts.get(space["slug"], space.get("member_count", 0)))
        schedule = ai_schedules.get(space["slug"], {})
        ai_enabled = int(schedule.get("enabled") or 0)
        rows += f"<tr><td>{clean_html(space['name'])}</td><td>{clean_html(space.get('category') or '')}</td><td>{clean_html(space.get('region') or '')}</td><td>{counts.get(space['slug'], space.get('member_count',0))}</td><td>{metrics['trust_score']}%</td><td>{metrics['activity_score']}%</td><td>{ai_counts.get(space['slug'],0)} posts<br><span class='muted'>{'Live' if ai_enabled else 'Paused'} · {clean_html(schedule.get('next_run') or 'scheduled')}</span></td><td><form method='post'><input type='hidden' name='slug' value='{clean_html(space['slug'])}'><button name='action' value='feature'>Feature</button><button name='action' value='freeze'>Freeze</button><button name='action' value='resume_ai'>Resume AI</button><button name='action' value='pause_ai'>Pause AI</button></form></td></tr>"
    latest_ai = ""
    for row in latest_ai_rows:
        try:
            meta = json.loads(row.get("metadata_json") or "{}")
        except Exception:
            meta = {}
        duplicate = (meta.get("duplicate_risk") or {}).get("risk", 0)
        latest_ai += f"<tr><td>{clean_html(row.get('space_slug') or '')}</td><td>{clean_html(row.get('title') or '')}<br><span class='muted'>{clean_html(row.get('post_type') or '')} · {clean_html(row.get('topic') or '')} · {clean_html(row.get('schedule_slot') or '')}</span></td><td>{int(row.get('quality_score') or 0)}%</td><td>{int(row.get('trust_score') or 0)}%</td><td>{int(row.get('energy_score') or 0)}%</td><td>{int(row.get('topic_score') or 0)}%</td><td>{int(duplicate or 0)}%</td><td>{clean_html(row.get('status') or '')}</td><td>{clean_html(row.get('created_at') or '')}</td><td><form method='post'><input type='hidden' name='ai_post_id' value='{int(row.get('id') or 0)}'><button name='action' value='regenerate_ai'>Regenerate</button><button name='action' value='approve_ai'>Approve</button><button name='action' value='unpublish_ai'>Unpublish</button></form></td></tr>"
    body = f"<h1>Spaces Command</h1><p class='muted'>Feature, freeze, monitor, and grow the global Pulse Spaces network.</p><p>{clean_html(message)}</p><section class='card'><form method='post'><button class='button primary' name='action' value='run_ai'>Run due AI posts now</button></form></section><section class='card'><table class='table'><tr><th>Space</th><th>Category</th><th>Region</th><th>Members</th><th>Trust</th><th>Energy</th><th>AI</th><th>Actions</th></tr>{rows}</table></section><section class='card'><h2>AI Post Review</h2><p class='muted'>Pulse Intelligence posts are generated by category-aware safety rules, scored for quality, duplicate risk, trust, and engagement before publishing.</p><table class='table'><tr><th>Space</th><th>Post</th><th>Quality</th><th>Trust</th><th>Energy</th><th>Topic</th><th>Dup Risk</th><th>Status</th><th>Created</th><th>Controls</th></tr>{latest_ai}</table></section>"
    return admin_page_html("Spaces Command", body, admin)


