@webhook_app.route("/admin/media", methods=["GET"])
def admin_media_diagnostics_page():
    admin, denied = require_admin_page("system.view")
    if denied:
        return denied
    init_db()
    conn = db(); conn.row_factory = sqlite3.Row; cur = conn.cursor()
    cur.execute(
        """
        SELECT id, uploader_user_id, context_type, context_id, original_filename, stored_filename,
               media_url, thumbnail_url, media_type, mime_type, file_size_bytes, moderation_status, created_at
        FROM chat_media_uploads
        ORDER BY id DESC LIMIT 120
        """
    )
    rows = []
    broken = 0
    for row in cur.fetchall():
        item = dict(row)
        public_url = pulse_media_url(item.get("media_url") or "")
        thumb_url = pulse_media_url(item.get("thumbnail_url") or item.get("media_url") or "")
        exists = pulse_media_exists(public_url)
        thumb_exists = pulse_media_exists(thumb_url)
        if not exists:
            broken += 1
        rows.append({
            "id": item.get("id"),
            "context": f"{item.get('context_type') or ''}:{item.get('context_id') or ''}",
            "type": item.get("media_type") or "",
            "mime": item.get("mime_type") or "",
            "bytes": item.get("file_size_bytes") or 0,
            "exists": "yes" if exists else "missing",
            "thumb": "yes" if thumb_exists else "missing",
            "url": public_url,
            "created": item.get("created_at") or "",
        })
    total = admin_safe_count(cur, "SELECT COUNT(*) FROM chat_media_uploads")
    pulse_total = admin_safe_count(cur, "SELECT COUNT(*) FROM chat_media_uploads WHERE context_type='pulse'")
    local_warning = ""
    if os.getenv("MEDIA_STORAGE_PROVIDER", "local").lower() == "local":
        local_warning = "<p class='muted'>Warning: local media storage is active. Railway disks are not persistent for production uploads; R2/S3 should be attached for durable Pulse media.</p>"
    conn.close()
    table = admin_rows_table(rows, [("id", "ID"), ("context", "Context"), ("type", "Type"), ("mime", "MIME"), ("bytes", "Bytes"), ("exists", "File"), ("thumb", "Thumb"), ("url", "Public URL"), ("created", "Created")])
    body = f"""
    <h1>Media Diagnostics</h1><p class='muted'>Trace Pulse feed media from stored path to public URL and file availability.</p>{local_warning}
    <section class='grid'><div class='card'><h2>Total Uploads</h2><p class='metric'>{total}</p></div><div class='card'><h2>Pulse Uploads</h2><p class='metric'>{pulse_total}</p></div><div class='card'><h2>Recent Missing Files</h2><p class='metric'>{broken}</p></div></section>
    <section class='card'><h2>Recent Upload Path Check</h2>{table}</section>
    <p><a class='button' href='/admin/media-studio'>Media Studio</a> <a class='button' href='/admin/performance'>Performance</a></p>
    """
    return admin_page_html("Media Diagnostics", body, admin)


@webhook_app.route("/admin/media-health", methods=["GET"])
def admin_media_health_page():
    admin, denied = require_admin_page("system.view")
    if denied:
        return denied
    init_db()
    status = media_storage.storage_status()
    conn = db(); conn.row_factory = sqlite3.Row; cur = conn.cursor()
    cur.execute(
        """
        SELECT id, uploader_user_id, context_type, context_id, media_url, thumbnail_url, poster_url,
               media_type, mime_type, file_size_bytes, width, height, storage_provider, storage_key,
               is_available, availability_error, created_at
        FROM chat_media_uploads
        WHERE deleted_at IS NULL
        ORDER BY id DESC LIMIT 200
        """
    )
    rows = []
    broken = missing_thumbs = missing_posters = local_legacy = missing_objects = repaired_ready = 0
    for row in cur.fetchall():
        item = dict(row)
        resolved = media_service.resolve_media(item)
        is_ok = bool(resolved.get("is_available"))
        if not is_ok:
            broken += 1
            if item.get("storage_provider") in {"r2", "s3"} or str(resolved.get("media_url") or "").startswith("http"):
                missing_objects += 1
        if not resolved.get("thumbnail_url"):
            missing_thumbs += 1
        if resolved.get("media_type") == "video" and not resolved.get("poster_url"):
            missing_posters += 1
        if (item.get("storage_provider") or "local") == "local" or str(item.get("media_url") or "").startswith(("/static/", "/uploads/")):
            local_legacy += 1
        if is_ok and resolved.get("storage_provider") in {"r2", "s3"}:
            repaired_ready += 1
        rows.append({
            "id": item.get("id"),
            "context": f"{item.get('context_type') or ''}:{item.get('context_id') or ''}",
            "type": resolved.get("media_type") or "",
            "provider": resolved.get("storage_provider") or "",
            "available": "yes" if is_ok else "restoring",
            "dimensions": f"{resolved.get('width') or 0}x{resolved.get('height') or 0}",
            "url": resolved.get("media_url") or "",
            "error": item.get("availability_error") or "",
        })
    total = admin_safe_count(cur, "SELECT COUNT(*) FROM chat_media_uploads WHERE deleted_at IS NULL")
    conn.close()
    required = status.get("required") or {}
    env_rows = "".join(f"<tr><td>{clean_html(k)}</td><td>{'present' if v else 'missing'}</td></tr>" for k, v in required.items())
    if not env_rows:
        env_rows = "<tr><td>Local provider</td><td>active</td></tr>"
    table = admin_rows_table(rows, [("id", "ID"), ("context", "Context"), ("type", "Type"), ("provider", "Provider"), ("available", "Available"), ("dimensions", "Size"), ("url", "URL"), ("error", "Error")])
    local_warning = ""
    if status.get("provider") == "local":
        local_warning = "<section class='card'><h2>Production Warning</h2><p class='muted'>Local storage is active. Railway container storage is not durable after redeploy unless a volume is mounted. Attach R2/S3 for permanent Pulse media.</p></section>"
    body = f"""
    <h1>Media Health</h1><p class='muted'>Durable storage, URL resolution, fallback safety, and Pulse media availability.</p>
    {local_warning}
    <section class='grid'><div class='card'><h2>Total Active Media</h2><p class='metric'>{total}</p></div><div class='card'><h2>Broken / Restoring</h2><p class='metric'>{broken}</p></div><div class='card'><h2>Missing Objects</h2><p class='metric'>{missing_objects}</p></div><div class='card'><h2>Legacy Local Media</h2><p class='metric'>{local_legacy}</p></div><div class='card'><h2>Repaired / R2 Ready</h2><p class='metric'>{repaired_ready}</p></div><div class='card'><h2>Missing Thumbnails</h2><p class='metric'>{missing_thumbs}</p></div><div class='card'><h2>Missing Posters</h2><p class='metric'>{missing_posters}</p></div></section>
    <section class='card'><h2>Storage Provider</h2><p class='muted'>{clean_html(status.get('provider'))} · configured={bool(status.get('configured'))}</p><table class='table'><tr><th>Variable</th><th>Status</th></tr>{env_rows}</table></section>
    <section class='card'><h2>Recent Media Resolution</h2>{table}</section>
    <p><a class='button primary' href='/admin/media'>Open Media Diagnostics</a> <a class='button' href='/admin/performance'>Performance</a></p>
    """
    return admin_page_html("Media Health", body, admin)


@webhook_app.route("/admin/system-audit", methods=["GET"])
def admin_system_audit_page():
    admin, denied = require_admin_page("system.view")
    if denied:
        return denied
    init_db()
    route_groups = {
        "Pulse": ["/pulse", "/pulse/create", "/pulse/my-posts", "/pulse/reels", "/pulse/friends", "/pulse/messages", "/pulse/notifications", "/pulse/profile", "/pulse/profile/edit", "/pulse/groups", "/pulse/groups/create", "/pulse/spaces", "/pulse/teachers", "/pulse/marketplace", "/pulse/merchant/apply", "/pulse/merchant/dashboard", "/pulse/marketplace/create", "/pulse/creator-monetization", "/pulse/live", "/pulse/assistant", "/pulse/camera"],
        "Admin": ["/admin/command-center", "/admin/global-command", "/admin/capability-matrix", "/admin/reliability", "/admin/pulse-users", "/admin/realtime-grid", "/admin/intelligence-graph", "/admin/trust-map", "/admin/global-events", "/admin/marketplace-command", "/admin/merchant-applications", "/admin/monetization", "/admin/notifications", "/admin/groups-health", "/admin/group-chat-health", "/admin/messages-health", "/admin/reels-health", "/admin/media-studio"],
    }
    rows = []
    client = webhook_app.test_client()
    if session.get("admin_user_id"):
        with client.session_transaction() as sess:
            sess["admin_user_id"] = session.get("admin_user_id")
    if session.get("account_user_id"):
        with client.session_transaction() as sess:
            sess["account_user_id"] = session.get("account_user_id")
    for area, routes in route_groups.items():
        for route in routes:
            try:
                res = client.get(route)
                status_code = res.status_code
                status = "PASS" if status_code < 400 or status_code in {302, 401, 403} else "FAIL" if status_code >= 500 else "WARN"
                mobile = mobile_ux_engine.mobile_route_check(route, res.get_data(as_text=True)[:20000])
                reason = "loads" if status == "PASS" else f"HTTP {status_code}"
                if mobile.get("warnings"):
                    reason += "; mobile " + ", ".join(mobile["warnings"][:2])
                    if status == "PASS":
                        status = "WARN"
                rows.append({"area": area, "route": route, "status": status, "status_code": status_code, "reason": reason})
            except Exception as exc:
                rows.append({"area": area, "route": route, "status": "FAIL", "status_code": 0, "reason": str(exc)})
    hardening = production_hardening_engine.route_status_score(rows)
    stable = stability_engine.stability_snapshot({"route_failures": hardening["failures"], "raw_errors": sum(1 for r in rows if "Traceback" in r.get("reason", ""))})
    row_html = "".join(f"<tr><td>{clean_html(r['area'])}</td><td>{clean_html(r['route'])}</td><td>{clean_html(r['status'])}</td><td>{r['status_code']}</td><td>{clean_html(r['reason'])}</td></tr>" for r in rows)
    recs = "".join(f"<li>{clean_html(item)}</li>" for item in stable["recommendations"] + hardening["recommendations"])
    body = f"""
    <h1>System Audit</h1><p class='muted'>Production-grade route, mobile, and stability sampling. Use the full script for deeper API/action checks.</p>
    <section class='grid'><div class='card'><h2>Hardening Score</h2><p class='metric'>{hardening['score']}%</p><p>{clean_html(hardening['state'])}</p></div><div class='card'><h2>Stability Score</h2><p class='metric'>{stable['score']}%</p><p>{clean_html(stable['state'])}</p></div><div class='card'><h2>Failures</h2><p class='metric'>{hardening['failures']}</p><p>{hardening['warnings']} warnings</p></div></section>
    <section class='card'><h2>Recommendations</h2><ul>{recs}</ul></section>
    <section class='card'><h2>Route Audit</h2><table class='table'><tr><th>Area</th><th>Route</th><th>Status</th><th>HTTP</th><th>Reason</th></tr>{row_html}</table></section>
    <p><a class='button primary' href='/admin/capability-matrix'>Capability Matrix</a> <a class='button' href='/admin/reliability'>Reliability</a> <a class='button' href='/admin/global-command'>Global Command</a></p>
    """
    return admin_page_html("System Audit", body, admin)


