def apply_department_action(slug, action, target_id, note, admin):
    now = datetime.utcnow().isoformat(timespec="seconds")
    conn = db()
    cur = conn.cursor()
    message = "Action logged."
    before = {}
    after = {"department": slug, "action": action, "target_id": target_id, "note": note}

    def create_task(department, title, priority="high", source_type="", source_id=""):
        cur.execute(
            """
            INSERT INTO admin_tasks
            (department, title, description, priority, assigned_to, status, source_type, source_id, created_at, updated_at)
            VALUES (?, ?, ?, ?, ?, 'open', ?, ?, ?, ?)
            """,
            (department, title, note or title, priority, admin.get("id"), source_type, source_id, now, now),
        )

    try:
        if slug == "social" and target_id:
            cur.execute("SELECT id, moderation_status, engagement_score, deleted_at FROM pulse_posts WHERE id=?", (target_id,))
            before = dict(cur.fetchone() or {})
            if action == "approve_post" or action == "restore_content":
                cur.execute("UPDATE pulse_posts SET moderation_status='approved', updated_at=? WHERE id=?", (now, target_id))
                message = "Pulse post approved."
            elif action == "hide_post":
                cur.execute("UPDATE pulse_posts SET moderation_status='needs_review', updated_at=? WHERE id=?", (now, target_id))
                message = "Pulse post hidden into review."
            elif action == "remove_post":
                cur.execute("UPDATE pulse_posts SET deleted_at=?, updated_at=? WHERE id=?", (now, now, target_id))
                message = "Pulse post removed."
                pulse_emit_event("pulse_post_deleted", {"post_id": target_id, "deleted": True, "source": "global_command"}, admin.get("id") or 0, target_id)
                pulse_emit_event("post_deleted", {"post_id": target_id, "deleted": True, "source": "global_command"}, admin.get("id") or 0, target_id)
            elif action == "send_to_moderation":
                cur.execute("UPDATE pulse_posts SET moderation_status='needs_review', updated_at=? WHERE id=?", (now, target_id))
                create_task("moderation", f"Review Pulse post #{target_id}", "high", "post", target_id)
                message = "Post sent to moderation."
            elif action == "boost_quality":
                cur.execute("UPDATE pulse_posts SET engagement_score=COALESCE(engagement_score,0)+25, updated_at=? WHERE id=?", (now, target_id))
                message = "Pulse post boosted."
            elif action == "mark_misinformation":
                cur.execute("UPDATE pulse_posts SET moderation_status='needs_review', risk_score=MAX(COALESCE(risk_score,0), 80), updated_at=? WHERE id=?", (now, target_id))
                create_task("trust-safety", f"Misinformation risk review for post #{target_id}", "critical", "post", target_id)
                message = "Misinformation risk queued."
        elif slug in {"trust-safety", "moderation"}:
            if action in {"assign_case", "escalate_case", "resolve_case", "dismiss_case", "add_case_note"} and target_id:
                cur.execute("SELECT * FROM moderation_cases WHERE id=?", (target_id,))
                before = dict(cur.fetchone() or {})
                if action == "assign_case":
                    cur.execute("UPDATE moderation_cases SET assigned_admin_id=?, status='reviewing', notes=COALESCE(notes,'') || ? WHERE id=?", (admin.get("id"), f"\nAssigned: {note}", target_id))
                    message = "Case assigned."
                elif action == "escalate_case":
                    cur.execute("UPDATE moderation_cases SET priority='critical', status='reviewing', notes=COALESCE(notes,'') || ? WHERE id=?", (f"\nEscalated: {note}", target_id))
                    message = "Case escalated."
                elif action == "resolve_case":
                    cur.execute("UPDATE moderation_cases SET status='actioned', decision=?, resolved_at=? WHERE id=?", (note or "Actioned by operator.", now, target_id))
                    message = "Case resolved."
                elif action == "dismiss_case":
                    cur.execute("UPDATE moderation_cases SET status='dismissed', decision=?, resolved_at=? WHERE id=?", (note or "Dismissed by operator.", now, target_id))
                    message = "Case dismissed."
                else:
                    cur.execute("UPDATE moderation_cases SET notes=COALESCE(notes,'') || ? WHERE id=?", (f"\n{now}: {note}", target_id))
                    message = "Case note added."
            elif action in {"quarantine_content", "restore_content"} and target_id:
                status = "approved" if action == "restore_content" else "needs_review"
                cur.execute("UPDATE pulse_posts SET moderation_status=?, updated_at=? WHERE id=?", (status, now, target_id))
                message = "Content status updated."
            elif action == "dismiss_report" and target_id:
                cur.execute("UPDATE pulse_reports SET status='dismissed' WHERE id=?", (target_id,))
                message = "Report dismissed."
            else:
                create_task(slug, f"{action.replace('_', ' ').title()} {target_id}", "critical" if action in {"ban_user", "suspend_user"} else "high", "admin_action", target_id)
                message = "Trust & Safety action queued."
        elif slug == "creators" and target_id:
            cur.execute("SELECT * FROM creator_profiles WHERE id=? OR user_id=?", (target_id, target_id))
            before = dict(cur.fetchone() or {})
            if action == "verify_creator":
                cur.execute("UPDATE creator_profiles SET verification_status='verified', creator_score=COALESCE(creator_score,0)+10 WHERE id=? OR user_id=?", (target_id, target_id))
                message = "Creator verified."
            elif action == "remove_verification":
                cur.execute("UPDATE creator_profiles SET verification_status='removed' WHERE id=? OR user_id=?", (target_id, target_id))
                message = "Creator verification removed."
            elif action == "restrict_creator":
                cur.execute("UPDATE creator_profiles SET monetization_enabled=0, verification_status='restricted' WHERE id=? OR user_id=?", (target_id, target_id))
                message = "Creator tools restricted."
            else:
                create_task("creators", f"{action.replace('_', ' ').title()} creator {target_id}", "high", "creator", target_id)
                message = "Creator operation queued."
        elif slug in {"delivery", "messaging"} and action == "retry_failed_delivery" and target_id:
            cur.execute("SELECT * FROM alert_delivery_jobs WHERE id=?", (target_id,))
            before = dict(cur.fetchone() or {})
            cur.execute("UPDATE alert_delivery_jobs SET status='pending', attempts=COALESCE(attempts,0)+1, next_retry_at=?, error_message='' WHERE id=?", (now, target_id))
            message = "Delivery job moved to retry queue."
        elif slug == "support" and target_id:
            cur.execute("SELECT * FROM support_tickets WHERE id=?", (target_id,))
            before = dict(cur.fetchone() or {})
            if action == "mark_resolved":
                cur.execute("UPDATE support_tickets SET status='closed', updated_at=? WHERE id=?", (now, target_id))
                message = "Ticket resolved."
            elif action == "assign_ticket":
                cur.execute("UPDATE support_tickets SET assigned_to=?, status='open', updated_at=? WHERE id=?", (admin.get("id"), now, target_id))
                message = "Ticket assigned."
            else:
                destination = "security" if action == "escalate_security" else "engineering" if action == "escalate_engineering" else "support"
                create_task(destination, f"{action.replace('_', ' ').title()} ticket #{target_id}", "high", "ticket", target_id)
                message = "Support action queued."
        elif slug == "security" and action == "false_positive" and target_id:
            cur.execute("SELECT * FROM security_events WHERE id=?", (target_id,))
            before = dict(cur.fetchone() or {})
            cur.execute("UPDATE security_events SET status='false_positive' WHERE id=?", (target_id,))
            message = "Security event marked false positive."
        elif slug == "roast-battle" and action == "remove_abusive_line" and target_id:
            cur.execute("SELECT * FROM arena_roast_lines WHERE id=?", (target_id,))
            before = dict(cur.fetchone() or {})
            cur.execute("UPDATE arena_roast_lines SET safe=0, moderation_reason=? WHERE id=?", (note or "Removed by admin operator.", target_id))
            message = "Roast line marked unsafe."
        elif slug == "monetization" and action == "review_enterprise_lead" and target_id:
            cur.execute("UPDATE enterprise_leads SET status='reviewing' WHERE id=?", (target_id,))
            message = "Enterprise lead moved to review."
        else:
            create_task(slug, f"{action.replace('_', ' ').title()} {target_id or slug}", "high", "admin_action", target_id)
            message = "Operational action queued."
        cur.execute(
            """
            INSERT INTO admin_activity_logs
            (admin_user_id, department, action, route, target_type, target_id, before_json, after_json, ip_hash, user_agent, created_at)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                admin.get("id"), slug, action, request.path, slug, target_id,
                json.dumps(before, default=str)[:4000], json.dumps(after, default=str)[:4000],
                client_ip_hash(), request.headers.get("User-Agent", "")[:500], now,
            ),
        )
        conn.commit()
    finally:
        conn.close()
    log_admin_audit(admin.get("id"), action, slug, str(target_id or ""), after)
    return message


def global_command_snapshot(persist=True):
    init_db()
    conn = db()
    conn.row_factory = sqlite3.Row
    cur = conn.cursor()
    now = datetime.utcnow().isoformat(timespec="seconds")

    def scalar(sql, params=()):
        try:
            cur.execute(sql, params)
            row = cur.fetchone()
            if not row:
                return 0
            return int((row[0] if not isinstance(row, dict) else next(iter(row.values()))) or 0)
        except Exception as exc:
            logging.info("GLOBAL_COMMAND_SCALAR_SKIPPED sql=%s error=%s", sql, exc)
            return 0

    nodes = []
    edges = []
    signals = []
    try:
        cur.execute("SELECT user_id, display_name, username, trust_score FROM user_trust_profiles LEFT JOIN users USING(user_id) ORDER BY trust_score DESC LIMIT 80")
        for row in cur.fetchall():
            row = dict(row)
            nodes.append(global_intelligence_graph.node("user", row.get("user_id"), row.get("display_name") or row.get("username") or "Pulse user", {"username": row.get("username")}, row.get("trust_score") or 0))
    except Exception as exc:
        logging.info("GLOBAL_COMMAND_USER_NODES_SKIPPED error=%s", exc)
    try:
        cur.execute("SELECT id, user_id, post_type, title, body, created_at FROM pulse_posts ORDER BY id DESC LIMIT 80")
        for row in cur.fetchall():
            row = dict(row)
            title = row.get("title") or (row.get("body") or "Pulse post")[:80]
            nodes.append(global_intelligence_graph.node("post", row.get("id"), title, {"post_type": row.get("post_type"), "created_at": row.get("created_at")}, 50))
            if row.get("user_id"):
                edges.append(global_intelligence_graph.edge("user", row.get("user_id"), "post", row.get("id"), "created_post", 1))
    except Exception as exc:
        logging.info("GLOBAL_COMMAND_POST_NODES_SKIPPED error=%s", exc)
    try:
        cur.execute("SELECT id, reporter_user_id, target_type, target_id, reason, created_at FROM pulse_reports ORDER BY id DESC LIMIT 80")
        for row in cur.fetchall():
            row = dict(row)
            signals.append({"signal_type": "scam" if "scam" in str(row.get("reason") or "").lower() else "report", "topic": row.get("reason") or "report", "created_at": row.get("created_at")})
            if row.get("reporter_user_id") and row.get("target_id"):
                edges.append(global_intelligence_graph.edge("user", row.get("reporter_user_id"), row.get("target_type") or "content", row.get("target_id"), "reported_scam" if "scam" in str(row.get("reason") or "").lower() else "reported", 2))
    except Exception as exc:
        logging.info("GLOBAL_COMMAND_REPORT_SIGNALS_SKIPPED error=%s", exc)

    summary = global_intelligence_graph.executive_summary(nodes, edges, signals)
    realtime_health = realtime_engine.health_snapshot()
    bus_metrics = event_bus_engine.metrics()
    distributed_health = distributed_realtime_engine.health()
    websocket_health = websocket_orchestrator.health_snapshot()
    stream_analytics = event_stream_analytics.stream_pressure(bus_metrics, distributed_health.get("metrics", {}))
    counts = {
        "users": scalar("SELECT COUNT(*) FROM users"),
        "posts": scalar("SELECT COUNT(*) FROM pulse_posts"),
        "reels": scalar("SELECT COUNT(*) FROM pulse_reels"),
        "live_sessions": scalar("SELECT COUNT(*) FROM pulse_live_sessions"),
        "marketplace": scalar("SELECT COUNT(*) FROM marketplace_listings"),
        "teachers": scalar("SELECT COUNT(*) FROM teacher_profiles"),
        "reports": scalar("SELECT COUNT(*) FROM pulse_reports"),
        "messages": scalar("SELECT COUNT(*) FROM pulse_messages"),
    }
    stale_cutoff = (datetime.utcnow() - timedelta(minutes=5)).isoformat(timespec="seconds")
    health_metrics = {
        "realtime_failures": realtime_health.get("failed_broadcasts", 0),
        "distributed_realtime_failures": distributed_health.get("metrics", {}).get("failed", 0),
        "websocket_pressure": websocket_health.get("pressure", 0),
        "stream_pressure": stream_analytics.get("stream_pressure", 0),
        "queue_backlog": scalar("SELECT COUNT(*) FROM notification_jobs WHERE status IN ('pending','failed','retry')"),
        "stale_workers": scalar("SELECT COUNT(*) FROM worker_heartbeats WHERE COALESCE(last_seen_at,'')<?", (stale_cutoff,)),
        "db_latency_ms": 0,
        "ai_failures": scalar("SELECT COUNT(*) FROM ai_observability_events WHERE COALESCE(error_message,'')!=''"),
        "media_failures": scalar("SELECT COUNT(*) FROM pulse_jobs WHERE status='failed' AND job_type IN ('generate_thumbnail','process_video')"),
        "livestream_errors": scalar("SELECT COUNT(*) FROM global_events WHERE event_type='livestream_error' AND status='active'"),
        "security_events": scalar("SELECT COUNT(*) FROM security_events"),
    }
    system_health = system_health_engine.snapshot(health_metrics)
    predictions = {
        "community": predictive_ai_engine.forecast_community_health({"active_members": counts["users"], "reports": counts["reports"], "helpful_posts": counts["posts"]}),
        "safety": autonomous_safety_engine.detect_attack_cluster(signals),
        "energy": global_social_energy_engine.global_energy({"activity": counts["posts"] + counts["messages"], "live_viewers": counts["live_sessions"]}),
        "resilience": platform_resilience_engine.resilience_score({"degraded_services": 1 if system_health["state"] in {"degraded", "critical"} else 0, "attack_signals": 1 if summary["scam_clusters"] else 0, "queue_backlog": health_metrics["queue_backlog"]}),
    }
    fabric_reasoning = universal_intelligence_fabric.reason({
        "summary": summary,
        "counts": counts,
        "predictions": predictions,
        "system_health": system_health,
        "health_metrics": health_metrics,
        "event_bus": bus_metrics,
        "realtime": realtime_health,
        "distributed_realtime": distributed_health,
        "websocket": websocket_health,
        "stream": stream_analytics,
    })
    meta_coordination = meta_intelligence_engine.coordinate(fabric_reasoning, system_health, bus_metrics)
    try:
        action_summary = ai_command_action_summary(limit=5)
    except Exception as exc:
        logging.info("GLOBAL_COMMAND_AI_ACTIONS_SKIPPED error=%s", exc)
        action_summary = {"pending_approvals": 0, "open_recommendations": 0, "critical_actions": [], "top_recommendations": [], "recent_results": [], "failed_actions": []}
    try:
        if not persist:
            raise RuntimeError("snapshot persistence skipped for live refresh")
        cur.execute(
            """
            INSERT INTO global_intelligence_snapshots
            (snapshot_type, health_score, node_count, edge_count, signal_count, summary_json, created_at)
            VALUES (?, ?, ?, ?, ?, ?, ?)
            """,
            ("admin_global_command", summary["health"]["health_score"], summary["health"]["node_count"], summary["health"]["edge_count"], summary["health"]["signal_count"], json.dumps({"summary": summary, "counts": counts, "predictions": predictions, "fabric": fabric_reasoning, "meta": meta_coordination}, default=str), now),
        )
        cur.execute(
            """
            INSERT INTO system_health_snapshots
            (health_score, state, metrics_json, warnings_json, failsafe_json, created_at)
            VALUES (?, ?, ?, ?, ?, ?)
            """,
            (system_health["overall_score"], system_health["state"], json.dumps(health_metrics, default=str), json.dumps(system_health["warnings"], default=str), json.dumps(system_health["failsafe"], default=str), now),
        )
        for event in bus_metrics.get("latest_events", [])[:5]:
            cur.execute(
                """
                INSERT INTO event_bus_events
                (channel, event_type, priority, status, trace_id, payload_json, created_at)
                VALUES (?, ?, ?, ?, ?, ?, ?)
                """,
                (event.get("channel"), event.get("event_type"), event.get("priority"), event.get("status"), event.get("trace_id"), json.dumps(event.get("payload") or {}, default=str)[:12000], event.get("created_at") or now),
            )
        conn.commit()
    except Exception as exc:
        conn.rollback()
        if persist:
            logging.info("GLOBAL_COMMAND_SNAPSHOT_WRITE_SKIPPED error=%s", exc)
    finally:
        conn.close()
    return {"summary": summary, "counts": counts, "predictions": predictions, "system_health": system_health, "health_metrics": health_metrics, "event_bus": bus_metrics, "realtime": realtime_health, "distributed_realtime": distributed_health, "websocket": websocket_health, "stream": stream_analytics, "fabric": fabric_reasoning, "meta": meta_coordination, "actions": action_summary, "nodes": nodes, "edges": edges, "signals": signals}


@webhook_app.route("/admin/global-command", methods=["GET"])
def admin_global_command_page():
    admin, denied = require_admin_page("command_center.view")
    if denied:
        return denied
    snapshot = global_command_snapshot()
    health = snapshot["summary"]["health"]
    counts = snapshot["counts"]
    predictions = snapshot["predictions"]
    system_health = snapshot["system_health"]
    event_bus = snapshot["event_bus"]
    realtime = snapshot["realtime"]
    distributed = snapshot["distributed_realtime"]
    websocket = snapshot["websocket"]
    stream = snapshot["stream"]
    fabric = snapshot["fabric"]
    meta = snapshot["meta"]
    actions = snapshot.get("actions") or {}
    cards = "".join(
        f"<div class='card live-card'><h2>{clean_html(label)}</h2><p class='metric' data-live-key='{clean_html(key)}'>{value}</p><div class='spark'><span style='width:{max(8, min(100, int(value or 0) % 100))}%'></span></div></div>"
        for label, value, key in [
            ("Global Users", counts["users"], "users"),
            ("Online Users", realtime.get("online_users", 0), "online_users"),
            ("Realtime Clients", realtime.get("active_realtime_clients", 0), "realtime_clients"),
            ("AI Events/min", event_bus.get("events_per_minute", 0), "events_per_minute"),
            ("Live Sessions", counts["live_sessions"], "live_sessions"),
            ("Queue Backlog", snapshot["health_metrics"].get("queue_backlog", 0), "queue_backlog"),
            ("Stream Pressure", stream.get("stream_pressure", 0), "stream_pressure"),
            ("Socket Pressure", websocket.get("pressure", 0), "websocket_pressure"),
        ]
    )
    attention = "".join(f"<li>{clean_html(item)}</li>" for item in snapshot["summary"]["what_needs_attention"])
    trend_rows = "".join(
        f"<tr><td>{clean_html(item.get('topic'))}</td><td>{int(item.get('mentions') or 0)}</td><td>{clean_html((item.get('origin') or {}).get('created_at') or 'n/a')}</td></tr>"
        for item in snapshot["summary"]["trend_origins"]
    ) or "<tr><td colspan='3'>No trend origins indexed yet.</td></tr>"
    scam_rows = "".join(
        f"<tr><td>{clean_html(item.get('cluster_key'))}</td><td>{clean_html(item.get('risk_weight'))}</td><td>{len(item.get('members') or [])}</td></tr>"
        for item in snapshot["summary"]["scam_clusters"]
    ) or "<tr><td colspan='3'>No scam clusters detected.</td></tr>"
    event_rows = "".join(
        f"<li><span>{clean_html(event.get('event_type'))}</span><small>{clean_html(event.get('channel'))} · {clean_html(event.get('created_at'))}</small></li>"
        for event in event_bus.get("latest_events", [])[:8]
    ) or "<li><span>event bus ready</span><small>No live events buffered yet.</small></li>"
    warnings = "".join(f"<li>{clean_html(item)}</li>" for item in system_health.get("warnings", [])) or "<li>All core systems are stable.</li>"
    recommendations = "".join(f"<li>{clean_html(item)}</li>" for item in system_health.get("failsafe", {}).get("recommendations", []))
    fabric_factors = "".join(
        f"<li><strong>{clean_html(str(item.get('system') or ''))}</strong>: {clean_html(str(item.get('signal_type') or ''))} = {clean_html(str(item.get('value') or ''))} <span class='pill'>{clean_html(str(item.get('confidence') or ''))}</span></li>"
        for item in fabric.get("signals", [])[:8]
    )
    meta_questions = "".join(
        f"<li><strong>{clean_html(str(item.get('question') or ''))}</strong><br><span class='muted'>{clean_html(str(item.get('answer') or ''))}</span></li>"
        for item in meta_intelligence_engine.command_questions(meta)
    )
    meta_decision = meta.get("decision") or {}
    action_rows = "".join(
        f"<li><strong>{clean_html(str(item.get('priority') or ''))}</strong> · {clean_html(str(item.get('title') or ''))}<br><span class='muted'>{clean_html(str(item.get('recommended_action') or ''))}</span></li>"
        for item in (actions.get("top_recommendations") or [])[:5]
    ) or "<li>No saved AI action recommendations yet.</li>"
    failed_action_rows = "".join(
        f"<li>#{item.get('id')} {clean_html(str(item.get('action_type') or ''))}: {clean_html(str(item.get('status') or ''))}</li>"
        for item in (actions.get("failed_actions") or [])[:5]
    ) or "<li>No failed AI actions.</li>"
    command_css = """
    <style>
    .global-command-stage{position:relative;overflow:hidden;border:1px solid rgba(110,223,246,.22);border-radius:22px;padding:18px;background:radial-gradient(circle at 20% 10%,rgba(110,223,246,.16),transparent 28rem),radial-gradient(circle at 82% 18%,rgba(54,229,143,.12),transparent 20rem),linear-gradient(145deg,rgba(4,12,24,.96),rgba(8,18,34,.94));box-shadow:0 30px 100px rgba(0,0,0,.38)}
    .global-command-stage:before{content:"";position:absolute;inset:-40%;background:conic-gradient(from 130deg,transparent,rgba(110,223,246,.12),transparent 35%,rgba(255,209,102,.08),transparent 70%);animation:commandSweep 18s linear infinite;pointer-events:none}
    .global-command-stage>*{position:relative}.live-card{overflow:hidden}.spark{height:8px;border-radius:999px;background:rgba(255,255,255,.07);overflow:hidden}.spark span{display:block;height:100%;border-radius:999px;background:linear-gradient(90deg,#36e58f,#6edff6,#ffd166);box-shadow:0 0 18px rgba(110,223,246,.45)}
    .orb-grid{display:grid;grid-template-columns:1.2fr .8fr;gap:14px}.planet{min-height:360px;width:100%;border-radius:18px;background:rgba(0,0,0,.24)}.event-feed,.brain-list{list-style:none;padding:0;margin:0;display:grid;gap:8px}.event-feed li,.brain-list li{border:1px solid rgba(255,255,255,.1);border-radius:12px;padding:10px;background:rgba(255,255,255,.045)}.event-feed span{display:block;font-weight:950}.event-feed small{color:#9fb5c0}.status-healthy{color:#36e58f}.status-watch{color:#ffd166}.status-degraded,.status-critical{color:#ff6b7a}.brainstem{border-color:rgba(255,209,102,.28);background:linear-gradient(135deg,rgba(255,209,102,.08),rgba(110,223,246,.06)),rgba(255,255,255,.035)}
    @keyframes commandSweep{to{transform:rotate(360deg)}}@media(max-width:820px){.orb-grid{grid-template-columns:1fr}.planet{min-height:260px}.global-command-stage{padding:12px}}
    @media(prefers-reduced-motion:reduce){.global-command-stage:before{animation:none}}
    </style>
    """
    command_script = f"""
    <script>
    const graphHealth={int(health['health_score'])}, trustHeat={int(health['trust_score'])}, riskHeat={100-int(system_health['overall_score'])};
    const canvas=document.getElementById('globalCommandCanvas'); const ctx=canvas?.getContext('2d');
    function sizeCanvas(){{if(!canvas)return;canvas.width=canvas.clientWidth*2;canvas.height=canvas.clientHeight*2}}
    function draw(){{if(!ctx)return;sizeCanvas();const w=canvas.width,h=canvas.height;ctx.clearRect(0,0,w,h);ctx.fillStyle='rgba(3,10,20,.9)';ctx.fillRect(0,0,w,h);const cx=w/2,cy=h/2,r=Math.min(w,h)*.28;ctx.strokeStyle='rgba(110,223,246,.28)';ctx.lineWidth=2;for(let i=0;i<6;i++){{ctx.beginPath();ctx.arc(cx,cy,r+i*18,0,Math.PI*2);ctx.stroke()}}const points=[graphHealth,trustHeat,riskHeat,{int(predictions['energy']['energy_score'])},{int(system_health['overall_score'])}];points.forEach((v,i)=>{{const a=(Date.now()/1800+i*1.25)%(Math.PI*2);const rr=r+v;const x=cx+Math.cos(a)*rr,y=cy+Math.sin(a)*rr;ctx.beginPath();ctx.fillStyle=i===2?'rgba(255,107,122,.88)':i===3?'rgba(255,209,102,.88)':'rgba(110,223,246,.9)';ctx.shadowBlur=22;ctx.shadowColor=ctx.fillStyle;ctx.arc(x,y,8+v/14,0,Math.PI*2);ctx.fill();ctx.shadowBlur=0;ctx.strokeStyle='rgba(255,255,255,.12)';ctx.beginPath();ctx.moveTo(cx,cy);ctx.lineTo(x,y);ctx.stroke()}});requestAnimationFrame(draw)}}
    draw();
    async function refreshCommand(){{try{{const d=await fetch('/api/admin/global-command/live',{{cache:'no-store'}}).then(r=>r.json());if(!d.ok)return;Object.entries(d.counts||{{}}).forEach(([k,v])=>{{document.querySelectorAll(`[data-live-key="${{k}}"]`).forEach(el=>el.textContent=v)}});document.getElementById('systemState').textContent=d.system_health?.state||'unknown';document.getElementById('systemState').className='status-'+(d.system_health?.state||'watch');}}catch(e){{}}}}
    setInterval(refreshCommand,7000);
    </script>
    """
    body = f"""
    {command_css}
    <section class='global-command-stage'>
    <h1>Global Command Grid</h1>
    <p class='muted'>A realtime planetary operations grid for trust, creator momentum, event flow, social energy, infrastructure, and AI recommendations.</p>
    <div class='grid'>{cards}</div>
    <section class='orb-grid'>
      <div class='card'><h2>Live Planetary Pulse</h2><canvas class='planet' id='globalCommandCanvas'></canvas></div>
      <div class='card'><h2>System Nervous System</h2><p class='metric'><span id='systemState' class='status-{clean_html(system_health['state'])}'>{clean_html(system_health['state'])}</span></p><p><span class='pill'>Health {system_health['overall_score']}%</span> <span class='pill'>Realtime {realtime.get('active_realtime_clients', 0)}</span> <span class='pill'>Events {event_bus.get('events_per_minute', 0)}/min</span></p><h3>Warnings</h3><ul>{warnings}</ul><h3>Failsafe Recommendations</h3><ul>{recommendations}</ul></div>
    </section>
    <section class='grid'>
      <div class='card brainstem'><h2>Universal Intelligence Fabric</h2><p class='metric'>{fabric.get('correlation', {}).get('correlation_strength', 0)}%</p><p>{clean_html(str(fabric.get('recommendation') or ''))}</p><p><span class='pill'>Priority {clean_html(str(fabric.get('priority') or ''))}</span> <span class='pill'>Confidence {clean_html(str(fabric.get('confidence') or ''))}</span> <span class='pill'>Domains {len(fabric.get('domains') or [])}</span></p><ul class='brain-list'>{fabric_factors}</ul></div>
      <div class='card brainstem'><h2>Meta-Intelligence Coordination</h2><p class='metric'>{meta.get('coordination_score', 0)}%</p><p>{clean_html(str(meta_decision.get('decision') or ''))}</p><p><span class='pill'>Priority {clean_html(str(meta_decision.get('priority') or ''))}</span> <span class='pill'>Owner approval {'required' if meta_decision.get('requires_owner_approval') else 'not required'}</span></p><ul class='brain-list'>{meta_questions}</ul></div>
    </section>
    <section class='grid'>
      <div class='card brainstem'><h2>Actionable Command Queue</h2><p class='metric'>{actions.get('pending_approvals', 0)}</p><p>pending owner approvals</p><p><span class='pill'>Open recommendations {actions.get('open_recommendations', 0)}</span> <span class='pill'>Queued actions {len(actions.get('critical_actions') or [])}</span></p><ul class='brain-list'>{action_rows}</ul><p><a class='button primary' href='/admin/approvals'>Review Approvals</a> <a class='button' href='/admin/ai-actions'>AI Actions</a></p></div>
      <div class='card brainstem'><h2>Execution Results</h2><p class='metric'>{len(actions.get('recent_results') or [])}</p><p>recent tracked outcomes</p><ul class='brain-list'>{failed_action_rows}</ul><p><a class='button' href='/admin/tasks'>Admin Tasks</a></p></div>
    </section>
    <section class='grid'>
      <div class='card'><h2>Distributed Realtime Nervous System</h2><p class='metric'>{distributed.get('score', 0)}%</p><p><span class='pill'>Status {clean_html(str(distributed.get('status') or ''))}</span> <span class='pill'>Success {clean_html(str((distributed.get('metrics') or {}).get('delivery_success_rate') or 0))}%</span> <span class='pill'>Replay {sum(((distributed.get('metrics') or {}).get('replay_depths') or {}).values())}</span></p></div>
      <div class='card'><h2>Websocket Orchestration</h2><p class='metric'>{websocket.get('pressure', 0)}%</p><p><span class='pill'>Sockets {websocket.get('active_sockets', 0)}</span> <span class='pill'>Reconnects {websocket.get('reconnect_spikes', 0)}</span> <span class='pill'>{clean_html(str((websocket.get('policy') or {}).get('mode') or ''))}</span></p></div>
      <div class='card'><h2>Event Stream Pressure</h2><p class='metric'>{stream.get('stream_pressure', 0)}%</p><p><span class='pill'>Lag {stream.get('queue_lag', 0)}</span> <span class='pill'>Dropped {stream.get('dropped_events', 0)}</span> <span class='pill'>Replay {stream.get('replay_count', 0)}</span></p></div>
    </section>
    <div class='grid'>
      <div class='card'><h2>Graph Health</h2><p class='metric'>{health['health_score']}%</p><p><span class='pill'>Nodes {health['node_count']}</span> <span class='pill'>Edges {health['edge_count']}</span> <span class='pill'>Signals {health['signal_count']}</span></p></div>
      <div class='card'><h2>Community Prediction</h2><p class='metric'>{clean_html(predictions['community']['status'])}</p><p>Health score {predictions['community']['health_score']}%</p></div>
      <div class='card'><h2>Global Energy</h2><p class='metric'>{predictions['energy']['energy_score']}%</p><p>{clean_html(predictions['energy']['visual_state'])}</p></div>
      <div class='card'><h2>Resilience</h2><p class='metric'>{predictions['resilience']['resilience_score']}%</p><p>{clean_html(predictions['resilience']['status'])}</p></div>
    </div>
    <section class='card'><h2>What Needs Attention Today</h2><ul>{attention}</ul></section>
    <section class='grid'>
      <div class='card'><h2>Predictive Insight Panels</h2><p><span class='pill'>Creator Forecast active</span> <span class='pill'>Scam Forecast {clean_html(predictions['safety']['recommended_action'])}</span> <span class='pill'>Infrastructure {clean_html(predictions['resilience']['status'])}</span></p><ul><li>Community health forecast: {clean_html(predictions['community']['status'])} at {predictions['community']['health_score']}%.</li><li>Social energy: {clean_html(predictions['energy']['visual_state'])} at {predictions['energy']['energy_score']}%.</li><li>Event throughput: {event_bus.get('events_per_minute', 0)} events/min.</li></ul></div>
      <div class='card'><h2>Global Event Feed</h2><ul class='event-feed'>{event_rows}</ul></div>
    </section>
    <section class='grid'>
      <div class='card'><h2>Trend Origin Tracing</h2><table class='table'><tr><th>Topic</th><th>Mentions</th><th>First Seen</th></tr>{trend_rows}</table></div>
      <div class='card'><h2>Scam Cluster Detection</h2><table class='table'><tr><th>Cluster</th><th>Risk</th><th>Members</th></tr>{scam_rows}</table></div>
    </section>
    <p><a class='button' href='/admin/command-center'>Department Command Center</a> <a class='button' href='/admin/capability-matrix'>Capability Matrix</a> <a class='button' href='/admin/reliability'>Reliability</a> <a class='button' href='/admin/pulse-core'>Pulse Core</a> <a class='button' href='/admin/realtime-grid'>Realtime Grid</a> <a class='button' href='/admin/intelligence-graph'>Intelligence Graph</a> <a class='button' href='/admin/trust-map'>Trust Map</a> <a class='button' href='/admin/global-events'>Global Events</a></p>
    </section>
    {command_script}
    """
    return admin_page_html("Global Command Grid", body, admin)


@webhook_app.route("/api/admin/global-command/live", methods=["GET"])
def api_admin_global_command_live():
    admin = admin_login_required()
    if not admin or not admin_has_permission(admin, "command_center.view"):
        return jsonify({"ok": False, "message": "Admin access required."}), 403
    snapshot = global_command_snapshot(persist=False)
    return jsonify({
        "ok": True,
        "counts": {
            **snapshot["counts"],
            "online_users": snapshot["realtime"].get("online_users", 0),
            "realtime_clients": snapshot["realtime"].get("active_realtime_clients", 0),
            "events_per_minute": snapshot["event_bus"].get("events_per_minute", 0),
            "queue_backlog": snapshot["health_metrics"].get("queue_backlog", 0),
            "stream_pressure": snapshot["stream"].get("stream_pressure", 0),
            "websocket_pressure": snapshot["websocket"].get("pressure", 0),
        },
        "system_health": snapshot["system_health"],
        "event_bus": {
            "published": snapshot["event_bus"].get("published", 0),
            "failed": snapshot["event_bus"].get("failed", 0),
            "dead_letters": snapshot["event_bus"].get("dead_letters", 0),
            "latest_events": snapshot["event_bus"].get("latest_events", [])[:8],
        },
        "fabric": {
            "priority": snapshot["fabric"].get("priority"),
            "confidence": snapshot["fabric"].get("confidence"),
            "recommendation": snapshot["fabric"].get("recommendation"),
            "correlation": snapshot["fabric"].get("correlation"),
        },
        "meta": snapshot["meta"],
        "actions": snapshot.get("actions", {}),
        "distributed_realtime": snapshot["distributed_realtime"],
        "websocket": snapshot["websocket"],
        "stream": snapshot["stream"],
        "summary": snapshot["summary"],
    })


@webhook_app.route("/admin/realtime-grid", methods=["GET"])
def admin_realtime_grid_page():
    admin, denied = require_admin_page("system.view")
    if denied:
        return denied
    snapshot = global_command_snapshot(persist=False)
    distributed = snapshot["distributed_realtime"]
    websocket = snapshot["websocket"]
    stream = snapshot["stream"]
    dist_metrics = distributed.get("metrics") or {}
    priority_rows = "".join(f"<tr><td>{clean_html(k)}</td><td>{v}</td></tr>" for k, v in (dist_metrics.get("priority_counts") or {}).items())
    partition_rows = "".join(f"<tr><td>{clean_html(k)}</td><td>{v}</td></tr>" for k, v in sorted((dist_metrics.get("partition_depths") or {}).items())[:24])
    channel_rows = "".join(f"<tr><td>{clean_html(name)}</td><td>{count}</td></tr>" for name, count in websocket.get("top_channels", []))
    css = """
    <style>
    .ops-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(230px,1fr));gap:12px}.pressure{height:12px;border-radius:999px;background:rgba(255,255,255,.08);overflow:hidden}.pressure span{display:block;height:100%;border-radius:999px;background:linear-gradient(90deg,#36e58f,#ffd166,#ff6b7a);box-shadow:0 0 18px rgba(110,223,246,.32)}@media(max-width:720px){.table{font-size:13px}}
    </style>
    """
    body = f"""
    {css}
    <h1>Realtime Grid</h1><p class='muted'>Distributed realtime nervous system, websocket orchestration, replay buffers, partition pressure, and stream analytics.</p>
    <section class='ops-grid'>
      <div class='card'><h2>Distributed Health</h2><p class='metric'>{distributed.get('score', 0)}%</p><div class='pressure'><span style='width:{distributed.get('score', 0)}%'></span></div><p>{clean_html(distributed.get('status'))}</p></div>
      <div class='card'><h2>Delivery Success</h2><p class='metric'>{clean_html(str(dist_metrics.get('delivery_success_rate') or 0))}%</p><p><span class='pill'>Published {dist_metrics.get('published', 0)}</span> <span class='pill'>Failed {dist_metrics.get('failed', 0)}</span></p></div>
      <div class='card'><h2>Websocket Pressure</h2><p class='metric'>{websocket.get('pressure', 0)}%</p><p><span class='pill'>Active {websocket.get('active_sockets', 0)}</span> <span class='pill'>Reconnects {websocket.get('reconnect_spikes', 0)}</span></p></div>
      <div class='card'><h2>Stream Pressure</h2><p class='metric'>{stream.get('stream_pressure', 0)}%</p><p><span class='pill'>Lag {stream.get('queue_lag', 0)}</span> <span class='pill'>Replay {stream.get('replay_count', 0)}</span></p></div>
    </section>
    <section class='grid'>
      <div class='card'><h2>Priority Tiers</h2><table class='table'><tr><th>Tier</th><th>Events</th></tr>{priority_rows or '<tr><td colspan=2>No events yet.</td></tr>'}</table></div>
      <div class='card'><h2>Partition Depth</h2><table class='table'><tr><th>Partition</th><th>Depth</th></tr>{partition_rows or '<tr><td colspan=2>No partition pressure.</td></tr>'}</table></div>
      <div class='card'><h2>Socket Channels</h2><table class='table'><tr><th>Channel</th><th>Clients</th></tr>{channel_rows or '<tr><td colspan=2>No active sockets.</td></tr>'}</table></div>
    </section>
    <p><a class='button' href='/admin/global-command'>Global Command</a> <a class='button' href='/admin/global-events'>Global Events</a></p>
    """
    return admin_page_html("Realtime Grid", body, admin)


@webhook_app.route("/admin/intelligence-graph", methods=["GET"])
def admin_intelligence_graph_page():
    admin, denied = require_admin_page("command_center.view")
    if denied:
        return denied
    snapshot = global_command_snapshot(persist=False)
    nodes = []
    for item in snapshot.get("nodes", [])[:160]:
        entity_type = item.get("entity_type")
        nodes.append({
            "id": item.get("key"),
            "label": item.get("label") or item.get("key"),
            "type": entity_type,
            "score": item.get("score") or 0,
            "risk": 1 if entity_type in {"report", "scam"} else 0,
        })
    edges = [{"source": item.get("source_key"), "target": item.get("target_key"), "relationship": item.get("relationship"), "weight": item.get("weight") or 1} for item in snapshot.get("edges", [])[:260]]
    graph_json = json.dumps({"nodes": nodes, "edges": edges}, default=str)
    body = f"""
    <style>
    .graph-shell{{display:grid;grid-template-columns:minmax(0,1fr) 300px;gap:14px}}.graph-canvas{{width:100%;height:68vh;min-height:420px;border-radius:18px;border:1px solid rgba(110,223,246,.22);background:radial-gradient(circle at 50% 45%,rgba(110,223,246,.12),transparent 32rem),#030914;touch-action:none}}.legend-dot{{display:inline-block;width:10px;height:10px;border-radius:50%;margin-right:6px;background:#6edff6;box-shadow:0 0 14px #6edff6}}.legend-dot.risk{{background:#ff6b7a;box-shadow:0 0 14px #ff6b7a}}@media(max-width:820px){{.graph-shell{{grid-template-columns:1fr}}.graph-canvas{{height:58vh;min-height:320px}}}}
    </style>
    <h1>Global Intelligence Graph</h1><p class='muted'>Force-directed view of users, creators, posts, communities, trust relationships, scam clusters, and trend propagation.</p>
    <section class='graph-shell'><canvas id='intelligenceGraph' class='graph-canvas'></canvas><aside class='card'><h2>Graph Controls</h2><p><span class='legend-dot'></span> Trusted/neutral entity</p><p><span class='legend-dot risk'></span> Risk or report signal</p><p><span class='pill'>Nodes {len(nodes)}</span> <span class='pill'>Edges {len(edges)}</span></p><p class='muted'>Drag nodes. Scroll/touch remains page-safe on mobile.</p><p><a class='button' href='/admin/global-command'>Back to Global Command</a></p></aside></section>
    <script>
    const graph={graph_json};
    const canvas=document.getElementById('intelligenceGraph'),ctx=canvas.getContext('2d');let drag=null;
    function resize(){{canvas.width=canvas.clientWidth*2;canvas.height=canvas.clientHeight*2}}resize();
    const nodes=graph.nodes.map((n,i)=>({{...n,x:(Math.random()*canvas.width*.7)+canvas.width*.15,y:(Math.random()*canvas.height*.7)+canvas.height*.15,vx:0,vy:0,r:8+Math.min(12,Number(n.score||0)/10)}}));const byId=Object.fromEntries(nodes.map(n=>[n.id,n]));
    function tick(){{for(const e of graph.edges){{const a=byId[e.source],b=byId[e.target];if(!a||!b)continue;const dx=b.x-a.x,dy=b.y-a.y,d=Math.max(40,Math.hypot(dx,dy));const f=(d-160)*.0008*(Number(e.weight||1));a.vx+=dx/d*f;a.vy+=dy/d*f;b.vx-=dx/d*f;b.vy-=dy/d*f}}for(let i=0;i<nodes.length;i++)for(let j=i+1;j<nodes.length;j++){{const a=nodes[i],b=nodes[j],dx=b.x-a.x,dy=b.y-a.y,d=Math.max(1,Math.hypot(dx,dy));if(d<90){{const f=(90-d)*.0015;a.vx-=dx/d*f;a.vy-=dy/d*f;b.vx+=dx/d*f;b.vy+=dy/d*f}}}}for(const n of nodes){{if(n!==drag){{n.vx+=(canvas.width/2-n.x)*.00008;n.vy+=(canvas.height/2-n.y)*.00008;n.x+=n.vx;n.y+=n.vy;n.vx*=.88;n.vy*=.88}}}}
    function draw(){{tick();ctx.clearRect(0,0,canvas.width,canvas.height);ctx.lineWidth=1.2;for(const e of graph.edges){{const a=byId[e.source],b=byId[e.target];if(!a||!b)continue;ctx.strokeStyle='rgba(110,223,246,.16)';ctx.beginPath();ctx.moveTo(a.x,a.y);ctx.lineTo(b.x,b.y);ctx.stroke()}}for(const n of nodes){{ctx.beginPath();ctx.fillStyle=n.risk?'rgba(255,107,122,.9)':n.type==='user'?'rgba(54,229,143,.9)':'rgba(110,223,246,.86)';ctx.shadowBlur=18;ctx.shadowColor=ctx.fillStyle;ctx.arc(n.x,n.y,n.r,0,Math.PI*2);ctx.fill();ctx.shadowBlur=0}}requestAnimationFrame(draw)}}draw();
    function pos(e){{const r=canvas.getBoundingClientRect(),t=e.touches?e.touches[0]:e;return{{x:(t.clientX-r.left)*2,y:(t.clientY-r.top)*2}}}}function pick(p){{return nodes.find(n=>Math.hypot(n.x-p.x,n.y-p.y)<n.r+10)}}canvas.addEventListener('pointerdown',e=>{{drag=pick(pos(e));if(drag)canvas.setPointerCapture(e.pointerId)}});canvas.addEventListener('pointermove',e=>{{if(!drag)return;const p=pos(e);drag.x=p.x;drag.y=p.y;drag.vx=drag.vy=0}});canvas.addEventListener('pointerup',()=>drag=null);
    </script>
    """
    return admin_page_html("Intelligence Graph", body, admin)


@webhook_app.route("/admin/trust-map", methods=["GET"])
def admin_trust_map_page():
    admin, denied = require_admin_page("security.events")
    if denied:
        return denied
    snapshot = global_command_snapshot(persist=False)
    health = snapshot["summary"]["health"]
    clusters = snapshot["summary"]["scam_clusters"]
    cluster_html = "".join(f"<div class='card'><h2>{clean_html(c.get('cluster_key'))}</h2><p class='metric'>{clean_html(c.get('risk_weight'))}</p><p class='muted'>{len(c.get('members') or [])} connected entities</p></div>" for c in clusters) or "<div class='card'><h2>No active scam cluster</h2><p class='muted'>Trust map is calm right now.</p></div>"
    body = f"""
    <style>.heat{{height:18px;border-radius:999px;background:linear-gradient(90deg,#ff6b7a,#ffd166,#36e58f);position:relative;overflow:hidden}}.heat:after{{content:"";position:absolute;inset:0 {max(0,100-health['trust_score'])}% 0 0;background:rgba(255,255,255,.16);box-shadow:0 0 20px rgba(110,223,246,.35)}}.trust-grid{{display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:12px}}</style>
    <h1>Trust Map</h1><p class='muted'>Trust clusters, scam propagation, creator reliability, reputation spread, and suspicious behavior overlays.</p>
    <section class='card'><h2>Trust Heat</h2><p class='metric'>{health['trust_score']}%</p><div class='heat'></div><p><span class='pill'>Safety {health['safety_score']}%</span> <span class='pill'>Coverage {health['coverage_score']}%</span></p></section>
    <section class='trust-grid'>{cluster_html}</section>
    <p><a class='button' href='/admin/intelligence-graph'>Open Graph</a> <a class='button' href='/admin/global-command'>Global Command</a></p>
    """
