@webhook_app.route("/admin/departments/<slug>", methods=["GET", "POST"])
def admin_department_page(slug):
    meta = ADMIN_DEPARTMENTS.get(slug)
    if not meta:
        return redirect("/admin/command-center")
    admin, denied = require_admin_page(meta["permission"])
    if denied:
        return denied
    init_db()
    message = ""
    if request.method == "POST":
        form_action = request.form.get("form_action") or "create_task"
        conn = db()
        cur = conn.cursor()
        if form_action == "update_task":
            task_id = int(request.form.get("task_id") or 0)
            status = clean_html(request.form.get("status", "open"))[:40]
            if task_id and status in {"open", "in_progress", "blocked", "done"}:
                completed_at = datetime.utcnow().isoformat(timespec="seconds") if status == "done" else None
                cur.execute("UPDATE admin_tasks SET status=?, completed_at=COALESCE(?, completed_at), updated_at=? WHERE id=? AND department=?", (status, completed_at, datetime.utcnow().isoformat(timespec="seconds"), task_id, slug))
                conn.commit()
                log_admin_audit(admin.get("id"), "admin_task_status_updated", "department", slug, {"task_id": task_id, "status": status})
                message = "Task updated."
        elif form_action == "department_action":
            conn.close()
            action = clean_html(request.form.get("department_action", ""))[:100]
            target_id = clean_html(request.form.get("target_id", ""))[:140]
            note = clean_html(request.form.get("action_note", ""))[:1200]
            message = apply_department_action(slug, action, target_id, note, admin)
            conn = db()
            cur = conn.cursor()
        elif form_action == "create_case" and slug in {"trust-safety", "moderation", "social"}:
            target_type = clean_html(request.form.get("target_type", "post"))[:80]
            target_id = clean_html(request.form.get("target_id", ""))[:120]
            reason = clean_html(request.form.get("reason", ""))[:1200]
            priority = clean_html(request.form.get("case_priority", "medium"))[:40]
            if target_id and reason:
                cur.execute(
                    """
                    INSERT INTO moderation_cases
                    (target_type, target_id, assigned_admin_id, status, priority, reason, ai_risk_score, notes, created_at)
                    VALUES (?, ?, ?, 'open', ?, ?, ?, ?, ?)
                    """,
                    (target_type, target_id, admin.get("id"), priority, reason, int(request.form.get("ai_risk_score") or 0), "Created from department control room.", datetime.utcnow().isoformat(timespec="seconds")),
                )
                conn.commit()
                log_admin_audit(admin.get("id"), "moderation_case_created", "department", slug, {"target_type": target_type, "target_id": target_id, "priority": priority})
                message = "Moderation case created."
        else:
            title = clean_html(request.form.get("title", ""))[:180]
            description = clean_html(request.form.get("description", ""))[:1200]
            priority = clean_html(request.form.get("priority", "normal"))[:40]
            assigned_to = int(request.form.get("assigned_to") or 0) or None
            if title:
                cur.execute(
                    """
                    INSERT INTO admin_tasks
                    (department, title, description, priority, assigned_to, status, source_type, source_id, due_at, created_at, updated_at)
                    VALUES (?, ?, ?, ?, ?, 'open', ?, ?, ?, ?, ?)
                    """,
                    (
                        slug,
                        title,
                        description,
                        priority,
                        assigned_to,
                        clean_html(request.form.get("source_type", ""))[:80],
                        clean_html(request.form.get("source_id", ""))[:120],
                        clean_html(request.form.get("due_at", ""))[:80],
                        datetime.utcnow().isoformat(timespec="seconds"),
                        datetime.utcnow().isoformat(timespec="seconds"),
                    ),
                )
                conn.commit()
                log_admin_audit(admin.get("id"), "admin_task_created", "department", slug, {"title": title, "priority": priority, "assigned_to": assigned_to})
                message = "Department task created."
        conn.close()
    counts = department_counts(slug)
    conn = db()
    conn.row_factory = sqlite3.Row
    cur = conn.cursor()
    cur.execute("SELECT * FROM admin_tasks WHERE department=? ORDER BY CASE priority WHEN 'critical' THEN 0 WHEN 'high' THEN 1 WHEN 'normal' THEN 2 ELSE 3 END, id DESC LIMIT 80", (slug,))
    tasks = [dict(row) for row in cur.fetchall()]
    cur.execute("SELECT * FROM moderation_cases WHERE status IN ('open','reviewing') ORDER BY id DESC LIMIT 30")
    cases = [dict(row) for row in cur.fetchall()] if slug in {"trust-safety", "social", "moderation"} else []
    cur.execute(
        """
        SELECT dm.*, au.email AS admin_email
        FROM department_members dm
        LEFT JOIN admin_users au ON au.id=dm.admin_user_id
        WHERE dm.department_id=(SELECT id FROM departments WHERE lower(name)=lower(?) OR slug=? LIMIT 1)
          AND dm.active=1
        ORDER BY dm.role, au.email
        """,
        (meta["title"], slug),
    )
    members = [dict(row) for row in cur.fetchall()]
    conn.close()
    focus = "".join(f"<li>{clean_html(item)}</li>" for item in meta["focus"])
    task_rows = "".join(
        f"<tr><td>{t.get('id')}</td><td>{clean_html(t.get('priority') or '')}</td><td>{clean_html(t.get('status') or '')}</td><td>{clean_html(t.get('title') or '')}</td><td>{clean_html(t.get('created_at') or '')}</td><td><form method='post'><input type='hidden' name='form_action' value='update_task'><input type='hidden' name='task_id' value='{t.get('id')}'><select name='status'><option>open</option><option>in_progress</option><option>blocked</option><option>done</option></select><button>Update</button></form></td></tr>"
        for t in tasks
    )
    case_rows = "".join(f"<tr><td>{c.get('id')}</td><td>{clean_html(c.get('priority') or '')}</td><td>{clean_html(c.get('target_type') or '')}</td><td>{clean_html(c.get('reason') or '')}</td></tr>" for c in cases)
    cases_panel = ""
    if slug in {"trust-safety", "social", "moderation"}:
        cases_panel = f"<div class='card'><h2>Moderation Cases</h2><table><tr><th>ID</th><th>Priority</th><th>Target</th><th>Reason</th></tr>{case_rows or '<tr><td colspan=4>No open cases.</td></tr>'}</table></div><div class='card'><h2>Create Moderation Case</h2><form method='post'><input type='hidden' name='form_action' value='create_case'><select name='target_type'><option>post</option><option>comment</option><option>media</option><option>user</option><option>roast_line</option></select><input name='target_id' placeholder='Target ID'><select name='case_priority'><option>medium</option><option>high</option><option>critical</option><option>low</option></select><textarea name='reason' placeholder='Reason and context'></textarea><button>Create Case</button></form></div>"
    member_rows = "".join(f"<tr><td>{clean_html(m.get('admin_email') or '')}</td><td>{clean_html(m.get('role') or '')}</td><td>{clean_html(m.get('permissions') or '')}</td></tr>" for m in members)
    panels = department_control_panels(slug)
    controls = department_action_panel(slug)
    body = f"<h1>{clean_html(meta['title'])}</h1><p>{clean_html(message)}</p><div class='grid'><div class='card'><h2>Health</h2><p style='font-size:34px;font-weight:900'>{counts['health']}%</p><div class='mini-chart'><span style='width:{max(5, min(100, counts['health']))}%'></span></div></div><div class='card'><h2>Pending Tasks</h2><p style='font-size:34px;font-weight:900'>{counts['pending_tasks']}</p></div><div class='card'><h2>Warnings</h2><p style='font-size:34px;font-weight:900'>{counts['warnings']}</p></div><div class='card'><h2>Today</h2><p style='font-size:34px;font-weight:900'>{counts['today']}</p></div></div>{panels}{controls}<div class='card'><h2>Department Focus</h2><ul>{focus}</ul></div><div class='card'><h2>Assigned Team</h2><table><tr><th>Admin</th><th>Role</th><th>Permissions</th></tr>{member_rows or '<tr><td colspan=3>No active department members assigned yet.</td></tr>'}</table></div><div class='card'><h2>Create Task</h2><form method='post'><input type='hidden' name='form_action' value='create_task'><input name='title' placeholder='Task title'><select name='priority'><option>normal</option><option>high</option><option>critical</option><option>low</option></select><input name='assigned_to' placeholder='Assigned admin ID optional'><input name='source_type' placeholder='Source type optional'><input name='source_id' placeholder='Source ID optional'><input name='due_at' placeholder='Due date optional'><textarea name='description' placeholder='Task details'></textarea><button>Create Task</button></form></div><div class='card'><h2>Work Queue</h2><table><tr><th>ID</th><th>Priority</th><th>Status</th><th>Title</th><th>Created</th><th>Action</th></tr>{task_rows or '<tr><td colspan=6>No tasks yet.</td></tr>'}</table></div>{cases_panel}"
    return admin_page_html(meta["title"], body, admin)


def ai_command_seed_recommendation(admin_id=0):
    snapshot = global_command_snapshot(persist=False)
    rec = ai_action_pipeline.from_meta_coordination(snapshot.get("meta"), snapshot.get("fabric"))
    now = datetime.utcnow().isoformat(timespec="seconds")
    conn = db()
    conn.row_factory = sqlite3.Row
    cur = conn.cursor()
    cur.execute("SELECT * FROM ai_recommendations WHERE external_id=? LIMIT 1", (rec["external_id"],))
    existing = cur.fetchone()
    if existing:
        cur.execute(
            """
            UPDATE ai_recommendations
            SET source_engine=?, recommendation_type=?, title=?, description=?, priority=?, confidence=?,
                risk_level=?, recommended_action=?, owner_approval_required=?, estimated_impact=?,
                affected_area=?, status=CASE WHEN status='closed' THEN status ELSE ? END, updated_at=?
            WHERE external_id=?
            """,
            (
                rec["source_engine"], rec["recommendation_type"], rec["title"], rec["description"], rec["priority"],
                rec["confidence"], rec["risk_level"], rec["recommended_action"], 1 if rec["owner_approval_required"] else 0,
                rec["estimated_impact"], rec["affected_area"], rec["status"], now, rec["external_id"],
            ),
        )
        rec_id = int(existing["id"])
    else:
        cur.execute(
            """
            INSERT INTO ai_recommendations
            (external_id, source_engine, recommendation_type, title, description, priority, confidence, risk_level,
             recommended_action, owner_approval_required, estimated_impact, affected_area, status, created_at, updated_at)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                rec["external_id"], rec["source_engine"], rec["recommendation_type"], rec["title"], rec["description"],
                rec["priority"], rec["confidence"], rec["risk_level"], rec["recommended_action"],
                1 if rec["owner_approval_required"] else 0, rec["estimated_impact"], rec["affected_area"],
                rec["status"], rec["created_at"], now,
            ),
        )
        rec_id = int(cur.lastrowid or 0)
    conn.commit()
    conn.close()
    log_admin_audit(admin_id, "ai_recommendation_seeded", "ai_recommendation", str(rec_id), {"external_id": rec["external_id"]})
    return rec_id


def ai_command_fetch_recommendation(rec_id):
    conn = db()
    conn.row_factory = sqlite3.Row
    cur = conn.cursor()
    cur.execute("SELECT * FROM ai_recommendations WHERE id=? LIMIT 1", (int(rec_id or 0),))
    row = cur.fetchone()
    conn.close()
    return dict(row) if row else None


def ai_command_create_task_from_recommendation(rec_id, admin):
    rec = ai_command_fetch_recommendation(rec_id)
    if not rec:
        return None, "Recommendation not found."
    now = datetime.utcnow().isoformat(timespec="seconds")
    department = ai_action_pipeline.department_for_recommendation(rec)
    conn = db()
    cur = conn.cursor()
    cur.execute(
        """
        INSERT INTO admin_tasks
        (department, title, description, priority, assigned_to, status, source_type, source_id,
         source_recommendation_id, approval_required, created_at, updated_at)
        VALUES (?, ?, ?, ?, ?, 'open', 'ai_recommendation', ?, ?, ?, ?, ?)
        """,
        (
            department,
            rec.get("title") or "AI recommended task",
            rec.get("description") or rec.get("recommended_action") or "",
            rec.get("priority") or "normal",
            (admin or {}).get("id"),
            str(rec.get("id")),
            rec.get("external_id") or str(rec.get("id")),
            1 if rec.get("owner_approval_required") else 0,
            now,
            now,
        ),
    )
    task_id = int(cur.lastrowid or 0)
    if rec.get("owner_approval_required"):
        cur.execute(
            """
            INSERT INTO admin_approvals
            (approval_type, target_type, target_id, title, description, status, priority, risk_level, confidence,
             requested_by, created_at, updated_at)
            VALUES ('admin_task', 'admin_task', ?, ?, ?, 'pending', ?, ?, ?, ?, ?, ?)
            """,
            (
                str(task_id), rec.get("title") or "Approval required", rec.get("recommended_action") or rec.get("description") or "",
                rec.get("priority") or "normal", rec.get("risk_level") or "normal", float(rec.get("confidence") or 0),
                (admin or {}).get("id"), now, now,
            ),
        )
    cur.execute("UPDATE ai_recommendations SET status='task_created', updated_at=? WHERE id=?", (now, rec_id))
    conn.commit()
    conn.close()
    log_admin_audit((admin or {}).get("id"), "ai_recommendation_task_created", "ai_recommendation", str(rec_id), {"task_id": task_id, "department": department})
    return task_id, "Admin task created."


def ai_command_create_action_request(rec_id, action_type, admin):
    rec = ai_command_fetch_recommendation(rec_id)
    if not rec:
        return None, "Recommendation not found."
    now = datetime.utcnow().isoformat(timespec="seconds")
    action_info = safe_execution_engine.classify_action(action_type)
    approval_required = bool(rec.get("owner_approval_required")) or action_info.get("owner_approval_required")
    payload = {
        "recommendation_id": rec.get("id"),
        "title": rec.get("title"),
        "recommended_action": rec.get("recommended_action"),
        "affected_area": rec.get("affected_area"),
        "risk_level": rec.get("risk_level"),
    }
    conn = db()
    cur = conn.cursor()
    cur.execute(
        """
        INSERT INTO ai_action_requests
        (recommendation_id, action_type, target_type, target_id, payload_json, status, approval_required,
         requested_by, created_at, updated_at)
        VALUES (?, ?, 'ai_recommendation', ?, ?, ?, ?, ?, ?, ?)
        """,
        (
            rec.get("id"),
            action_info["action_type"],
            str(rec.get("id")),
            json.dumps(payload, default=str),
            "pending_approval" if approval_required else "approved",
            1 if approval_required else 0,
            (admin or {}).get("id"),
            now,
            now,
        ),
    )
    request_id = int(cur.lastrowid or 0)
    if approval_required:
        cur.execute(
            """
            INSERT INTO admin_approvals
            (approval_type, target_type, target_id, title, description, status, priority, risk_level, confidence,
             requested_by, created_at, updated_at)
            VALUES ('ai_action', 'ai_action_request', ?, ?, ?, 'pending', ?, ?, ?, ?, ?, ?)
            """,
            (
                str(request_id),
                rec.get("title") or "AI action approval",
                f"{action_info['action_type']}: {rec.get('recommended_action') or ''}",
                rec.get("priority") or "normal",
                rec.get("risk_level") or "normal",
                float(rec.get("confidence") or 0),
                (admin or {}).get("id"),
                now,
                now,
            ),
        )
    conn.commit()
    conn.close()
    log_admin_audit((admin or {}).get("id"), "ai_action_request_created", "ai_action_request", str(request_id), {"action_type": action_info["action_type"], "approval_required": approval_required})
    return request_id, "Action request created."


def ai_command_audit_action(conn, recommendation_id, action_type, target_type, target_id, requested_by=0, approved_by=0, executed_by=0, before=None, after=None, status="", error_message=""):
    cur = conn.cursor()
    cur.execute(
        """
        INSERT INTO ai_action_audit_logs
        (recommendation_id, action_type, target_type, target_id, requested_by, approved_by, executed_by,
         before_json, after_json, status, error_message, created_at)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        """,
        (
            int(recommendation_id or 0), action_type, target_type, target_id, int(requested_by or 0),
            int(approved_by or 0), int(executed_by or 0), json.dumps(before or {}, default=str)[:4000],
            json.dumps(after or {}, default=str)[:4000], status, (error_message or "")[:1200],
            datetime.utcnow().isoformat(timespec="seconds"),
        ),
    )


def ai_command_execute_request(request_id, admin):
    now = datetime.utcnow().isoformat(timespec="seconds")
    conn = db()
    conn.row_factory = sqlite3.Row
    cur = conn.cursor()
    cur.execute("SELECT * FROM ai_action_requests WHERE id=? LIMIT 1", (int(request_id or 0),))
    action_row = cur.fetchone()
    if not action_row:
        conn.close()
        return {"status": "failed", "message": "Action request not found."}
    action = dict(action_row)
    if int(action.get("approval_required") or 0) and not action.get("approved_by"):
        conn.close()
        return {"status": "skipped", "message": "Owner approval is required before execution."}
    before = {"action_request": action}
    payload = json.loads(action.get("payload_json") or "{}")
    result = safe_execution_engine.execute(action.get("action_type"), payload, approved=bool(action.get("approved_by") or not action.get("approval_required")))
    try:
        if result.get("status") == "success" and action.get("action_type") == "create_admin_task":
            rec_id = int(action.get("recommendation_id") or 0)
            rec = ai_command_fetch_recommendation(rec_id)
            if rec:
                task_id, _ = ai_command_create_task_from_recommendation(rec_id, admin)
                result.setdefault("result", {})["task_id"] = task_id
        cur.execute(
            """
            UPDATE ai_action_requests
            SET status=?, executed_by=?, executed_at=?, result_json=?, error_message=?, updated_at=?
            WHERE id=?
            """,
            (
                result.get("status"),
                (admin or {}).get("id"),
                now,
                json.dumps(result, default=str)[:4000],
                result.get("message") if result.get("status") in {"failed", "needs_manual_review", "skipped"} else "",
                now,
                action.get("id"),
            ),
        )
        ai_command_audit_action(
            conn,
            action.get("recommendation_id"),
            action.get("action_type"),
            action.get("target_type"),
            action.get("target_id"),
            action.get("requested_by"),
            action.get("approved_by"),
            (admin or {}).get("id"),
            before,
            result,
            result.get("status"),
            result.get("message") if result.get("status") != "success" else "",
        )
        score_payload = action_result_tracker.result_payload(
            action.get("recommendation_id"),
            action.get("id"),
            status=result.get("status"),
            useful=True if result.get("status") == "success" else None,
            metrics={"action_type": action.get("action_type")},
        )
        cur.execute(
            """
            INSERT INTO ai_action_results
            (recommendation_id, action_request_id, status, useful, owner_feedback, metrics_json, created_at)
            VALUES (?, ?, ?, ?, ?, ?, ?)
            """,
            (
                score_payload["recommendation_id"], score_payload["action_request_id"], score_payload["status"],
                1 if score_payload["useful"] is True else 0 if score_payload["useful"] is False else None,
                score_payload["owner_feedback"], json.dumps(score_payload["metrics"], default=str), score_payload["created_at"],
            ),
        )
        conn.commit()
    except Exception as exc:
        conn.rollback()
        result = {"status": "failed", "message": str(exc)}
    finally:
        conn.close()
    log_admin_audit((admin or {}).get("id"), "ai_action_request_executed", "ai_action_request", str(request_id), result)
    return result


def ai_command_action_summary(limit=5):
    init_db()
    conn = db()
    conn.row_factory = sqlite3.Row
    cur = conn.cursor()
    summary = {
        "pending_approvals": 0,
        "open_recommendations": 0,
        "critical_actions": [],
        "top_recommendations": [],
        "recent_results": [],
        "failed_actions": [],
    }
    try:
        cur.execute("SELECT COUNT(*) AS c FROM admin_approvals WHERE status='pending'")
        row = cur.fetchone()
        summary["pending_approvals"] = int(row["c"] if row else 0)
        cur.execute("SELECT COUNT(*) AS c FROM ai_recommendations WHERE status NOT IN ('closed','rejected')")
        row = cur.fetchone()
        summary["open_recommendations"] = int(row["c"] if row else 0)
        cur.execute("SELECT * FROM ai_recommendations WHERE status NOT IN ('closed','rejected') ORDER BY CASE priority WHEN 'critical' THEN 0 WHEN 'high' THEN 1 WHEN 'normal' THEN 2 ELSE 3 END, id DESC LIMIT ?", (limit,))
        summary["top_recommendations"] = [dict(row) for row in cur.fetchall()]
        cur.execute("SELECT * FROM ai_action_requests WHERE status IN ('pending_approval','pending','approved') ORDER BY CASE approval_required WHEN 1 THEN 0 ELSE 1 END, id DESC LIMIT ?", (limit,))
        summary["critical_actions"] = [dict(row) for row in cur.fetchall()]
        cur.execute("SELECT * FROM ai_action_results ORDER BY id DESC LIMIT ?", (limit,))
        summary["recent_results"] = [dict(row) for row in cur.fetchall()]
        cur.execute("SELECT * FROM ai_action_requests WHERE status IN ('failed','needs_manual_review') ORDER BY id DESC LIMIT ?", (limit,))
        summary["failed_actions"] = [dict(row) for row in cur.fetchall()]
    except Exception as exc:
        logging.info("AI_COMMAND_SUMMARY_SKIPPED error=%s", exc)
    conn.close()
    return summary


