@webhook_app.route("/api/pulse/media/upload", methods=["POST"])
def api_pulse_media_upload():
    init_db()
    user = api_account_user()
    if not user:
        return api_error("Login required.", 401)
    file = request.files.get("file")
    if file:
        file.stream.seek(0, os.SEEK_END)
        size = file.stream.tell()
        file.stream.seek(0)
        check = camera_filter_engine.validate_media(file.filename or "", file.mimetype or "", size)
        if not check.get("ok"):
            return api_error(check.get("message") or "Media could not be validated.", 400)
    result, status = upload_progress_service.stage_upload(
        user["user_id"],
        file,
        context_type=request.form.get("context_type") or "pulse_camera",
        context_id=request.form.get("group") or request.form.get("target") or "",
    )
    if result.get("ok") and result.get("media"):
        result["media"]["filter_name"] = clean_html(request.form.get("filter_name") or "")[:80]
        try:
            media = result.get("media") or {}
            now = datetime.utcnow().isoformat(timespec="seconds")
            conn = db()
            cur = conn.cursor()
            cur.execute(
                """
                INSERT INTO pulse_media_assets
                (media_id, owner_user_id, storage_provider, storage_key, public_url, thumbnail_url, poster_url, media_type, mime_type, width, height, aspect_ratio, processing_status, created_at, updated_at)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'ready', ?, ?)
                """,
                (
                    safe_int(media.get("id"), 0),
                    int(user["user_id"]),
                    clean_html(media.get("storage_provider") or media_storage.provider())[:40],
                    clean_html(media.get("storage_key") or "")[:600],
                    clean_html(media.get("valid_url") or media.get("media_url") or "")[:1000],
                    clean_html(media.get("thumbnail_url") or "")[:1000],
                    clean_html(media.get("poster_url") or media.get("thumbnail_url") or "")[:1000],
                    clean_html(media.get("media_type") or "")[:40],
                    clean_html(media.get("mime_type") or "")[:120],
                    safe_int(media.get("width"), 0),
                    safe_int(media.get("height"), 0),
                    float(media.get("aspect_ratio") or 0),
                    now,
                    now,
                ),
            )
            if (request.form.get("context_type") or "").startswith("pulse_camera"):
                cur.execute(
                    """
                    INSERT INTO pulse_camera_captures (user_id, media_id, target, mode, filter_name, effect_key, created_at)
                    VALUES (?, ?, ?, ?, ?, ?, ?)
                    """,
                    (
                        int(user["user_id"]),
                        safe_int(media.get("id"), 0),
                        clean_html(request.form.get("target") or "")[:80],
                        clean_html(request.form.get("mode") or "")[:40],
                        clean_html(request.form.get("filter_name") or "")[:80],
                        clean_html(request.form.get("effect_key") or "")[:80],
                        now,
                    ),
                )
            conn.commit()
            conn.close()
        except Exception:
            logging.exception("PULSE_MEDIA_ASSET_INDEX_FAILED user_id=%s", user.get("user_id"))
    log_product_event(user["user_id"], "pulse_media_upload", {"ok": result.get("ok"), "target": request.form.get("target") or ""})
    return jsonify(result), status


