_MIGRATION_IDENTIFIER_RE = re.compile(r"^[A-Za-z_][A-Za-z0-9_]*$")


def _migration_identifier(identifier):
    if not _MIGRATION_IDENTIFIER_RE.match(identifier or ""):
        raise ValueError(f"Unsafe migration identifier: {identifier}")
    return identifier


def _rollback_failed_migration(conn, label, exc):
    try:
        conn.rollback()
    except Exception as rollback_exc:
        logging.warning("MIGRATION_ERROR_ROLLBACK_FAILED label=%s rollback_error=%s", label, rollback_exc)
    logging.warning("MIGRATION_ERROR_ROLLED_BACK label=%s error=%s", label, exc)


def add_column_if_missing(cur, table, column, definition, conn=None):
    table_name = _migration_identifier(table)
    column_name = _migration_identifier(column)
    label = f"{table_name}.{column_name}"
    try:
        if db_service.IS_POSTGRES:
            cur.execute(
                """
                SELECT 1
                FROM information_schema.columns
                WHERE table_schema = 'public'
                  AND table_name = ?
                  AND column_name = ?
                """,
                (table_name, column_name),
            )
            exists = bool(cur.fetchone())
        else:
            cur.execute(f"PRAGMA table_info({table_name})")
            exists = any((row.get("name") if hasattr(row, "get") else row["name"]) == column_name for row in cur.fetchall())

        if exists:
            logging.info("COLUMN_EXISTS_SKIPPED table=%s column=%s", table_name, column_name)
            return False

        if db_service.IS_POSTGRES:
            cur.execute(f"ALTER TABLE {table_name} ADD COLUMN IF NOT EXISTS {column_name} {definition}")
        else:
            cur.execute(f"ALTER TABLE {table_name} ADD COLUMN {column_name} {definition}")
        logging.info("COLUMN_ADDED table=%s column=%s definition=%s", table_name, column_name, definition)
        return True
    except Exception as exc:
        if conn is not None:
            _rollback_failed_migration(conn, label, exc)
        else:
            logging.warning("MIGRATION_ERROR_ROLLED_BACK label=%s error=%s", label, exc)
        return False


def add_columns_if_missing(cur, table, columns, conn=None):
    for column, definition in columns:
        add_column_if_missing(cur, table, column, definition, conn=conn)


def _migration_row_value(row, key, index=0):
    if row is None:
        return None
    if hasattr(row, "get"):
        return row.get(key)
    try:
        return row[key]
    except Exception:
        return row[index]


def migration_table_exists(cur, table):
    table = _migration_identifier(table)
    try:
        if db_service.IS_POSTGRES:
            cur.execute("SELECT COUNT(*) AS c FROM information_schema.tables WHERE table_schema='public' AND table_name=?", (table,))
        else:
            cur.execute("SELECT COUNT(*) AS c FROM sqlite_master WHERE type='table' AND name=?", (table,))
        row = cur.fetchone()
        return bool(_migration_row_value(row, "c", 0) if row else 0)
    except Exception as exc:
        logging.info("MIGRATION_TABLE_EXISTS_CHECK_SKIPPED table=%s error=%s", table, exc)
        return False


def migration_table_columns(cur, table):
    table = _migration_identifier(table)
    try:
        if db_service.IS_POSTGRES:
            cur.execute("SELECT column_name FROM information_schema.columns WHERE table_schema='public' AND table_name=?", (table,))
            return {_migration_row_value(row, "column_name", 0) for row in cur.fetchall()}
        cur.execute(f"PRAGMA table_info({table})")
        return {_migration_row_value(row, "name", 1) for row in cur.fetchall()}
    except Exception as exc:
        logging.info("MIGRATION_COLUMN_CHECK_SKIPPED table=%s error=%s", table, exc)
        return set()


def safe_create_index(cur, conn, statement):
    match = re.search(r"\bON\s+([a-zA-Z_][a-zA-Z0-9_]*)\s*\(([^)]+)\)", statement or "", flags=re.I)
    table = _migration_identifier(match.group(1)) if match else ""
    columns = []
    if match:
        for part in match.group(2).split(","):
            column = _migration_identifier(part.strip().split()[0].strip('"'))
            if column:
                columns.append(column)
    try:
        if table and not migration_table_exists(cur, table):
            logging.info("INDEX_CREATE_SKIPPED_MISSING_TABLE table=%s statement=%s", table, statement)
            return False
        if table and columns:
            existing = migration_table_columns(cur, table)
            missing = [column for column in columns if column not in existing]
            if missing:
                logging.info("INDEX_CREATE_SKIPPED_MISSING_COLUMNS table=%s columns=%s statement=%s", table, missing, statement)
                return False
        cur.execute(statement)
        try:
            conn.commit()
        except Exception:
            pass
        return True
    except Exception as exc:
        try:
            conn.rollback()
        except Exception:
            pass
        logging.info("INDEX_CREATE_SKIPPED statement=%s error=%s", statement, exc)
        return False


