def scan_btc_whales(limit=25):
    block_hash = btc_tip_hash()
    if not block_hash:
        return []
    txs = blockstream_json(f"/block/{block_hash}/txs") or []
    events = []
    for tx in txs[:limit]:
        event = classify_whale_tx(tx)
        if event:
            save_whale_intelligence(event)
            events.append(event)
    return events


