def normalize_country(country):
    raw = clean_html(country).strip()
    if not raw:
        return "Haiti"
    lowered = raw.lower()
    if lowered in COUNTRY_ALIASES:
        return COUNTRY_ALIASES[lowered]
    for known in COUNTRY_PROFILES:
        if lowered == known.lower():
            return known
    return raw.title()


