def stripe_period_end_to_iso(value):
    try:
        if value:
            return datetime.fromtimestamp(int(value)).isoformat()
    except Exception:
        return None
    return None


def stripe_object_get(obj, key, default=None):
    try:
        if isinstance(obj, dict):
            return obj.get(key, default)
        return obj.get(key, default)
    except Exception:
        return getattr(obj, key, default)


def fetch_stripe_customer_email(customer_id):
    if not customer_id or not STRIPE_SECRET_KEY:
        return ""
    try:
        customer = stripe.Customer.retrieve(customer_id)
        email = stripe_object_get(customer, "email", "") or ""
        logging.info("Stripe customer lookup customer_id=%s email_found=%s", customer_id, bool(email))
        return email
    except Exception as exc:
        logging.warning("Stripe customer lookup failed customer_id=%s error=%s", customer_id, exc)
        return ""


def fetch_stripe_subscription(subscription_id):
    if not subscription_id or not STRIPE_SECRET_KEY:
        return None
    try:
        subscription = stripe.Subscription.retrieve(subscription_id)
        logging.info("Stripe subscription lookup success subscription_id=%s", subscription_id)
        return subscription
    except Exception as exc:
        logging.warning("Stripe subscription lookup failed subscription_id=%s error=%s", subscription_id, exc)
        return None


def stripe_amount_to_decimal(value):
    try:
        if value is not None:
            return int(value) / 100
    except Exception:
        return None
    return None


def stripe_object_summary(obj):
    try:
        if isinstance(obj, dict):
            data = obj
        else:
            data = dict(obj)
    except Exception:
        data = {}
    return {
        "id": stripe_object_get(obj, "id", data.get("id")),
        "object": stripe_object_get(obj, "object", data.get("object")),
        "customer": stripe_object_get(obj, "customer", data.get("customer")),
        "subscription": stripe_object_get(obj, "subscription", data.get("subscription")),
        "payment_status": stripe_object_get(obj, "payment_status", data.get("payment_status")),
        "status": stripe_object_get(obj, "status", data.get("status")),
        "amount_total": stripe_object_get(obj, "amount_total", data.get("amount_total")),
        "amount_paid": stripe_object_get(obj, "amount_paid", data.get("amount_paid")),
        "currency": stripe_object_get(obj, "currency", data.get("currency")),
        "client_reference_id": stripe_object_get(obj, "client_reference_id", data.get("client_reference_id")),
        "metadata": stripe_object_get(obj, "metadata", data.get("metadata")) or {},
    }


def default_pro_period_end(days=None):
    try:
        configured_days = int(days or os.getenv("PRO_ACCESS_DAYS") or os.getenv("STRIPE_PRO_ACCESS_DAYS") or 30)
    except Exception:
        configured_days = 30
    configured_days = max(1, min(configured_days, 3650))
    return (datetime.now() + timedelta(days=configured_days)).isoformat()


def activate_pro_from_stripe_session(session, event_id="", source="success_page"):
    session = session or {}
    session_id = stripe_object_get(session, "id", "")
    customer_id = stripe_object_get(session, "customer", "")
    payment_status = (stripe_object_get(session, "payment_status", "") or "").lower()
    amount = stripe_amount_to_decimal(stripe_object_get(session, "amount_total"))
    currency = stripe_object_get(session, "currency", "usd") or "usd"
    subscription = stripe_object_get(session, "subscription")
    subscription_id = subscription if isinstance(subscription, str) else stripe_object_get(subscription, "id", "")
    if subscription_id and isinstance(subscription, str):
        subscription = fetch_stripe_subscription(subscription_id)
    period_end = None
    subscription_status = "active"
    if subscription:
        subscription_status = (stripe_object_get(subscription, "status", "") or "active").lower()
        period_end = stripe_period_end_to_iso(stripe_object_get(subscription, "current_period_end")) or stripe_period_end_to_iso(stripe_object_get(subscription, "trial_end"))
    user_id, resolved_email = resolve_checkout_session_user(session)
    logging.info(
        "STRIPE_SESSION_CONFIRM session_id=%s source=%s user_id=%s customer_id=%s subscription_id=%s payment_status=%s period_end=%s",
        session_id,
        source,
        user_id,
        customer_id,
        subscription_id,
        payment_status,
        period_end,
    )
    if not user_id:
        record_unmatched_payment({"id": event_id or f"session_confirm_{session_id}", "type": "checkout.session.confirmed"}, stripe_object_summary(session), "success page session confirmation could not resolve local user")
        return {"ok": False, "message": "Could not match this Stripe session to a CoinPilotXAI account.", "status": "user_not_found"}
    if payment_status not in {"paid", "no_payment_required"} and not subscription_id:
        logging.warning("STRIPE_SESSION_CONFIRM_NOT_PAID session_id=%s user_id=%s payment_status=%s", session_id, user_id, payment_status)
        return {"ok": False, "message": "Stripe has not marked this checkout session as paid yet.", "status": payment_status or "pending", "user_id": user_id}
    if resolved_email and is_valid_email(resolved_email):
        save_user_email(user_id, resolved_email)
    activation_event_id = event_id or f"session_confirm_{session_id}"
    activated_user_id = activate_pro(
        user_id,
        payment_type="stripe",
        stripe_customer_id=customer_id,
        stripe_session_id=session_id,
        stripe_subscription_id=subscription_id,
        subscription_status=subscription_status if subscription_status in {"active", "trialing"} else "active",
        pro_expires_at=period_end,
        stripe_event_id=activation_event_id,
        payment_status=payment_status or "paid",
        payment_amount=amount,
        payment_currency=currency,
    )
    if not activated_user_id:
        logging.error("STRIPE_SESSION_CONFIRM_ACTIVATION_FAILED session_id=%s user_id=%s", session_id, user_id)
        return {"ok": False, "message": "Payment was found, but Pro activation failed.", "status": "activation_failed", "user_id": user_id}
    payment_id = record_payment_record(
        activated_user_id,
        stripe_event_id=activation_event_id,
        stripe_session_id=session_id,
        stripe_customer_id=customer_id,
        stripe_subscription_id=subscription_id,
        payment_intent_id=stripe_object_get(session, "payment_intent", "") or "",
        amount=amount,
        currency=currency,
        status="succeeded",
        payment_type="stripe",
        metadata={"source": source, "payment_status": payment_status},
        stripe_payload=stripe_object_summary(session),
        pro_activated_at=datetime.now().isoformat(),
    )
    save_payment_verification(
        activated_user_id,
        txid=session_id,
        payment_type="stripe",
        amount=amount,
        status="verified",
        details=f"Stripe checkout session confirmed from {source}",
    )
    record_stripe_event(
        {"id": activation_event_id, "type": "checkout.session.confirmed", "data": {"object": stripe_object_summary(session)}},
        "processed",
        activated_user_id,
    )
    fresh_user = load_account_by_id(activated_user_id)
    email_results = {}
    if fresh_user and has_pro_access(fresh_user):
        email_results = send_successful_payment_email_bundle(fresh_user, {
            "stripe_event_id": activation_event_id,
            "stripe_session_id": session_id,
            "payment_id": session_id or stripe_object_get(session, "payment_intent", "") or "",
            "amount": amount,
            "currency": currency,
            "billing_date": datetime.now().strftime("%b %d, %Y"),
            "next_billing_date": format_date(period_end) if period_end else "",
        })
        email_sent = any(bool(value) for value in (email_results or {}).values())
        try:
            conn = db()
            cur = conn.cursor()
            cur.execute("UPDATE payment_records SET email_sent=? WHERE id=?", (1 if email_sent else 0, payment_id))
            conn.commit()
            conn.close()
        except Exception as exc:
            logging.info("Payment email_sent flag update skipped payment_id=%s error=%s", payment_id, exc)
    logging.info("STRIPE_SESSION_CONFIRM_SUCCESS session_id=%s user_id=%s payment_record_id=%s email_sent=%s", session_id, activated_user_id, payment_id, bool(email_results))
    return {
        "ok": True,
        "status": "pro_active",
        "user_id": activated_user_id,
        "payment_record_id": payment_id,
        "stripe_customer_id": customer_id,
        "stripe_subscription_id": subscription_id,
        "next_url": "/dashboard?pro=active",
    }


def user_id_from_candidate(value):
    if not value:
        return None
    try:
        candidate = int(str(value))
    except Exception:
        return None
    if load_account_by_id(candidate):
        return candidate
    return None


def find_user_by_stripe(customer_id=None, subscription_id=None, metadata_user_id=None, customer_email=None):
    candidate = user_id_from_candidate(metadata_user_id)
    if candidate:
        logging.info("Stripe user resolved by metadata/client reference user_id=%s", candidate)
        return candidate
    conn = db()
    cur = conn.cursor()
    if subscription_id:
        cur.execute("SELECT user_id FROM users WHERE stripe_subscription_id=? LIMIT 1", (subscription_id,))
        row = cur.fetchone()
        if row:
            conn.close()
            logging.info("Stripe user resolved by subscription_id user_id=%s", row[0])
            return row[0]
    if customer_id:
        cur.execute("SELECT user_id FROM users WHERE stripe_customer_id=? LIMIT 1", (customer_id,))
        row = cur.fetchone()
        if row:
            conn.close()
            logging.info("Stripe user resolved by customer_id user_id=%s", row[0])
            return row[0]
    conn.close()
    email = normalize_email(customer_email)
    if not email:
        email = normalize_email(fetch_stripe_customer_email(customer_id))
    if email and is_valid_email(email):
        user = load_account_by_email(email)
        if user:
            logging.info("Stripe user resolved by email user_id=%s email=%s", user["user_id"], email)
            return user["user_id"]
    logging.warning(
        "Stripe user resolution failed customer_id=%s subscription_id=%s metadata_user_id=%s email_present=%s",
        customer_id,
        subscription_id,
        metadata_user_id,
        bool(customer_email),
    )
    return None


def resolve_checkout_session_user(session):
    session = session or {}
    metadata = stripe_object_get(session, "metadata", {}) or {}
    customer_details = stripe_object_get(session, "customer_details", {}) or {}
    customer_email = (
        customer_details.get("email")
        or stripe_object_get(session, "customer_email", "")
        or metadata.get("email")
        or ""
    )
    metadata_user_id = (
        stripe_object_get(session, "client_reference_id", "")
        or metadata.get("user_id")
        or metadata.get("client_reference_id")
        or metadata.get("account_user_id")
    )
    subscription = stripe_object_get(session, "subscription", "")
    subscription_id = subscription if isinstance(subscription, str) else stripe_object_get(subscription, "id", "")
    customer_id = stripe_object_get(session, "customer", "")
    user_id = find_user_by_stripe(customer_id, subscription_id, metadata_user_id, customer_email)
    logging.info(
        "Stripe checkout resolution session_id=%s customer_id=%s customer_email=%s client_reference_id=%s metadata_user_id=%s resolved_user_id=%s",
        stripe_object_get(session, "id", ""),
        customer_id,
        bool(customer_email),
        stripe_object_get(session, "client_reference_id", ""),
        metadata.get("user_id"),
        user_id,
    )
    return user_id, customer_email


def sync_stripe_subscription(subscription):
    subscription = subscription or {}
    customer_id = subscription.get("customer")
    subscription_id = subscription.get("id")
    metadata = subscription.get("metadata") or {}
    user_id = find_user_by_stripe(
        customer_id,
        subscription_id,
        metadata.get("user_id") or metadata.get("client_reference_id"),
        metadata.get("email"),
    )
    if not user_id:
        logging.info("Stripe subscription sync skipped: no matching user for customer=%s subscription=%s", customer_id, subscription_id)
        return None
    raw_status = (subscription.get("status") or "").lower()
    status = raw_status if raw_status in {"active", "trialing"} else ("past_due" if raw_status in {"past_due", "unpaid"} else ("canceled" if raw_status in {"canceled", "incomplete_expired"} else raw_status or "inactive"))
    period_end = stripe_period_end_to_iso(subscription.get("current_period_end")) or stripe_period_end_to_iso(subscription.get("trial_end"))
    before = load_account_by_id(user_id) or {}
    logging.info(
        "Stripe subscription sync start event_subscription=%s user_id=%s before_plan=%s before_status=%s stripe_status=%s period_end=%s",
        subscription_id,
        user_id,
        before.get("plan") or before.get("subscription_plan"),
        before.get("subscription_status"),
        raw_status,
        period_end,
    )
    if status in {"active", "trialing"}:
        activate_pro(
            user_id,
            payment_type="stripe",
            stripe_customer_id=customer_id,
            stripe_subscription_id=subscription_id,
            subscription_status=status,
            pro_expires_at=period_end,
        )
    else:
        conn = db()
        cur = conn.cursor()
        cur.execute(
            """
            UPDATE users
            SET subscription_status=?, pro_active=0, is_pro=0,
                stripe_customer_id=COALESCE(?, stripe_customer_id),
                stripe_subscription_id=COALESCE(?, stripe_subscription_id),
                payment_provider='stripe',
                provider_customer_id=COALESCE(?, provider_customer_id),
                provider_subscription_id=COALESCE(?, provider_subscription_id),
                last_payment_status=?,
                pro_expires_at=COALESCE(?, pro_expires_at),
                subscription_expires_at=COALESCE(?, subscription_expires_at),
                updated_at=?
            WHERE user_id=?
            """,
            (status, customer_id, subscription_id, customer_id, subscription_id, status, period_end, period_end, datetime.now().isoformat(), user_id),
        )
        cur.execute(
            """
            INSERT INTO subscriptions
            (user_id, plan, status, payment_type, stripe_customer_id, stripe_subscription_id, current_period_end, pro_expires_at, created_at, updated_at)
            VALUES (?, 'pro', ?, 'stripe', ?, ?, ?, ?, ?, ?)
            """,
            (user_id, status, customer_id, subscription_id, period_end, period_end, datetime.now().isoformat(), datetime.now().isoformat()),
        )
        conn.commit()
        conn.close()
    after = load_account_by_id(user_id) or {}
    logging.info(
        "Stripe subscription sync committed user_id=%s after_plan=%s after_status=%s customer_id=%s subscription_id=%s",
        user_id,
        after.get("plan") or after.get("subscription_plan"),
        after.get("subscription_status"),
        customer_id,
        subscription_id,
    )
    logging.info(
        "SUBSCRIPTION_RECORD_UPDATED user_id=%s status=%s stripe_customer_id=%s stripe_subscription_id=%s period_end=%s",
        user_id,
        status,
        customer_id,
        subscription_id,
        period_end,
    )
    if (before.get("subscription_status") or "").lower() == "trialing" and status == "active":
        logging.info("TRIAL_TO_PAID_CONVERSION user_id=%s subscription_id=%s", user_id, subscription_id)
    log_product_event(user_id, "pro_subscription_active" if status == "active" else "pro_subscription_updated", {"stripe_status": raw_status or status})
    expire_trials(send_email=False)
    user = load_account_by_id(user_id)
    if user:
        sync_brevo_contact_safe({**user, "source": "stripe_subscription"}, entity_type="user", entity_id=user_id)
    return user_id


def sync_stripe_invoice(invoice, event_type):
    invoice = invoice or {}
    customer_id = invoice.get("customer")
    subscription_id = invoice.get("subscription")
    customer_email = invoice.get("customer_email") or invoice.get("customer_email_address") or ""
    subscription = None
    metadata_user_id = ""
    if subscription_id:
        subscription = fetch_stripe_subscription(subscription_id)
        if subscription:
            metadata = subscription.get("metadata") or {}
            metadata_user_id = metadata.get("user_id") or metadata.get("client_reference_id") or ""
            customer_email = customer_email or metadata.get("email") or ""
    user_id = find_user_by_stripe(customer_id, subscription_id, metadata_user_id, customer_email)
    if not user_id:
        logging.info("Stripe invoice sync skipped: no matching user for customer=%s subscription=%s", customer_id, subscription_id)
        return None
    lines = (invoice.get("lines") or {}).get("data") or []
    period_end = None
    if lines:
        period_end = stripe_period_end_to_iso((lines[0].get("period") or {}).get("end"))
    if event_type in {"invoice.paid", "invoice.payment_succeeded"}:
        logging.info("Stripe invoice payment succeeded user_id=%s invoice_id=%s customer_id=%s subscription_id=%s", user_id, invoice.get("id"), customer_id, subscription_id)
        activate_pro(
            user_id,
            payment_type="stripe",
            stripe_customer_id=customer_id,
            stripe_subscription_id=subscription_id,
            subscription_status="active",
            pro_expires_at=period_end,
            stripe_event_id=invoice.get("id") or "",
            payment_status="paid",
            payment_amount=stripe_amount_to_decimal(invoice.get("amount_paid")),
            payment_currency=invoice.get("currency", "usd"),
        )
        return user_id
    logging.warning("Stripe invoice payment failed user_id=%s invoice_id=%s customer_id=%s subscription_id=%s", user_id, invoice.get("id"), customer_id, subscription_id)
    conn = db()
    cur = conn.cursor()
    cur.execute(
        "UPDATE users SET subscription_status='past_due', updated_at=? WHERE user_id=?",
        (datetime.now().isoformat(), user_id),
    )
    conn.commit()
    conn.close()
    log_product_event(user_id, "pro_subscription_payment_failed", {"invoice": invoice.get("id")})
    return user_id


def activate_pro(user_id, payment_type=None, stripe_customer_id=None, stripe_session_id=None, stripe_subscription_id=None, subscription_status="active", pro_expires_at=None, stripe_event_id="", payment_status="", payment_amount=None, payment_currency="usd"):
    target_user = load_account_by_id(user_id) or get_linked_website_account(user_id)
    if not target_user:
        logging.error("Pro activation failed: local user not found user_id=%s payment_type=%s customer_id=%s subscription_id=%s", user_id, payment_type, stripe_customer_id, stripe_subscription_id)
        return None
    target_user_id = (target_user or {}).get("user_id") or user_id
    activation_time = datetime.now().isoformat()
    normalized_status = (subscription_status or "active").lower()
    if normalized_status in {"active", "trialing"} and not pro_expires_at:
        pro_expires_at = default_pro_period_end()
    provider = payment_type or "manual"
    last_payment_status = payment_status or ("approved" if normalized_status in {"active", "trialing"} else normalized_status)
    pro_active = 1 if normalized_status in {"active", "trialing"} else 0
    logging.info(
        "Pro activation starting user_id=%s before_plan=%s before_status=%s payment_type=%s customer_id=%s session_id=%s subscription_id=%s expires=%s",
        target_user_id,
        target_user.get("plan") or target_user.get("subscription_plan"),
        target_user.get("subscription_status"),
        payment_type,
        stripe_customer_id,
        stripe_session_id,
        stripe_subscription_id,
        pro_expires_at,
    )
    logging.info(
        "PAYMENT_SUCCESS_USER_BEFORE user_id=%s plan=%s status=%s trial_status=%s subscription_id=%s",
        target_user_id,
        target_user.get("plan") or target_user.get("subscription_plan"),
        target_user.get("subscription_status"),
        target_user.get("trial_status"),
        target_user.get("stripe_subscription_id"),
    )
    conn = db()
    cur = conn.cursor()
    cur.execute(
        """
        UPDATE users
        SET is_pro=1,
            pro_active=?,
            pro_started_at=COALESCE(pro_started_at, ?),
            subscription_plan='pro',
            plan='pro',
            subscription_status=?,
            subscription_started_at=?,
            updated_at=?,
            last_payment_type=COALESCE(?, last_payment_type),
            payment_provider=?,
            provider_customer_id=COALESCE(?, provider_customer_id),
            provider_subscription_id=COALESCE(?, provider_subscription_id),
            last_payment_status=?,
            payment_status=?,
            payment_amount=COALESCE(?, payment_amount),
            payment_currency=COALESCE(?, payment_currency),
            latest_stripe_event=COALESCE(?, latest_stripe_event),
            latest_payment_at=?,
            stripe_customer_id=COALESCE(?, stripe_customer_id),
            stripe_session_id=COALESCE(?, stripe_session_id),
            stripe_subscription_id=COALESCE(?, stripe_subscription_id),
            trial_status=CASE WHEN ?='trialing' THEN 'active' WHEN ?='active' THEN 'converted' ELSE COALESCE(trial_status, '') END,
            trial_end_date=CASE WHEN ?='trialing' THEN COALESCE(?, trial_end_date) ELSE trial_end_date END,
            pro_expires_at=?,
            subscription_expires_at=?
        WHERE user_id=? OR telegram_user_id=?
        """,
        (
            pro_active,
            activation_time,
            normalized_status,
            activation_time,
            activation_time,
            payment_type,
            provider,
            stripe_customer_id,
            stripe_subscription_id,
            last_payment_status,
            last_payment_status,
            payment_amount,
            (payment_currency or "usd").upper() if payment_currency else None,
            stripe_event_id or None,
            activation_time,
            stripe_customer_id,
            stripe_session_id,
            stripe_subscription_id,
            normalized_status,
            normalized_status,
            normalized_status,
            pro_expires_at,
            pro_expires_at,
            pro_expires_at,
            target_user_id,
            user_id,
        )
    )
    cur.execute(
        """
        INSERT INTO subscriptions
        (user_id, plan, status, payment_type, stripe_customer_id, stripe_subscription_id, current_period_end, pro_expires_at, created_at, updated_at)
        VALUES (?, 'pro', ?, ?, ?, ?, ?, ?, ?, ?)
        """,
        (
            target_user_id,
            normalized_status,
            provider,
            stripe_customer_id,
            stripe_subscription_id,
            pro_expires_at,
            pro_expires_at,
            activation_time,
            activation_time,
        ),
    )
    conn.commit()
    conn.close()
    after_user = load_account_by_id(target_user_id) or {}
    logging.info(
        "Pro activation database commit success user_id=%s after_plan=%s after_status=%s has_pro=%s",
        target_user_id,
        after_user.get("plan") or after_user.get("subscription_plan"),
        after_user.get("subscription_status"),
        has_pro_access(after_user),
    )
    logging.info(
        "PAYMENT_SUCCESS_USER_AFTER user_id=%s plan=%s status=%s trial_status=%s subscription_id=%s",
        target_user_id,
        after_user.get("plan") or after_user.get("subscription_plan"),
        after_user.get("subscription_status"),
        after_user.get("trial_status"),
        after_user.get("stripe_subscription_id"),
    )
    if (target_user.get("subscription_status") or "").lower() == "trialing" and normalized_status == "active":
        logging.info("TRIAL_TO_PAID_CONVERSION user_id=%s subscription_id=%s", target_user_id, stripe_subscription_id)
    logging.info("PRO_UPGRADE_COMPLETED user_id=%s status=%s", target_user_id, normalized_status)
    log_product_event(target_user_id, "pro_subscription_active" if normalized_status == "active" else "pro_subscription_updated", {"payment_type": provider, "status": normalized_status})
    log_security_event("pro_access_activated", "success", target_user_id, "/stripe-webhook", {"provider": provider, "status": normalized_status, "subscription_id": stripe_subscription_id or "", "stripe_event_id": stripe_event_id or ""})
    if normalized_status in {"active", "trialing"}:
        premium_entitlement_service.grant_entitlement(target_user_id, "pulse_premium", source="subscription" if provider == "stripe" else "admin_grant", ends_at=pro_expires_at or "", metadata={"provider": provider, "stripe_event_id": stripe_event_id or ""})
    else:
        premium_entitlement_service.revoke_entitlement(target_user_id, "pulse_premium", reason=f"subscription_{normalized_status}")
    user = load_account_by_id(target_user_id)
    if user:
        sync_brevo_contact_safe({**user, "source": payment_type or "pro_upgrade"}, entity_type="user", entity_id=user.get("user_id") or target_user_id)
    return target_user_id


DAY_SIGNAL_QUESTIONS = [
    {
        "key": "feeling",
        "question": "How do you feel today?",
        "options": [
            ("confident", "Confident"),
            ("calm", "Calm"),
            ("nervous", "Nervous"),
            ("tired", "Tired"),
        ],
    },
    {
        "key": "prepared",
        "question": "How prepared are you for what you want to do today?",
        "options": [
            ("very_prepared", "Very prepared"),
            ("somewhat_prepared", "Somewhat prepared"),
            ("not_prepared", "Not prepared"),
            ("guessing", "I'm guessing"),
        ],
    },
    {
        "key": "opportunity",
        "question": "What kind of opportunity are you thinking about?",
        "options": [
            ("crypto", "Crypto/Trading"),
            ("sports", "Sports Edge"),
            ("business", "Business/Money"),
            ("personal", "Personal decision"),
        ],
    },
    {
        "key": "walkaway",
        "question": "Are you willing to walk away if the signal looks risky?",
        "options": [
            ("yes", "Yes"),
            ("maybe", "Maybe"),
            ("no", "No"),
        ],
    },
]


def build_day_signal(answers):
    return day_signal_service.generate(answers)
    if not isinstance(answers, dict):
        return {"ok": False, "response": "Answer the Day Signal questions first."}

    normalized = {}
    for question in DAY_SIGNAL_QUESTIONS:
        value = str(answers.get(question["key"], "")).strip().lower()
        valid = {option_key for option_key, _ in question["options"]}
        if value not in valid:
            return {"ok": False, "response": f"Please answer: {question['question']}"}
        normalized[question["key"]] = value

    score = (
        {"confident": 22, "calm": 25, "nervous": 12, "tired": 8}[normalized["feeling"]]
        + {"very_prepared": 35, "somewhat_prepared": 24, "not_prepared": 8, "guessing": 4}[normalized["prepared"]]
        + {"crypto": 14, "sports": 12, "business": 17, "personal": 18}[normalized["opportunity"]]
        + {"yes": 22, "maybe": 12, "no": 0}[normalized["walkaway"]]
    )
    score = max(0, min(100, score))

    if score >= 80:
        signal = "Strong"
    elif score >= 62:
        signal = "Moderate"
    elif score >= 42:
        signal = "Caution"
    else:
        signal = "Not Today"

    opportunity_copy = {
        "crypto": {
            "name": "Crypto/Trading",
            "best": "Review your plan, risk limit, entry reason, and exit rule before touching real money.",
            "avoid": "Avoid revenge trading, oversized positions, leverage, or chasing a move because it already started.",
        },
        "sports": {
            "name": "Sports Edge",
            "best": "Compare the matchup data, price, timing, and risk. If the edge is unclear, waiting is a valid position.",
            "avoid": "Avoid forcing a position just because a game is live or because you want action today.",
        },
        "business": {
            "name": "Business/Money",
            "best": "Take one researched step, write down the downside, and choose the smallest move that still teaches you something.",
            "avoid": "Avoid rushed agreements, emotional spending, or decisions you cannot calmly explain tomorrow.",
        },
        "personal": {
            "name": "Personal decision",
            "best": "Choose the clearest next step, slow the conversation down, and keep the decision reversible if possible.",
            "avoid": "Avoid making high-stakes choices from fatigue, pressure, pride, or fear of missing out.",
        },
    }[normalized["opportunity"]]

    if normalized["prepared"] in {"not_prepared", "guessing"}:
        ai_message = "Your signal is asking for more preparation before action. The goal today is not bravery. It is clarity."
    elif normalized["walkaway"] == "no":
        ai_message = "Your drive is active, but discipline is the missing protection layer. A strong day still needs a stop point."
    elif normalized["feeling"] == "tired":
        ai_message = "Your energy looks low, so treat today as a risk-control day. Smaller, slower decisions can protect your future options."
    elif signal == "Strong":
        ai_message = "You look emotionally steady and prepared. Keep the confidence grounded in a plan, not impulse."
    elif signal == "Moderate":
        ai_message = "There may be room to move, but the signal favors patience, confirmation, and controlled sizing."
    elif signal == "Caution":
        ai_message = "The better win today may be avoiding a bad decision. Slow down and let the setup prove itself."
    else:
        ai_message = "Today does not look aligned for pressure-based action. Reset, prepare, and come back with a cleaner mind."

    if signal == "Not Today":
        best_move = "Pause the high-stakes move. Prepare, review, and revisit when your readiness is higher."
    elif signal == "Caution":
        best_move = f"Use a checklist first. {opportunity_copy['best']}"
    else:
        best_move = opportunity_copy["best"]

    disclaimer = "This is motivational and educational insight only. It is not financial, betting, or life advice."
    response = (
        "✨ CoinPilotX Day Signal\n\n"
        f"Today's Day Score: {score}/100\n\n"
        f"Signal: {signal}\n\n"
        f"AI Message:\n{ai_message}\n\n"
        f"Best Move Today:\n{best_move}\n\n"
        f"Avoid Today:\n{opportunity_copy['avoid']}\n\n"
        f"Disclaimer:\n{disclaimer}"
    )

    return {
        "ok": True,
        "score": score,
        "signal": signal,
        "message": ai_message,
        "best_move": best_move,
        "avoid": opportunity_copy["avoid"],
        "opportunity": opportunity_copy["name"],
        "response": response,
        "disclaimer": disclaimer,
    }


